-- Performance caches
local favorite_set          = {}
local pinned_set            = {}
local pinned_norm_set       = {}
local plugin_lower_name     = {}
local normalized_name_cache = {}
local clean_name_cache      = {} -- NEW
local strip_x86_cache       = {} -- NEW
local plugin_type_cache     = {}
local type_priority_cache   = nil

local fuzzy_norm_cache = {}
local function FuzzyNormalize(s)
    if not s then return "" end
    local c = fuzzy_norm_cache[s]
    if c then return c end
    local n = s:lower():gsub("[%-_%.%s]+", "")
    fuzzy_norm_cache[s] = n
    return n
end

function FuzzyFind(haystack, needle)
    if not needle or needle == "" then return true end
    if not haystack then return false end
    local n_l = needle:lower()
    local h_l = haystack:lower()
    if h_l:find(n_l, 1, true) then return true end
    if n_l:find("%s") then
        local h_norm = FuzzyNormalize(haystack)
        for tok in n_l:gmatch("%S+") do
            local t = tok:gsub("[%-_%.]+", "")
            if t ~= "" then
                if not h_l:find(tok, 1, true) and not h_norm:find(t, 1, true) then
                    return false
                end
            end
        end
        return true
    end
    if n_l:find("[%-_%.]") then
        local hs = FuzzyNormalize(haystack)
        local ns = n_l:gsub("[%-_%.%s]+", "")
        if ns ~= "" and hs:find(ns, 1, true) then return true end
    end
    return false
end


-- OPTIMALISATIE: Cache Command ID voor Notes
local cached_notes_command_id = nil

local function LaunchTKNotes()
    local notes_path = script_path .. "TK_NOTES.lua"
    if not r.file_exists(notes_path) then
        r.ShowMessageBox("TK_NOTES.lua not found.\nExpected path:\n" .. notes_path, "TK Notes Error", 0)
        return
    end

    -- Gebruik cached ID indien beschikbaar
    if not cached_notes_command_id or cached_notes_command_id == 0 then
        local command_id = r.AddRemoveReaScript(true, 0, notes_path, false)
        if not command_id or command_id == 0 or command_id == "" then
            command_id = r.AddRemoveReaScript(true, 0, notes_path, true)
        end

        if type(command_id) == "string" then
            command_id = r.NamedCommandLookup(command_id)
        end
        cached_notes_command_id = command_id
    end

    if not cached_notes_command_id or cached_notes_command_id == 0 then
        r.ShowMessageBox("Unable to register TK_NOTES.lua as an action.", "TK Notes Error", 0)
        return
    end

    r.Main_OnCommand(cached_notes_command_id, 0)
end


local SCRIPT_VERSION
local function GetScriptVersion()
    if SCRIPT_VERSION then return SCRIPT_VERSION end
    local info = debug.getinfo(1, "S")
    local src = info and info.source and info.source:match("^@(.+)$")
    local f = src and io.open(src, "r")
    if f then
        for i = 1, 50 do
            local l = f:read("*l"); if not l then break end
            local v = l:match("^%-%-%s*@version%s+([%w%._%-]+)")
            if v then SCRIPT_VERSION = v; break end
        end
        f:close()
    end
    SCRIPT_VERSION = SCRIPT_VERSION or "dev"
    return SCRIPT_VERSION
end

