-- NIEUWE FUNCTIE: Bouw de cache één keer op voor extreme snelheid
function BuildPluginCache()
    global_search_cache = {}
    if not FX_LIST_TEST then return end
    
    for i = 1, #FX_LIST_TEST do
        local name = FX_LIST_TEST[i]
        local alias = plugin_aliases[name]
        
        -- 1. Bereken lowercase naam voor zoeken
        local lower_name = s_lower(name)
        
        -- 2. Bereken lowercase alias (indien aanwezig)
        local lower_alias = alias and s_lower(alias) or nil
        
        -- 3. Bereken sorteernaam (zonder VST: prefix)
        local sort_name
        if alias and alias ~= "" then
            sort_name = lower_alias
        else
            local clean = name:match('^[^:]+: (.+)$') or name
            sort_name = s_lower(clean)
        end
        
        global_search_cache[name] = {
            lower_name = lower_name,
            lower_alias = lower_alias,
            sort_key = sort_name,
            display_len = (alias and alias ~= "") and alias:len() or name:len()
        }
    end
end

function GetLowerName(name)
    if not name then return "" end
    -- Check de snelle cache eerst (O(1) lookup)
    if global_search_cache[name] then
        return global_search_cache[name].sort_key
    end
    
    -- Fallback (zou niet moeten gebeuren als cache gebouwd is)
    local lower = plugin_lower_name[name]
    if lower then return lower end
    
    local alias = plugin_aliases and plugin_aliases[name]
    if alias and alias ~= "" then
        lower = s_lower(alias)
    else
        local clean = name:match('^[^:]+: (.+)$') or name
        lower = s_lower(clean)
    end
    
    plugin_lower_name[name] = lower
    return lower
end

if not ClearScreenshotCache then function ClearScreenshotCache() end end

function _build_screenshot_signature()
    local cfg = rawget(_G, 'config') or {}
    local folder = tostring(selected_folder or "")
    local subgroup = tostring(browser_panel_selected or "")
    local term = tostring(browser_search_term or "")
    local mode = tostring(view_mode or "")
    local stype = tostring(cfg.screenshot_view_type or "")
    local page = tostring((screenshot_pagination and screenshot_pagination.current_page) or "")
    local priority = table.concat(cfg.plugin_type_priority or {}, ",")
    local apply = tostring(cfg.apply_type_priority or false)
    local respect = tostring(cfg.respect_search_exclusions_in_screenshots or false)
    
    local track_id = ""
    if folder == "Current Track FX" and (stype == "1" or stype == "2") then
        if TRACK and r.ValidatePtr2(0, TRACK, "MediaTrack*") then
            track_id = r.GetTrackGUID(TRACK)
        end
    end
    
    return table.concat({folder, subgroup, term, mode, stype, page, priority, apply, respect, track_id}, "|")
end

local last_visibility_state = nil
local main_search_focus_requested = false
local function CheckVisibilityState()
    local visibility_state = r.GetExtState("TK_FX_BROWSER_MINI", "visibility")
    local is_visible = visibility_state ~= "hidden"
    
  
    if last_visibility_state == "hidden" and visibility_state ~= "hidden" then
        ClearScreenshotCache()
        screenshot_window_os_focus_needed = 3
        screenshot_search_focus_requested = true
        pending_clear_on_show = true
        main_search_focus_requested = true
        if config and config.clear_search_on_toggle then
            browser_search_term = ""
            if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
        end
    end
    
    last_visibility_state = visibility_state
    return is_visible
end

