local force_open_developer_header = false
local force_open_category_header  = false
local force_open_all_plugins_header = false
local force_open_folders_header = false
local force_headers_open_applied = false 
local initial_header_auto_expand_done = false 
local function BuildAutoExpandPaths(target)
    auto_expand_paths = nil
    if not target or target == '' then return end
    if not target:find('/') then return end 
    auto_expand_paths = {}
    local accum = ''
    for part in target:gmatch("[^/]+") do
        accum = (accum == '' and part) or (accum .. '/' .. part)
        auto_expand_paths[accum] = true
    end
end

local function MarkForcedHeaderForSubgroup(subgroup)
    if not subgroup or subgroup == '' or not CAT_TEST then return end
    for i = 1, #CAT_TEST do
        local cat = CAT_TEST[i]
        if cat and type(cat.list) == 'table' then
            if cat.name == 'DEVELOPER' or cat.name == 'CATEGORY' then
                for j = 1, #cat.list do
                    local entry = cat.list[j]
                    if entry and entry.name == subgroup then
                        if cat.name == 'DEVELOPER' then force_open_developer_header = true end
                        if cat.name == 'CATEGORY'  then force_open_category_header  = true end
                        return
                    end
                end
            elseif cat.name == 'ALL PLUGINS' then
                for j = 1, #cat.list do
                    local entry = cat.list[j]
                    if entry and entry.name == subgroup then
                        force_open_all_plugins_header = true
                        return
                    end
                end
            elseif cat.name == 'FOLDERS' then
                for j = 1, #cat.list do
                    local entry = cat.list[j]
                    if entry and entry.name == subgroup then
                        force_open_folders_header = true
                        return
                    end
                end
            end
        end
    end
end

-- Voorwaards mars ;o)
local SearchActions
local CreateSmartMarker

local last_action_search_term = nil
local last_show_categories = nil
local last_show_only_active = nil
local _action_search_change_time = 0.0
local _action_search_debounce_ms = 150

function RenderActionsSection()
    local avail_w = r.ImGui_GetContentRegionAvail(ctx)
    local button_h = r.ImGui_GetFrameHeight(ctx)
    local button_w = button_h
            r.ImGui_PushItemWidth(ctx, avail_w - (button_w * 2) - 10)
    local changed, new_term = r.ImGui_InputTextWithHint(ctx, "##ActionSearch", "SEARCH ACTIONS", action_search_term or "")
    if changed then
        action_search_term = new_term
        _action_search_change_time = r.time_precise()
    end
    r.ImGui_PopItemWidth(ctx)
    r.ImGui_SameLine(ctx)
    if r.ImGui_Button(ctx, show_categories and "C" or "A", button_w, button_h) then
        show_categories = not show_categories
    end
    r.ImGui_SameLine(ctx)
    if r.ImGui_Button(ctx, show_only_active and "O" or "F", button_w, button_h) then
        show_only_active = not show_only_active
    end

    local window_h = r.ImGui_GetWindowHeight(ctx)
    local cur_y = r.ImGui_GetCursorPosY(ctx)
    local footer = 50
    local list_h = window_h - cur_y - footer
    local action_child_open = r.ImGui_BeginChild(ctx, "ActionList", 0, list_h)
    if action_child_open then
        local now_t = r.time_precise()
        local term_changed = (action_search_term ~= last_action_search_term)
        local other_changed = (show_categories ~= last_show_categories) or (show_only_active ~= last_show_only_active)
        local debounce_ready = (now_t - _action_search_change_time) * 1000.0 >= _action_search_debounce_ms
        if cached_actions_list == nil or other_changed or (term_changed and debounce_ready) then
           
            cached_actions_list = {}
            if show_categories then
                local filtered = SearchActions(action_search_term or "")
                for category, actions in pairs(filtered) do
                    if #actions > 0 then
                        table.insert(cached_actions_list, {type="category", name=category, actions=actions})
                    end
                end
                table.sort(cached_actions_list, function(a,b) return a.name < b.name end)
            else
                for _, action in ipairs(allActions) do
                    local state = r.GetToggleCommandState(action.id)
                    local matches = (not action_search_term or action_search_term == "") or FuzzyFind(action.name, action_search_term)
                    if matches and (not show_only_active or state == 1) then
                        table.insert(cached_actions_list, {type="action", action=action})
                    end
                end
            end
            
            last_action_search_term = action_search_term
            last_show_categories = show_categories
            last_show_only_active = show_only_active
        end

        local should_open_action_ctx = false

        if show_categories then
            for _, cat in ipairs(cached_actions_list) do
                if r.ImGui_TreeNode(ctx, string.format("%s (%d)", cat.name, #cat.actions)) then
                    for _, action in ipairs(cat.actions) do
                        if action.state == 1 then r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFF4000FF) end
                        local prefix = action.state == 1 and "[ON] " or ""
                        if r.ImGui_Selectable(ctx, prefix .. action.name .. "##cat" .. tostring(action.id), false, r.ImGui_SelectableFlags_AllowOverlap()) then
                            r.Main_OnCommand(action.id, 0)
                        elseif r.ImGui_IsItemClicked(ctx, 1) then
                            action_ctx_menu_id = action.id
                            action_ctx_menu_name = action.name
                            should_open_action_ctx = true
                        end
                        if action.shortcut then
                            local sc_text = "[" .. action.shortcut .. "]"
                            local text_w = r.ImGui_CalcTextSize(ctx, sc_text)
                            local avail_w = r.ImGui_GetContentRegionAvail(ctx)
                            r.ImGui_SameLine(ctx, avail_w - text_w)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                            r.ImGui_Text(ctx, sc_text)
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if action.state == 1 then r.ImGui_PopStyleColor(ctx) end
                    end
                    r.ImGui_TreePop(ctx)
                end
            end
        else
            for _, item in ipairs(cached_actions_list) do
                local action = item.action
                local state = r.GetToggleCommandState(action.id)
                if state == 1 then r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFF4000FF) end
                local prefix = state == 1 and "[ON] " or ""
                if r.ImGui_Selectable(ctx, prefix .. action.name .. "##flat" .. tostring(action.id), false, r.ImGui_SelectableFlags_AllowOverlap()) then
                    r.Main_OnCommand(action.id, 0)
                elseif r.ImGui_IsItemClicked(ctx, 1) then
                    action_ctx_menu_id = action.id
                    action_ctx_menu_name = action.name
                    should_open_action_ctx = true
                end
                if action.shortcut then
                    local sc_text = "[" .. action.shortcut .. "]"
                    local text_w = r.ImGui_CalcTextSize(ctx, sc_text)
                    local avail_w = r.ImGui_GetContentRegionAvail(ctx)
                    r.ImGui_SameLine(ctx, avail_w - text_w)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                    r.ImGui_Text(ctx, sc_text)
                    r.ImGui_PopStyleColor(ctx)
                end
                if state == 1 then r.ImGui_PopStyleColor(ctx) end
            end
        end

        if should_open_action_ctx then
            r.ImGui_OpenPopup(ctx, "##ActionContextMenu")
        end

        if r.ImGui_BeginPopup(ctx, "##ActionContextMenu") then
            if r.ImGui_MenuItem(ctx, "Action Marker") then
                CreateSmartMarker(action_ctx_menu_id)
            end
            if r.ImGui_MenuItem(ctx, "Copy Command ID") then
                if r.CF_SetClipboard then
                    r.CF_SetClipboard(tostring(action_ctx_menu_id))
                end
            end
            if r.ImGui_MenuItem(ctx, "Add to Scripts Launcher") then
                local already = false
                for _, entry in ipairs(scripts_launcher) do
                    if tostring(entry.cmd) == tostring(action_ctx_menu_id) then already = true; break end
                end
                if not already then
                    table.insert(scripts_launcher, {name = action_ctx_menu_name or tostring(action_ctx_menu_id), cmd = tostring(action_ctx_menu_id)})
                    SaveScriptsLauncher()
                end
            end
            r.ImGui_EndPopup(ctx)
        end
    end
    r.ImGui_EndChild(ctx)
    r.ImGui_Separator(ctx)
    r.ImGui_TextWrapped(ctx, "Left-click: Execute. Right-click: Context menu.")
end

