function GenerateUniqueID(base_name)
    unique_id_counter = unique_id_counter + 1
    local sanitized_name = base_name:gsub("[^%w%s-]", "_") 
    return "##" .. sanitized_name .. "_" .. unique_id_counter .. "_" .. os.time()
end

