local function PathExists(path)
    if not path or path == '' then return false end
    local first_file = r.EnumerateFiles(path, 0)
    if first_file then return true end
    local first_sub = r.EnumerateSubdirectories(path, 0)
    if first_sub then return true end
    local ok, _, code = os.rename(path, path)
    if ok then return true end
    if code == 13 then return true end
    return false
end

local function ResolveFxChainsRoot()
    if config.use_custom_fxchain_dir and type(config.custom_fxchain_dir) == 'string' and config.custom_fxchain_dir ~= '' then
        return config.custom_fxchain_dir
    end
    return r.GetResourcePath() .. "/FXChains"
end

local function ResolveTrackTemplatesRoot()
    if config.use_custom_template_dir and type(config.custom_template_dir) == 'string' and config.custom_template_dir ~= '' then
        return config.custom_template_dir
    end
    return r.GetResourcePath() .. "/TrackTemplates"
end

local function PathJoin(a, b)
    if not a or a == '' then return b or '' end
    if not b or b == '' then return a end
    if a:sub(-1) == os_separator then return a .. b end
    return a .. os_separator .. b
end

local function BuildTreeFromFS(base_dir, ext)
    if not base_dir or base_dir == "" then
        DebugLog("[BuildTreeFromFS] ERROR: Invalid base_dir")
        return {}
    end
    
    local function scan(dir)
        local node = { dir = dir:sub(#base_dir + 2) } 
        for i = 0, 999 do
            local sub = r.EnumerateSubdirectories(dir, i)
            if not sub or sub == "" then break end
            local child = scan(PathJoin(dir, sub))
            child.dir = sub
            node[#node + 1] = child
        end
        for i = 0, 9999 do
            local file = r.EnumerateFiles(dir, i)
            if not file or file == "" then break end
            if not ext or file:sub(-#ext):lower() == ext:lower() then
                node[#node + 1] = ext and file:sub(1, #file - #ext) or file
            end
        end
        return node
    end
    local root = {}
    for i = 0, 999 do
        local sub = r.EnumerateSubdirectories(base_dir, i)
        if not sub or sub == "" then break end
        local child = scan(PathJoin(base_dir, sub))
        child.dir = sub
        root[#root + 1] = child
    end
    for i = 0, 9999 do
        local file = r.EnumerateFiles(base_dir, i)
        if not file or file == "" then break end
        if not ext or file:sub(-#ext):lower() == ext:lower() then
            root[#root + 1] = ext and file:sub(1, #file - #ext) or file
        end
    end
    return root
end

local function GetFxChainsTree()
    local root = ResolveFxChainsRoot()
    
    -- Create state signature for caching
    local current_state = tostring(root) .. "|" .. tostring(config.use_custom_fxchain_dir)
    
    -- Only log if state changed
    if debug_last_fx_chains_state ~= current_state then
        DebugLog("[GetFxChainsTree] Root path: " .. tostring(root))
        
        if not root or root == "" then
            DebugLog("[GetFxChainsTree] ERROR: Invalid root path")
            debug_last_fx_chains_state = current_state
            return {}, root
        end
        if not PathExists(root) then
            DebugLog("[GetFxChainsTree] ERROR: Path does not exist!")
            debug_last_fx_chains_state = current_state
            return {}, root
        end
        
        local tree = BuildTreeFromFS(root, ".RfxChain")
        DebugLog("[GetFxChainsTree] Found " .. #tree .. " top-level entries")
        debug_last_fx_chains_state = current_state
        return tree, root
    end
    
    if not root or root == "" then
        return {}, root
    end
    if not PathExists(root) then
        return {}, root
    end
    
    local tree = BuildTreeFromFS(root, ".RfxChain")
    return tree, root
end

local function CollectAllFxChainsFlat(tbl, path, result)
    path = path or ""
    result = result or {}
    for i = 1, #tbl do
        local item = tbl[i]
        if type(item) == "table" and item.dir then
            CollectAllFxChainsFlat(item, path .. os_separator .. item.dir, result)
        elseif type(item) == "string" then
            result[#result+1] = { name = item, path = path }
        elseif type(item) == "table" and not item.dir then
            for j = 1, #item do
                if type(item[j]) == "string" then
                    result[#result+1] = { name = item[j], path = path }
                end
            end
        end
    end
    return result
end

local function GetTrackTemplatesTree()
    local root = ResolveTrackTemplatesRoot()
    
    local current_state = tostring(root) .. "|" .. tostring(config.use_custom_template_dir)
    
    if debug_last_track_templates_state ~= current_state then
        DebugLog("[GetTrackTemplatesTree] Root path: " .. tostring(root))
        
        if not root or root == "" then
            DebugLog("[GetTrackTemplatesTree] ERROR: Invalid root path")
            debug_last_track_templates_state = current_state
            return {}, root
        end
        if not PathExists(root) then
            DebugLog("[GetTrackTemplatesTree] ERROR: Path does not exist!")
            debug_last_track_templates_state = current_state
            return {}, root
        end
        
        local tree = BuildTreeFromFS(root, ".RTrackTemplate")
        DebugLog("[GetTrackTemplatesTree] Found " .. #tree .. " top-level entries")
        debug_last_track_templates_state = current_state
        return tree, root
    end
    
    if not root or root == "" then
        return {}, root
    end
    if not PathExists(root) then
        return {}, root
    end
    
    local tree = BuildTreeFromFS(root, ".RTrackTemplate")
    return tree, root
end
do
    local function ApplyStartupDedupe()
        if not config.apply_type_priority then return end
        if browser_panel_selected and type(GetFxListForSubgroup) == 'function' then
            local list = GetFxListForSubgroup(browser_panel_selected) or {}
            current_filtered_fx = DedupeByTypePriority(list)
        elseif selected_folder and type(GetPluginsForFolder) == 'function' then
            current_filtered_fx = GetPluginsForFolder(selected_folder) or {}
        end
        if (not screenshot_search_results or #screenshot_search_results == 0) and current_filtered_fx and #current_filtered_fx > 0 then
            screenshot_search_results = {}
            local cap = loaded_items_count or ITEMS_PER_BATCH or 30
            for i = 1, math.min(cap, #current_filtered_fx) do
                screenshot_search_results[#screenshot_search_results+1] = { name = current_filtered_fx[i] }
            end
            if type(SortScreenshotResults) == 'function' then SortScreenshotResults() end
        end
    end
    ApplyStartupDedupe()
end

local scripts_launcher_path = script_path .. "scripts_launcher.json"
scripts_launcher = {}

function LoadScriptsLauncher()
    local f = io.open(scripts_launcher_path, "r")
    if f then
        local content = f:read("*all"); f:close()
        local ok, data = pcall(function() return json.decode(content) end)
        if ok and type(data) == "table" then scripts_launcher = data end
    elseif legacy_scripts_launcher then
       
        scripts_launcher = legacy_scripts_launcher
        legacy_scripts_launcher = nil
        local mf = io.open(scripts_launcher_path, "w")
        if mf then mf:write(json.encode(scripts_launcher)); mf:close() end
        SaveConfig() 
    end
end

function SaveScriptsLauncher()
    local f = io.open(scripts_launcher_path, "w")
    if f then f:write(json.encode(scripts_launcher)); f:close() end
end

LoadScriptsLauncher()

local capture_window_list = {}
local capture_window_mode = nil
local capture_target_index = nil

function GetVisibleWindows()
    local windows = {}
    local count, list = r.JS_Window_ListAllTop()
    if not list or list == "" then return windows end
    local main_hwnd = r.GetMainHwnd()
    for addr_str in list:gmatch("[^,]+") do
        local hwnd = r.JS_Window_HandleFromAddress(tonumber(addr_str))
        if hwnd and hwnd ~= main_hwnd then
            local is_visible = r.JS_Window_IsVisible(hwnd)
            if is_visible then
                local title = r.JS_Window_GetTitle(hwnd)
                if title and title ~= "" and not title:match("^TK FX BROWSER") then
                    table.insert(windows, {hwnd = hwnd, title = title})
                end
            end
        end
    end
    table.sort(windows, function(a, b) return a.title:lower() < b.title:lower() end)
    return windows
end

function CaptureWindowScreenshot(hwnd, save_name)
    local retval, left, top, right, bottom = r.JS_Window_GetClientRect(hwnd)
    if not retval then return nil end
    local w, h = right - left, bottom - top
    if w <= 0 or h <= 0 then return nil end
    local safe_name = save_name:gsub("[^%w%s-]", "_")
    local filename = script_thumbs_path .. safe_name .. ".png"
    local srcDC = r.JS_GDI_GetClientDC(hwnd)
    local srcBmp = r.JS_LICE_CreateBitmap(true, w, h)
    local srcDC_LICE = r.JS_LICE_GetDC(srcBmp)
    r.JS_GDI_Blit(srcDC_LICE, 0, 0, srcDC, 0, 0, w, h)
    r.JS_LICE_WritePNG(filename, srcBmp, false)
    r.JS_GDI_ReleaseDC(hwnd, srcDC)
    r.JS_LICE_DestroyBitmap(srcBmp)
    local f = io.open(filename, "rb")
    if f then
        local size = f:seek("end")
        f:close()
        if size and size > 0 then return filename end
    end
    return nil
end

function ResetConfig()
    config = SetDefaultConfig()
    _G.config = config
    SaveConfig()
end

-- CUSTOM FOLDERS HELPERS
-- Get plugins from a folder (numeric keys only)
function GetFolderPlugins(folder_content)
    if type(folder_content) ~= "table" then return {} end
    local plugins = {}
    for k, v in pairs(folder_content) do
        if type(k) == "number" and type(v) == "string" then
            plugins[#plugins + 1] = v
        end
    end
    return plugins
end

-- Get subfolders from a folder (string keys that are tables)
function GetFolderSubfolders(folder_content)
    if type(folder_content) ~= "table" then return {} end
    local subfolders = {}
    for k, v in pairs(folder_content) do
        if type(k) == "string" and type(v) == "table" then
            subfolders[k] = v
        end
    end
    return subfolders
end

-- Check if folder has any subfolders
function HasSubfolders(folder_content)
    if type(folder_content) ~= "table" then return false end
    for k, v in pairs(folder_content) do
        if type(k) == "string" and type(v) == "table" then
            return true
        end
    end
    return false
end

-- Check if folder has any plugins
function HasPlugins(folder_content)
    if type(folder_content) ~= "table" then return false end
    for k, v in pairs(folder_content) do
        if type(k) == "number" and type(v) == "string" then
            return true
        end
    end
    return false
end

-- Legacy compatibility aliases
IsSubfolderStructure = HasSubfolders
IsPluginArray = function(folder_content)
    return not HasSubfolders(folder_content) and HasPlugins(folder_content)
end

function CollectAllFolderPaths(folders, prefix, exclude_path, result)
    result = result or {}
    prefix = prefix or ""
    if type(folders) ~= "table" then return result end
    for folder_name, folder_content in pairs(folders) do
        if type(folder_name) == "string" and type(folder_content) == "table" then
            local full_path = prefix == "" and folder_name or (prefix .. "/" .. folder_name)
            local dominated = false
            if exclude_path and exclude_path ~= "" then
                local escaped = exclude_path:gsub("([%%%^%$%(%)%.%[%]%*%+%-%?])", "%%%1")
                if full_path == exclude_path or full_path:find("^" .. escaped .. "/") then
                    dominated = true
                end
            end
            if not dominated then
                table.insert(result, full_path)
                CollectAllFolderPaths(folder_content, full_path, exclude_path, result)
            end
        end
    end
    table.sort(result)
    return result
end

function MoveFolderTo(source_path, target_path)
    if not source_path or source_path == "" then return false end
    
    local source_parts = {}
    for part in source_path:gmatch("[^/]+") do
        table.insert(source_parts, part)
    end
    if #source_parts == 0 then return false end
    
    local folder_name = source_parts[#source_parts]
    
    local source_parent = config.custom_folders
    for i = 1, #source_parts - 1 do
        source_parent = source_parent[source_parts[i]]
        if not source_parent then return false end
    end
    
    local folder_content = source_parent[folder_name]
    if not folder_content then return false end
    
    local target_parent
    if not target_path or target_path == "" then
        target_parent = config.custom_folders
    else
        target_parent = config.custom_folders
        for part in target_path:gmatch("[^/]+") do
            if not target_parent[part] then
                target_parent[part] = {}
            end
            target_parent = target_parent[part]
            if not target_parent then return false end
        end
    end
    
    if target_parent[folder_name] then
        r.ShowMessageBox("A folder with name '" .. folder_name .. "' already exists in the target location!", "Error", 0)
        return false
    end
    
    target_parent[folder_name] = folder_content
    source_parent[folder_name] = nil
    
    SaveCustomFolders()
    return true
end

function IsCustomPinned(full_path)
    if not config.pinned_custom_subfolders then return false end
    for _, p in ipairs(config.pinned_custom_subfolders) do if p == full_path then return true end end
    return false
end

function PinCustom(full_path)
    config.pinned_custom_subfolders = config.pinned_custom_subfolders or {}
    if not IsCustomPinned(full_path) then
        table.insert(config.pinned_custom_subfolders, full_path)
        SavePinned()
    end
end

function UnpinCustom(full_path)
    if not config.pinned_custom_subfolders then return end
    for i = #config.pinned_custom_subfolders, 1, -1 do
        if config.pinned_custom_subfolders[i] == full_path then
            table.remove(config.pinned_custom_subfolders, i)
            SavePinned()
            break
        end
    end
end

function DrawCustomFolderContextMenu(folder_name, path_prefix, full_path)
    local menu_text_color = config.text_color or r.ImGui_ColorConvertDouble4ToU32((config.text_gray or 200)/255, (config.text_gray or 200)/255, (config.text_gray or 200)/255, 1)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), menu_text_color)
    if r.ImGui_MenuItem(ctx, "Add Subfolder") then
        show_add_subfolder_popup = true
        selected_folder_for_subfolder = full_path
        selected_folder_name = folder_name
        new_subfolder_name = ""
    end
    if r.ImGui_MenuItem(ctx, "Create Parent Folder Above") then
        show_create_parent_folder_popup = true
        selected_folder_for_parent = full_path
        selected_folder_name = folder_name
    end
    local toggle_label = (view_mode == "screenshots" and "Show List" or "Show Screenshots")
    if r.ImGui_MenuItem(ctx, toggle_label) then
        local prev = view_mode
        view_mode = (view_mode == "screenshots" and "list" or "screenshots")
        config.view_mode = view_mode
        SaveConfig()
        if view_mode == "screenshots" and prev ~= "screenshots" then ClearScreenshotCache() end
    end
    local is_pinned = IsCustomPinned(full_path)
    if is_pinned then
        if r.ImGui_MenuItem(ctx, "Unpin Folder") then UnpinCustom(full_path) end
    else
        if r.ImGui_MenuItem(ctx, "Pin Folder") then PinCustom(full_path) end
    end
    if r.ImGui_MenuItem(ctx, "Capture Folder Screenshots") then
        StartFolderScreenshots(full_path)
    end
    r.ImGui_Separator(ctx)
    if r.ImGui_MenuItem(ctx, "Rename Folder") then
        show_rename_folder_popup = true
        folder_to_rename = folder_name
        folder_to_rename_path = path_prefix
        new_folder_name_for_rename = folder_name
    end
    if r.ImGui_BeginMenu(ctx, "Move to Folder...") then
        if r.ImGui_MenuItem(ctx, "[Root Level]") then
            if MoveFolderTo(full_path, "") then
                if selected_folder == full_path then
                    selected_folder = folder_name
                end
            end
        end
        r.ImGui_Separator(ctx)
        local available_targets = CollectAllFolderPaths(config.custom_folders, "", full_path, {})
        for _, target_path in ipairs(available_targets) do
            if r.ImGui_MenuItem(ctx, target_path) then
                if MoveFolderTo(full_path, target_path) then
                    if selected_folder == full_path then
                        selected_folder = target_path .. "/" .. folder_name
                    end
                end
            end
        end
        if #available_targets == 0 then
            r.ImGui_TextDisabled(ctx, "No other folders available")
        end
        r.ImGui_EndMenu(ctx)
    end
    if r.ImGui_MenuItem(ctx, "Delete Folder") then
        local result = r.MB("Are you sure you want to delete '" .. folder_name .. "' and all its plugins?", "Confirm Delete", 4)
        if result == 6 then
            if path_prefix == "" then
                config.custom_folders[folder_name] = nil
            else
                local target = config.custom_folders
                local path_parts = {}
                for part in path_prefix:gmatch("[^/]+") do
                    table.insert(path_parts, part)
                end
                for i = 1, #path_parts do
                    target = target[path_parts[i]]
                    if not target then break end
                end
                if target then
                    target[folder_name] = nil
                end
            end
            SaveCustomFolders()
            if selected_folder == full_path then
                selected_folder = nil
                screenshot_search_results = {}
            end
            r.ShowMessageBox("Folder '" .. folder_name .. "' deleted", "Success", 0)
        end
    end
    r.ImGui_PopStyleColor(ctx)
end

function CleanPluginName(name)
    if not name or name == '' then return name end
    
    local cached = clean_name_cache[name]
    if cached then return cached end

    local original = name
   
    name = name:gsub('^VST3i?:%s*','')
               :gsub('^VSTi:%s*','')
               :gsub('^VST3:%s*','')
               :gsub('^VST:%s*','')
               :gsub('^CLAPi?:%s*','')
               :gsub('^JSFX:%s*','')
               :gsub('^JS:%s*','')
               :gsub('^AU:%s*','')
               :gsub('^LV2:%s*','')
    
    name = name:gsub('%s*%(%d+%s*ch%)$','')
               :gsub('%s*%(%d+in%s*%d+out%)$','')
   
    name = name:gsub('%s+$','')
    local result = name ~= '' and name or original
    clean_name_cache[original] = result
    return result
end

function RemoveManufacturerSuffix(name)
    if not name or name == '' then return name end
    local base = CleanPluginName(name)
    
    local patterns = { '%s*%(([^()]+)%)%s*$', '%s*%[([^%[%]]+)%]%s*$', '%s*%{([^{}]+)%}%s*$' }
    for _, pat in ipairs(patterns) do
        local before, manu = base:match('^(.*)'..pat)
        if before and manu then
            local trimmed_before = before:gsub('%s+$','')
            
            if #manu:gsub('%s','') >= 3 and not manu:match('^vst3?i?$') then
                base = trimmed_before
                break
            end
        end
    end
    return base
end

function GetDisplayPluginName(raw_name)
    if not raw_name then return raw_name end
    
    -- Check for alias first
    local alias = plugin_aliases[raw_name]
    if alias then return alias end
    
    local name = raw_name
    if config.clean_plugin_names then
        name = CleanPluginName(name)
    end
    if config.remove_manufacturer_names then
        name = RemoveManufacturerSuffix(name)
    end
    return name
end

function StripX86Markers(name)
    if not name then return '' end
    
    local cached = strip_x86_cache[name]
    if cached then return cached end

    local original = name
    name = name
        :gsub('%s*[%(%[]x86[^%]%)]*[%]%)]','')    
        :gsub('[%s%-]+x86[%s%-]*bridged',' ')      
        :gsub('[%s%-]x86[%s%-]',' ')               
        :gsub('x86%s*:%s*','')                     
    
    strip_x86_cache[original] = name
    return name
end

function NormalizePluginNameForMatch(name)
    if not name then return '' end
    
    local cached = normalized_name_cache[name]
    if cached then return cached end
    
    local result = name:lower()
    result = result:gsub('^vst3i?:%s*',''):gsub('^vsti?:%s*',''):gsub('^vst3:%s*',''):gsub('^vst:%s*',''):gsub('^js:%s*',''):gsub('^jsfx:%s*',''):gsub('^clapi?:%s*',''):gsub('^clap:%s*',''):gsub('^au:%s*',''):gsub('^lv2:%s*','')
    result = StripX86Markers(result)
    result = result:gsub('%s+$','')
    result = result:gsub('%s+',' ')
    result = result:gsub('[^%w]+','')
    
    normalized_name_cache[name] = result
    return result
end

function GetPluginType(name)
    if not name or name == '' then return 'OTHER' end
    
    local cached = plugin_type_cache[name]
    if cached then return cached end
    
    local result = 'OTHER'
    if name:match('^VST3i?:') then 
        result = 'VST3' 
    elseif name:match('^VSTi?:') then 
        result = 'VST' 
    elseif name:match('^CLAPi?:') then 
        result = 'CLAP' 
    elseif name:match('^JSFX:') or name:match('^JS:') then 
        result = 'JS' 
    elseif name:match('^AU:') or name:match('^AUi:') then 
        result = 'AU' 
    elseif name:match('^LV2i?:') then 
        result = 'LV2' 
    end
    
    plugin_type_cache[name] = result
    return result
end

function IsInstrumentPlugin(name)
    if not name or name == '' then return false end
    return name:match('^VSTi:')
        or name:match('^VST3i:')
        or name:match('^CLAPi:')
        or name:match('^AUi:')
        or name:match('^LV2i:')
        or false
end

function GetTargetTrack()
    -- First check if Master track is selected
    local master_track = r.GetMasterTrack(0)
    if master_track and r.IsTrackSelected(master_track) then
        return master_track
    end
    
    -- Otherwise try to get selected track, or fall back to first track
    return r.GetSelectedTrack(0, 0) or r.GetTrack(0, 0)
end

function AddFXToTrack(track, plugin_name, preserve_order)
    if not track or not plugin_name or plugin_name == '' then return -1 end
    local dest_index = r.TrackFX_GetCount(track)
    local fx_index = r.TrackFX_AddByName(track, plugin_name, false, -1000 - dest_index)
    if not preserve_order and fx_index and fx_index >= 0 and config and config.add_instruments_on_top and IsInstrumentPlugin(plugin_name) then
        r.TrackFX_CopyToTrack(track, fx_index, track, 0, true)
        fx_index = 0
    end
    
    if fx_index and fx_index >= 0 and not START and not START_SELECTED and not IS_CAPTURING_SCREENSHOT then
        if AddToRecent then AddToRecent(plugin_name) end
        if selected_folder == "Current Track FX" or selected_folder == "Current Project FX" then
            if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
        end
        if config.hide_after_insert then SHOULD_HIDE_BROWSER = true end
    end

    return fx_index or -1
end

_layout_fx_click_override = _layout_fx_click_override or nil

function _LayoutPerformAddOrAction(plugin_name)
    if _layout_fx_click_override then
        local handled = _layout_fx_click_override(plugin_name)
        if handled then return true end
    end
    local target_track = GetTargetTrack()
    if target_track then
        AddFXToTrack(target_track, plugin_name)
        LAST_USED_FX = plugin_name
        if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
    end
    return false
end

function RestoreChainBuilderChunk(track, fx_idx, saved_chunk)
    if not track or not saved_chunk or fx_idx < 0 then return false end
    local _, chunk = r.GetTrackStateChunk(track, "", false)
    if not chunk then return false end
    local bs, be = FindFXBlockBounds(chunk, "FXCHAIN", fx_idx)
    if not bs or not be then return false end
    local new_chunk = chunk:sub(1, bs - 1) .. saved_chunk .. chunk:sub(be + 1)
    r.SetTrackStateChunk(track, new_chunk, false)
    return true
end

function GrabChainBuilderChunks(track)
    if not track then return {} end
    local fx_count = r.TrackFX_GetCount(track)
    if fx_count == 0 then return {} end
    local _, chunk = r.GetTrackStateChunk(track, "", false)
    if not chunk then return {} end
    local chunks = {}
    for fi = 0, fx_count - 1 do
        local bs, be = FindFXBlockBounds(chunk, "FXCHAIN", fi)
        if bs and be then
            chunks[fi + 1] = chunk:sub(bs, be)
        end
    end
    return chunks
end

function CreateInstrumentTrack(plugin_name, midi_input_value)
    local track_idx = r.CountTracks(0)
    r.InsertTrackAtIndex(track_idx, true)
    local new_track = r.GetTrack(0, track_idx)
    
    AddFXToTrack(new_track, plugin_name)
    r.GetSetMediaTrackInfo_String(new_track, "P_NAME", plugin_name, true)
    
    local input_value
    if midi_input_value == 6112 then
        input_value = 6112 
    else
        local device_index = midi_input_value - 6113
        input_value = (device_index * 32) + 4096  
    end
    
    r.SetMediaTrackInfo_Value(new_track, "I_RECINPUT", input_value)
    
    -- Set record mode to MIDI input (not output)
    r.SetMediaTrackInfo_Value(new_track, "I_RECMODE", 0)  -- 0 = input (MIDI), 1 = output
    r.SetMediaTrackInfo_Value(new_track, "I_RECMON", 2)
    
    r.SetOnlyTrackSelected(new_track)
    
    r.UpdateArrange()
end

function GetSendTrackName(plugin_name)
    local mode = config.sends_track_name_mode or "prompt"
    local default_name = plugin_name .. " Send"
    if mode == "auto" then
        return default_name
    elseif mode == "custom" then
        local suffix = config.sends_track_name_custom or "Send"
        if suffix == "" then return default_name end
        return plugin_name .. " " .. suffix
    else
        local ok, retval = r.GetUserInputs("Name send track", 1, "Track name:,extrawidth=200", default_name)
        if not ok then return nil end
        local trimmed = retval and retval:match("^%s*(.-)%s*$") or ""
        if trimmed == "" then return default_name end
        return trimmed
    end
end

function AddPluginAsSend(plugin_name, source_tracks)
    if not source_tracks or #source_tracks == 0 then return end
    local track_name = GetSendTrackName(plugin_name)
    if not track_name then return end

    r.Undo_BeginBlock()
    r.PreventUIRefresh(1)

    local track_count = r.CountTracks(0)
    local insert_idx = track_count
    local folder_name = config.sends_folder_name or "SEND TRACK"
    local use_folder = config.create_sends_folder

    if use_folder then
        local folder_idx = -1
        for k = 0, track_count - 1 do
            local tr = r.GetTrack(0, k)
            local _, nm = r.GetTrackName(tr)
            if nm == folder_name and r.GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH") == 1 then
                folder_idx = k
                break
            end
        end
        if folder_idx >= 0 then
            local last_in_folder_idx = track_count - 1
            local depth = 1
            for k = folder_idx + 1, track_count - 1 do
                local tr = r.GetTrack(0, k)
                local d = r.GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH")
                depth = depth + d
                if depth <= 0 then
                    last_in_folder_idx = k
                    break
                end
            end
            insert_idx = last_in_folder_idx + 1
            r.InsertTrackAtIndex(insert_idx, true)
            local last_tr = r.GetTrack(0, last_in_folder_idx)
            local last_depth = r.GetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH")
            if last_depth == -1 then
                r.SetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH", 0)
            end
            local new_tr = r.GetTrack(0, insert_idx)
            r.SetMediaTrackInfo_Value(new_tr, "I_FOLDERDEPTH", -1)
        else
            r.InsertTrackAtIndex(track_count, true)
            local f_tr = r.GetTrack(0, track_count)
            r.GetSetMediaTrackInfo_String(f_tr, "P_NAME", folder_name, true)
            r.SetMediaTrackInfo_Value(f_tr, "I_FOLDERDEPTH", 1)
            r.InsertTrackAtIndex(track_count + 1, true)
            insert_idx = track_count + 1
            local new_tr = r.GetTrack(0, insert_idx)
            r.SetMediaTrackInfo_Value(new_tr, "I_FOLDERDEPTH", -1)
        end
    else
        r.InsertTrackAtIndex(track_count, true)
        insert_idx = track_count
    end

    local send_track = r.GetTrack(0, insert_idx)
    AddFXToTrack(send_track, plugin_name)
    r.GetSetMediaTrackInfo_String(send_track, "P_NAME", track_name, true)

    for _, src in ipairs(source_tracks) do
        if src and r.ValidatePtr(src, "MediaTrack*") and src ~= send_track then
            r.CreateTrackSend(src, send_track)
        end
    end

    r.PreventUIRefresh(-1)
    r.Undo_EndBlock("Add " .. plugin_name .. " as send", -1)
    r.UpdateArrange()
end

function CreateSendTargetTrack(track_name)
    local track_count = r.CountTracks(0)
    local insert_idx = track_count
    local folder_name = config.sends_folder_name or "SEND TRACK"
    local use_folder = config.create_sends_folder

    if use_folder then
        local folder_idx = -1
        for k = 0, track_count - 1 do
            local tr = r.GetTrack(0, k)
            local _, nm = r.GetTrackName(tr)
            if nm == folder_name and r.GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH") == 1 then
                folder_idx = k
                break
            end
        end
        if folder_idx >= 0 then
            local last_in_folder_idx = track_count - 1
            local depth = 1
            for k = folder_idx + 1, track_count - 1 do
                local tr = r.GetTrack(0, k)
                local d = r.GetMediaTrackInfo_Value(tr, "I_FOLDERDEPTH")
                depth = depth + d
                if depth <= 0 then
                    last_in_folder_idx = k
                    break
                end
            end
            insert_idx = last_in_folder_idx + 1
            r.InsertTrackAtIndex(insert_idx, true)
            local last_tr = r.GetTrack(0, last_in_folder_idx)
            local last_depth = r.GetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH")
            if last_depth == -1 then
                r.SetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH", 0)
            end
            local new_tr = r.GetTrack(0, insert_idx)
            r.SetMediaTrackInfo_Value(new_tr, "I_FOLDERDEPTH", -1)
        else
            r.InsertTrackAtIndex(track_count, true)
            local f_tr = r.GetTrack(0, track_count)
            r.GetSetMediaTrackInfo_String(f_tr, "P_NAME", folder_name, true)
            r.SetMediaTrackInfo_Value(f_tr, "I_FOLDERDEPTH", 1)
            r.InsertTrackAtIndex(track_count + 1, true)
            insert_idx = track_count + 1
            local new_tr = r.GetTrack(0, insert_idx)
            r.SetMediaTrackInfo_Value(new_tr, "I_FOLDERDEPTH", -1)
        end
    else
        r.InsertTrackAtIndex(track_count, true)
        insert_idx = track_count
    end

    local send_track = r.GetTrack(0, insert_idx)
    if track_name and track_name ~= "" then
        r.GetSetMediaTrackInfo_String(send_track, "P_NAME", track_name, true)
    end
    return send_track
end

function BuildTypePriorityIndex()
    if type_priority_cache and config._priority_cache_version == config._current_version then
        return type_priority_cache
    end
    
    local idx = {}
    if type(config.plugin_type_priority) == 'table' then
        for i, t in ipairs(config.plugin_type_priority) do
            idx[t] = i
        end
    end
    
    type_priority_cache = idx
    config._priority_cache_version = config._current_version or 1
    return idx
end

DedupeByTypePriority = function(list)
    if not config.apply_type_priority or type(list) ~= 'table' or #list == 0 then 
        return list 
    end
    
    if #list <= 1 then return list end
    
    local priority = BuildTypePriorityIndex()
    local best_by_key = {}
    local order = {}
    local seen_keys = {}
    local has_duplicates = false
    
    for i = 1, #list do
        local fx = list[i]
        local key = NormalizePluginNameForMatch(fx)
        
        -- Skip empty keys
        if key ~= '' then
            if not seen_keys[key] then
                -- First occurrence of this key
                local t = GetPluginType(fx)
                local p = priority[t] or math.huge
                best_by_key[key] = {name = fx, prio = p, type = t}
                order[#order + 1] = key
                seen_keys[key] = true
            else
                -- We found a duplicate
                has_duplicates = true
                local t = GetPluginType(fx)
                local p = priority[t] or math.huge
                local cur = best_by_key[key]
                if p < cur.prio then
                    best_by_key[key] = {name = fx, prio = p, type = t}
                end
            end
        end
    end
    
    -- If no duplicates were found, return original list
    if not has_duplicates and #order == #list then
        return list
    end
    
    -- Build result list
    local out = {}
    for i = 1, #order do
        local key = order[i]
        out[#out + 1] = best_by_key[key].name
    end
    
    return out
end

local screenshot_index_norm = nil
function BuildScreenshotIndex(force)
    if screenshot_index_norm and not force then return end
    screenshot_index_norm = {}
    local i = 0
    while true do
        local fname = r.EnumerateFiles(screenshot_path, i)
        if not fname then break end
        local base = fname:match('(.+)%.png$') or fname:match('(.+)%.jpg$') or fname:match('(.+)%.jpeg$')
        if base then
            local norm = NormalizePluginNameForMatch(base)
            if not screenshot_index_norm[norm] then
                screenshot_index_norm[norm] = fname
            end
        end
        i = i + 1
    end
end

-- Pinned plugins helpers
function EnsurePinnedPluginsList()
    if type(config.pinned_plugins) ~= 'table' then config.pinned_plugins = {} end
end

function IsPluginPinned(name)
    if not name or name == '' then return false end
    if pinned_set[name] then return true end
    local key = (type(NormalizePluginNameForMatch) == 'function') and NormalizePluginNameForMatch(name) or ''
    return key ~= '' and pinned_norm_set[key] == true
end

function PinPlugin(name)
    if not name or name == '' then return end
    EnsurePinnedPluginsList()
    if not pinned_set[name] then
        pinned_set[name] = true
        table.insert(config.pinned_plugins, name)
        -- keep normalized pins in sync
        if type(NormalizePluginNameForMatch) == 'function' then
            local k = NormalizePluginNameForMatch(name)
            if k ~= '' then pinned_norm_set[k] = true end
        end
    SavePinned()
    if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
    end
end

function UnpinPlugin(name)
    if not name or name == '' then return end
    if pinned_set[name] then
        pinned_set[name] = nil
        if type(config.pinned_plugins) == 'table' then
            for i = #config.pinned_plugins, 1, -1 do
                if config.pinned_plugins[i] == name then
                    table.remove(config.pinned_plugins, i)
                end
            end
        end
        -- keep normalized pins in sync
        if type(NormalizePluginNameForMatch) == 'function' then
            local k = NormalizePluginNameForMatch(name)
            if k ~= '' then pinned_norm_set[k] = nil end
        end
    SavePinned()
    if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
    end
end

local screenshot_exists_cache = {}

function HasScreenshot(plugin_name)
    if screenshot_exists_cache[plugin_name] ~= nil then
        return screenshot_exists_cache[plugin_name]
    end

    BuildScreenshotIndex()
    local norm = NormalizePluginNameForMatch(plugin_name)
    local indexed_file = screenshot_index_norm[norm]
    if type(indexed_file) == 'string' and indexed_file ~= '' then 
        local full_path = screenshot_path .. indexed_file
        screenshot_exists_cache[plugin_name] = full_path
        return full_path 
    end
    
    local stripped_x86 = StripX86Markers(plugin_name)
    local variants = {
        plugin_name,
        CleanPluginName(plugin_name),
        (plugin_name or ''):gsub('[^%w%s-]','_'),
        CleanPluginName(plugin_name):gsub('[^%w%s-]','_'),
        stripped_x86,
        CleanPluginName(stripped_x86),
        StripX86Markers(CleanPluginName(plugin_name))
    }
    for _, base in ipairs(variants) do
        if base and base ~= '' then
            local png = screenshot_path .. base .. '.png'
            local jpg = screenshot_path .. base .. '.jpg'
            if r.file_exists(png) then 
                screenshot_exists_cache[plugin_name] = png
                return png 
            elseif r.file_exists(jpg) then
                screenshot_exists_cache[plugin_name] = jpg
                return jpg
            end
        end
    end
    screenshot_exists_cache[plugin_name] = false
    return false
end

function SplitPluginsByScreenshot(plugin_list)
    local with_shot, missing = {}, {}
    if not plugin_list then return with_shot, missing end
    for _, name in ipairs(plugin_list) do
        if config.respect_search_exclusions_in_screenshots and config.excluded_plugins and config.excluded_plugins[name] then
            goto continue_plugin
        end
        if name == "--Favorites End--" or name == "--Pinned End--" or name:match("^%-%-Chain:.+%-%-$") then
            table.insert(with_shot, name) 
        else
            if HasScreenshot(name) then
                table.insert(with_shot, name)
            else
                table.insert(missing, name)
            end
        end
        ::continue_plugin::
    end
    return with_shot, missing
end

