local GetStarsString

function RenderMissingList(missing)
    if not (config.show_missing_list ~= false) then return end 
    if missing and #missing > 0 then
        r.ImGui_Dummy(ctx, 0, 10)
        r.ImGui_Separator(ctx)
        r.ImGui_Text(ctx, string.format("Missing Screenshots (%d)", #missing))
        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FramePadding(), 2, 2)
            for i, name in ipairs(missing) do
                local display_name = GetDisplayPluginName(name)
                local stars = GetStarsString(name)
                local activated = r.ImGui_Selectable(ctx, display_name .. (stars ~= "" and "  " .. stars or "") .. "##missing_" .. i, false)
                local do_add = false
                if config.add_fx_with_double_click then
                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx, 0) then
                        do_add = true
                    end
                else
                    if activated then do_add = true end
                end
                if do_add then
                    local target_track = GetTargetTrack()
                    if target_track then
                        AddFXToTrack(target_track, name)
                        LAST_USED_FX = name
                        if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                    end
                end
                ShowPluginContextMenu(name, "missing_ctx_" .. i)
        end
        r.ImGui_PopStyleVar(ctx)
    end
end

local top_screenshot_spacing_applied = false
function ApplyTopScreenshotSpacing()
    if not top_screenshot_spacing_applied then
        r.ImGui_Dummy(ctx, 0, 6) 
        top_screenshot_spacing_applied = true
    end
end

function GetPluginsFromCustomFolder(folder_path)
    local parts = {}
    for part in folder_path:gmatch("[^/]+") do
        table.insert(parts, part)
    end
    
    local current = config.custom_folders
    for _, part in ipairs(parts) do
        if current[part] then
            current = current[part]
        else
            return {}
        end
    end
    
    local plugins = {}
    if type(current) == "table" then
        for k, v in pairs(current) do
            if type(k) == "number" and type(v) == "string" then
                plugins[#plugins + 1] = v
            end
        end
    end
    return plugins
end

function CreateNestedFolder(folder_path, is_subfolder_of)
    local parts = {}
    if is_subfolder_of then
        for part in is_subfolder_of:gmatch("[^/]+") do
            table.insert(parts, part)
        end
    end
    for part in folder_path:gmatch("[^/]+") do
        table.insert(parts, part)
    end
    
    local current = config.custom_folders
    for i, part in ipairs(parts) do
        if i == #parts then
           
            current[part] = current[part] or {}
        else
           
            current[part] = current[part] or {}
            current = current[part]
        end
    end
end

function IsCustomFolder(folder_path)
    if not folder_path or folder_path == "" then return false end
    
    -- Navigate to folder using path
    local target = config.custom_folders
    for folder in folder_path:gmatch("[^/]+") do
        if not target or type(target) ~= "table" then return false end
        target = target[folder]
    end
    
    return target ~= nil
end

function GetCustomFolderPlugins(folder_path, folders)
    if not folder_path or folder_path == "" then return {} end
    
    -- Navigate to folder using path
    local target = folders
    for folder in folder_path:gmatch("[^/]+") do
        if not target then return {} end
        target = target[folder]
    end
    
    if not target then return {} end
    
    -- Extract plugins from folder
    local plugins = {}
    for k, v in pairs(target) do
        if type(k) == "number" and type(v) == "string" then
            table.insert(plugins, v)
        end
    end
    
    return plugins
end

function SaveCustomFolders()
    
    local function convertForJSON(folders)
        local result = {}
        for folder_name, folder_content in pairs(folders) do
            if type(folder_name) == "string" and type(folder_content) == "table" then
                
                local plugins = GetFolderPlugins(folder_content)
                local subfolders = GetFolderSubfolders(folder_content)
                
                local folder_data = {}
                
                -- Always save plugins if present
                if #plugins > 0 then
                    folder_data.plugins = plugins
                end
                
                -- Always save subfolders if present (recurse)
                if next(subfolders) ~= nil then
                    folder_data.subfolders = convertForJSON(subfolders)
                end
                
                -- If folder is completely empty, mark it
                if #plugins == 0 and next(subfolders) == nil then
                    folder_data._empty = true
                end
                
                result[folder_name] = folder_data
            end
        end
        return result
    end
    
    local json_data = convertForJSON(config.custom_folders)
    
    -- Debug: log what we're trying to save
    local success, json_string = pcall(json.encode, json_data)
    
    if success and json_string then
        local file = io.open(script_path .. "custom_folders.json", "w")
        if file then
            file:write(json_string)
            file:close()
        else
            r.ShowConsoleMsg("Error: Could not open custom_folders.json for writing\n")
        end
    else
        r.ShowConsoleMsg("Error: Could not encode custom folders to JSON\n")
        r.ShowConsoleMsg("Error details: " .. tostring(json_string) .. "\n")
        -- Try to save a safe empty structure instead
        local file = io.open(script_path .. "custom_folders.json", "w")
        if file then
            file:write("{}")
            file:close()
        end
    end
end

function LoadCustomFolders()
    local file = io.open(script_path .. "custom_folders.json", "r")
    if file then
        local content = file:read("*all")
        file:close()
        
        -- Check if content is empty or only whitespace
        if not content or content == "" or content:match("^%s*$") then
            config.custom_folders = {}
            return
        end
        
        -- Trim whitespace and check if it starts with valid JSON
        content = content:match("^%s*(.-)%s*$")
        if not content:match("^[%[{]") then
            r.ShowConsoleMsg("Warning: custom_folders.json does not start with valid JSON\n")
            config.custom_folders = {}
            -- Create backup
            local backup_path = script_path .. "custom_folders_backup_corrupt.json"
            local backup_file = io.open(backup_path, "w")
            if backup_file then
                backup_file:write(content)
                backup_file:close()
                r.ShowConsoleMsg("Corrupt file backed up to: " .. backup_path .. "\n")
            end
            return
        end
        
        local success, loaded_data = pcall(json.decode, content)
        
        if success and loaded_data and type(loaded_data) == "table" then
           
            local function convertFromJSON(data)
                local result = {}
                for folder_name, folder_data in pairs(data) do
                    if type(folder_name) == "string" and type(folder_data) == "table" then
                        local folder_table = {}
                        
                        -- Load plugins if present (numeric keys)
                        if folder_data.plugins and type(folder_data.plugins) == "table" then
                            for i, plugin in ipairs(folder_data.plugins) do
                                folder_table[i] = plugin
                            end
                        end
                        
                        -- Load subfolders if present (string keys) - recurse
                        if folder_data.subfolders and type(folder_data.subfolders) == "table" then
                            local subfolders = convertFromJSON(folder_data.subfolders)
                            for subfolder_name, subfolder_content in pairs(subfolders) do
                                folder_table[subfolder_name] = subfolder_content
                            end
                        end
                        
                        result[folder_name] = folder_table
                    end
                end
                return result
            end
            
            config.custom_folders = convertFromJSON(loaded_data)
        else
            
            r.ShowConsoleMsg("Warning: Could not parse custom_folders.json, initializing with empty folders\n")
            config.custom_folders = {}
            
            local backup_path = script_path .. "custom_folders_backup.json"
            local backup_file = io.open(backup_path, "w")
            if backup_file then
                backup_file:write(content)
                backup_file:close()
                r.ShowConsoleMsg("Backup of corrupt file saved as: " .. backup_path .. "\n")
            end
        end
    else
        config.custom_folders = {}
    end
end

LoadCustomFolders()

-------------------------------------------------------------
-- NATIVE FX FOLDERS (reaper-fxfolders.ini)
-------------------------------------------------------------
local native_folders_ini_path = r.GetResourcePath() .. os_separator .. "reaper-fxfolders.ini"

local native_fx_reverse_lookup = nil
local native_fx_normalized_lookup = nil
local native_fx_identifier_lookup = nil

local _nf_cache_folders_list = nil
local _nf_cache_folder_data = nil
local _nf_cache_nb_folders = nil
local _nf_cache_names = nil

local function InvalidateNativeFolderCache()
    _nf_cache_folders_list = nil
    _nf_cache_folder_data = nil
    _nf_cache_nb_folders = nil
    _nf_cache_names = nil
    native_fx_reverse_lookup = nil
    native_fx_normalized_lookup = nil
    native_fx_identifier_lookup = nil
end

local function AddNativeFxLookupKey(map, key, name)
    if not key or key == "" or not name or name == "" then return end
    key = tostring(key):gsub("\\", "/"):lower()
    if key ~= "" and not map[key] then map[key] = name end

    local normalized = key:gsub(" ", "_"):gsub("-", "_")
    if normalized ~= "" and not map[normalized] then map[normalized] = name end
end

local function AddNativeFxIdentifierVariants(map, ident, name)
    if not ident or ident == "" then return end

    local value = tostring(ident):gsub("\\", "/")
    AddNativeFxLookupKey(map, value, name)

    local base = value:match("([^/]+)$")
    AddNativeFxLookupKey(map, base, name)

    local lower = value:lower()
    local vst3_pos = lower:find("%.vst3", 1, true)
    if vst3_pos then
        local bundle = value:sub(1, vst3_pos + 4)
        AddNativeFxLookupKey(map, bundle, name)
        AddNativeFxLookupKey(map, bundle:match("([^/]+)$"), name)

        local suffix = value:sub(vst3_pos + 5):match("^(<.+)")
        if suffix then
            AddNativeFxLookupKey(map, bundle .. suffix, name)
            AddNativeFxLookupKey(map, (bundle .. suffix):match("([^/]+)$"), name)
        end
    end
end

function BuildNativeFxReverseLookup()
    native_fx_reverse_lookup = {}
    native_fx_normalized_lookup = {}
    native_fx_identifier_lookup = {}
    for i = 0, math.huge do
        local retval, name, ident = r.EnumInstalledFX(i)
        if not retval then break end
        native_fx_reverse_lookup[name] = ident
        AddNativeFxIdentifierVariants(native_fx_identifier_lookup, ident, name)
        local norm = name:lower()
        norm = norm:gsub("^vst3?i?:%s*", "")
        norm = norm:gsub("^js:%s*", "")
        norm = norm:gsub("^clap:%s*", "")
        norm = norm:gsub("^lv2:%s*", "")
        norm = norm:gsub("^au:%s*", "")
        if norm ~= "" and not native_fx_normalized_lookup[norm] then
            native_fx_normalized_lookup[norm] = name
        end
    end
end

function ResolveNativeFxName(plugin_name)
    if not plugin_name or plugin_name == "" then return nil end
    if not native_fx_reverse_lookup then
        BuildNativeFxReverseLookup()
    end
    if native_fx_reverse_lookup[plugin_name] then
        return plugin_name
    end
    if plugin_aliases then
        for raw, alias in pairs(plugin_aliases) do
            if alias == plugin_name and native_fx_reverse_lookup[raw] then
                return raw
            end
        end
    end
    local norm = plugin_name:lower()
    norm = norm:gsub("^vst3?i?:%s*", "")
    norm = norm:gsub("^js:%s*", "")
    norm = norm:gsub("^clap:%s*", "")
    norm = norm:gsub("^lv2:%s*", "")
    norm = norm:gsub("^au:%s*", "")
    return native_fx_normalized_lookup and native_fx_normalized_lookup[norm] or nil
end

function GetNativeFxIdentifier(plugin_name)
    if not native_fx_reverse_lookup then
        BuildNativeFxReverseLookup()
    end
    return native_fx_reverse_lookup[plugin_name]
end

function GetNativeFxType(plugin_name)
    if plugin_name:match("^VST3?i?: ") then return "3" end
    if plugin_name:match("^JS:") or plugin_name:match("^JS: ") then return "2" end
    if plugin_name:match("^CLAP") then return "7" end
    if plugin_name:match("^LV2") then return "1" end
    if plugin_name:match("^AU") then return "5" end
    return nil
end

function ResolveNativeFolderItem(item_path)
    if not item_path or item_path == "" then return nil end
    if not native_fx_identifier_lookup then
        BuildNativeFxReverseLookup()
    end

    local candidates = {}
    local function add(v)
        if v and v ~= "" then candidates[#candidates + 1] = v end
    end

    local value = tostring(item_path):gsub("\\", "/")
    add(value)
    add(value:match("([^/]+)$"))

    local lower = value:lower()
    local vst3_pos = lower:find("%.vst3", 1, true)
    if vst3_pos then
        local bundle = value:sub(1, vst3_pos + 4)
        add(bundle)
        add(bundle:match("([^/]+)$"))

        local suffix = value:sub(vst3_pos + 5):match("^(<.+)")
        if suffix then
            add(bundle .. suffix)
            add((bundle .. suffix):match("([^/]+)$"))
        end
    end

    for _, candidate in ipairs(candidates) do
        local key = tostring(candidate):gsub("\\", "/"):lower()
        local found = native_fx_identifier_lookup[key]
        if found then return found end

        key = key:gsub(" ", "_"):gsub("-", "_")
        found = native_fx_identifier_lookup[key]
        if found then return found end
    end

    return nil
end

function GetNativeFolderResolvedPlugins(folder_idx)
    local _, folder_data = ParseNativeFoldersINI()
    local fd = folder_data and folder_data[folder_idx]
    if not fd then return {} end

    local plugins = {}
    local seen = {}
    for i = 0, (fd.nb or 0) - 1 do
        local fx_type = tostring(fd.types[i] or "")
        local item = fd.items[i]
        local fx_name

        if fx_type == "1000" and item and item ~= "" then
            fx_name = item .. ".RfxChain"
        elseif fx_type ~= "1048576" then
            fx_name = ResolveNativeFolderItem(item)
        end

        if fx_name and not seen[fx_name] then
            plugins[#plugins + 1] = fx_name
            seen[fx_name] = true
        end
    end

    return plugins
end

function CountNativeFolderPluginItems(folder_idx)
    local _, folder_data = ParseNativeFoldersINI()
    local fd = folder_data and folder_data[folder_idx]
    if not fd then return 0 end

    local count = 0
    for i = 0, (fd.nb or 0) - 1 do
        local fx_type = tostring(fd.types[i] or "")
        if fx_type ~= "1048576" then
            count = count + 1
        end
    end
    return count
end

function ParseNativeFoldersINI()
    if _nf_cache_folders_list then
        return _nf_cache_folders_list, _nf_cache_folder_data, _nf_cache_nb_folders
    end

    local f = io.open(native_folders_ini_path, "r")
    if not f then return {}, {} end
    local content = f:read("*all")
    f:close()

    local folders_list = {}
    local folder_data = {}
    local current_section = nil
    local nb_folders = 0

    for line in content:gmatch("[^\r\n]+") do
        local section = line:match("^%[(.-)%]")
        if section then
            current_section = section
        elseif current_section == "Folders" then
            local name_id, name_val = line:match("^Name(%d+)=(.+)")
            local nb = line:match("^NbFolders=(%d+)")
            if nb then nb_folders = tonumber(nb) end
            if name_id and name_val then
                folders_list[tonumber(name_id)] = name_val
            end
        elseif current_section and current_section:match("^Folder%d+$") then
            local folder_idx = tonumber(current_section:match("^Folder(%d+)$"))
            if not folder_data[folder_idx] then
                folder_data[folder_idx] = { items = {}, types = {}, nb = 0 }
            end
            local item_id, item_val = line:match("^Item(%d+)=(.+)")
            local type_id, type_val = line:match("^Type(%d+)=(.+)")
            local nb_val = line:match("^Nb=(%d+)")
            if item_id and item_val then
                folder_data[folder_idx].items[tonumber(item_id)] = item_val
            end
            if type_id and type_val then
                folder_data[folder_idx].types[tonumber(type_id)] = type_val
            end
            if nb_val then
                folder_data[folder_idx].nb = tonumber(nb_val)
            end
        end
    end

    _nf_cache_folders_list = folders_list
    _nf_cache_folder_data = folder_data
    _nf_cache_nb_folders = nb_folders

    return folders_list, folder_data, nb_folders
end

function WriteNativeFoldersINI(folders_list, folder_data, nb_folders)
    local f = io.open(native_folders_ini_path, "r")
    if not f then return false end
    local content = f:read("*all")
    f:close()

    local pre_sections = {}
    local current_section = nil
    local skip = false

    for line in content:gmatch("[^\r\n]+") do
        local section = line:match("^%[(.-)%]")
        if section then
            if section == "Folders" or section:match("^Folder%d+$") then
                skip = true
            else
                skip = false
                pre_sections[#pre_sections + 1] = line
            end
            current_section = section
        elseif not skip then
            pre_sections[#pre_sections + 1] = line
        end
    end

    local out = {}
    for _, line in ipairs(pre_sections) do
        out[#out + 1] = line
    end
    out[#out + 1] = ""

    local max_folder_idx = -1
    for idx, _ in pairs(folder_data) do
        if idx > max_folder_idx then max_folder_idx = idx end
    end

    for idx = 0, max_folder_idx do
        if folder_data[idx] then
            local fd = folder_data[idx]
            out[#out + 1] = "[Folder" .. idx .. "]"
            for i = 0, fd.nb - 1 do
                if fd.items[i] then
                    out[#out + 1] = "Item" .. i .. "=" .. fd.items[i]
                end
            end
            out[#out + 1] = "Nb=" .. fd.nb
            for i = 0, fd.nb - 1 do
                if fd.types[i] then
                    out[#out + 1] = "Type" .. i .. "=" .. fd.types[i]
                end
            end
            out[#out + 1] = ""
        end
    end

    out[#out + 1] = "[Folders]"
    local id_counter = 0
    for idx = 0, max_folder_idx do
        if folder_data[idx] then
            out[#out + 1] = "Id" .. id_counter .. "=" .. idx
            id_counter = id_counter + 1
        end
    end

    local sorted_names = {}
    for idx, name in pairs(folders_list) do
        sorted_names[#sorted_names + 1] = { idx = idx, name = name }
    end
    table.sort(sorted_names, function(a, b) return a.idx < b.idx end)
    for _, entry in ipairs(sorted_names) do
        out[#out + 1] = "Name" .. entry.idx .. "=" .. entry.name
    end
    out[#out + 1] = "NbFolders=" .. id_counter
    out[#out + 1] = ""

    local wf = io.open(native_folders_ini_path, "w")
    if not wf then return false end
    wf:write(table.concat(out, "\n"))
    wf:close()
    InvalidateNativeFolderCache()
    return true
end

function GetNativeFolderNames()
    if _nf_cache_names then return _nf_cache_names end
    local folders_list = ParseNativeFoldersINI()
    local names = {}
    for idx, name in pairs(folders_list) do
        names[#names + 1] = { idx = idx, name = name }
    end
    table.sort(names, function(a, b) return a.name:lower() < b.name:lower() end)
    _nf_cache_names = names
    return names
end

function GetNativeFolderNamesInOrder()
    local folders_list = ParseNativeFoldersINI()
    local names = {}
    for idx, name in pairs(folders_list) do
        names[#names + 1] = { idx = idx, name = name }
    end
    table.sort(names, function(a, b) return a.idx < b.idx end)
    return names
end

function ReorderNativeFolders(ordered_names)
    local folders_list, folder_data = ParseNativeFoldersINI()
    local name_to_old_idx = {}
    for idx, name in pairs(folders_list) do
        name_to_old_idx[name] = idx
    end
    local new_folders_list = {}
    local new_folder_data = {}
    local count = 0
    for _, name in ipairs(ordered_names) do
        local old_idx = name_to_old_idx[name]
        if old_idx ~= nil and folder_data[old_idx] then
            new_folders_list[count] = name
            new_folder_data[count] = folder_data[old_idx]
            count = count + 1
        end
    end
    WriteNativeFoldersINI(new_folders_list, new_folder_data)
    RefreshAfterNativeFolderChange()
end

function SortNativeFoldersAlphabetically()
    local names_ordered = GetNativeFolderNamesInOrder()
    table.sort(names_ordered, function(a, b) return a.name:lower() < b.name:lower() end)
    local ordered = {}
    for _, entry in ipairs(names_ordered) do
        ordered[#ordered + 1] = entry.name
    end
    ReorderNativeFolders(ordered)
end

function CreateNativeFolder(folder_name)
    local folders_list, folder_data, nb_folders = ParseNativeFoldersINI()

    local next_idx = 0
    for idx, _ in pairs(folder_data) do
        if idx >= next_idx then next_idx = idx + 1 end
    end
    for idx, _ in pairs(folders_list) do
        if idx >= next_idx then next_idx = idx + 1 end
    end

    folders_list[next_idx] = folder_name
    folder_data[next_idx] = { items = {}, types = {}, nb = 0 }

    if WriteNativeFoldersINI(folders_list, folder_data, nb_folders + 1) then
        return next_idx
    end
    return nil
end

function AddPluginToNativeFolder(folder_idx, plugin_name)
    local folders_list, folder_data = ParseNativeFoldersINI()
    if not folder_data[folder_idx] then return false end

    local native_name = ResolveNativeFxName(plugin_name)
    if not native_name then return false end

    local ident = GetNativeFxIdentifier(native_name)
    if not ident then return false end

    local fx_type = GetNativeFxType(native_name)
    if not fx_type then return false end

    local fd = folder_data[folder_idx]

    for i = 0, fd.nb - 1 do
        if fd.items[i] == ident then
            return false
        end
    end

    local new_idx = fd.nb
    fd.items[new_idx] = ident
    fd.types[new_idx] = fx_type
    fd.nb = fd.nb + 1

    return WriteNativeFoldersINI(folders_list, folder_data)
end

function RemovePluginFromNativeFolder(folder_idx, plugin_name)
    local folders_list, folder_data = ParseNativeFoldersINI()
    if not folder_data[folder_idx] then return false end

    local native_name = ResolveNativeFxName(plugin_name)
    if not native_name then return false end

    local ident = GetNativeFxIdentifier(native_name)
    if not ident then return false end

    local fd = folder_data[folder_idx]
    local remove_idx = nil
    for i = 0, fd.nb - 1 do
        if fd.items[i] == ident then
            remove_idx = i
            break
        end
    end
    if not remove_idx then return false end

    local new_items = {}
    local new_types = {}
    local new_nb = 0
    for i = 0, fd.nb - 1 do
        if i ~= remove_idx then
            new_items[new_nb] = fd.items[i]
            new_types[new_nb] = fd.types[i]
            new_nb = new_nb + 1
        end
    end
    fd.items = new_items
    fd.types = new_types
    fd.nb = new_nb

    return WriteNativeFoldersINI(folders_list, folder_data)
end

function DeleteNativeFolder(folder_idx)
    local folders_list, folder_data = ParseNativeFoldersINI()
    if not folder_data[folder_idx] then return false end

    folder_data[folder_idx] = nil
    folders_list[folder_idx] = nil

    return WriteNativeFoldersINI(folders_list, folder_data)
end

function RenameNativeFolder(folder_idx, new_name)
    local folders_list, folder_data = ParseNativeFoldersINI()
    if not folders_list[folder_idx] then return false end
    folders_list[folder_idx] = new_name
    return WriteNativeFoldersINI(folders_list, folder_data)
end

function RefreshAfterNativeFolderChange()
    InvalidateNativeFolderCache()
    local old_plugin_list = PLUGIN_LIST
    FX_LIST_TEST, CAT_TEST, FX_DEV_LIST_FILE = MakeFXFiles()
    PLUGIN_LIST = old_plugin_list or FX_LIST_TEST
    initFoldersCategory()
end

