end
function ClearScreenshotCache(periodic_cleanup)
    local current_time = r.time_precise()
    
    if not periodic_cleanup then
        screenshot_exists_cache = {}
    end

    if periodic_cleanup then
        local to_remove = {}
        for key, last_used in pairs(texture_last_used) do
            if current_time - last_used > 300 then 
                table.insert(to_remove, key)
            end
        end
        for _, key in ipairs(to_remove) do
            if search_texture_cache[key] then
                r.ImGui_Detach(ctx, search_texture_cache[key])
            end
            search_texture_cache[key] = nil
            texture_last_used[key] = nil
            texture_load_queue[key] = nil
        end
    else
        for key, texture in pairs(search_texture_cache or {}) do
            r.ImGui_Detach(ctx, texture)
        end
        for fx_name, texture in pairs(fx_chain_texture_cache or {}) do
            r.ImGui_Detach(ctx, texture)
        end
        for fx_name, texture in pairs(info_fx_texture_cache or {}) do
            r.ImGui_Detach(ctx, texture)
        end
        for k, tex in pairs(list_hover_texture_cache or {}) do
            r.ImGui_Detach(ctx, tex)
        end
        search_texture_cache = {}
        texture_last_used = {}
        texture_load_queue = {}
        fx_chain_texture_cache = {}
        info_fx_texture_cache = {}
        list_hover_texture_cache = {}
    end
end

local folders_category = {}
function initFoldersCategory()
    folders_category = {}
    for i = 1, #(CAT_TEST or {}) do
        if CAT_TEST[i].name == "FOLDERS" then
            folders_category = CAT_TEST[i].list or {}
            break
        end
    end
    local ini_names = GetNativeFolderNamesInOrder and GetNativeFolderNamesInOrder() or {}
    for _, entry in ipairs(ini_names) do
        local found = false
        local native_item_count = CountNativeFolderPluginItems and CountNativeFolderPluginItems(entry.idx) or 0
        local resolved_fx = nil
        for _, fc in ipairs(folders_category) do
            if fc.name == entry.name then
                found = true
                fc.fx = fc.fx or {}
                if native_item_count > #fc.fx then
                    resolved_fx = GetNativeFolderResolvedPlugins and GetNativeFolderResolvedPlugins(entry.idx) or {}
                end
                if resolved_fx and #resolved_fx > #fc.fx then
                    fc.fx = resolved_fx
                elseif resolved_fx then
                    local seen = {}
                    for _, fx in ipairs(fc.fx) do seen[fx] = true end
                    for _, fx in ipairs(resolved_fx) do
                        if not seen[fx] then
                            fc.fx[#fc.fx + 1] = fx
                            seen[fx] = true
                        end
                    end
                end
                break
            end
        end
        if not found then
            resolved_fx = GetNativeFolderResolvedPlugins and GetNativeFolderResolvedPlugins(entry.idx) or {}
            folders_category[#folders_category + 1] = { name = entry.name, fx = resolved_fx }
        end
    end
end
initFoldersCategory()

