function IsX86Bridged(plugin_name)
    if not plugin_name then return false end
    return (plugin_name:match('%(x86%)')
        or plugin_name:match('%[x86%]')
        or plugin_name:match('[%s%-]x86[%s%)]*$')
        or plugin_name:lower():match('x86%s*bridged')
        or plugin_name:match('x86:')) and true or false
end

function ScreenshotExists(plugin_name, size_option)
    if screenshot_database[plugin_name] ~= nil then
        return true
    end

    local safe_name = plugin_name:gsub("[^%w%s-]", "_")
    if size_option == 1 then -- 128x128
        local track_icons_path = script_path .. "TrackIcons" .. os_separator
        local filename = track_icons_path .. safe_name .. ".png"
        return r.file_exists(filename)
    else
        local filename = screenshot_path .. safe_name .. ".png"
        return r.file_exists(filename)
    end
end

-- bodem knoppen
function IsMuted(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        return r.GetMediaTrackInfo_Value(track, "B_MUTE") == 1
    end
    return false
end

function ToggleMute(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        local mute = r.GetMediaTrackInfo_Value(track, "B_MUTE")
        r.SetMediaTrackInfo_Value(track, "B_MUTE", mute == 0 and 1 or 0)
    end
end

function IsSoloed(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        return r.GetMediaTrackInfo_Value(track, "I_SOLO") ~= 0
    end
    return false
end

function ToggleSolo(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        local solo = r.GetMediaTrackInfo_Value(track, "I_SOLO")
        r.SetMediaTrackInfo_Value(track, "I_SOLO", solo == 0 and 1 or 0)
    end
end

function ToggleArm(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        local armed = r.GetMediaTrackInfo_Value(track, "I_RECARM")
        r.SetMediaTrackInfo_Value(track, "I_RECARM", armed == 0 and 1 or 0)
    end
end

function IsArmed(track)
    if track and reaper.ValidatePtr(track, "MediaTrack*") then
        return r.GetMediaTrackInfo_Value(track, "I_RECARM") == 1
    end
    return false
end

function AddFXToItem(fx_name)
    local item = r.GetSelectedMediaItem(0, 0)
    if not item then return -1 end
    local take = r.GetActiveTake(item)
    if not take then return -1 end
    
    local dest_index = r.TakeFX_GetCount(take)
    local fx_index = r.TakeFX_AddByName(take, fx_name, -1000 - dest_index)
    
    if fx_index and fx_index >= 0 then
        if config and config.open_floating_after_adding then
            r.TakeFX_Show(take, fx_index, 3)
        end
        if config and config.hide_after_insert then SHOULD_HIDE_BROWSER = true end
        return fx_index, take
    end
    return -1
end

function CreateFXChain()
    if not TRACK or not reaper.ValidatePtr(TRACK, "MediaTrack*") then return end
    local fx_count = r.TrackFX_GetCount(TRACK)
    if fx_count == 0 then return end
    r.SetOnlyTrackSelected(TRACK)
    r.Main_OnCommand(r.NamedCommandLookup("_S&M_SAVE_FXCHAIN_SLOT1"), 0)
    FX_LIST_TEST, CAT_TEST = MakeFXFiles()
    r.ShowMessageBox("FX Chain created successfully!", "Success", 0)
end

-- Debug toggle for texture I/O logging (set true only for diagnostics)
local DEBUG_TEX_LOG = false
function tex_log(msg)
    if DEBUG_TEX_LOG then log_to_file(msg) end
end

function LoadTexture(file)
    if type(file) ~= 'string' then return nil end
    local texture = r.ImGui_CreateImage(file)
    if texture then
        r.ImGui_Attach(ctx, texture)
    else
        tex_log("Failed to load texture: " .. file)
    end
    return texture
end

function SafeImage(ctx, texture, w, h)
    if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
        r.ImGui_Image(ctx, texture, w, h)
        return true
    end
    return false
end
    
function LoadSearchTexture(file, plugin_name)
    if type(file) ~= 'string' then return nil end
    local relative_path = file:gsub(screenshot_path, "")
    local unique_key = relative_path .. "_" .. (plugin_name or "unknown")
    local current_time = r.time_precise()

    -- Check missing file cache
    if missing_file_cache and missing_file_cache[file] then return nil end

    if search_texture_cache[unique_key] then
        texture_last_used[unique_key] = current_time
        return search_texture_cache[unique_key]
    end
    if not r.file_exists(file) then
        if missing_file_cache then missing_file_cache[file] = true end
        tex_log("File does not exist: " .. file .. " for plugin: " .. (plugin_name or "unknown"))
        return nil
    end
    if not texture_load_queue[unique_key] then
        texture_load_queue[unique_key] = { file = file, queued_at = current_time, plugin = plugin_name }
        tex_log("Queued texture load: " .. file .. " for plugin: " .. (plugin_name or "unknown"))
    end
    return nil
end

    local function ProcessTextureLoadQueue()
    if not texture_load_queue or next(texture_load_queue) == nil then return end
   
    -- PERFORMANCE: Limit queue size to prevent disk I/O bottleneck
    local queue_count = 0
    for _ in pairs(texture_load_queue) do queue_count = queue_count + 1 end
    
    if queue_count > 500 then
        DebugLog("WARNING: Texture queue overflow (" .. queue_count .. " items). Clearing oldest 50% to prevent slowdown.")
        -- Keep only newest 250 entries
        local sorted_queue = {}
        for k, v in pairs(texture_load_queue) do
            t_insert(sorted_queue, {key = k, data = v, time = v.queued_at or 0})
        end
        t_sort(sorted_queue, function(a,b) return a.time > b.time end)
        texture_load_queue = {}
        for i = 1, m_min(250, #sorted_queue) do
            local entry = sorted_queue[i]
            texture_load_queue[entry.key] = entry.data
        end
    end
   
    local VISIBLE_BUFFER = 30
    local keep_set = {}
    local cap = (loaded_items_count or ITEMS_PER_BATCH or 30) + VISIBLE_BUFFER
    if selected_folder and type(current_filtered_fx) == 'table' then
        cap = m_max(cap, #current_filtered_fx)
    end

    if selected_folder and type(current_filtered_fx) == 'table' and #current_filtered_fx > 0 then
        for i = 1, m_min(cap, #current_filtered_fx) do
            local name = current_filtered_fx[i]
            if type(name) == 'string' then keep_set[name] = true end
        end
    end
   
    if type(screenshot_search_results) == 'table' and #screenshot_search_results > 0 then
        local added = 0
        for _, fx in ipairs(screenshot_search_results) do
            if added >= cap then break end
            if fx and not fx.is_separator and not fx.is_message and fx.name then
                keep_set[fx.name] = true
                added = added + 1
            end
        end
    elseif (not selected_folder) and type(current_filtered_fx) == 'table' and #current_filtered_fx > 0 then
        
        for i = 1, m_min(cap, #current_filtered_fx) do
            local name = current_filtered_fx[i]
            if type(name) == 'string' then keep_set[name] = true end
        end
    end

    local original_max_per_frame = config.max_textures_per_frame
    local original_cache_max = config.max_cached_search_textures
    local original_min_cache = config.min_cached_textures
    local is_all_plugins_context = (not selected_folder and (browser_panel_selected == "ALL PLUGINS" or browser_panel_selected == nil))
    local visible_targets = loaded_items_count or ITEMS_PER_BATCH or 30
    if is_all_plugins_context and visible_targets > 60 then
        config.max_textures_per_frame = m_max(2, m_floor(original_max_per_frame * 0.5))
        config.max_cached_search_textures = m_max(40, m_floor(original_cache_max * 0.7))
        config.min_cached_textures = m_min(config.min_cached_textures, m_floor(config.max_cached_search_textures * 0.4))
    end

    local textures_loaded = 0
    local current_time = r.time_precise()
    for unique_key, info in pairs(texture_load_queue) do
        if textures_loaded >= config.max_textures_per_frame then break end
        local file = info.file
        
        -- OPTIMALISATIE: Extra check op missing cache voor het geval hij er later in is gekomen
        if not search_texture_cache[unique_key] and not missing_file_cache[file] then
            if r.file_exists(file) then
                local texture = r.ImGui_CreateImage(file)
                if texture then
                    r.ImGui_Attach(ctx, texture)
                    search_texture_cache[unique_key] = texture
                    texture_last_used[unique_key] = current_time
                    textures_loaded = textures_loaded + 1
                    tex_log("Texture loaded (deferred): " .. file .. " for plugin: " .. (info.plugin or "unknown"))
                else
                    tex_log("Error loading texture: " .. file)
                end
            else
                missing_file_cache[file] = true -- Markeer als missing
            end
        end
        texture_load_queue[unique_key] = nil
    end
  
    local cache_size = 0
    for _ in pairs(search_texture_cache) do cache_size = cache_size + 1 end
    if cache_size > config.max_cached_search_textures then
        local textures_to_remove = {}
        for key, last_used in pairs(texture_last_used) do
            if current_time - last_used > config.texture_reload_delay and cache_size > config.min_cached_textures then
                table.insert(textures_to_remove, key)
                cache_size = cache_size - 1
            end
        end
        for _, key in ipairs(textures_to_remove) do
            if search_texture_cache[key] then
                r.ImGui_Detach(ctx, search_texture_cache[key])
            end
            search_texture_cache[key] = nil
            texture_last_used[key] = nil
            tex_log("Texture removed: " .. key)
        end
    end
    
    if is_all_plugins_context and visible_targets > 60 then
        config.max_textures_per_frame = original_max_per_frame
        config.max_cached_search_textures = original_cache_max
        config.min_cached_textures = original_min_cache
    end
end  

function Lead_Trim_ws(s) return s:match '^%s*(.*)' end

function SetMinMax(Input, Min, Max)
    return math.max(Min, math.min(Input, Max))
end

function SortTable(tab, val1, val2)
    table.sort(tab, function(a, b)
        if (a[val1] < b[val1]) then return true
        elseif (a[val1] > b[val1]) then return false
        else return a[val2] < b[val2] end
    end)
end

function GetButtonColors()
    local base = config.button_background_color or 0x333333FF
    local base_r = (base >> 24) & 0xFF
    local base_g = (base >> 16) & 0xFF
    local base_b = (base >> 8) & 0xFF
    
    local hover_r = math.min(255, base_r + 20)
    local hover_g = math.min(255, base_g + 20)
    local hover_b = math.min(255, base_b + 20)
    local active_r = math.min(255, base_r + 40)
    local active_g = math.min(255, base_g + 40)
    local active_b = math.min(255, base_b + 40)
    
    local hover = (hover_r << 24) | (hover_g << 16) | (hover_b << 8) | 0xFF
    local active = (active_r << 24) | (active_g << 16) | (active_b << 8) | 0xFF
    local text = config.text_color or r.ImGui_ColorConvertDouble4ToU32(config.text_gray/255, config.text_gray/255, config.text_gray/255, 1)
    
    return base, hover, active, text
end

function DrawCollapseHeader(label, is_expanded, tooltip_show, tooltip_hide)
    local dl = r.ImGui_GetWindowDrawList(ctx)
    local avail_w = r.ImGui_GetContentRegionAvail(ctx)
    local screen_x, screen_y = r.ImGui_GetCursorScreenPos(ctx)
    local header_h = 20
    local text_w, text_h = r.ImGui_CalcTextSize(ctx, label)
    local rounding = 3
    
    local mouse_x, mouse_y = r.ImGui_GetMousePos(ctx)
    local is_hovered = mouse_x >= screen_x and mouse_x <= screen_x + avail_w and
                       mouse_y >= screen_y and mouse_y <= screen_y + header_h
    local is_clicked = is_hovered and r.ImGui_IsMouseClicked(ctx, 0)
    
    local base_color = config.button_background_color or 0x333333FF
    local base_r = (base_color >> 24) & 0xFF
    local base_g = (base_color >> 16) & 0xFF
    local base_b = (base_color >> 8) & 0xFF
    
    local light_offset = is_hovered and 30 or 15
    local dark_offset = is_hovered and 10 or 25
    
    local top_r = math.min(255, base_r + light_offset)
    local top_g = math.min(255, base_g + light_offset)
    local top_b = math.min(255, base_b + light_offset)
    local bottom_r = math.max(0, base_r - dark_offset)
    local bottom_g = math.max(0, base_g - dark_offset)
    local bottom_b = math.max(0, base_b - dark_offset)
    
    local top_color = (top_r << 24) | (top_g << 16) | (top_b << 8) | 0xFF
    local bottom_color = (bottom_r << 24) | (bottom_g << 16) | (bottom_b << 8) | 0xFF
    local border_color = 0x50505080
    
    local base_text = config.text_color or r.ImGui_ColorConvertDouble4ToU32(config.text_gray/255, config.text_gray/255, config.text_gray/255, 1)
    local text_r = (base_text >> 24) & 0xFF
    local text_g = (base_text >> 16) & 0xFF
    local text_b = (base_text >> 8) & 0xFF
    local hover_text_r = math.min(255, text_r + 40)
    local hover_text_g = math.min(255, text_g + 40)
    local hover_text_b = math.min(255, text_b + 40)
    local text_color = is_hovered and ((hover_text_r << 24) | (hover_text_g << 16) | (hover_text_b << 8) | 0xFF) or base_text
    
    r.ImGui_DrawList_AddRectFilledMultiColor(dl, 
        screen_x, screen_y, 
        screen_x + avail_w, screen_y + header_h,
        top_color, top_color, bottom_color, bottom_color)
    
    r.ImGui_DrawList_AddRect(dl, screen_x, screen_y, screen_x + avail_w, screen_y + header_h, border_color, rounding)
    
    local text_x = screen_x + (avail_w - text_w) / 2
    local text_y = screen_y + (header_h - text_h) / 2
    
    r.ImGui_DrawList_AddText(dl, text_x, text_y, text_color, label)
    
    r.ImGui_Dummy(ctx, avail_w, header_h + 2)
    
    if is_hovered then
        local tip = is_expanded and (tooltip_hide or ("Hide " .. label)) or (tooltip_show or ("Show " .. label))
        r.ImGui_SetTooltip(ctx, tip)
    end
    
    return is_clicked
end

function GetTrackColorAndTextColor(track)
    if not track or not reaper.ValidatePtr(track, "MediaTrack*") then
        return r.ImGui_ColorConvertDouble4ToU32(0.5, 0.5, 0.5, 1), 0xFFFFFFFF
    end
    local color = r.GetTrackColor(track)
    if color == 0 then
        return r.ImGui_ColorConvertDouble4ToU32(1, 1, 1, 1), 0x000000FF
    else
        -- Convert from REAPER's native color encoding (platform-dependent) to RGB
        local rr, gg, bb = r.ColorFromNative(color)
        rr, gg, bb = rr or 128, gg or 128, bb or 128
        local red = rr / 255
        local green = gg / 255
        local blue = bb / 255
        local brightness = (red * 0.299 + green * 0.587 + blue * 0.114)
        local text_color = brightness > 0.5 and 0x000000FF or 0xFFFFFFFF
        return r.ImGui_ColorConvertDouble4ToU32(red, green, blue, 1), text_color
    end
end

local info_slider_block_drag = {}

local function DrawInfoSlider(id, value, min_val, max_val, label, value_text, rail_color)
    rail_color = rail_color or 0x808080FF
    local label_offset = 42
    local avail_w = r.ImGui_GetContentRegionAvail(ctx)
    local height = 20
    local grab_radius = 8.0
    local pad = 10.0
    local cx, cy = r.ImGui_GetCursorScreenPos(ctx)
    local dl = r.ImGui_GetWindowDrawList(ctx)
    local center_y = cy + height * 0.5

    local text_h = r.ImGui_GetTextLineHeight(ctx)
    r.ImGui_DrawList_AddText(dl, cx, cy + (height - text_h) * 0.5, 0xFFFFFFFF, label)

    local slider_x = cx + label_offset
    local slider_w = avail_w - label_offset
    local track_w = slider_w - pad * 2

    r.ImGui_InvisibleButton(ctx, id, avail_w, height)
    local is_active = r.ImGui_IsItemActive(ctx)
    local is_hovered = r.ImGui_IsItemHovered(ctx)
    local changed = false
    local double_clicked = false

    if is_hovered and r.ImGui_IsMouseDoubleClicked(ctx, 0) then
        double_clicked = true
        info_slider_block_drag[id] = true
    end

    if not is_active then
        info_slider_block_drag[id] = nil
    end

    if is_active and not info_slider_block_drag[id] then
        local mx = r.ImGui_GetMousePos(ctx)
        local t = (mx - (slider_x + pad)) / math.max(1, track_w)
        t = math.max(0, math.min(1, t))
        local new_val = min_val + t * (max_val - min_val)
        if new_val ~= value then
            value = new_val
            changed = true
        end
    end

    local t = (value - min_val) / (max_val - min_val)
    t = math.max(0, math.min(1, t))
    local knob_x = slider_x + pad + t * track_w

    r.ImGui_DrawList_AddLine(dl, slider_x + pad, center_y, slider_x + pad + track_w, center_y, rail_color, 2.0)
    r.ImGui_DrawList_AddCircleFilled(dl, knob_x, center_y, grab_radius, rail_color)
    r.ImGui_DrawList_AddCircle(dl, knob_x, center_y, grab_radius, 0x333333FF, 0, 1.0)

    if is_hovered or is_active then
        r.ImGui_SetTooltip(ctx, value_text)
    end

    return value, changed, is_hovered, double_clicked
end

function GetTagColorAndTextColor(tag_color)
    local red, g, b, a = r.ImGui_ColorConvertU32ToDouble4(tag_color)
    local brightness = (red * 299 + g * 587 + b * 114) / 1000
    local text_color = brightness > 0.5 
        and r.ImGui_ColorConvertDouble4ToU32(0, 0, 0, 1) 
        or r.ImGui_ColorConvertDouble4ToU32(1, 1, 1, 1)
    return tag_color, text_color
end

function GetBounds(hwnd)
    local retval, left, top, right, bottom = r.JS_Window_GetClientRect(hwnd)
    return left, top, right-left, bottom-top
end

function Literalize(str)
    return str:gsub("[%(%)%.%%%+%-%*%?%[%]%^%$]", "%%%1")
end

function GetTrackName(track)
    if not track or not reaper.ValidatePtr(track, "MediaTrack*") then
        return "No Track Selected"
    end
    local _, name = r.GetTrackName(track)
    return name
end
function IsOSX()
    local platform = reaper.GetOS()
    return platform:match("OSX") or platform:match("macOS")
end

function ScreenshotOSX(path, x, y, w, h)
    x, y = r.ImGui_PointConvertNative(ctx, x, y, false)
    local command = 'screencapture -x -R %d,%d,%d,%d -t png "%s"'
    os.execute(command:format(x, y, w, h, path))
end
                            

