function LoadChainFxScreenshot(fx_name)
    if fx_chain_texture_cache[fx_name] then
        if r.ImGui_ValidatePtr(fx_chain_texture_cache[fx_name], 'ImGui_Image*') then
            return fx_chain_texture_cache[fx_name]
        else
            r.ImGui_Detach(ctx, fx_chain_texture_cache[fx_name])
            fx_chain_texture_cache[fx_name] = nil
        end
    end
    
    -- Use the same naming convention as the regular screenshot system
    local safe_name = fx_name:gsub("[^%w%s-]", "_")
    local screenshot_file = screenshot_path .. safe_name .. ".png"
    
    if r.file_exists(screenshot_file) then
        local tex = LoadTexture(screenshot_file)
        if tex then
            -- Cache the texture for reuse
            fx_chain_texture_cache[fx_name] = tex
            return tex
        end
    end
    
    return nil
end

function FindFXBlockBounds(chunk, chain_tag, fx_idx)
    local chain_start = chunk:find("<" .. chain_tag .. "\n")
    if not chain_start then return nil end
    local depth = 0
    local fx_count = -1
    local target_start, target_depth
    for i = chain_start, #chunk do
        local c = chunk:sub(i, i)
        if c == "<" then
            depth = depth + 1
            if depth == 2 and not target_start then
                fx_count = fx_count + 1
                if fx_count == fx_idx then
                    target_start = i
                    target_depth = depth
                end
            end
        elseif c == ">" then
            if target_start and depth == target_depth then
                return target_start, i
            end
            depth = depth - 1
            if depth == 0 then break end
        end
    end
    return nil
end

function GetABKey(track, fx_idx, is_take, take)
    if is_take then
        local item = r.GetMediaItemTake_Item(take)
        local item_guid = r.BR_GetMediaItemGUID(item)
        local fx_guid = r.TakeFX_GetFXGUID(take, fx_idx)
        if not fx_guid then fx_guid = tostring(fx_idx) end
        return "I:" .. item_guid .. ":" .. fx_guid
    else
        local track_guid = r.GetTrackGUID(track)
        local fx_guid = r.TrackFX_GetFXGUID(track, fx_idx)
        if not fx_guid then fx_guid = tostring(fx_idx) end
        return "T:" .. track_guid .. ":" .. fx_guid
    end
end

function SaveFXSnapshot(track, fx_idx, slot, is_take, take)
    local chain_tag = is_take and "TAKEFX" or "FXCHAIN"
    local chunk
    if is_take then
        local item = r.GetMediaItemTake_Item(take)
        local _, c = r.GetItemStateChunk(item, "", false)
        chunk = c
    else
        local _, c = r.GetTrackStateChunk(track, "", false)
        chunk = c
    end
    if not chunk then return false end
    local bs, be = FindFXBlockBounds(chunk, chain_tag, fx_idx)
    if not bs or not be then return false end
    local fx_block = chunk:sub(bs, be)
    local key = GetABKey(track, fx_idx, is_take, take)
    if not ab_snapshots[key] then
        ab_snapshots[key] = { active = nil }
    end
    local enabled
    if is_take then
        enabled = r.TakeFX_GetEnabled(take, fx_idx)
    else
        enabled = r.TrackFX_GetEnabled(track, fx_idx)
    end
    ab_snapshots[key][slot] = { chunk = fx_block, enabled = enabled }
    ab_snapshots[key].active = slot
    return true
end

function RestoreFXSnapshot(track, fx_idx, slot, is_take, take)
    local key = GetABKey(track, fx_idx, is_take, take)
    if not ab_snapshots[key] or not ab_snapshots[key][slot] then return false end
    local snap = ab_snapshots[key][slot]
    local chain_tag = is_take and "TAKEFX" or "FXCHAIN"
    local chunk
    if is_take then
        local item = r.GetMediaItemTake_Item(take)
        local _, c = r.GetItemStateChunk(item, "", false)
        chunk = c
    else
        local _, c = r.GetTrackStateChunk(track, "", false)
        chunk = c
    end
    if not chunk then return false end
    local bs, be = FindFXBlockBounds(chunk, chain_tag, fx_idx)
    if not bs or not be then return false end
    local new_chunk = chunk:sub(1, bs - 1) .. snap.chunk .. chunk:sub(be + 1)
    r.Undo_BeginBlock()
    r.PreventUIRefresh(1)
    if is_take then
        local item = r.GetMediaItemTake_Item(take)
        r.SetItemStateChunk(item, new_chunk, false)
        r.TakeFX_SetEnabled(take, fx_idx, snap.enabled)
    else
        r.SetTrackStateChunk(track, new_chunk, false)
        r.TrackFX_SetEnabled(track, fx_idx, snap.enabled)
    end
    r.PreventUIRefresh(-1)
    r.Undo_EndBlock("Restore FX Snapshot " .. string.upper(slot), -1)
    ab_snapshots[key].active = slot
    return true
end

function GetABInfo(track, fx_idx, is_take, take)
    local key = GetABKey(track, fx_idx, is_take, take)
    local snap = ab_snapshots[key]
    if not snap then return nil end
    return {
        has_a = snap.a ~= nil,
        has_b = snap.b ~= nil,
        active = snap.active,
    }
end

function LoadInfoFxScreenshot(fx_name)
    if info_fx_texture_cache[fx_name] then
        if r.ImGui_ValidatePtr(info_fx_texture_cache[fx_name], 'ImGui_Image*') then
            return info_fx_texture_cache[fx_name]
        else
            r.ImGui_Detach(ctx, info_fx_texture_cache[fx_name])
            info_fx_texture_cache[fx_name] = nil
        end
    end
    local clean = CleanPluginName(fx_name)
    local variants = {
        fx_name:gsub("[^%w%s-]", "_"),
        clean,
        clean:gsub("[^%w%s-]", "_"),
        StripX86Markers(fx_name):gsub("[^%w%s-]", "_"),
        StripX86Markers(clean):gsub("[^%w%s-]", "_"),
    }
    for _, base in ipairs(variants) do
        if base and base ~= "" then
            local png = screenshot_path .. base .. ".png"
            if r.file_exists(png) then
                local tex = LoadTexture(png)
                if tex then
                    info_fx_texture_cache[fx_name] = tex
                    return tex
                end
            end
            local jpg = screenshot_path .. base .. ".jpg"
            if r.file_exists(jpg) then
                local tex = LoadTexture(jpg)
                if tex then
                    info_fx_texture_cache[fx_name] = tex
                    return tex
                end
            end
        end
    end
    return nil
end

function ShowFxChainInScreenshotWindow(chain_path, relative_path, chain_name)
    -- Store the current FX chain for display in screenshot window
    current_fx_chain_path = chain_path
    current_fx_chain_relative_path = relative_path
    current_fx_chain_name = chain_name
    
    -- Parse the FX chain to get list of plugins
    local fx_list = ParseFxChainFile(chain_path)
    if not fx_list or #fx_list == 0 then 
        return 
    end
    
    -- Clear previous search results and cache
    screenshot_search_results = {}
    selected_folder = nil
    browser_panel_selected = nil
    ClearScreenshotCache()
    if fx_chain_cache then fx_chain_cache[chain_path] = nil end
    
    -- Populate screenshot_search_results with the FX from the chain
    for i, fx_name in ipairs(fx_list) do
        table.insert(screenshot_search_results, {
            name = fx_name,
            is_fx_chain_item = true,
            chain_path = chain_path,
            chain_name = chain_name
        })
    end
    
    -- Pre-load textures for the FX in the chain
    for i, fx_name in ipairs(fx_list) do
        local safe_name = fx_name:gsub("[^%w%s-]", "_")
        local screenshot_file = screenshot_path .. safe_name .. ".png"
        if r.file_exists(screenshot_file) then
            local relative_path = screenshot_file:gsub(screenshot_path, "")
            local unique_key = relative_path .. "_" .. fx_name
            if not texture_load_queue[unique_key] and not search_texture_cache[unique_key] then
                texture_load_queue[unique_key] = { 
                    file = screenshot_file, 
                    queued_at = r.time_precise(), 
                    plugin = fx_name 
                }
            end
        end
    end
end

function DrawFxChainActionButtons(suffix)
    if not (current_fx_chain_relative_path and current_fx_chain_name) then return 0 end

    local start_y = r.ImGui_GetCursorPosY(ctx)
    r.ImGui_Dummy(ctx, 0, 5)

    local win_w = r.ImGui_GetContentRegionAvail(ctx)
    local btn_count = config.show_chain_builder and 5 or 4
    local spacing = 4
    local min_btn_w = 55
    local per_row = math.min(btn_count, math.max(1, math.floor((win_w + spacing) / (min_btn_w + spacing))))
    local btn_w = math.floor((win_w - spacing * (per_row - 1)) / per_row)
    local btn_idx = 0

    local function NextBtn()
        if btn_idx % per_row == 0 then
            local cols = math.min(per_row, btn_count - btn_idx)
            local row_w = btn_w * cols + spacing * (cols - 1)
            r.ImGui_SetCursorPosX(ctx, (win_w - row_w) * 0.5)
        else
            r.ImGui_SameLine(ctx, 0, spacing)
        end
        btn_idx = btn_idx + 1
    end

    NextBtn()
    if r.ImGui_Button(ctx, "Add##" .. suffix, btn_w, 26) then
        local cnt = r.CountSelectedTracks(0)
        if cnt > 0 then
            for t = 0, cnt - 1 do
                local track = r.GetSelectedTrack(0, t)
                if track and r.ValidatePtr(track, "MediaTrack*") then
                    AddFXToTrack(track, current_fx_chain_relative_path)
                end
            end
            if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
        else
            r.ShowMessageBox("No tracks selected.", "Add FX Chain", 0)
        end
    end
    if r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Add '" .. current_fx_chain_name .. "' to selected tracks")
    end

    NextBtn()
    if r.ImGui_Button(ctx, "Replace##" .. suffix, btn_w, 26) then
        local cnt = r.CountSelectedTracks(0)
        if cnt > 0 then
            for t = 0, cnt - 1 do
                local track = r.GetSelectedTrack(0, t)
                if track and r.ValidatePtr(track, "MediaTrack*") then
                    local fx_count = r.TrackFX_GetCount(track)
                    for j = fx_count - 1, 0, -1 do r.TrackFX_Delete(track, j) end
                    AddFXToTrack(track, current_fx_chain_relative_path)
                end
            end
            if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
        else
            r.ShowMessageBox("No tracks selected.", "Replace FX", 0)
        end
    end
    if r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Replace FX on selected tracks with '" .. current_fx_chain_name .. "'")
    end

    if config.show_chain_builder then
        NextBtn()
        if r.ImGui_Button(ctx, "Builder##" .. suffix, btn_w, 26) then
            if current_fx_chain_path then
                local fx_list = ParseFxChainFile(current_fx_chain_path)
                if fx_list then
                    for _, pname in ipairs(fx_list) do
                        table.insert(chain_builder_plugins, pname)
                        chain_builder_chunks[#chain_builder_plugins] = false
                    end
                    config.chain_builder_plugins = chain_builder_plugins
                    SaveConfig()
                end
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            r.ImGui_SetTooltip(ctx, "Add all FX to Chain Builder")
        end
    end

    NextBtn()
    if r.ImGui_Button(ctx, "Rename##" .. suffix, btn_w, 26) then
        if current_fx_chain_path and current_fx_chain_name then
            local retval, new_name = r.GetUserInputs("Rename FX Chain", 1, "New name:", current_fx_chain_name)
            if retval then
                local dir_part = current_fx_chain_path:match("^(.*)[/\\]")
                local new_path = dir_part .. os_separator .. new_name .. ".RfxChain"
                if os.rename(current_fx_chain_path, new_path) then
                    FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                    if fx_chain_cache then fx_chain_cache[current_fx_chain_path] = nil end
                    local new_rel = current_fx_chain_relative_path:gsub(
                        current_fx_chain_name .. "%.RfxChain$",
                        new_name .. ".RfxChain"
                    )
                    ShowFxChainInScreenshotWindow(new_path, new_rel, new_name)
                else
                    r.ShowMessageBox("Could not rename FX Chain", "Error", 0)
                end
            end
        end
    end
    if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Rename this FX Chain") end

    NextBtn()
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x8B0000FF)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xCC0000FF)
    if r.ImGui_Button(ctx, "Delete##" .. suffix, btn_w, 26) then
        if current_fx_chain_path then
            local confirm = r.ShowMessageBox(
                "Delete '" .. (current_fx_chain_name or "") .. "'?",
                "Delete FX Chain", 4
            )
            if confirm == 6 then
                if os.remove(current_fx_chain_path) then
                    FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                    if fx_chain_cache then fx_chain_cache[current_fx_chain_path] = nil end
                    current_fx_chain_path = nil
                    current_fx_chain_relative_path = nil
                    current_fx_chain_name = nil
                    screenshot_search_results = {}
                    ClearScreenshotCache()
                else
                    r.ShowMessageBox("Could not delete FX Chain", "Error", 0)
                end
            end
        end
    end
    r.ImGui_PopStyleColor(ctx, 2)
    if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Delete this FX Chain") end

    r.ImGui_Dummy(ctx, 0, 8)
    return r.ImGui_GetCursorPosY(ctx) - start_y
end

function ShowChainDividerContextMenu(popup_id, fx)
    if r.ImGui_BeginPopup(ctx, popup_id) then
        local chain_rel = fx.chain_relative_path
        local chain_abs = fx.chain_file_path
        local chain_name = fx.chain_name or fx.label

        if r.ImGui_MenuItem(ctx, "Add to selected track(s)") then
            if chain_rel then
                local selected_track_count = r.CountSelectedTracks(0)
                if selected_track_count > 0 then
                    for t = 0, selected_track_count - 1 do
                        local track = r.GetSelectedTrack(0, t)
                        if track and r.ValidatePtr(track, "MediaTrack*") then
                            AddFXToTrack(track, chain_rel)
                        end
                    end
                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                else
                    r.ShowMessageBox("No tracks selected.", "Add FX Chain", 0)
                end
            end
        end

        if r.ImGui_MenuItem(ctx, "Replace selected track(s) FX") then
            if chain_rel then
                local selected_track_count = r.CountSelectedTracks(0)
                if selected_track_count > 0 then
                    for t = 0, selected_track_count - 1 do
                        local track = r.GetSelectedTrack(0, t)
                        if track and r.ValidatePtr(track, "MediaTrack*") then
                            local fx_count = r.TrackFX_GetCount(track)
                            for j = fx_count - 1, 0, -1 do r.TrackFX_Delete(track, j) end
                            AddFXToTrack(track, chain_rel)
                        end
                    end
                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                else
                    r.ShowMessageBox("No tracks selected.", "Replace FX", 0)
                end
            end
        end

        if config.show_chain_builder then
            if r.ImGui_MenuItem(ctx, "Add to FX Chain Builder") then
                if chain_abs then
                    local fx_list = ParseFxChainFile(chain_abs)
                    if fx_list then
                        for _, pname in ipairs(fx_list) do
                            table.insert(chain_builder_plugins, pname)
                            chain_builder_chunks[#chain_builder_plugins] = false
                        end
                        config.chain_builder_plugins = chain_builder_plugins
                        SaveConfig()
                    end
                end
            end
        end

        r.ImGui_Separator(ctx)

        if r.ImGui_MenuItem(ctx, "Rename") then
            if chain_abs and chain_name then
                local retval, new_name = r.GetUserInputs("Rename FX Chain", 1, "New name:", chain_name)
                if retval then
                    local dir_part = chain_abs:match("^(.*)[/\\]")
                    local new_path = dir_part .. os_separator .. new_name .. ".RfxChain"
                    if os.rename(chain_abs, new_path) then
                        FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                        if fx_chain_cache then fx_chain_cache[chain_abs] = nil end
                        ShowAllFxChainsInScreenshotWindow()
                    else
                        r.ShowMessageBox("Could not rename FX Chain", "Error", 0)
                    end
                end
            end
        end

        if r.ImGui_MenuItem(ctx, "Delete") then
            if chain_abs then
                local confirm = r.ShowMessageBox("Delete '" .. (chain_name or "") .. "'?", "Delete FX Chain", 4)
                if confirm == 6 then
                    if os.remove(chain_abs) then
                        FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                        if fx_chain_cache then fx_chain_cache[chain_abs] = nil end
                        ShowAllFxChainsInScreenshotWindow()
                    else
                        r.ShowMessageBox("Could not delete FX Chain", "Error", 0)
                    end
                end
            end
        end

        r.ImGui_EndPopup(ctx)
    end
end

function ShowAllFxChainsInScreenshotWindow()
    local tree = GetFxChainsTree()
    local all_chains = CollectAllFxChainsFlat(tree)
    if #all_chains == 0 then return end
    
    screenshot_search_results = {}
    selected_folder = nil
    browser_panel_selected = nil
    ClearScreenshotCache()
    if fx_chain_cache then
        for k in pairs(fx_chain_cache) do fx_chain_cache[k] = nil end
    end
    current_fx_chain_path = nil
    current_fx_chain_relative_path = nil
    current_fx_chain_name = nil
    
    local extension = ".RfxChain"
    local fx_chains_root = ResolveFxChainsRoot()
    
    for idx, chain_info in ipairs(all_chains) do
        local chain_file_path = fx_chains_root .. chain_info.path .. os_separator .. chain_info.name .. extension
        local fx_list = ParseFxChainFile(chain_file_path)
        
        if fx_list and #fx_list > 0 then
            local relative_path = chain_info.path .. os_separator .. chain_info.name .. extension
            table.insert(screenshot_search_results, {
                is_separator = true,
                kind = "chain_divider",
                label = chain_info.name,
                chain_file_path = chain_file_path,
                chain_relative_path = relative_path,
                chain_name = chain_info.name
            })
            
            for _, fx_name in ipairs(fx_list) do
                table.insert(screenshot_search_results, {
                    name = fx_name,
                    is_fx_chain_item = true,
                    chain_path = chain_file_path,
                    chain_name = chain_info.name
                })
            end
            
            local safe_name
            for _, fx_name in ipairs(fx_list) do
                safe_name = fx_name:gsub("[^%w%s-]", "_")
                local screenshot_file = screenshot_path .. safe_name .. ".png"
                if r.file_exists(screenshot_file) then
                    local rel = screenshot_file:gsub(screenshot_path, "")
                    local unique_key = rel .. "_" .. fx_name
                    if not texture_load_queue[unique_key] and not search_texture_cache[unique_key] then
                        texture_load_queue[unique_key] = {
                            file = screenshot_file,
                            queued_at = r.time_precise(),
                            plugin = fx_name
                        }
                    end
                end
            end
        end
    end
    
    show_screenshot_window = true
    screenshot_window_interactive = true
end

function GetCurrentProjectFX()
    local fx_list = {}
    local track_count = reaper.CountTracks(0)
    
    -- MASTER TRACK EERST
    local master_track = reaper.GetMasterTrack(0)
    local master_fx_count = reaper.TrackFX_GetCount(master_track)
    for j = 0, master_fx_count - 1 do
        local retval, fx_name = reaper.TrackFX_GetFXName(master_track, j, "")
        if retval then
            table.insert(fx_list, {
                fx_name = fx_name,
                track_name = "Master Track",
                track_number = 0,  -- Master track identifier
                track_color = 0x404040FF,
                fx_index = j,
                is_master = true,  -- Nieuwe flag voor master track
                unique_id = "master_" .. j
            })
        end
    end
    
    -- NORMALE TRACKS
    for i = 0, track_count - 1 do
        local track = reaper.GetTrack(0, i)
        local _, track_name = reaper.GetTrackName(track)
        local track_number = reaper.GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER")
        local track_color = reaper.GetTrackColor(track)
        local fx_count = reaper.TrackFX_GetCount(track)
        for j = 0, fx_count - 1 do
            local retval, fx_name = reaper.TrackFX_GetFXName(track, j, "")
            if retval then
                table.insert(fx_list, {
                    fx_name = fx_name,
                    track_name = track_name,
                    track_number = track_number,
                    track_color = track_color,
                    fx_index = j,  
                    is_master = false,
                    unique_id = track_number .. "_" .. j
                })
            end
        end
    end
    return fx_list
end

function AddPluginToSelectedTracks(plugin_name)
    -- Check if Master track is selected
    local master_track = r.GetMasterTrack(0)
    if master_track and r.IsTrackSelected(master_track) then
        local fx_index = AddFXToTrack(master_track, plugin_name)
        r.TrackFX_Show(master_track, fx_index, 2)
    end
    
    -- Add to regular selected tracks
    local track_count = r.CountSelectedTracks(0)
    for i = 0, track_count - 1 do
        local track = r.GetSelectedTrack(0, i)
        local fx_index = AddFXToTrack(track, plugin_name)
        r.TrackFX_Show(track, fx_index, 2)  
    end
end

function AddPluginToAllTracks(plugin_name)
    -- Add to Master track if selected
    local master_track = r.GetMasterTrack(0)
    if master_track and r.IsTrackSelected(master_track) then
        local fx_index = AddFXToTrack(master_track, plugin_name)
        r.TrackFX_Show(master_track, fx_index, 2)
    end
    
    -- Add to all regular tracks
    local track_count = r.CountTracks(0)
    for i = 0, track_count - 1 do
        local track = r.GetTrack(0, i)
        local fx_index = AddFXToTrack(track, plugin_name)
        r.TrackFX_Show(track, fx_index, 2)  
    end
end

function AddToFavorites(plugin_name)
    if favorite_set[plugin_name] then return end
    table.insert(favorite_plugins, plugin_name)
    favorite_set[plugin_name] = true
    SaveFavorites()
    if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
end

function RemoveFromFavorites(plugin_name)
    for i, fav in ipairs(favorite_plugins) do
        if fav == plugin_name then
            table.remove(favorite_plugins, i)
            favorite_set[plugin_name] = nil
            SaveFavorites()
            if RefreshCurrentScreenshotView then RefreshCurrentScreenshotView() end
            break
        end
    end
end

function GetFileSize(file_path)
    local file = io.open(file_path, "rb")
    if file then
        local size = file:seek("end")
        file:close()
        return size
    end
    return 0
end

function GetProjectPreviewPath(project_path)
    if not project_path then return nil end
    local dir = project_path:match("(.*[/\\])") or ""
    local proj_name = project_path:match("([^/\\]+)%.rpp$")
    if dir ~= "" and proj_name then
        local prefix = proj_name .. ".tkprev."
        local allowed_ext = { wav = true, mp3 = true, flac = true, ogg = true }
        local override = GetActivePreviewFilename(project_path)
        if override and override:sub(1, #prefix) == prefix then
            local ov_full = dir .. override
            if r.file_exists(ov_full) then return ov_full end
        end
        local newest, newest_score = nil, -1
        local i = 0
        repeat
            local f = r.EnumerateFiles(dir, i)
            local ext = f and f:match("%.([^%.]+)$")
            if f and f:sub(1, #prefix) == prefix and ext and allowed_ext[ext:lower()] then
                local full = dir .. f
                local stamp_part = f:sub(#prefix + 1, -(#ext + 2))
                local ts = tonumber(stamp_part:match("^(%d+)")) or 0
                local mtime = 0
                if r.JS_File_Stat then
                    local rv, _, _, mt = r.JS_File_Stat(full)
                    if rv then mtime = tonumber(mt) or 0 end
                end
                local score = ts * 1e9 + mtime
                if score >= newest_score then
                    newest = full
                    newest_score = score
                end
            end
            i = i + 1
        until not f
        if newest then return newest end
    end
    local prox = project_path .. "-PROX"
    if r.file_exists(prox) then return prox end
    return nil
end

function ReleaseCurrentPreview()
    if current_preview and r.CF_Preview_Stop then
        pcall(r.CF_Preview_Stop, current_preview)
    end
    if current_source and r.PCM_Source_Destroy then
        pcall(r.PCM_Source_Destroy, current_source)
    end
    current_preview = nil
    current_source = nil
    collectgarbage("collect")
end

local function TryDeleteFile(fp)
    if not r.file_exists(fp) then return true end
    return os.remove(fp) ~= nil
end

function DeletePreviewFile(project_path, full_path)
    if not full_path then return false end
    local norm_full = full_path:gsub("\\", "/"):lower()
    local current_full = nil
    if current_source then
        local ok, fn = pcall(r.GetMediaSourceFileName, current_source, "")
        if ok and fn then current_full = fn:gsub("\\", "/"):lower() end
    end
    if current_full == norm_full then
        if r.CF_Preview_StopAll then r.CF_Preview_StopAll() end
        ReleaseCurrentPreview()
        collectgarbage("collect")
        collectgarbage("collect")
    end
    local ok = TryDeleteFile(full_path)
    if ok then
        local peaks = full_path .. ".reapeaks"
        if r.file_exists(peaks) then TryDeleteFile(peaks) end
    end
    if project_path then
        local basename = full_path:match("[^/\\]+$") or ""
        if GetActivePreviewFilename(project_path) == basename then
            ClearActivePreviewFilename(project_path)
        end
        if type(filtered_projects) == "table" then
            for _, p in ipairs(filtered_projects) do
                if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
            end
        end
        if type(projects) == "table" then
            for _, p in ipairs(projects) do
                if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
            end
        end
        if current_project_info and current_project_info.path == project_path then
            local newest = GetProjectPreviewPath(project_path)
            current_project_info.has_preview = newest ~= nil
        end
    end
    return ok
end

function FindOpenProjectByPath(project_path)
    if not project_path then return nil end
    local norm_target = project_path:gsub("\\", "/"):lower()
    local idx = 0
    repeat
        local proj, projfn = r.EnumProjects(idx)
        if proj and projfn and projfn ~= "" then
            local norm = projfn:gsub("\\", "/"):lower()
            if norm == norm_target then return proj end
        end
        idx = idx + 1
    until not proj
    return nil
end

function DoMakeProjectPreview(project_path, mode, range_s, range_e)
    local was_open = FindOpenProjectByPath(project_path) ~= nil

    if mode == "timesel" then
        if not was_open then
            r.ShowMessageBox(
                "Open the project first and set a time selection before making a time-selection preview.",
                "Make Preview", 0)
            return
        end
        local proj_check = FindOpenProjectByPath(project_path)
        local s_, e_ = r.GetSet_LoopTimeRange2(proj_check, false, false, 0, 0, false)
        if not s_ or not e_ or e_ <= s_ then
            r.ShowMessageBox(
                "No time selection set in the project. Set a time selection first.",
                "Make Preview", 0)
            return
        end
        range_s, range_e = s_, e_
    end

    if not was_open then
        r.Main_OnCommand(41929, 0)
        r.Main_openProject(project_path)
    end

    if mode == "full" then
        local proj = FindOpenProjectByPath(project_path)
        if proj then r.SelectProjectInstance(proj) end
        r.Main_OnCommand(42332, 0)
        if not was_open then r.Main_OnCommand(40860, 0) end
        return
    end

    local proj = FindOpenProjectByPath(project_path)
    if not proj then
        if not was_open then r.Main_OnCommand(40860, 0) end
        return
    end
    r.SelectProjectInstance(proj)

    if not range_s or not range_e or range_e <= range_s then
        if not was_open then r.Main_OnCommand(40860, 0) end
        return
    end

    r.GetSet_LoopTimeRange2(proj, true, false, range_s, range_e, false)

    if r.CF_Preview_StopAll then r.CF_Preview_StopAll() end
    ReleaseCurrentPreview()
    collectgarbage("collect")

    local proj_dir = project_path:match("(.*[/\\])") or ""
    local proj_name = project_path:match("([^/\\]+)%.rpp$") or "preview"
    local stamp = tostring(os.time()) .. "_" .. tostring(math.random(1000, 9999))
    local pattern = proj_name .. ".tkprev." .. stamp
    local out_path = proj_dir .. pattern .. ".wav"

    local old_bounds = r.GetSetProjectInfo(proj, 'RENDER_BOUNDSFLAG', 0, false)
    local old_settings = r.GetSetProjectInfo(proj, 'RENDER_SETTINGS', 0, false)
    local _, old_file = r.GetSetProjectInfo_String(proj, 'RENDER_FILE', '', false)
    local _, old_pattern = r.GetSetProjectInfo_String(proj, 'RENDER_PATTERN', '', false)

    r.GetSetProjectInfo(proj, 'RENDER_BOUNDSFLAG', 2, true)
    r.GetSetProjectInfo(proj, 'RENDER_SETTINGS', 0, true)
    r.GetSetProjectInfo_String(proj, 'RENDER_FILE', proj_dir, true)
    r.GetSetProjectInfo_String(proj, 'RENDER_PATTERN', pattern, true)

    r.Main_OnCommand(42230, 0)

    r.GetSetProjectInfo(proj, 'RENDER_BOUNDSFLAG', old_bounds, true)
    r.GetSetProjectInfo(proj, 'RENDER_SETTINGS', old_settings, true)
    r.GetSetProjectInfo_String(proj, 'RENDER_FILE', old_file, true)
    r.GetSetProjectInfo_String(proj, 'RENDER_PATTERN', old_pattern, true)

    if type(filtered_projects) == "table" then
        for _, p in ipairs(filtered_projects) do
            if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
        end
    end
    if type(projects) == "table" then
        for _, p in ipairs(projects) do
            if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
        end
    end

    local newest_path = out_path
    if not r.file_exists(newest_path) then
        newest_path = GetProjectPreviewPath(project_path) or out_path
    end

    ClearActivePreviewFilename(project_path)

    if selected_project and selected_project.path == project_path then
        if r.file_exists(newest_path) then
            ReleaseCurrentPreview()
            local source = r.PCM_Source_CreateFromFile(newest_path)
            if source then
                current_preview = r.CF_CreatePreview(source)
                r.CF_Preview_SetValue(current_preview, "D_VOLUME", preview_volume or 1.0)
                current_source = source
                if current_project_info then
                    current_project_info.has_preview = true
                    current_project_info.length = r.GetMediaSourceLength(source) or 0
                end
            end
        end
    end

    if not was_open then
        r.Main_OnCommand(40860, 0)
    end
end

function DoMakeProjectPreviewCustom(project_path)
    if not project_path then return end
    if not r.JS_Dialog_BrowseForOpenFiles then
        r.ShowMessageBox("js_ReaScriptAPI required for file dialog.", "Make Preview", 0)
        return
    end
    local rv, file = r.JS_Dialog_BrowseForOpenFiles(
        "Choose Audio File for Preview", "", "",
        "Audio files\0*.wav;*.mp3;*.flac;*.ogg;*.aif;*.aiff\0All files\0*.*\0", false)
    if not rv or not file or file == "" then return end
    local ext = file:match("%.([^%.\\/]+)$")
    if not ext then
        r.ShowMessageBox("Could not determine file extension.", "Make Preview", 0)
        return
    end
    ext = ext:lower()
    local allowed = { wav = true, mp3 = true, flac = true, ogg = true, aif = true, aiff = true }
    if not allowed[ext] then
        r.ShowMessageBox("Unsupported audio format: " .. ext, "Make Preview", 0)
        return
    end
    local proj_dir = project_path:match("(.*[/\\])") or ""
    local proj_name = project_path:match("([^/\\]+)%.rpp$") or "preview"
    local stamp = tostring(os.time()) .. "_" .. tostring(math.random(1000, 9999))
    local out_path = proj_dir .. proj_name .. ".tkprev." .. stamp .. "." .. ext

    local fin = io.open(file, "rb")
    if not fin then
        r.ShowMessageBox("Could not read source file.", "Make Preview", 0)
        return
    end
    local fout = io.open(out_path, "wb")
    if not fout then
        fin:close()
        r.ShowMessageBox("Could not write to project folder.", "Make Preview", 0)
        return
    end
    while true do
        local chunk = fin:read(1024 * 1024)
        if not chunk then break end
        fout:write(chunk)
    end
    fin:close()
    fout:close()

    if r.CF_Preview_StopAll then r.CF_Preview_StopAll() end
    ReleaseCurrentPreview()
    collectgarbage("collect")

    ClearActivePreviewFilename(project_path)

    if type(filtered_projects) == "table" then
        for _, p in ipairs(filtered_projects) do
            if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
        end
    end
    if type(projects) == "table" then
        for _, p in ipairs(projects) do
            if p.path == project_path then p.cached_length = nil; p.cached_has_preview = nil; p.cached_preview_path = nil end
        end
    end

    if selected_project and selected_project.path == project_path then
        if r.file_exists(out_path) then
            local source = r.PCM_Source_CreateFromFile(out_path)
            if source then
                current_preview = r.CF_CreatePreview(source)
                r.CF_Preview_SetValue(current_preview, "D_VOLUME", preview_volume or 1.0)
                current_source = source
                if current_project_info then
                    current_project_info.has_preview = true
                    current_project_info.length = r.GetMediaSourceLength(source) or 0
                end
            end
        end
    end
end

function GetProjectCoverPath(project_path)
    local safe_name = project_path:match("([^/\\]+)%.rpp$") or ""
    safe_name = safe_name:gsub("[^%w%s-]", "_")
    local png = project_covers_path .. safe_name .. ".png"
    if r.file_exists(png) then return png end
    local jpg = project_covers_path .. safe_name .. ".jpg"
    if r.file_exists(jpg) then return jpg end

    local proj_dir = project_path:match("(.*[/\\])") or ""
    if proj_dir ~= "" then
        local raw_name = project_path:match("([^/\\]+)%.rpp$") or ""
        local fallbacks = {
            raw_name .. ".png", raw_name .. ".jpg", raw_name .. ".jpeg",
            "cover.png", "cover.jpg", "cover.jpeg",
            "folder.png", "folder.jpg", "folder.jpeg",
            "front.png",  "front.jpg",  "front.jpeg",
            "artwork.png", "artwork.jpg", "artwork.jpeg",
        }
        for _, fname in ipairs(fallbacks) do
            local p = proj_dir .. fname
            if r.file_exists(p) then return p end
        end
        local i = 0
        repeat
            local f = r.EnumerateFiles(proj_dir, i)
            if f then
                local low = f:lower()
                if low:match("%.png$") or low:match("%.jpg$") or low:match("%.jpeg$") then
                    return proj_dir .. f
                end
            end
            i = i + 1
        until not f
    end

    return nil
end

function LoadProjectCover(project_path)
    if project_cover_loaded_for == project_path then return end
    project_cover_loaded_for = project_path
    if project_cover_texture and r.ImGui_ValidatePtr(project_cover_texture, 'ImGui_Image*') then
        r.ImGui_Detach(ctx, project_cover_texture)
    end
    project_cover_texture = nil
    local cover = GetProjectCoverPath(project_path)
    if cover then
        project_cover_texture = r.ImGui_CreateImage(cover)
        if project_cover_texture then
            r.ImGui_Attach(ctx, project_cover_texture)
        end
    end
end

function SetProjectCover(project_path)
    local rv, file = r.JS_Dialog_BrowseForOpenFiles("Choose Cover Image", "", "", "Image files\0*.png;*.jpg;*.jpeg\0All files\0*.*\0", false)
    if rv == 1 and file and file ~= "" then
        local safe_name = project_path:match("([^/\\]+)%.rpp$") or ""
        safe_name = safe_name:gsub("[^%w%s-]", "_")
        local ext = file:match("%.(%w+)$")
        if not ext then return end
        ext = ext:lower()
        if ext ~= "png" and ext ~= "jpg" and ext ~= "jpeg" then
            r.MB("Alleen PNG en JPG afbeeldingen worden ondersteund.", "Ongeldig bestandstype", 0)
            return
        end
        local dest_ext = (ext == "jpg" or ext == "jpeg") and ".jpg" or ".png"
        local dest = project_covers_path .. safe_name .. dest_ext
        local src = io.open(file, "rb")
        if src then
            local data = src:read("*a")
            src:close()
            local dst = io.open(dest, "wb")
            if dst then
                dst:write(data)
                dst:close()
            end
        end
        project_cover_loaded_for = nil
        LoadProjectCover(project_path)
    end
end

function CountProjectFolderFiles(project_path)
    local folder = project_path:match("(.*[/\\])")
    local count = 0
    if folder then
        local handle = r.EnumerateFiles(folder, 0)
        while handle do
            count = count + 1
            handle = r.EnumerateFiles(folder, count)
        end
    end
    return count - 1
end

function FormatFileSize(bytes)
    if not bytes or bytes <= 0 then return "-" end
    if bytes < 1024 then return string.format("%d B", bytes) end
    if bytes < 1048576 then return string.format("%.1f KB", bytes / 1024) end
    return string.format("%.1f MB", bytes / 1048576)
end

function FormatDuration(seconds)
    if not seconds or seconds <= 0 then return "-" end
    local m = math.floor(seconds / 60)
    local s = seconds % 60
    return string.format("%d:%02d", m, math.floor(s))
end

