local rpp_header_cache = {}

function ParseRPPHeader(rpp_path)
    if rpp_header_cache[rpp_path] then return rpp_header_cache[rpp_path] end
    local f = io.open(rpp_path, "r")
    if not f then return nil end
    local bpm, samplerate, track_count = nil, nil, 0
    local lines_read = 0
    for line in f:lines() do
        lines_read = lines_read + 1
        if lines_read > 5000 then break end
        if not bpm then
            local b = line:match("^%s*TEMPO%s+([%d%.]+)")
            if b then bpm = tonumber(b) end
        end
        if not samplerate then
            local sr = line:match("^%s*SAMPLERATE%s+(%d+)")
            if sr then samplerate = tonumber(sr) end
        end
        if line:match("^%s*<TRACK") then
            track_count = track_count + 1
        end
    end
    f:close()
    local info = { bpm = bpm, samplerate = samplerate, track_count = track_count }
    rpp_header_cache[rpp_path] = info
    return info
end

function IsSendTrack(track)
    local folder_name = config.sends_folder_name or "SEND TRACK"
    local parent = r.GetParentTrack(track)
    if parent then
        local _, name = r.GetTrackName(parent)
        return name == folder_name
    end
    local _, name = r.GetTrackName(track)
    return name == folder_name
end

local hub_open_state = {}
local routing_last_selected_guid = nil
local routing_scroll_pending = false
local routing_expand_all_pending = false
local routing_collapse_all_pending = false

function BuildVisibleRoutingTracks()
    local track_count = r.CountTracks(0)
    local filter = (config.routing_filter_text or ""):lower()
    local only_routed = config.routing_only_routed
    local only_selected = config.routing_only_selected
    local group_by_folder = config.routing_group_by_folder

    local related = nil
    if only_selected and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
        related = { [TRACK] = true }
        local ns = r.GetTrackNumSends(TRACK, 0)
        for i = 0, ns - 1 do
            local d = r.GetTrackSendInfo_Value(TRACK, 0, i, "P_DESTTRACK")
            if d then related[d] = true end
        end
        local nr = r.GetTrackNumSends(TRACK, -1)
        for i = 0, nr - 1 do
            local s = r.GetTrackSendInfo_Value(TRACK, -1, i, "P_SRCTRACK")
            if s then related[s] = true end
        end
    end

    local list = {}
    local filter_partners = nil
    if filter ~= "" and config.routing_include_partners then
        filter_partners = {}
        for i = 0, track_count - 1 do
            local tr = r.GetTrack(0, i)
            local _, name = r.GetTrackName(tr)
            if name:lower():find(filter, 1, true) then
                filter_partners[tr] = true
                local ns = r.GetTrackNumSends(tr, 0)
                for k = 0, ns - 1 do
                    local d = r.GetTrackSendInfo_Value(tr, 0, k, "P_DESTTRACK")
                    if d then filter_partners[d] = true end
                end
                local nr = r.GetTrackNumSends(tr, -1)
                for k = 0, nr - 1 do
                    local s = r.GetTrackSendInfo_Value(tr, -1, k, "P_SRCTRACK")
                    if s then filter_partners[s] = true end
                end
            end
        end
    end
    for i = 0, track_count - 1 do
        local tr = r.GetTrack(0, i)
        local _, name = r.GetTrackName(tr)
        local include = true
        if filter ~= "" then
            if filter_partners then
                if not filter_partners[tr] then include = false end
            else
                if not name:lower():find(filter, 1, true) then include = false end
            end
        end
        if include and only_routed then
            if r.GetTrackNumSends(tr, 0) == 0 and r.GetTrackNumSends(tr, -1) == 0 then
                include = false
            end
        end
        if include and only_selected then
            if not (related and related[tr]) then include = false end
        end
        if include then
            local folder_label = ""
            local parent = r.GetParentTrack(tr)
            if parent then
                local _, pname = r.GetTrackName(parent)
                folder_label = pname or ""
            end
            list[#list + 1] = { idx = i, track = tr, name = name, folder = folder_label }
        end
    end

    if group_by_folder then
        table.sort(list, function(a, b)
            if a.folder == b.folder then return a.idx < b.idx end
            if a.folder == "" then return false end
            if b.folder == "" then return true end
            return a.folder:lower() < b.folder:lower()
        end)
    end
    return list
end

function DrawRoutingFilterBar(is_matrix)
    local function RoutingTextButton(id, label, w)
        local h = r.ImGui_GetFrameHeight(ctx)
        local clicked = r.ImGui_InvisibleButton(ctx, id, w, h)
        local dl = r.ImGui_GetWindowDrawList(ctx)
        local x1, y1 = r.ImGui_GetItemRectMin(ctx)
        local _, y2 = r.ImGui_GetItemRectMax(ctx)
        local hovered = r.ImGui_IsItemHovered(ctx)
        local active = r.ImGui_IsItemActive(ctx)
        local col = 0xD0D0D0FF
        if hovered then col = 0x7AA2F7FF end
        if active then col = 0x9CB6F9FF end
        local th = r.ImGui_GetTextLineHeight(ctx)
        r.ImGui_DrawList_AddText(dl, x1 + 4, y1 + ((y2 - y1 - th) * 0.5), col, label)
        return clicked
    end

    r.ImGui_PushItemWidth(ctx, 160)
    local ch_f, v_f = r.ImGui_InputTextWithHint(ctx, "##routing_filter", "Filter tracks...", config.routing_filter_text or "")
    if ch_f then config.routing_filter_text = v_f end
    if r.ImGui_IsItemDeactivatedAfterEdit and r.ImGui_IsItemDeactivatedAfterEdit(ctx) then SaveConfig() end
    r.ImGui_PopItemWidth(ctx)
    if not is_matrix and config.routing_view_mode == "patchbay" then
        r.ImGui_SameLine(ctx)
        r.ImGui_SetNextItemWidth(ctx, 130)
        local ch_nw, v_nw = r.ImGui_SliderInt(ctx, "##patchbay_node_width_filter", config.patchbay_node_width or 180, 80, 400)
        if ch_nw then
            config.patchbay_node_width = v_nw
            SaveConfig()
        end
        r.ImGui_SameLine(ctx)
        if RoutingTextButton("##patchbay_zoom_out", "-", 16) and _G.PatchbayZoomStep then
            _G.PatchbayZoomStep(1 / 1.2)
        end
        r.ImGui_SameLine(ctx)
        local zoom_label = _G.PatchbayZoomPercent and string.format("%d%%", _G.PatchbayZoomPercent()) or "100%"
        r.ImGui_Text(ctx, zoom_label)
        r.ImGui_SameLine(ctx)
        if RoutingTextButton("##patchbay_zoom_in", "+", 16) and _G.PatchbayZoomStep then
            _G.PatchbayZoomStep(1.2)
        end
        r.ImGui_SameLine(ctx)
        if RoutingTextButton("##patchbay_zoom_reset", "1:1", 28) and _G.PatchbayZoomReset then
            _G.PatchbayZoomReset()
        end
        r.ImGui_SameLine(ctx)
        if RoutingTextButton("##patchbay_zoom_fit", "Fit", 22) and _G.PatchbayZoomFit then
            _G.PatchbayZoomFit()
        end
        r.ImGui_SameLine(ctx)
        local lock_mode = (config and config.patchbay_lock_mode) or "none"
        local lock_text = "Lock: Off"
        local lock_col = 0x9AA0A6FF
        if lock_mode == "layout" then
            lock_text = "Lock: Layout"
            lock_col = 0xE3C06FFF
        elseif lock_mode == "all" then
            lock_text = "Lock: All"
            lock_col = 0xE36D6DFF
        end
        r.ImGui_TextColored(ctx, lock_col, lock_text)
    end
    if is_matrix then
        r.ImGui_SameLine(ctx)
        local ch1, v1 = r.ImGui_Checkbox(ctx, "Routed", config.routing_only_routed and true or false)
        if ch1 then config.routing_only_routed = v1; SaveConfig() end
        r.ImGui_SameLine(ctx)
        local chp, vp = r.ImGui_Checkbox(ctx, "Partners", config.routing_include_partners and true or false)
        if chp then config.routing_include_partners = vp; SaveConfig() end
        if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Include routing partners of filtered tracks") end
        r.ImGui_SameLine(ctx)
        local ch2, v2 = r.ImGui_Checkbox(ctx, "Focus selected", config.routing_only_selected and true or false)
        if ch2 then config.routing_only_selected = v2; SaveConfig() end
    elseif config.routing_view_mode ~= "patchbay" then
        r.ImGui_SameLine(ctx)
        local ch2, v2 = r.ImGui_Checkbox(ctx, "Focus selected", config.routing_only_selected and true or false)
        if ch2 then config.routing_only_selected = v2; SaveConfig() end
    end
    if not is_matrix and config.routing_view_mode == "hubs" then
        r.ImGui_SameLine(ctx)
        local dir_opts = { "All", "In", "Out" }
        local cur_dir = config.routing_direction or "All"
        r.ImGui_PushItemWidth(ctx, 60)
        if r.ImGui_BeginCombo(ctx, "##routing_direction", cur_dir) then
            for di = 1, #dir_opts do
                if r.ImGui_Selectable(ctx, dir_opts[di], cur_dir == dir_opts[di]) then
                    config.routing_direction = dir_opts[di]
                    SaveConfig()
                end
            end
            r.ImGui_EndCombo(ctx)
        end
        r.ImGui_PopItemWidth(ctx)
        if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Show incoming, outgoing, or both") end
        if config.routing_view_mode == "hubs" then
            r.ImGui_SameLine(ctx)
            local ch_all, v_all = r.ImGui_Checkbox(ctx, "All tracks", config.routing_hubs_show_all_tracks and true or false)
            if ch_all then config.routing_hubs_show_all_tracks = v_all; SaveConfig() end
            if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Show tracks without sends/receives as empty hubs") end
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "\xE2\x96\xBC##expand_all") then
            routing_expand_all_pending = true
        end
        if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Expand all hubs") end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "\xE2\x96\xB6##collapse_all") then
            routing_collapse_all_pending = true
        end
        if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Collapse all hubs") end
    end
    if is_matrix then
        r.ImGui_SameLine(ctx)
        local ch3, v3 = r.ImGui_Checkbox(ctx, "By folder", config.routing_group_by_folder and true or false)
        if ch3 then config.routing_group_by_folder = v3; SaveConfig() end
    end
    r.ImGui_Separator(ctx)
end

function ShowRoutingMatrix()
    r.ImGui_Separator(ctx)
    DrawRoutingFilterBar(true)
    r.ImGui_Dummy(ctx, 0, 8)

    local visible = BuildVisibleRoutingTracks()
    local n = #visible
    if n == 0 then
        r.ImGui_TextDisabled(ctx, "No tracks match filter.")
        return
    end

    local max_name_width = 0
    for vi = 1, n do
        local v = visible[vi]
        local tw = r.ImGui_CalcTextSize(ctx, (v.idx + 1) .. ": " .. v.name)
        if tw > max_name_width then max_name_width = tw end
    end

    local cell_size = 20
    local header_height = 20
    local left_margin = 20
    local legend_width = max_name_width + 20
    local matrix_width = (n + 1) * cell_size + left_margin + legend_width
    local matrix_height = (n + 1) * cell_size + header_height + 10

    local routing_open = r.ImGui_BeginChild(ctx, "RoutingMatrix", matrix_width, matrix_height)
    if routing_open then
        local group_by_folder = config.routing_group_by_folder
        local draw_list = r.ImGui_GetWindowDrawList(ctx)
        local origin_x, origin_y = r.ImGui_GetCursorScreenPos(ctx)

        if group_by_folder then
            local folder_palette = { 0x4444FF22, 0xFF884422, 0x44CC8822, 0xCC44CC22, 0xCCAA4422, 0x44AACC22 }
            local fmap = {}
            local fcount = 0
            for vi = 1, n do
                local fkey = visible[vi].folder ~= "" and visible[vi].folder or "__none__"
                if not fmap[fkey] then
                    fcount = fcount + 1
                    fmap[fkey] = folder_palette[((fcount - 1) % #folder_palette) + 1]
                end
            end
            for vi = 1, n do
                local fkey = visible[vi].folder ~= "" and visible[vi].folder or "__none__"
                local color = fmap[fkey]
                if color then
                    local row_y = origin_y + vi * cell_size + header_height
                    r.ImGui_DrawList_AddRectFilled(draw_list, origin_x, row_y, origin_x + matrix_width, row_y + cell_size, color)
                    local col_x = origin_x + vi * cell_size + left_margin
                    r.ImGui_DrawList_AddRectFilled(draw_list, col_x, origin_y, col_x + cell_size, origin_y + matrix_width, color)
                end
            end
        end

        for vi = 1, n do
            local x = vi * cell_size + left_margin
            r.ImGui_SetCursorPos(ctx, x + 5, 0)
            r.ImGui_Text(ctx, tostring(visible[vi].idx + 1))
        end
        for vi = 1, n do
            local y = vi * cell_size + header_height
            r.ImGui_SetCursorPos(ctx, 15, y + 2)
            r.ImGui_Text(ctx, tostring(visible[vi].idx + 1))
        end

        for si = 1, n do
            local src_track = visible[si].track
            for di = 1, n do
                if si ~= di then
                    local dst_track = visible[di].track
                    local x = di * cell_size + left_margin
                    local y = si * cell_size + header_height
                    r.ImGui_SetCursorPos(ctx, x, y)
                    r.ImGui_PushID(ctx, string.format("cell_%d_%d", visible[si].idx, visible[di].idx))
                    local send_idx = GetSendIndex(src_track, dst_track)
                    local has_send = send_idx >= 0
                    if has_send then
                        if IsSendTrack(dst_track) or IsSendTrack(src_track) then
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00BFFFFF)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x33CCFFFF)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x0099CCFF)
                        else
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0xFF0000FF)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xFF3333FF)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0xCC0000FF)
                        end
                        if r.ImGui_Button(ctx, "##send", cell_size - 4, cell_size - 4) then
                            r.RemoveTrackSend(src_track, 0, send_idx)
                        end
                        r.ImGui_PopStyleColor(ctx, 3)
                    else
                        if IsSendTrack(dst_track) or IsSendTrack(src_track) then
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00BFFF33)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x33CCFF66)
                        else
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x333333FF)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x666666FF)
                        end
                        if r.ImGui_Button(ctx, "##empty", cell_size - 4, cell_size - 4) then
                            r.CreateTrackSend(src_track, dst_track)
                        end
                        r.ImGui_PopStyleColor(ctx, 2)
                    end
                    r.ImGui_PopID(ctx)
                end
            end
        end

        local legend_x = (n + 1) * cell_size + left_margin + 20
        r.ImGui_SetCursorPos(ctx, legend_x, 0)
        r.ImGui_Text(ctx, "Track Legend:")
        for vi = 1, n do
            r.ImGui_SetCursorPos(ctx, legend_x, 20 + ((vi - 1) * 20))
            r.ImGui_Text(ctx, string.format("%d: %s", visible[vi].idx + 1, visible[vi].name))
        end
    end
    r.ImGui_EndChild(ctx)
end

function ShowRoutingHubs()
    r.ImGui_Separator(ctx)
    DrawRoutingFilterBar(false)

    local filter = (config.routing_filter_text or ""):lower()
    local only_selected = config.routing_only_selected
    local show_all_tracks = config.routing_hubs_show_all_tracks == true
    local track_count = r.CountTracks(0)

    local cur_sel_guid = (TRACK and r.ValidatePtr(TRACK, "MediaTrack*")) and r.GetTrackGUID(TRACK) or nil
    if cur_sel_guid ~= routing_last_selected_guid then
        routing_last_selected_guid = cur_sel_guid
        routing_scroll_pending = (cur_sel_guid ~= nil)
    end

    local hubs = {}
    for i = 0, track_count - 1 do
        local hub = r.GetTrack(0, i)
        local nrec = r.GetTrackNumSends(hub, -1)
        local nsnd = r.GetTrackNumSends(hub, 0)
        if nrec > 0 or nsnd > 0 or show_all_tracks then
            local incoming = {}
            for k = 0, nrec - 1 do
                local src = r.GetTrackSendInfo_Value(hub, -1, k, "P_SRCTRACK")
                if src and r.ValidatePtr(src, "MediaTrack*") then
                    local sidx = GetSendIndex(src, hub)
                    if sidx >= 0 then
                        incoming[#incoming + 1] = { owner = src, send_idx = sidx, other = src }
                    end
                end
            end
            local outgoing = {}
            for k = 0, nsnd - 1 do
                local dst = r.GetTrackSendInfo_Value(hub, 0, k, "P_DESTTRACK")
                if dst and r.ValidatePtr(dst, "MediaTrack*") then
                    outgoing[#outgoing + 1] = { owner = hub, send_idx = k, other = dst }
                end
            end
            if #incoming > 0 or #outgoing > 0 or show_all_tracks then
                local _, hname = r.GetTrackName(hub)
                hubs[#hubs + 1] = { hub = hub, hub_idx = i, name = hname, incoming = incoming, outgoing = outgoing }
            end
        end
    end

    if #hubs == 0 then
        r.ImGui_TextDisabled(ctx, "No tracks match filter.")
        return
    end

    local function StateColors(state)
        if state == "all_on"  then return 0x3FAA3FFF, 0x55C055FF, 0x2F8F2FFF
        elseif state == "mixed" then return 0xC07A1FFF, 0xD08A2FFF, 0xA0660FFF
        else return 0x3F3F3FFF, 0x555555FF, 0x2F2F2FFF end
    end
    local function ToggleButton(label, state, tooltip, w)
        local bg, hov, act = StateColors(state)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), bg)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), hov)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), act)
        local clicked = r.ImGui_Button(ctx, label, w or 0, 0)
        r.ImGui_PopStyleColor(ctx, 3)
        if tooltip and r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, tooltip) end
        return clicked
    end
    local function PushXDelete()
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x802020FF)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xA03030FF)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x601010FF)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFFFFFF)
    end

    local BTN_M, BTN_PH, BTN_MONO, BTN_MODE, BTN_X = 30, 30, 56, 140, 26
    local BTN_RST = 38
    local SPC = 4
    local ROW_W = BTN_M + SPC + BTN_PH + SPC + BTN_MONO + SPC + BTN_MODE + SPC + BTN_X

    local function RenderSection(h, items, header_label, header_color, section_tag)
        if #items == 0 then return end
        r.ImGui_PushID(ctx, section_tag)
        r.ImGui_Dummy(ctx, 0, 2)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), header_color)
        r.ImGui_Text(ctx, string.format("%s  (%d)", header_label, #items))
        r.ImGui_PopStyleColor(ctx)

        local function GetAggregateState(param)
            local on, off = 0, 0
            for bi = 1, #items do
                local s = items[bi]
                local v = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, param)
                if v == 1 then on = on + 1 else off = off + 1 end
            end
            if on > 0 and off == 0 then return "all_on"
            elseif off > 0 and on == 0 then return "all_off"
            else return "mixed" end
        end
        local function GetAggregateMode()
            local first_mode = nil
            local mixed = false
            for bi = 1, #items do
                local s = items[bi]
                local m = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "I_SENDMODE")
                if first_mode == nil then first_mode = m
                elseif first_mode ~= m then mixed = true; break end
            end
            if mixed then return nil end
            return first_mode
        end
        local function ApplyBulk(param, value, undo_label)
            r.Undo_BeginBlock()
            r.PreventUIRefresh(1)
            for bi = 1, #items do
                local s = items[bi]
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, param, value)
            end
            r.PreventUIRefresh(-1)
            r.Undo_EndBlock(undo_label, -1)
        end

        if #items >= 2 then
        r.ImGui_PushID(ctx, "bulk_bar")
        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), SPC, 4)

        local mute_state = GetAggregateState("B_MUTE")
        if ToggleButton("M", mute_state, "Toggle mute", BTN_M) then
            ApplyBulk("B_MUTE", (mute_state == "all_on") and 0 or 1, "Bulk mute")
        end
        r.ImGui_SameLine(ctx)
        local phase_state = GetAggregateState("B_PHASE")
        if ToggleButton("\xCE\xA6", phase_state, "Toggle phase", BTN_PH) then
            ApplyBulk("B_PHASE", (phase_state == "all_on") and 0 or 1, "Bulk phase")
        end
        r.ImGui_SameLine(ctx)
        local mono_state = GetAggregateState("B_MONO")
        local mono_label = (mono_state == "all_on") and "Mono" or (mono_state == "all_off" and "Stereo" or "M/S")
        if ToggleButton(mono_label, mono_state, "Toggle mono/stereo", BTN_MONO) then
            ApplyBulk("B_MONO", (mono_state == "all_on") and 0 or 1, "Bulk mono")
        end
        r.ImGui_SameLine(ctx)
        local cur_mode = GetAggregateMode()
        local mode_names = { "Post-Fader", "Pre-Fader (Post-FX)", "Pre-FX" }
        local mode_values = { 0, 3, 1 }
        local cur_label = "mixed"
        if cur_mode then
            for k = 1, #mode_values do if mode_values[k] == cur_mode then cur_label = mode_names[k]; break end end
        end
        r.ImGui_PushItemWidth(ctx, BTN_MODE)
        if r.ImGui_BeginCombo(ctx, "##bulk_mode", cur_label) then
            for k = 1, #mode_names do
                local sel = (cur_mode == mode_values[k])
                if r.ImGui_Selectable(ctx, mode_names[k], sel) then
                    ApplyBulk("I_SENDMODE", mode_values[k], "Bulk send mode")
                end
            end
            r.ImGui_EndCombo(ctx)
        end
        r.ImGui_PopItemWidth(ctx)
        r.ImGui_SameLine(ctx)
        PushXDelete()
        if r.ImGui_Button(ctx, "\xC3\x97##bulk_del", BTN_X, 0) then
            r.ImGui_OpenPopup(ctx, "ConfirmBulkDelete")
        end
        r.ImGui_PopStyleColor(ctx, 4)
        if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Delete all in this section") end

        r.ImGui_SameLine(ctx)
        r.ImGui_Dummy(ctx, 8, 0)
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Vol\xE2\x86\x920", BTN_RST, 0) then
            ApplyBulk("D_VOL", 1.0, "Bulk reset volume")
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Pan\xE2\x86\x92C", BTN_RST, 0) then
            ApplyBulk("D_PAN", 0.0, "Bulk center pan")
        end
        r.ImGui_PopStyleVar(ctx)

        if r.ImGui_BeginPopup(ctx, "ConfirmBulkDelete") then
            r.ImGui_Text(ctx, string.format("Delete %d connection%s?", #items, #items == 1 and "" or "s"))
            r.ImGui_Separator(ctx)
            if r.ImGui_Button(ctx, "Yes, delete") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                local to_delete = {}
                for bi = 1, #items do to_delete[#to_delete + 1] = items[bi] end
                table.sort(to_delete, function(a, b)
                    if a.owner == b.owner then return a.send_idx > b.send_idx end
                    return tostring(a.owner) < tostring(b.owner)
                end)
                for di = 1, #to_delete do
                    local s = to_delete[di]
                    r.RemoveTrackSend(s.owner, 0, s.send_idx)
                end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Bulk delete connections", -1)
                r.ImGui_CloseCurrentPopup(ctx)
            end
            r.ImGui_SameLine(ctx)
            if r.ImGui_Button(ctx, "Cancel") then r.ImGui_CloseCurrentPopup(ctx) end
            r.ImGui_EndPopup(ctx)
        end
        r.ImGui_PopID(ctx)
        r.ImGui_Separator(ctx)
        end

        for si = 1, #items do
            local s = items[si]
            local _, sname = r.GetTrackName(s.other)
            r.ImGui_PushID(ctx, "row_" .. si)
            if r.ImGui_Selectable(ctx, sname, false, nil, ROW_W) then
                r.SetOnlyTrackSelected(s.other)
                if r.SetMixerScroll then r.SetMixerScroll(s.other) end
                r.UpdateArrange()
            end
            r.ImGui_PushItemWidth(ctx, ROW_W)
            local vol = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "D_VOL")
            local vol_db = vol > 0 and (20 * math.log(vol, 10)) or -150
            local ch_v, new_db = r.ImGui_SliderDouble(ctx, "##vol", vol_db, -60, 12, "%.1f dB")
            if ch_v then
                local nv = math.exp(new_db * math.log(10) / 20)
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "D_VOL", nv)
            end
            local pan = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "D_PAN")
            local ch_p, new_pan = r.ImGui_SliderDouble(ctx, "##pan", pan, -1, 1, "%.2f")
            if ch_p then
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "D_PAN", new_pan)
            end
            r.ImGui_PopItemWidth(ctx)

            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), SPC, 4)
            local mute = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_MUTE") == 1
            if ToggleButton("M", mute and "all_on" or "all_off", "Mute", BTN_M) then
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_MUTE", mute and 0 or 1)
            end
            r.ImGui_SameLine(ctx)
            local phase = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_PHASE") == 1
            if ToggleButton("\xCE\xA6", phase and "all_on" or "all_off", "Invert phase", BTN_PH) then
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_PHASE", phase and 0 or 1)
            end
            r.ImGui_SameLine(ctx)
            local mono = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_MONO") == 1
            if ToggleButton(mono and "Mono" or "Stereo", mono and "all_on" or "all_off", "Mono/Stereo", BTN_MONO) then
                r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "B_MONO", mono and 0 or 1)
            end
            r.ImGui_SameLine(ctx)
            local row_mode = r.GetTrackSendInfo_Value(s.owner, 0, s.send_idx, "I_SENDMODE")
            local row_mode_names = { "Post-Fader", "Pre-Fader/Post-FX", "Pre-FX" }
            local row_mode_values = { 0, 3, 1 }
            local row_idx = 1
            for k = 1, #row_mode_values do if row_mode_values[k] == row_mode then row_idx = k; break end end
            r.ImGui_PushItemWidth(ctx, BTN_MODE)
            if r.ImGui_BeginCombo(ctx, "##mode", row_mode_names[row_idx]) then
                for k = 1, #row_mode_names do
                    if r.ImGui_Selectable(ctx, row_mode_names[k], row_idx == k) then
                        r.SetTrackSendInfo_Value(s.owner, 0, s.send_idx, "I_SENDMODE", row_mode_values[k])
                    end
                end
                r.ImGui_EndCombo(ctx)
            end
            r.ImGui_PopItemWidth(ctx)
            r.ImGui_SameLine(ctx)
            PushXDelete()
            if r.ImGui_Button(ctx, "\xC3\x97##del", BTN_X, 0) then
                r.RemoveTrackSend(s.owner, 0, s.send_idx)
            end
            r.ImGui_PopStyleColor(ctx, 4)
            r.ImGui_PopStyleVar(ctx)
            r.ImGui_PopID(ctx)
            r.ImGui_Separator(ctx)
        end
        r.ImGui_PopID(ctx)
    end

    for hi = 1, #hubs do
        local h = hubs[hi]
        local hub_match = filter == "" or h.name:lower():find(filter, 1, true)

        local function FilterEntries(list)
            local out = {}
            for si = 1, #list do
                local _, n = r.GetTrackName(list[si].other)
                local m = filter == "" or n:lower():find(filter, 1, true)
                if hub_match or m then out[#out + 1] = list[si] end
            end
            return out
        end
        local vis_in = FilterEntries(h.incoming)
        local vis_out = FilterEntries(h.outgoing)

        local dir = config.routing_direction or "All"
        if dir == "In" then vis_out = {}
        elseif dir == "Out" then vis_in = {} end

        if only_selected and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            if h.hub ~= TRACK then vis_in = {}; vis_out = {} end
        end

        local show_empty_hub = show_all_tracks and hub_match
        if only_selected and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") and h.hub ~= TRACK then
            show_empty_hub = false
        end

        if #vis_in > 0 or #vis_out > 0 or show_empty_hub then
            r.ImGui_PushID(ctx, "hub_" .. h.hub_idx)
            local hub_guid = r.GetTrackGUID(h.hub)
            if hub_open_state[hub_guid] == nil then hub_open_state[hub_guid] = false end
            if routing_expand_all_pending then hub_open_state[hub_guid] = true end
            if routing_collapse_all_pending then hub_open_state[hub_guid] = false end
            local open = hub_open_state[hub_guid]
            local is_st = IsSendTrack(h.hub)

            local tcol = r.GetTrackColor(h.hub)
            local r8, g8, b8 = 96, 96, 96
            if tcol and tcol ~= 0 then r8, g8, b8 = r.ColorFromNative(tcol) end
            local bar_col = ((r8 & 0xFF) << 24) | ((g8 & 0xFF) << 16) | ((b8 & 0xFF) << 8) | 0xFF
            local is_selected_hub = (TRACK and r.ValidatePtr(TRACK, "MediaTrack*") and h.hub == TRACK)
            if is_selected_hub and routing_scroll_pending then
                r.ImGui_SetScrollHereY(ctx, 0.25)
                routing_scroll_pending = false
            end
            local bg_col, bg_hov
            if is_selected_hub then
                local sr = math.min(255, math.floor(r8 * 0.55 + 35))
                local sg = math.min(255, math.floor(g8 * 0.55 + 35))
                local sb = math.min(255, math.floor(b8 * 0.55 + 35))
                bg_col = ((sr & 0xFF) << 24) | ((sg & 0xFF) << 16) | ((sb & 0xFF) << 8) | 0xFF
                local hr = math.min(255, sr + 25)
                local hg = math.min(255, sg + 25)
                local hb = math.min(255, sb + 25)
                bg_hov = ((hr & 0xFF) << 24) | ((hg & 0xFF) << 16) | ((hb & 0xFF) << 8) | 0xFF
            else
                bg_col = is_st and 0x1A2A38FF or 0x1E1E1EFF
                bg_hov = is_st and 0x244055FF or 0x2A2A2AFF
            end

            local draw_list = r.ImGui_GetWindowDrawList(ctx)
            local p_x, p_y = r.ImGui_GetCursorScreenPos(ctx)
            local avail_w = r.ImGui_GetContentRegionAvail(ctx)
            local row_h = r.ImGui_GetTextLineHeight(ctx) + 8
            local bar_w = 5
            local arrow = open and "\xE2\x96\xBC" or "\xE2\x96\xB6"
            local count_str = string.format("(%d in - %d out)", #vis_in, #vis_out)

            local count_w = r.ImGui_CalcTextSize(ctx, count_str)
            local right_pad = 8
            local count_x = p_x + avail_w - count_w - right_pad
            local mbtn_w = 22
            local mbtn_h = row_h - 4
            local mbtn_x = count_x - mbtn_w - 8
            local hdr_click_w = math.max(1, mbtn_x - p_x - 4)

            if r.ImGui_InvisibleButton(ctx, "##hub_hdr", hdr_click_w, row_h) then
                hub_open_state[hub_guid] = not open
                open = hub_open_state[hub_guid]
            end
            local hovered = r.ImGui_IsItemHovered(ctx)
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.SetOnlyTrackSelected(h.hub)
                if r.SetMixerScroll then r.SetMixerScroll(h.hub) end
                r.UpdateArrange()
            end
            if hovered then
                r.ImGui_SetTooltip(ctx, "Left-click: expand/collapse\nRight-click: select track in REAPER")
            end
            r.ImGui_DrawList_AddRectFilled(draw_list, p_x, p_y, p_x + bar_w, p_y + row_h, bar_col)
            r.ImGui_DrawList_AddRectFilled(draw_list, p_x + bar_w, p_y, p_x + avail_w, p_y + row_h, hovered and bg_hov or bg_col)

            r.ImGui_DrawList_AddText(draw_list, count_x, p_y + 4, 0xB0B0B0FF, count_str)

            local saved_cx, saved_cy = r.ImGui_GetCursorScreenPos(ctx)
            local mainsend = r.GetMediaTrackInfo_Value(h.hub, "B_MAINSEND") == 1
            local m_bg, m_hov, m_act
            if mainsend then m_bg, m_hov, m_act = 0x3FAA3FFF, 0x55C055FF, 0x2F8F2FFF
            else m_bg, m_hov, m_act = 0x3F3F3FFF, 0x555555FF, 0x2F2F2FFF end
            r.ImGui_SetCursorScreenPos(ctx, mbtn_x, p_y + 2)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), m_bg)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), m_hov)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), m_act)
            if r.ImGui_Button(ctx, "M##mainsend", mbtn_w, mbtn_h) then
                r.SetMediaTrackInfo_Value(h.hub, "B_MAINSEND", mainsend and 0 or 1)
            end
            r.ImGui_PopStyleColor(ctx, 3)
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "MasterSendChan")
            end
            if r.ImGui_IsItemHovered(ctx) then
                local cur_off = math.floor(r.GetMediaTrackInfo_Value(h.hub, "C_MAINSEND_OFFS") or 0)
                local off_label
                if cur_off == 0 then off_label = "1+2 (default)"
                else off_label = string.format("%d+%d", cur_off + 1, cur_off + 2) end
                r.ImGui_SetTooltip(ctx, string.format("Master/Parent send: %s\nChannel: %s\nLeft-click: toggle on/off\nRight-click: channel offset", mainsend and "ON" or "OFF", off_label))
            end
            if r.ImGui_BeginPopup(ctx, "MasterSendChan") then
                r.ImGui_Text(ctx, "Master/Parent channels")
                r.ImGui_Separator(ctx)
                local cur_nch = math.floor(r.GetMediaTrackInfo_Value(h.hub, "C_MAINSEND_NCH") or 0)
                local nch_opts = { {0, "All"}, {2, "Stereo (1-2)"}, {1, "Mono (1)"} }
                for ni = 1, #nch_opts do
                    local v, lbl = nch_opts[ni][1], nch_opts[ni][2]
                    if r.ImGui_Selectable(ctx, lbl, cur_nch == v) then
                        r.SetMediaTrackInfo_Value(h.hub, "C_MAINSEND_NCH", v)
                    end
                end
                r.ImGui_Separator(ctx)
                r.ImGui_Text(ctx, "Channel offset")
                r.ImGui_Separator(ctx)
                local cur_off = math.floor(r.GetMediaTrackInfo_Value(h.hub, "C_MAINSEND_OFFS") or 0)
                local opts = { {0, "1+2 (default)"}, {2, "3+4"}, {4, "5+6"}, {6, "7+8"}, {8, "9+10"}, {10, "11+12"}, {12, "13+14"}, {14, "15+16"} }
                for oi = 1, #opts do
                    local v, lbl = opts[oi][1], opts[oi][2]
                    if r.ImGui_Selectable(ctx, lbl, cur_off == v) then
                        r.SetMediaTrackInfo_Value(h.hub, "C_MAINSEND_OFFS", v)
                    end
                end
                r.ImGui_EndPopup(ctx)
            end
            r.ImGui_SetCursorScreenPos(ctx, saved_cx, saved_cy)
            r.ImGui_Dummy(ctx, 0, 0)

            local prefix = string.format("%s  #%d  ", arrow, h.hub_idx + 1)
            local prefix_w = r.ImGui_CalcTextSize(ctx, prefix)
            local name_x = p_x + bar_w + 8 + prefix_w
            local name_max_w = count_x - name_x - 8
            local name_disp = h.name
            local name_w = r.ImGui_CalcTextSize(ctx, name_disp)
            if name_w > name_max_w and name_max_w > 0 then
                local lo, hi = 1, #name_disp
                while lo < hi do
                    local mid = (lo + hi) // 2
                    local cand = name_disp:sub(1, mid) .. "..."
                    if r.ImGui_CalcTextSize(ctx, cand) <= name_max_w then lo = mid + 1 else hi = mid end
                end
                name_disp = name_disp:sub(1, math.max(0, lo - 1)) .. "..."
            end
            r.ImGui_DrawList_AddText(draw_list, p_x + bar_w + 8, p_y + 4, 0xE6E6E6FF, prefix .. name_disp)

            if open then
                RenderSection(h, vis_in, "Incoming", 0x88CCFFFF, "sec_in")
                RenderSection(h, vis_out, "Outgoing", 0xFFCC88FF, "sec_out")

                r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), SPC, 4)
                if r.ImGui_Button(ctx, "+ Receive from...") then
                    r.ImGui_OpenPopup(ctx, "AddIncomingToHub")
                end
                r.ImGui_SameLine(ctx)
                if r.ImGui_Button(ctx, "+ Send to...") then
                    r.ImGui_OpenPopup(ctx, "AddOutgoingFromHub")
                end
                r.ImGui_PopStyleVar(ctx)

                if r.ImGui_BeginPopup(ctx, "AddIncomingToHub") then
                    r.ImGui_Text(ctx, "Add receive from:")
                    r.ImGui_Separator(ctx)
                    local existing = {}
                    for si = 1, #h.incoming do existing[h.incoming[si].other] = true end
                    existing[h.hub] = true
                    for ti = 0, track_count - 1 do
                        local cand = r.GetTrack(0, ti)
                        if not existing[cand] then
                            local _, cname = r.GetTrackName(cand)
                            if r.ImGui_Selectable(ctx, cname) then
                                r.CreateTrackSend(cand, h.hub)
                                r.ImGui_CloseCurrentPopup(ctx)
                            end
                        end
                    end
                    r.ImGui_EndPopup(ctx)
                end
                if r.ImGui_BeginPopup(ctx, "AddOutgoingFromHub") then
                    r.ImGui_Text(ctx, "Add send to:")
                    r.ImGui_Separator(ctx)
                    if r.ImGui_Selectable(ctx, "+ New track...") then
                        local default_name = "Send"
                        local ok, retval = r.GetUserInputs("Name send track", 1, "Track name:,extrawidth=200", default_name)
                        if ok then
                            local trimmed = retval and retval:match("^%s*(.-)%s*$") or ""
                            if trimmed == "" then trimmed = default_name end
                            r.Undo_BeginBlock()
                            r.PreventUIRefresh(1)
                            local new_track = CreateSendTargetTrack(trimmed)
                            if new_track then
                                r.CreateTrackSend(h.hub, new_track)
                            end
                            r.PreventUIRefresh(-1)
                            r.Undo_EndBlock("Create new send track", -1)
                            r.UpdateArrange()
                        end
                        r.ImGui_CloseCurrentPopup(ctx)
                    end
                    r.ImGui_Separator(ctx)
                    r.ImGui_Text(ctx, "Existing track:")
                    local existing = {}
                    for si = 1, #h.outgoing do existing[h.outgoing[si].other] = true end
                    existing[h.hub] = true
                    for ti = 0, track_count - 1 do
                        local cand = r.GetTrack(0, ti)
                        if not existing[cand] then
                            local _, cname = r.GetTrackName(cand)
                            if r.ImGui_Selectable(ctx, cname) then
                                r.CreateTrackSend(h.hub, cand)
                                r.ImGui_CloseCurrentPopup(ctx)
                            end
                        end
                    end
                    r.ImGui_EndPopup(ctx)
                end
            end
            r.ImGui_PopID(ctx)
        end
    end
    routing_expand_all_pending = false
    routing_collapse_all_pending = false
end

function GetSendIndex(src_track, dst_track)
    local num_sends = r.GetTrackNumSends(src_track, 0)
    for i = 0, num_sends - 1 do
        local dest = r.GetTrackSendInfo_Value(src_track, 0, i, "P_DESTTRACK")
        if dest == dst_track then
            return i
        end
    end
    return -1
end

function BuildShortcutMap()
    shortcut_map = {}
    for _, action in ipairs(allActions) do
        local cnt = r.CountActionShortcuts(0, action.id)
        if cnt and cnt > 0 then
            local rv, desc = r.GetActionShortcutDesc(0, action.id, 0)
            if rv and desc and desc ~= "" then
                shortcut_map[action.id] = desc
            end
        end
    end
end

function FilterActions()
    if #allActions == 0 then
        if reaper.CF_EnumerateActions then
            local i = 0
            repeat
                local retval, name = reaper.CF_EnumerateActions(0, i)
                if retval > 0 and name and name ~= "" then
                    table.insert(allActions, {name = name, id = retval})
                end
                i = i + 1
            until retval <= 0
        else
            local basic_actions = {
                {name = "Transport: Play/stop", id = 40044},
                {name = "Transport: Record", id = 1013},
                {name = "Edit: Copy items/tracks/envelope points", id = 40698},
                {name = "Edit: Paste items/tracks", id = 40058},
                {name = "Track: Insert new track", id = 40001},
                {name = "Item: Split items at edit cursor", id = 40746},
                {name = "View: Zoom to fit all in window", id = 40031}
            }
            for _, action in ipairs(basic_actions) do
                table.insert(allActions, action)
            end
        end
        BuildShortcutMap()
        for _, action in ipairs(allActions) do
            action.shortcut = shortcut_map[action.id]
        end
    end
end
FilterActions()
function CategorizeActions()
    for _, action in ipairs(allActions) do
        local name = action.name:lower()
        if name:find("project") or name:find("file") or name:find("save") or name:find("open") then
            table.insert(categories["Project Management"], action)
        elseif name:find("edit") or name:find("cut") or name:find("copy") or name:find("paste") then
            table.insert(categories["Editing"], action)
        elseif name:find("track") or name:find("item") then
            table.insert(categories["Track and Item Management"], action)
        elseif name:find("record") or name:find("play") then
            table.insert(categories["Recording and Playback"], action)
        elseif name:find("mix") or name:find("fx") or name:find("effect") then
            table.insert(categories["Mixing and Effects"], action)
        elseif name:find("midi") then
            table.insert(categories["MIDI"], action)
        elseif name:find("marker") or name:find("region") then
            table.insert(categories["Markers and Regions"], action)
        elseif name:find("view") or name:find("zoom") then
            table.insert(categories["View and Zoom"], action)
        elseif name:find("automation") or name:find("envelope") then
            table.insert(categories["Automation"], action)
        elseif name:find("sync") or name:find("tempo") then
            table.insert(categories["Synchronization and Tempo"], action)
        elseif name:find("script") or name:find("action") then
            table.insert(categories["Scripting and Customization"], action)
        elseif name:find("theme") or name:find("color") then
            table.insert(categories["Appearance and Themes"], action)
        elseif name:find("play") or name:find("stop") or name:find("pause") or name:find("rewind") or name:find("forward") or name:find("transport") then
            table.insert(categories["Transport"], action)
        else
            table.insert(categories["Miscellaneous"], action)
        end
    end
end
CategorizeActions()
function SearchActions(search_term)
    if not search_term or search_term == "" then
        return categories
    end
    
    local filteredActions = {}
    for category, actions in pairs(categories) do
        filteredActions[category] = {}
        for _, action in ipairs(actions) do
            if action and action.name and FuzzyFind(action.name, search_term) then
                local state = reaper.GetToggleCommandState(action.id)
                action.state = state
                table.insert(filteredActions[category], action)
            end
        end
    end
    return filteredActions
end

function CreateSmartMarker(action_id)
    local cur_pos = reaper.GetCursorPosition()
    local marker_name = "!" .. action_id
    local _, num_markers, num_regions = reaper.CountProjectMarkers(0)
    local new_marker_id = num_markers + num_regions
    local red_color = reaper.ColorToNative(255, 0, 0)|0x1000000 -- Rood met alpha
    local result = reaper.AddProjectMarker2(0, false, cur_pos, 0, marker_name, new_marker_id, red_color)
    if result then
        reaper.UpdateTimeline()
    end
end 


local old_ShowPluginContextMenu = ShowPluginContextMenu
function ShowPluginContextMenu(plugin_name, menu_id)
    if type(plugin_name) == "table" then
        plugin_name = plugin_name.fx_name or plugin_name.name
    end
    if not plugin_name or type(plugin_name) ~= "string" then return end

    local item_index = tonumber(menu_id:match("_(%d+)$"))
    local multi_count = GetMultiSelectedCount()
    local is_multi = multi_count > 1 and item_index and (screenshot_multi_selected[item_index] or screenshot_nav_index == item_index)

    if is_multi then
        if r.ImGui_IsItemClicked(ctx, 1) then
            r.ImGui_OpenPopup(ctx, "MultiSelectContextMenu_" .. menu_id)
        end
        if r.ImGui_BeginPopup(ctx, "MultiSelectContextMenu_" .. menu_id) then
            r.ImGui_Text(ctx, multi_count .. " plugins selected")
            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Add All to Track") then
                local names = GetMultiSelectedPluginNames()
                local target_track = GetTargetTrack()
                if target_track and #names > 0 then
                    r.Undo_BeginBlock()
                    r.PreventUIRefresh(1)
                    for _, pname in ipairs(names) do
                        AddFXToTrack(target_track, pname)
                    end
                    r.PreventUIRefresh(-1)
                    r.Undo_EndBlock("Add " .. #names .. " FX plugins", -1)
                    LAST_USED_FX = names[#names]
                end
            end

            if r.ImGui_MenuItem(ctx, "Add All to New Track") then
                local names = GetMultiSelectedPluginNames()
                if #names > 0 then
                    r.Undo_BeginBlock()
                    r.PreventUIRefresh(1)
                    local track_idx = r.CountTracks(0)
                    r.InsertTrackAtIndex(track_idx, true)
                    local new_track = r.GetTrack(0, track_idx)
                    if new_track then
                        r.GetSetMediaTrackInfo_String(new_track, "P_NAME", names[1] .. " + " .. (#names - 1) .. " more", true)
                        for _, pname in ipairs(names) do
                            AddFXToTrack(new_track, pname)
                        end
                        LAST_USED_FX = names[#names]
                    end
                    r.PreventUIRefresh(-1)
                    r.Undo_EndBlock("Add " .. #names .. " FX to new track", -1)
                end
            end

            if r.ImGui_MenuItem(ctx, "Add All to Chain Builder") then
                local names = GetMultiSelectedPluginNames()
                for _, pname in ipairs(names) do
                    if not table.contains(chain_builder_plugins, pname) then
                        table.insert(chain_builder_plugins, pname)
                        chain_builder_chunks[#chain_builder_plugins] = false
                    end
                end
                config.chain_builder_plugins = chain_builder_plugins
                SaveConfig()
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Add All to Favorites") then
                local names = GetMultiSelectedPluginNames()
                for _, pname in ipairs(names) do
                    if not favorite_set[pname] then
                        AddToFavorites(pname)
                    end
                end
            end

            if r.ImGui_MenuItem(ctx, "Remove All from Favorites") then
                local names = GetMultiSelectedPluginNames()
                for _, pname in ipairs(names) do
                    if favorite_set[pname] then
                        RemoveFromFavorites(pname)
                    end
                end
            end

            if next(config.custom_folders) then
                r.ImGui_Separator(ctx)
                if r.ImGui_BeginMenu(ctx, "Add All to Custom Folder") then
                    local function ShowMultiCustomFolderMenu(folders, path_prefix)
                        path_prefix = path_prefix or ""
                        local sorted_folder_names = {}
                        for folder_name, folder_content in pairs(folders) do
                            if type(folder_name) == "string" and type(folder_content) == "table" then
                                table.insert(sorted_folder_names, folder_name)
                            end
                        end
                        table.sort(sorted_folder_names, function(a, b) return a:lower() < b:lower() end)

                        for _, folder_name in ipairs(sorted_folder_names) do
                            local folder_content = folders[folder_name]
                            local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
                            local has_subfolders = HasSubfolders(folder_content)
                            local plugin_count = #GetFolderPlugins(folder_content)

                            if has_subfolders then
                                if r.ImGui_BeginMenu(ctx, folder_name) then
                                    if r.ImGui_MenuItem(ctx, "[Add here] (" .. plugin_count .. ")") then
                                        local target = config.custom_folders
                                        if path_prefix ~= "" then
                                            for folder in path_prefix:gmatch("[^/]+") do
                                                target = target[folder]
                                                if not target then break end
                                            end
                                        end
                                        if target and target[folder_name] then
                                            local target_folder = target[folder_name]
                                            local names = GetMultiSelectedPluginNames()
                                            local added_count = 0
                                            for _, pname in ipairs(names) do
                                                local already_exists = false
                                                for k, v in pairs(target_folder) do
                                                    if type(k) == "number" and v == pname then
                                                        already_exists = true
                                                        break
                                                    end
                                                end
                                                if not already_exists then
                                                    local max_index = 0
                                                    for k in pairs(target_folder) do
                                                        if type(k) == "number" and k > max_index then max_index = k end
                                                    end
                                                    target_folder[max_index + 1] = pname
                                                    added_count = added_count + 1
                                                end
                                            end
                                            SaveCustomFolders()
                                            if added_count > 0 then
                                                r.ShowMessageBox(added_count .. " plugin(s) added to " .. folder_name, "Success", 0)
                                            else
                                                r.ShowMessageBox("All plugins already exist in " .. folder_name, "Info", 0)
                                            end
                                        end
                                    end
                                    r.ImGui_Separator(ctx)
                                    ShowMultiCustomFolderMenu(folder_content, full_path)
                                    r.ImGui_EndMenu(ctx)
                                end
                            else
                                if r.ImGui_MenuItem(ctx, folder_name .. " (" .. plugin_count .. ")") then
                                    local target = config.custom_folders
                                    if path_prefix ~= "" then
                                        for folder in path_prefix:gmatch("[^/]+") do
                                            target = target[folder]
                                            if not target then break end
                                        end
                                    end
                                    if target and target[folder_name] then
                                        local target_folder = target[folder_name]
                                        local names = GetMultiSelectedPluginNames()
                                        local added_count = 0
                                        for _, pname in ipairs(names) do
                                            local already_exists = false
                                            for k, v in pairs(target_folder) do
                                                if type(k) == "number" and v == pname then
                                                    already_exists = true
                                                    break
                                                end
                                            end
                                            if not already_exists then
                                                local max_index = 0
                                                for k in pairs(target_folder) do
                                                    if type(k) == "number" and k > max_index then max_index = k end
                                                end
                                                target_folder[max_index + 1] = pname
                                                added_count = added_count + 1
                                            end
                                        end
                                        SaveCustomFolders()
                                    end
                                end
                            end
                        end
                    end
                    ShowMultiCustomFolderMenu(config.custom_folders)
                    r.ImGui_EndMenu(ctx)
                end
                if r.ImGui_BeginMenu(ctx, "Remove All from Custom Folder") then
                    local names = GetMultiSelectedPluginNames()
                    local function CollectFoldersWithSelectedPlugins(folders, path_prefix, results)
                        path_prefix = path_prefix or ""
                        results = results or {}
                        for folder_name, folder_content in pairs(folders) do
                            if folder_name ~= "__folder_marker__" and type(folder_content) == "table" then
                                local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
                                local has_any = false
                                for k, v in pairs(folder_content) do
                                    if type(k) == "number" and type(v) == "string" then
                                        for _, pname in ipairs(names) do
                                            if v == pname then
                                                has_any = true
                                                break
                                            end
                                        end
                                    end
                                    if has_any then break end
                                end
                                if has_any then
                                    results[#results + 1] = full_path
                                end
                                CollectFoldersWithSelectedPlugins(folder_content, full_path, results)
                            end
                        end
                        return results
                    end

                    local matched_folders = CollectFoldersWithSelectedPlugins(config.custom_folders, "", {})
                    table.sort(matched_folders, function(a, b) return a:lower() < b:lower() end)

                    if #matched_folders > 0 then
                        for _, folder_path in ipairs(matched_folders) do
                            if r.ImGui_MenuItem(ctx, folder_path) then
                                local target = config.custom_folders
                                for folder in folder_path:gmatch("[^/]+") do
                                    target = target[folder]
                                    if not target then break end
                                end
                                if target then
                                    local removed_count = 0
                                    for k, v in pairs(target) do
                                        if type(k) == "number" and type(v) == "string" then
                                            for _, pname in ipairs(names) do
                                                if v == pname then
                                                    target[k] = nil
                                                    removed_count = removed_count + 1
                                                    break
                                                end
                                            end
                                        end
                                    end
                                    if removed_count > 0 then
                                        SaveCustomFolders()
                                        if selected_folder and IsCustomFolder(selected_folder) then
                                            local plugins = GetCustomFolderPlugins(selected_folder, config.custom_folders)
                                            screenshot_search_results = {}
                                            for _, p in ipairs(plugins) do
                                                table.insert(screenshot_search_results, {name = p})
                                            end
                                            ClearScreenshotCache()
                                        end
                                        r.ShowMessageBox(removed_count .. " plugin(s) removed from " .. folder_path, "Success", 0)
                                    else
                                        r.ShowMessageBox("No selected plugins found in " .. folder_path, "Info", 0)
                                    end
                                end
                            end
                        end
                    else
                        r.ImGui_MenuItem(ctx, "(none of the selected plugins in custom folders)", nil, false, false)
                    end
                    r.ImGui_EndMenu(ctx)
                end
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_BeginMenu(ctx, "Add All to Native Folder") then
                local native_folders = GetNativeFolderNames()
                for _, entry in ipairs(native_folders) do
                    if r.ImGui_MenuItem(ctx, entry.name) then
                        local names = GetMultiSelectedPluginNames()
                        local added = 0
                        for _, pname in ipairs(names) do
                            if AddPluginToNativeFolder(entry.idx, pname) then added = added + 1 end
                        end
                        if added > 0 then RefreshAfterNativeFolderChange() end
                    end
                end
                r.ImGui_Separator(ctx)
                if r.ImGui_MenuItem(ctx, "Create New Native Folder...") then
                    show_native_folder_create_popup = true
                    new_native_folder_for_plugin = nil
                    new_native_folder_name = ""
                end
                r.ImGui_EndMenu(ctx)
            end

            if r.ImGui_BeginMenu(ctx, "Remove All from Native Folder") then
                local native_folders = GetNativeFolderNames()
                local names = GetMultiSelectedPluginNames()
                local _, folder_data = ParseNativeFoldersINI()
                local found_any = false
                for _, entry in ipairs(native_folders) do
                    local fd = folder_data[entry.idx]
                    if fd then
                        local has_any = false
                        for _, pname in ipairs(names) do
                            local ident = GetNativeFxIdentifier(pname)
                            if ident then
                                for i = 0, fd.nb - 1 do
                                    if fd.items[i] == ident then has_any = true break end
                                end
                            end
                            if has_any then break end
                        end
                        if has_any then
                            found_any = true
                            if r.ImGui_MenuItem(ctx, entry.name) then
                                local removed = 0
                                for _, pname in ipairs(names) do
                                    if RemovePluginFromNativeFolder(entry.idx, pname) then removed = removed + 1 end
                                end
                                if removed > 0 then RefreshAfterNativeFolderChange() end
                            end
                        end
                    end
                end
                if not found_any then
                    r.ImGui_MenuItem(ctx, "(none of the selected plugins in native folders)", nil, false, false)
                end
                r.ImGui_EndMenu(ctx)
            end

            if r.ImGui_MenuItem(ctx, "Create New Native Folder...") then
                show_native_folder_create_popup = true
                new_native_folder_for_plugin = nil
                new_native_folder_name = ""
            end

            if r.ImGui_MenuItem(ctx, "Create Smart Folder...") then
                show_smart_folder_popup = true
                smart_folder_edit_idx = nil
                smart_folder_edit_name = ""
                smart_folder_edit_query = ""
                smart_folder_preview_results = {}
            end

            if r.ImGui_BeginMenu(ctx, "Edit Smart Folder") then
                local native_folders = GetNativeFolderNames()
                local found_smart = false
                for _, entry in ipairs(native_folders) do
                    if IsNativeSmartFolder(entry.idx) then
                        found_smart = true
                        if r.ImGui_MenuItem(ctx, entry.name) then
                            show_smart_folder_popup = true
                            smart_folder_edit_idx = entry.idx
                            smart_folder_edit_name = entry.name
                            smart_folder_edit_query = GetNativeSmartFolderQuery(entry.idx) or ""
                            smart_folder_preview_dirty = true
                        end
                    end
                end
                if not found_smart then
                    r.ImGui_MenuItem(ctx, "(no smart folders)", nil, false, false)
                end
                r.ImGui_EndMenu(ctx)
            end

            if r.ImGui_BeginMenu(ctx, "Delete Native Folder") then
                local native_folders = GetNativeFolderNames()
                if #native_folders > 0 then
                    for _, entry in ipairs(native_folders) do
                        local label = entry.name
                        if IsNativeSmartFolder(entry.idx) then label = label .. "  [smart]" end
                        if r.ImGui_MenuItem(ctx, label) then
                            pending_delete_native_folder_idx = entry.idx
                            pending_delete_native_folder_name = entry.name
                            show_delete_native_folder_popup = true
                        end
                    end
                else
                    r.ImGui_MenuItem(ctx, "(no native folders)", nil, false, false)
                end
                r.ImGui_EndMenu(ctx)
            end

            r.ImGui_Separator(ctx)
            if r.ImGui_MenuItem(ctx, "Clear Selection") then
                screenshot_multi_selected = {}
            end

            r.ImGui_EndPopup(ctx)
        end
        return
    end

    if r.ImGui_IsItemClicked(ctx, 1) then
        r.ImGui_OpenPopup(ctx, "PluginContextMenu_" .. menu_id)
    end

    if r.ImGui_BeginPopup(ctx, "PluginContextMenu_" .. menu_id) then
        -- Rating UI bovenaan
        r.ImGui_Text(ctx, "Rating:")
        ShowPluginRatingUI(plugin_name)
        r.ImGui_Separator(ctx)
        if r.ImGui_MenuItem(ctx, "Make Screenshot") then
            StartSingleScreenshotCapture(plugin_name, function()
                ClearScreenshotCache()
                BuildScreenshotIndex(true)
                folder_changed = true
            end, true)
        end
        if r.ImGui_MenuItem(ctx, "Make Screenshot (OpenGL/DX)") then
            StartScreenCaptureScreenshot(plugin_name, function()
                ClearScreenshotCache()
                BuildScreenshotIndex(true)
                folder_changed = true
            end)
        end
        if HasScreenshot(plugin_name) then
            if r.ImGui_MenuItem(ctx, "Remove Screenshot") then
                local norm = NormalizePluginNameForMatch(plugin_name)
                local indexed_file = screenshot_index_norm and screenshot_index_norm[norm]
                if type(indexed_file) == 'string' and indexed_file ~= '' then
                    local fpath = screenshot_path .. indexed_file
                    if r.file_exists(fpath) then
                        os.remove(fpath)
                    end
                end
                local stripped_x86 = StripX86Markers(plugin_name)
                local variants = {
                    plugin_name,
                    CleanPluginName(plugin_name),
                    (plugin_name or ''):gsub('[^%w%s-]','_'),
                    CleanPluginName(plugin_name):gsub('[^%w%s-]','_'),
                    stripped_x86,
                    CleanPluginName(stripped_x86),
                    StripX86Markers(CleanPluginName(plugin_name))
                }
                for _, base in ipairs(variants) do
                    if base and base ~= '' then
                        for _, ext in ipairs({'.png', '.jpg'}) do
                            local path = screenshot_path .. base .. ext
                            if r.file_exists(path) then
                                os.remove(path)
                            end
                        end
                    end
                end
                screenshot_exists_cache[plugin_name] = nil
                ClearScreenshotCache()
                BuildScreenshotIndex(true)
                folder_changed = true
            end
        end
        
        if r.ImGui_MenuItem(ctx, "Add to New Track") then
            r.Undo_BeginBlock()
            r.PreventUIRefresh(1)
            local track_idx = r.CountTracks(0)
            r.InsertTrackAtIndex(track_idx, true)
            local new_track = r.GetTrack(0, track_idx)
            if new_track then
                r.GetSetMediaTrackInfo_String(new_track, "P_NAME", plugin_name, true)
                local fx_index = AddFXToTrack(new_track, plugin_name)
                if config.open_floating_after_adding and fx_index and fx_index >= 0 then
                    r.TrackFX_Show(new_track, fx_index, 3)
                end
                LAST_USED_FX = plugin_name
                if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            end
            r.PreventUIRefresh(-1)
            r.Undo_EndBlock("Add " .. plugin_name .. " to new track", -1)
        end

        if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            if r.ImGui_MenuItem(ctx, "Add to Selected Tracks") then
                AddPluginToSelectedTracks(plugin_name)
            end
            if r.ImGui_MenuItem(ctx, "Add to All Tracks") then
                AddPluginToAllTracks(plugin_name)
            end
            if r.ImGui_MenuItem(ctx, "Add to Input FX") then
                r.Undo_BeginBlock()
                local fx_index = r.TrackFX_AddByName(TRACK, plugin_name, true, -1)
                if fx_index and fx_index >= 0 and config.open_floating_after_adding then
                    r.TrackFX_Show(TRACK, fx_index + 0x1000000, 3)
                end
                LAST_USED_FX = plugin_name
                r.Undo_EndBlock("Add " .. plugin_name .. " to Input FX", -1)
                if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            end
        end
        
        -- Add to Selected Items option
        local item_count = r.CountSelectedMediaItems(0)
        if item_count > 0 then
            if r.ImGui_MenuItem(ctx, "Add to Selected Items (" .. item_count .. ")") then
                for i = 0, item_count - 1 do
                    local item = r.GetSelectedMediaItem(0, i)
                    if item then
                        local take = r.GetActiveTake(item)
                        if take then
                            local dest_index = r.TakeFX_GetCount(take)
                            local fx_index = r.TakeFX_AddByName(take, plugin_name, -1000 - dest_index)
                            if fx_index and fx_index >= 0 and config.open_floating_after_adding then
                                r.TakeFX_Show(take, fx_index, 3)
                            end
                        end
                    end
                end
                LAST_USED_FX = plugin_name
                if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            end
        end
        
    local is_favorite = not not favorite_set[plugin_name]
        if is_favorite then
            if r.ImGui_MenuItem(ctx, "Remove from Favorites") then
                RemoveFromFavorites(plugin_name)
                GetPluginsForFolder(selected_folder)
                ClearScreenshotCache()
            end
        else
            if r.ImGui_MenuItem(ctx, "Add to Favorites") then
                AddToFavorites(plugin_name)
                GetPluginsForFolder(selected_folder)
                ClearScreenshotCache()
            end
        end

        -- Pin/unpin plugin
        local is_pinned = IsPluginPinned(plugin_name)
        if is_pinned then
            if r.ImGui_MenuItem(ctx, "Unpin Plugin") then
                UnpinPlugin(plugin_name)
            end
        else
            if r.ImGui_MenuItem(ctx, "Pin Plugin") then
                PinPlugin(plugin_name)
            end
        end

        -- Rename Plugin
        if r.ImGui_MenuItem(ctx, "Rename Plugin (Alias)") then
            rename_plugin_target = plugin_name
            rename_plugin_new_name = plugin_aliases[plugin_name] or plugin_name
            rename_plugin_open = true
        end

        -- ADD TO CUSTOM FOLDER SECTIE
        if next(config.custom_folders) then
            r.ImGui_Separator(ctx)
            if r.ImGui_BeginMenu(ctx, "Add to Custom Folder") then
                local function ShowCustomFolderMenu(folders, path_prefix)
                    path_prefix = path_prefix or ""
                    
                    -- SORTEER DE FOLDER NAMEN ALFABETISCH
                    local sorted_folder_names = {}
                    for folder_name, folder_content in pairs(folders) do
                        if type(folder_name) == "string" and type(folder_content) == "table" then
                            table.insert(sorted_folder_names, folder_name)
                        end
                    end
                    table.sort(sorted_folder_names, function(a, b) 
                        return a:lower() < b:lower() 
                    end)
                    
                    -- GEBRUIK DE GESORTEERDE NAMEN
                    for _, folder_name in ipairs(sorted_folder_names) do
                        local folder_content = folders[folder_name]
                        
                        local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
                        
                        local has_subfolders = HasSubfolders(folder_content)
                        local plugin_count = #GetFolderPlugins(folder_content)
                        
                        if has_subfolders then
                            if r.ImGui_BeginMenu(ctx, folder_name) then
                                if r.ImGui_MenuItem(ctx, "[Add here] (" .. plugin_count .. ")") then
                                    local target = config.custom_folders
                                    if path_prefix ~= "" then
                                        for folder in path_prefix:gmatch("[^/]+") do
                                            target = target[folder]
                                            if not target then break end
                                        end
                                    end
                                    if target and target[folder_name] then
                                        local target_folder = target[folder_name]
                                        local already_exists = false
                                        for k, v in pairs(target_folder) do
                                            if type(k) == "number" and v == plugin_name then
                                                already_exists = true
                                                break
                                            end
                                        end
                                        if not already_exists then
                                            local max_index = 0
                                            for k in pairs(target_folder) do
                                                if type(k) == "number" and k > max_index then
                                                    max_index = k
                                                end
                                            end
                                            target_folder[max_index + 1] = plugin_name
                                            SaveCustomFolders()
                                            r.ShowMessageBox("Plugin added to " .. folder_name, "Success", 0)
                                        else
                                            r.ShowMessageBox("Plugin already exists in " .. folder_name, "Info", 0)
                                        end
                                    end
                                end
                                r.ImGui_Separator(ctx)
                                ShowCustomFolderMenu(folder_content, full_path)
                                r.ImGui_EndMenu(ctx)
                            end
                        else
                            if r.ImGui_MenuItem(ctx, folder_name .. " (" .. plugin_count .. ")") then
                                local target = config.custom_folders
                                if path_prefix ~= "" then
                                    for folder in path_prefix:gmatch("[^/]+") do
                                        target = target[folder]
                                        if not target then break end
                                    end
                                end
                                
                                if target and target[folder_name] then
                                    local target_folder = target[folder_name]
                                    
                                    local already_exists = false
                                    for k, v in pairs(target_folder) do
                                        if type(k) == "number" and v == plugin_name then
                                            already_exists = true
                                            break
                                        end
                                    end
                                    
                                    if not already_exists then
                                        local max_index = 0
                                        for k in pairs(target_folder) do
                                            if type(k) == "number" and k > max_index then
                                                max_index = k
                                            end
                                        end
                                        target_folder[max_index + 1] = plugin_name
                                        SaveCustomFolders()
                                    end
                                end
                            end
                        end
                    end
                end
                
                ShowCustomFolderMenu(config.custom_folders)
                
                r.ImGui_Separator(ctx)
                if r.ImGui_MenuItem(ctx, "Create New Folder...") then
                    show_create_folder_popup = true
                    new_folder_for_plugin = plugin_name
                end
                
                r.ImGui_EndMenu(ctx)
            end
        end
        
        -- REMOVE FROM CUSTOM FOLDER SECTIE
        if next(config.custom_folders) then
            -- Check if plugin exists in any custom folder
            local function FindPluginInFolders(folders, plugin, path_prefix, results)
                path_prefix = path_prefix or ""
                results = results or {}
                
                for folder_name, folder_content in pairs(folders) do
                    if folder_name ~= "__folder_marker__" and type(folder_content) == "table" then
                        local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
                        
                        -- Check if this folder contains the plugin
                        local contains_plugin = false
                        for k, v in pairs(folder_content) do
                            if type(v) == "string" and v == plugin then
                                contains_plugin = true
                                table.insert(results, {path = full_path, key = k})
                                break
                            end
                        end
                        
                        -- Recurse into subfolders
                        if not contains_plugin then
                            FindPluginInFolders(folder_content, plugin, full_path, results)
                        end
                    end
                end
                
                return results
            end
            
            local found_in = FindPluginInFolders(config.custom_folders, plugin_name)
            
            if #found_in > 0 then
                if r.ImGui_BeginMenu(ctx, "Remove from Custom Folder") then
                    for _, location in ipairs(found_in) do
                        if r.ImGui_MenuItem(ctx, location.path) then
                            -- Navigate to folder and remove plugin
                            local target = config.custom_folders
                            for folder in location.path:gmatch("[^/]+") do
                                target = target[folder]
                                if not target then break end
                            end
                            
                            if target then
                                target[location.key] = nil
                                SaveCustomFolders()
                                
                                -- Refresh if we're viewing this folder
                                if selected_folder and IsCustomFolder(selected_folder) then
                                    local plugins = GetCustomFolderPlugins(selected_folder, config.custom_folders)
                                    screenshot_search_results = {}
                                    for _, p in ipairs(plugins) do
                                        table.insert(screenshot_search_results, {name = p})
                                    end
                                    ClearScreenshotCache()
                                end
                                
                                r.ShowMessageBox("Plugin removed from " .. location.path, "Success", 0)
                            end
                        end
                    end
                    r.ImGui_EndMenu(ctx)
                end
            end
        end

        r.ImGui_Separator(ctx)
        if r.ImGui_BeginMenu(ctx, "Add to Native Folder") then
            local native_folders = GetNativeFolderNames()
            for _, entry in ipairs(native_folders) do
                if r.ImGui_MenuItem(ctx, entry.name) then
                    if AddPluginToNativeFolder(entry.idx, plugin_name) then
                        RefreshAfterNativeFolderChange()
                    else
                        r.ShowMessageBox("Plugin kon niet worden toegevoegd.\nMogelijk bestaat het al in deze folder of is het type niet ondersteund.", "Info", 0)
                    end
                end
            end
            r.ImGui_Separator(ctx)
            if r.ImGui_MenuItem(ctx, "Create New Native Folder...") then
                show_native_folder_create_popup = true
                new_native_folder_for_plugin = plugin_name
                new_native_folder_name = ""
            end
            if r.ImGui_MenuItem(ctx, "Create Smart Folder...") then
                show_smart_folder_popup = true
                smart_folder_edit_idx = nil
                smart_folder_edit_name = ""
                smart_folder_edit_query = ""
                smart_folder_preview_results = {}
            end
            r.ImGui_EndMenu(ctx)
        end

        if r.ImGui_BeginMenu(ctx, "Remove from Native Folder") then
            local native_folders = GetNativeFolderNames()
            local ident = GetNativeFxIdentifier(plugin_name)
            local found_any = false
            if ident then
                local _, folder_data = ParseNativeFoldersINI()
                for _, entry in ipairs(native_folders) do
                    local fd = folder_data[entry.idx]
                    if fd then
                        local in_folder = false
                        for i = 0, fd.nb - 1 do
                            if fd.items[i] == ident then
                                in_folder = true
                                break
                            end
                        end
                        if in_folder then
                            found_any = true
                            if r.ImGui_MenuItem(ctx, entry.name) then
                                if RemovePluginFromNativeFolder(entry.idx, plugin_name) then
                                    RefreshAfterNativeFolderChange()
                                end
                            end
                        end
                    end
                end
            end
            if not found_any then
                r.ImGui_MenuItem(ctx, "(not in any native folder)", nil, false, false)
            end
            r.ImGui_EndMenu(ctx)
        end

        if r.ImGui_MenuItem(ctx, "Create New Native Folder...") then
            show_native_folder_create_popup = true
            new_native_folder_for_plugin = plugin_name
            new_native_folder_name = ""
        end

        if r.ImGui_MenuItem(ctx, "Create Smart Folder...") then
            show_smart_folder_popup = true
            smart_folder_edit_idx = nil
            smart_folder_edit_name = ""
            smart_folder_edit_query = ""
            smart_folder_preview_results = {}
        end

        if r.ImGui_BeginMenu(ctx, "Edit Smart Folder") then
            local native_folders = GetNativeFolderNames()
            local found_smart = false
            for _, entry in ipairs(native_folders) do
                if IsNativeSmartFolder(entry.idx) then
                    found_smart = true
                    if r.ImGui_MenuItem(ctx, entry.name) then
                        show_smart_folder_popup = true
                        smart_folder_edit_idx = entry.idx
                        smart_folder_edit_name = entry.name
                        smart_folder_edit_query = GetNativeSmartFolderQuery(entry.idx) or ""
                        smart_folder_preview_dirty = true
                    end
                end
            end
            if not found_smart then
                r.ImGui_MenuItem(ctx, "(no smart folders)", nil, false, false)
            end
            r.ImGui_EndMenu(ctx)
        end

        if r.ImGui_BeginMenu(ctx, "Delete Native Folder") then
            local native_folders = GetNativeFolderNames()
            if #native_folders > 0 then
                for _, entry in ipairs(native_folders) do
                    local label = entry.name
                    if IsNativeSmartFolder(entry.idx) then label = label .. "  [smart]" end
                    if r.ImGui_MenuItem(ctx, label) then
                        pending_delete_native_folder_idx = entry.idx
                        pending_delete_native_folder_name = entry.name
                        show_delete_native_folder_popup = true
                    end
                end
            else
                r.ImGui_MenuItem(ctx, "(no native folders)", nil, false, false)
            end
            r.ImGui_EndMenu(ctx)
        end
        r.ImGui_Separator(ctx)
        
        if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            if r.ImGui_MenuItem(ctx, "Add to new track as send (active track)") then
                AddPluginAsSend(plugin_name, { TRACK })
            end
            local sel_count = r.CountSelectedTracks(0)
            if sel_count > 0 then
                local lbl = (sel_count == 1)
                    and "Add to new track as send (1 selected track)"
                    or  ("Add to new track as send (" .. sel_count .. " selected tracks)")
                if r.ImGui_MenuItem(ctx, lbl) then
                    local sources = {}
                    for i = 0, sel_count - 1 do
                        sources[#sources + 1] = r.GetSelectedTrack(0, i)
                    end
                    AddPluginAsSend(plugin_name, sources)
                end
            end
        end

        if r.ImGui_MenuItem(ctx, "Add with Multi-Output Setup") then
            if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                AddFXToTrack(TRACK, plugin_name)
                
                local num_outputs = tonumber(plugin_name:match("%((%d+)%s+out%)")) or 0
                local num_receives = math.floor(num_outputs / 2) - 1
                
                r.SetMediaTrackInfo_Value(TRACK, "I_NCHAN", num_outputs)
                
                for k = 1, num_receives do
                    local track_idx = r.CountTracks(0)
                    r.InsertTrackAtIndex(track_idx, true)
                    local new_track = r.GetTrack(0, track_idx)
                    
                    r.CreateTrackSend(TRACK, new_track)
                    local send_idx = r.GetTrackNumSends(TRACK, 0) - 1
                    
                    r.SetTrackSendInfo_Value(TRACK, 0, send_idx, "I_SRCCHAN", k*2)
                    r.SetTrackSendInfo_Value(TRACK, 0, send_idx, "I_DSTCHAN", 0)
                    r.SetTrackSendInfo_Value(TRACK, 0, send_idx, "I_SENDMODE", 3)
                    r.SetTrackSendInfo_Value(TRACK, 0, send_idx, "I_MIDIFLAGS", 0)
                    
                    local output_num = (k * 2) + 1
                    r.GetSetMediaTrackInfo_String(new_track, "P_NAME", plugin_name .. " Out " .. output_num .. "-" .. (output_num + 1), true)
                end
            end
        end

        if IsInstrumentPlugin(plugin_name) then
            if r.ImGui_BeginMenu(ctx, "Add as virtual instrument to new track") then
                -- All MIDI inputs option
                if r.ImGui_MenuItem(ctx, "All MIDI inputs") then
                    CreateInstrumentTrack(plugin_name, 6112)
                end
                
                -- Individual MIDI inputs
                local num_midi_inputs = r.GetNumMIDIInputs()
                for i = 0, num_midi_inputs - 1 do
                    local retval, name = r.GetMIDIInputName(i, "")
                    if retval and name ~= "" then
                        if r.ImGui_MenuItem(ctx, name) then
                            CreateInstrumentTrack(plugin_name, 6113 + i)
                        end
                    end
                end
                
                r.ImGui_EndMenu(ctx)
            end
        end

        if config.hidden_names[plugin_name] then
            if r.ImGui_MenuItem(ctx, "Show Name") then
                config.hidden_names[plugin_name] = nil
                SaveConfig()
            end
        else
            if r.ImGui_MenuItem(ctx, "Hide Name") then
                config.hidden_names[plugin_name] = true
                SaveConfig()
            end
        end
        
        r.ImGui_EndPopup(ctx)
    end
end


function RemoveFXFromAllTracksByName(fx_name, include_master)
    if not fx_name or fx_name == '' then return end
    r.Undo_BeginBlock()
    -- Optionally remove from master
    if include_master then
        local master = r.GetMasterTrack(0)
        if master and r.ValidatePtr(master, "MediaTrack*") then
            while true do
                local idx = r.TrackFX_GetByName(master, fx_name, false)
                if not idx or idx < 0 then break end
                r.TrackFX_Delete(master, idx)
            end
        end
    end
    -- Remove from all normal tracks
    local track_count = r.CountTracks(0)
    for i = 0, track_count - 1 do
        local tr = r.GetTrack(0, i)
        if tr and r.ValidatePtr(tr, "MediaTrack*") then
            while true do
                local idx = r.TrackFX_GetByName(tr, fx_name, false)
                if not idx or idx < 0 then break end
                r.TrackFX_Delete(tr, idx)
            end
        end
    end
    r.Undo_EndBlock("Remove '" .. fx_name .. "' from all tracks", -1)
    if config.selected_folder == "Current Track FX" or config.selected_folder == "Current Project FX" then
        RefreshCurrentScreenshotView()
    end
end

function ShowFXContextMenu(plugin, menu_id)
    if r.ImGui_IsItemClicked(ctx, 1) then
        r.ImGui_OpenPopup(ctx, "FXContextMenu_" .. menu_id)
    end

    if r.ImGui_BeginPopup(ctx, "FXContextMenu_" .. menu_id) then
        local track
        local fx_index

            r.ImGui_Text(ctx, "Rating:")
            ShowPluginRatingUI(plugin.fx_name)
            r.ImGui_Separator(ctx)

        if not plugin or not plugin.fx_name then
            r.ImGui_Text(ctx, "Invalid plugin data")
            r.ImGui_EndPopup(ctx)
            return
        end

        if selected_folder == "Current Project FX" then
            if plugin.is_master then
                track = r.GetMasterTrack(0)
                fx_index = plugin.fx_index
            else
                track = r.GetTrack(0, plugin.track_number - 1)
                fx_index = plugin.fx_index
            end
        else
            track = TRACK
            if track and r.ValidatePtr(track, "MediaTrack*") then
                fx_index = r.TrackFX_GetByName(track, plugin.fx_name, false)
            end
        end

        if not track or not r.ValidatePtr(track, "MediaTrack*") then
            r.ImGui_Text(ctx, "No valid track selected")
            r.ImGui_EndPopup(ctx)
            return
        end

        if not fx_index or fx_index < 0 then
            r.ImGui_Text(ctx, "Plugin not found on track")
            r.ImGui_EndPopup(ctx)
            return
        end

        if r.ImGui_MenuItem(ctx, "Delete") then
            r.TrackFX_Delete(track, fx_index)
            if config.selected_folder == "Current Track FX" or config.selected_folder == "Current Project FX" then
                RefreshCurrentScreenshotView()
            end
        end

        -- Remove this plugin from all tracks (and master if the clicked instance is on master)
        if r.ImGui_MenuItem(ctx, "Remove from all tracks") then
            local include_master = (selected_folder == "Current Project FX" and plugin.is_master) or false
            RemoveFXFromAllTracksByName(plugin.fx_name, include_master)
        end

        if r.ImGui_MenuItem(ctx, "Copy to all tracks") then
            IS_COPYING_TO_ALL_TRACKS = true
            local track_count = r.CountTracks(0)
            for j = 0, track_count - 1 do
                local target_track = r.GetTrack(0, j)
                if target_track ~= track then
                    r.TrackFX_CopyToTrack(track, fx_index, target_track, r.TrackFX_GetCount(target_track), false)
                end
            end
            IS_COPYING_TO_ALL_TRACKS = false
        end

        if r.ImGui_MenuItem(ctx, "Copy Plugin") then
            copied_plugin = {track = track, index = fx_index}
        end

        if r.ImGui_MenuItem(ctx, "Paste Plugin", nil, copied_plugin ~= nil) then
            if copied_plugin then
                local _, orig_name = r.TrackFX_GetFXName(copied_plugin.track, copied_plugin.index, "")
                AddFXToTrack(track, orig_name)
            end
        end

        local is_enabled = r.TrackFX_GetEnabled(track, fx_index)
        if r.ImGui_MenuItem(ctx, is_enabled and "Bypass plugin" or "Unbypass plugin") then
            r.TrackFX_SetEnabled(track, fx_index, not is_enabled)
        end

        local item_count = r.CountSelectedMediaItems(0)
        if item_count > 0 then
            if r.ImGui_MenuItem(ctx, "Add to Selected Items (" .. item_count .. ")") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                for i = 0, item_count - 1 do
                    local item = r.GetSelectedMediaItem(0, i)
                    if item then
                        local take = r.GetActiveTake(item)
                        if take then
                            local dest_index = r.TakeFX_GetCount(take)
                            local added_fx = r.TakeFX_AddByName(take, plugin.fx_name, -1000 - dest_index)
                            if added_fx and added_fx >= 0 and config.open_floating_after_adding then
                                r.TakeFX_Show(take, added_fx, 3)
                            end
                        end
                    end
                end
                LAST_USED_FX = plugin.fx_name
                if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Add " .. plugin.fx_name .. " to selected items", -1)
            end
        end

    local fx_name = plugin.fx_name
    if favorite_set[fx_name] then
            if r.ImGui_MenuItem(ctx, "Remove from Favorites") then
                RemoveFromFavorites(fx_name)
            end
        else
            if r.ImGui_MenuItem(ctx, "Add to Favorites") then
                AddToFavorites(fx_name)
            end
        end

        -- ADD TO CUSTOM FOLDER SECTIE
        if next(config.custom_folders) then
            r.ImGui_Separator(ctx)
            if r.ImGui_BeginMenu(ctx, "Add to Custom Folder") then
                local function ShowCustomFolderMenu(folders, path_prefix)
                    path_prefix = path_prefix or ""
                    
                    -- SORTEER DE FOLDER NAMEN ALFABETISCH
                    local sorted_folder_names = {}
                    for folder_name, folder_content in pairs(folders) do
                        if type(folder_name) == "string" and type(folder_content) == "table" then
                            table.insert(sorted_folder_names, folder_name)
                        end
                    end
                    table.sort(sorted_folder_names, function(a, b) 
                        return a:lower() < b:lower() 
                    end)
                    
                    -- GEBRUIK DE GESORTEERDE NAMEN
                    for _, folder_name in ipairs(sorted_folder_names) do
                        local folder_content = folders[folder_name]
                        
                        local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
                        
                        local has_subfolders = HasSubfolders(folder_content)
                        local plugin_count = #GetFolderPlugins(folder_content)
                        
                        if has_subfolders then
                            if r.ImGui_BeginMenu(ctx, folder_name) then
                                if r.ImGui_MenuItem(ctx, "[Add here] (" .. plugin_count .. ")") then
                                    local target = config.custom_folders
                                    if path_prefix ~= "" then
                                        for folder in path_prefix:gmatch("[^/]+") do
                                            target = target[folder]
                                            if not target then break end
                                        end
                                    end
                                    if target and target[folder_name] then
                                        local target_folder = target[folder_name]
                                        local already_exists = false
                                        for k, v in pairs(target_folder) do
                                            if type(k) == "number" and v == fx_name then
                                                already_exists = true
                                                break
                                            end
                                        end
                                        if not already_exists then
                                            local max_index = 0
                                            for k in pairs(target_folder) do
                                                if type(k) == "number" and k > max_index then
                                                    max_index = k
                                                end
                                            end
                                            target_folder[max_index + 1] = fx_name
                                            SaveCustomFolders()
                                            r.ShowMessageBox("Plugin added to " .. folder_name, "Success", 0)
                                        else
                                            r.ShowMessageBox("Plugin already exists in " .. folder_name, "Info", 0)
                                        end
                                    end
                                end
                                r.ImGui_Separator(ctx)
                                ShowCustomFolderMenu(folder_content, full_path)
                                r.ImGui_EndMenu(ctx)
                            end
                        else
                            if r.ImGui_MenuItem(ctx, folder_name .. " (" .. plugin_count .. ")") then
                                local target = config.custom_folders
                                if path_prefix ~= "" then
                                    for folder in path_prefix:gmatch("[^/]+") do
                                        target = target[folder]
                                        if not target then break end
                                    end
                                end
                                
                                if target and target[folder_name] then
                                    local target_folder = target[folder_name]
                                    
                                    local already_exists = false
                                    for k, v in pairs(target_folder) do
                                        if type(k) == "number" and v == fx_name then
                                            already_exists = true
                                            break
                                        end
                                    end
                                    
                                    if not already_exists then
                                        local max_index = 0
                                        for k in pairs(target_folder) do
                                            if type(k) == "number" and k > max_index then
                                                max_index = k
                                            end
                                        end
                                        target_folder[max_index + 1] = fx_name
                                        SaveCustomFolders()
                                    end
                                end
                            end
                        end
                    end
                end
                
                ShowCustomFolderMenu(config.custom_folders)
                
                r.ImGui_Separator(ctx)
                if r.ImGui_MenuItem(ctx, "Create New Folder...") then
                    show_create_folder_popup = true
                    new_folder_for_plugin = fx_name
                end
                
                r.ImGui_EndMenu(ctx)
            end
        end

        r.ImGui_EndPopup(ctx)
    end
end

function ShowFolderDropdown()
    if config.screenshot_view_type == 3 then return end
    
    local folders_category
    for i = 1, #CAT_TEST do
        if CAT_TEST[i].name == "FOLDERS" then
            folders_category = CAT_TEST[i].list
            break
        end
    end

    if folders_category and #folders_category > 0 then
        r.ImGui_SetNextWindowSizeConstraints(ctx, 0, 0, FLT_MAX, config.dropdown_menu_length * r.ImGui_GetTextLineHeightWithSpacing(ctx))
        local window_width = r.ImGui_GetContentRegionAvail(ctx)
        local dropdown_width = 110  
        r.ImGui_PushItemWidth(ctx, dropdown_width)
        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FrameRounding(), 2)   
        
        if r.ImGui_BeginCombo(ctx, "##FolderDropdown", selected_folder or "Select Folder") then
        
                if r.ImGui_Selectable(ctx, "Select Folder", selected_folder == nil) then
                    SelectFolderExclusive(nil)
                    screenshot_search_results = nil
                    RequestClearScreenshotCache()
                end

            if config.show_favorites and r.ImGui_Selectable(ctx, "Favorites", selected_folder == "Favorites") then
                SelectFolderExclusive("Favorites")
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                screenshot_search_results = nil
                RequestClearScreenshotCache()
                GetPluginsForFolder(selected_folder)
            end
            if r.ImGui_Selectable(ctx, "Current Track FX", selected_folder == "Current Track FX") then
                SelectFolderExclusive("Current Track FX")
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                RequestClearScreenshotCache()
                GetPluginsForFolder("Current Track FX")
            end
            
            if r.ImGui_Selectable(ctx, "Current Project FX", selected_folder == "Current Project FX") then
                SelectFolderExclusive("Current Project FX")
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                RequestClearScreenshotCache()
                screenshot_search_results = nil
                GetPluginsForFolder("Current Project FX") -- Forceer het laden
                current_filtered_fx = nil -- Reset filtered fx
            end
            if config.show_projects and r.ImGui_Selectable(ctx, "Projects", selected_folder == "Projects") then
                SelectFolderExclusive("Projects")
                show_media_browser = true
                show_sends_window = false
                show_action_browser = false
                RequestClearScreenshotCache()
            end
            if config.show_sends and r.ImGui_Selectable(ctx, "Sends/Receives", selected_folder == "Sends/Receives") then
                SelectFolderExclusive("Sends/Receives")
                show_media_browser = false
                show_sends_window = true
                show_action_browser = false
                RequestClearScreenshotCache()
            end
            if config.show_actions and r.ImGui_Selectable(ctx, "Actions", selected_folder == "Actions") then
                SelectFolderExclusive("Actions")
                show_media_browser = false
                show_sends_window = false
                show_action_browser = true
                ClearScreenshotCache()
            end
            if config.show_scripts and r.ImGui_Selectable(ctx, "Scripts", selected_folder == "Scripts") then
                SelectFolderExclusive("Scripts")
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                show_scripts_browser = true
                ClearScreenshotCache()
            end
            if r.ImGui_Selectable(ctx, "Notes", selected_folder == "Notes") then
                LaunchTKNotes()
            end

            
            r.ImGui_Separator(ctx)
          
            if config.show_folders then
                for i = 1, #folders_category do
                    local is_selected = (selected_folder == folders_category[i].name)
                    if r.ImGui_Selectable(ctx, folders_category[i].name .. "##folder_" .. i, is_selected) then
                        SelectFolderExclusive(folders_category[i].name)
                        browser_panel_selected = nil
                        UpdateLastViewedFolder(selected_folder)
                        screenshot_search_results = nil
                        show_media_browser = false
                        show_sends_window = false
                        show_action_browser = false
                        show_scripts_browser = false
                        folder_page_state[folders_category[i].name] = 1
                        ClearScreenshotCache()
                        GetPluginsForFolder(selected_folder)
                    end
                    if r.ImGui_IsItemClicked(ctx, 1) then
                        _nf_ctx_folder_name = folders_category[i].name
                        _nf_ctx_folder_idx = nil
                        local nf = GetNativeFolderNames()
                        for _, entry in ipairs(nf) do
                            if entry.name == _nf_ctx_folder_name then _nf_ctx_folder_idx = entry.idx break end
                        end
                        r.ImGui_OpenPopup(ctx, "NativeFolderCtxMenu")
                    end
                    if config.use_pagination and view_mode ~= "list" then
                        local total = #(GetPluginsForFolder(folders_category[i].name) or {})
                        local total_pages = math.max(1, math.ceil(total / ITEMS_PER_PAGE))
                        if total_pages > 1 then
                            local page = folder_page_state[folders_category[i].name] or 1
                            r.ImGui_Indent(ctx, 20)
                            if r.ImGui_Button(ctx, "<##fp_" .. i, 15, 15) then
                                folder_page_state[folders_category[i].name] = page > 1 and page - 1 or total_pages
                                if is_selected then RequestClearScreenshotCache() end
                            end
                            r.ImGui_SameLine(ctx)
                            r.ImGui_Text(ctx, string.format("%d/%d", page, total_pages))
                            r.ImGui_SameLine(ctx)
                            if r.ImGui_Button(ctx, ">##fn_" .. i, 15, 15) then
                                folder_page_state[folders_category[i].name] = page < total_pages and page + 1 or 1
                                if is_selected then RequestClearScreenshotCache() end
                            end
                            r.ImGui_Unindent(ctx, 20)
                        end
                    end
                end
            end

            if r.ImGui_BeginPopup(ctx, "NativeFolderCtxMenu") then
                if _nf_ctx_folder_idx then
                    if r.ImGui_MenuItem(ctx, "Rename Folder") then
                        show_rename_native_folder_popup = true
                        rename_native_folder_idx = _nf_ctx_folder_idx
                        rename_native_folder_name = _nf_ctx_folder_name or ""
                    end
                    local is_smart = IsNativeSmartFolder(_nf_ctx_folder_idx)
                    if is_smart then
                        if r.ImGui_MenuItem(ctx, "Edit Smart Folder") then
                            show_smart_folder_popup = true
                            smart_folder_edit_idx = _nf_ctx_folder_idx
                            smart_folder_edit_name = _nf_ctx_folder_name
                            smart_folder_edit_query = GetNativeSmartFolderQuery(_nf_ctx_folder_idx) or ""
                            smart_folder_preview_dirty = true
                        end
                    end
                    if r.ImGui_MenuItem(ctx, "Delete Folder") then
                        pending_delete_native_folder_idx = _nf_ctx_folder_idx
                        pending_delete_native_folder_name = _nf_ctx_folder_name
                        show_delete_native_folder_popup = true
                    end
                end
                r.ImGui_Separator(ctx)
                if r.ImGui_MenuItem(ctx, "Create New Native Folder...") then
                    show_native_folder_create_popup = true
                    new_native_folder_for_plugin = nil
                    new_native_folder_name = ""
                end
                if r.ImGui_MenuItem(ctx, "Create Smart Folder...") then
                    show_smart_folder_popup = true
                    smart_folder_edit_idx = nil
                    smart_folder_edit_name = ""
                    smart_folder_edit_query = ""
                    smart_folder_preview_results = {}
                end
                r.ImGui_EndPopup(ctx)
            end

            r.ImGui_EndCombo(ctx)
     
        end
        r.ImGui_PopStyleVar(ctx)  
        r.ImGui_PopItemWidth(ctx)
        if r.ImGui_IsItemHovered(ctx) then
            local wheel_delta = r.ImGui_GetMouseWheel(ctx)
            if wheel_delta ~= 0 then
                local current_index = 0
                for i, folder in ipairs(folders_category) do
                    if folder.name == selected_folder then
                        current_index = i
                        break
                    end
                end
                current_index = current_index - wheel_delta
                if current_index < 1 then
                    current_index = #folders_category
                elseif current_index > #folders_category then
                    current_index = 1
                end
                SelectFolderExclusive(folders_category[current_index].name)
                UpdateLastViewedFolder(selected_folder)
                screenshot_search_results = nil
                ClearScreenshotCache()
                GetPluginsForFolder(selected_folder)
            end
        end
    
    end
end

function ShowCustomFolderDropdown(is_vertical_layout)
    if next(config.custom_folders) then
        -- Use the passed parameter to determine layout (avoids re-measuring width)
        if not is_vertical_layout then
            r.ImGui_SameLine(ctx)
            r.ImGui_PushItemWidth(ctx, 110)
        else
            -- Reserve 25px on the right for settings button
            r.ImGui_PushItemWidth(ctx, -25)
        end
        r.ImGui_SetNextWindowSizeConstraints(ctx, 0, 0, FLT_MAX, config.dropdown_menu_length * r.ImGui_GetTextLineHeightWithSpacing(ctx))
        
        if r.ImGui_BeginCombo(ctx, "##CustomFolderDropdown", "Custom") then
            -- Recursive functie om nested folders te tonen (MET SORTERING)
            local function ShowNestedFolders(folders, prefix)
                -- SORTEER DE FOLDER NAMEN ALFABETISCH
                local sorted_folder_names = {}
                for folder_name, _ in pairs(folders) do
                    if type(folder_name) == "string" then
                        table.insert(sorted_folder_names, folder_name)
                    end
                end
                table.sort(sorted_folder_names, function(a, b) 
                    return a:lower() < b:lower() 
                end)
                
                -- GEBRUIK DE GESORTEERDE NAMEN
                for _, folder_name in ipairs(sorted_folder_names) do
                    local folder_content = folders[folder_name]
                    local full_path = prefix == "" and folder_name or (prefix .. "/" .. folder_name)
                    
                    if IsPluginArray(folder_content) then
                        local display_name = prefix == "" and folder_name or ("  " .. folder_name)
                        if r.ImGui_Selectable(ctx, display_name .. " (" .. #folder_content .. ")", selected_folder == full_path) then
                            SelectFolderExclusive(full_path)
                            show_media_browser = false
                            show_sends_window = false
                            show_action_browser = false
                            screenshot_search_results = {}
                            for _, plugin in ipairs(folder_content) do
                                table.insert(screenshot_search_results, {name = plugin})
                            end
                            ClearScreenshotCache()
                        end
                    elseif IsSubfolderStructure(folder_content) then
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x888888FF)
                        r.ImGui_Text(ctx, (prefix == "" and "" or "  ") .. folder_name .. " >")
                        r.ImGui_PopStyleColor(ctx)
                        
                        ShowNestedFolders(folder_content, full_path)
                    end
                end
            end
            
            ShowNestedFolders(config.custom_folders, "")
            r.ImGui_EndCombo(ctx)
        end
        r.ImGui_PopItemWidth(ctx)
    end
end

-- Forward declare helper so functions above can reference it as a local upvalue
local SortPlainPluginList

function SortScreenshotResults()
    if screenshot_search_results and #screenshot_search_results > 0 then
        local mode = (config and config.sort_mode) or screenshot_sort_mode or "alphabet"
        local names = {}
        for _, e in ipairs(screenshot_search_results) do
            if type(e) == 'table' and e.name and not e.is_message then
                names[#names+1] = e.name
            end
        end
        local pinned, favorites, others = {}, {}, {}
        for _, n in ipairs(names) do
            if IsPluginPinned and IsPluginPinned(n) then
                pinned[#pinned+1] = n
            elseif favorite_set and favorite_set[n] then
                favorites[#favorites+1] = n
            else
                others[#others+1] = n
            end
        end
        SortPlainPluginList(pinned, mode)
        if config and config.show_favorites_on_top then
            SortPlainPluginList(favorites, mode)
        end
        SortPlainPluginList(others, mode)
        local ordered = {}
        if config and config.show_pinned_on_top then
            for _, n in ipairs(pinned) do ordered[#ordered+1] = {name = n} end
            if #pinned > 0 and ((config and config.show_favorites_on_top and (#favorites>0 or #others>0)) or (not (config and config.show_favorites_on_top) and #others>0)) then
                ordered[#ordered+1] = { is_separator = true, kind = "pinned_end" }
            end
        end
        if config and config.show_favorites_on_top then
            for _, n in ipairs(favorites) do ordered[#ordered+1] = {name = n} end
            if #favorites > 0 and #others > 0 then
                ordered[#ordered+1] = { is_separator = true, kind = "favorites_end" }
            end
        else
            for _, n in ipairs(favorites) do others[#others+1] = n end
        end
        if not (config and config.show_pinned_on_top) then
            for _, n in ipairs(pinned) do others[#others+1] = n end
        end
        for _, n in ipairs(others) do ordered[#ordered+1] = {name = n} end
        screenshot_search_results = ordered
    end
end

function SearchAllPlugins()
    screenshot_search_results = {}
    local MAX_RESULTS = 250
    local term = (browser_search_term or "")
    
    if term == "" then
        search_warning_message = nil
        new_search_performed = true
        RequestClearScreenshotCache()
        return
    end
    
    if selected_folder then
        last_selected_folder_before_global = selected_folder
        last_panel_before_global = nil
    elseif browser_panel_selected then
        last_panel_before_global = browser_panel_selected
        last_selected_folder_before_global = nil
    end
    
    local term_lower = term:lower()
    local matches = {}
    
    for _, plugin in ipairs(PLUGIN_LIST) do
        if FuzzyFind(plugin, term_lower) then
            matches[#matches+1] = plugin
        end
    end
    
    if config.apply_type_priority then
        matches = DedupeByTypePriority(matches)
    end
    
    local total = #matches
    local limit = math.min(total, MAX_RESULTS)
    for i = 1, limit do
        screenshot_search_results[#screenshot_search_results+1] = { name = matches[i] }
    end
    
    SortScreenshotResults()
    
    if total > MAX_RESULTS then
        search_warning_message = "First " .. MAX_RESULTS .. " results. Refine your search for more results."
    else
        search_warning_message = nil
    end
    
    new_search_performed = true
    selected_folder = nil
    browser_panel_selected = nil
    RequestClearScreenshotCache()
end

function ClearSearch()
    browser_search_term = ""
    search_warning_message = nil
    
    if last_panel_before_global then
        local sg = last_panel_before_global
        last_panel_before_global = nil
        browser_panel_selected = sg
        selected_folder = nil
        MarkForcedHeaderForSubgroup(sg)
        current_filtered_fx = GetFxListForSubgroup(sg) or {}
        if config.apply_type_priority then
            current_filtered_fx = DedupeByTypePriority(current_filtered_fx)
        end
        screenshot_search_results = {}
        local cap = loaded_items_count or ITEMS_PER_BATCH or 30
        for j = 1, math.min(cap, #current_filtered_fx) do
            table.insert(screenshot_search_results, {name = current_filtered_fx[j]})
        end
        SortScreenshotResults()
        RequestClearScreenshotCache()
        new_search_performed = true
        return
    end

    if last_selected_folder_before_global then
        selected_folder = last_selected_folder_before_global
        last_selected_folder_before_global = nil
        screenshot_search_results = nil
        current_filtered_fx = GetPluginsForFolder(selected_folder) or {}
        if config.apply_type_priority then
            current_filtered_fx = DedupeByTypePriority(current_filtered_fx)
        end
        RequestClearScreenshotCache()
        new_search_performed = true
        return
    end
    
    if config.always_search_all then
        SearchAllPlugins()
    else
        screenshot_search_results = {}
        if current_filtered_fx and #current_filtered_fx > 0 then
            for _, plugin in ipairs(current_filtered_fx) do
                table.insert(screenshot_search_results, {name = plugin})
            end
        elseif selected_folder then
            local filtered_plugins = GetPluginsForFolder(selected_folder)
            for _, plugin in ipairs(filtered_plugins) do
                table.insert(screenshot_search_results, {name = plugin})
            end
        end
        SortScreenshotResults()
        RequestClearScreenshotCache()
        new_search_performed = true
    end
end

function SortPlainPluginList(list, mode)
    local default_type_order = {"VST3", "VST", "CLAP", "JS", "AU", "LV2", "OTHER"}
    if not config.type_order then config.type_order = default_type_order end
    if not list or #list == 0 then return end
    local effective_mode = mode or screenshot_sort_mode or "alphabet"
    if effective_mode == "rating" then
        t_sort(list, function(a,b)
            local ra = plugin_ratings[a] or 0
            local rb = plugin_ratings[b] or 0
            if ra == rb then
                return GetLowerName(a) < GetLowerName(b)
            else
                return ra > rb
            end
        end)
    elseif effective_mode == "type" then
        -- FIX: Maak de order-tabel ÉÉN keer aan VOOR de sortering
        local type_order_map = {}
        for i, t in ipairs(config.type_order) do type_order_map[t] = i end

        t_sort(list, function(a,b)
            local ta = GetPluginType(a)
            local tb = GetPluginType(b)
            if ta == tb then
                return GetLowerName(a) < GetLowerName(b)
            else
                -- Gebruik de vooraf berekende map
                return (type_order_map[ta] or 99) < (type_order_map[tb] or 99)
            end
        end)
    else 
        table.sort(list, function(a,b) 
            return GetLowerName(a) < GetLowerName(b)
        end)
    end
end

function ShowScreenshotControls()
    local show_type_order_popup = false
    local show_customize_popup = false
    local layout = config.screenshot_controls_layout or "horizontal"
    local available_width = r.ImGui_GetContentRegionAvail(ctx)
    
    local auto_vertical = (layout == "auto" and available_width < 300)
    local is_vertical = (layout == "vertical" or auto_vertical)
    
    if layout == "vertical" or auto_vertical then
        -- VERTICAL LAYOUT
        -- Reserve space on the right for settings button (25px)
        local right_margin = 25
        
        -- If dropdown is hidden, add spacing to avoid overlap with settings button
        if config.screenshot_view_type == 3 then
            r.ImGui_Dummy(ctx, 0, 22)
        end
        r.ImGui_PushItemWidth(ctx, -right_margin)
        ShowFolderDropdown()
        r.ImGui_PopItemWidth(ctx)
        
        if not config.hide_custom_dropdown then
            ShowCustomFolderDropdown(true)  -- Pass true for vertical layout
        end
        
        show_screenshot_search = config.show_screenshot_search ~= false
        if show_screenshot_search then
            -- Buttons: Sort(20) + spacing(4) + All(30) = 54, plus right_margin to align with dropdown
            local button_space = 58 + right_margin
            if browser_search_term ~= "" then button_space = 83 + right_margin end  -- +25 for X button
            local search_width = r.ImGui_GetContentRegionAvail(ctx) - button_space
            
            r.ImGui_PushItemWidth(ctx, search_width)
            local search_input_flags = 0
            if screenshot_search_autoselect then
                search_input_flags = r.ImGui_InputTextFlags_AutoSelectAll()
            end
            if screenshot_search_focus_requested then
                r.ImGui_SetKeyboardFocusHere(ctx)
                screenshot_search_focus_requested = false
            end
            local changed, new_search = r.ImGui_InputTextWithHint(ctx, "##ScreenshotSearch", "Search...", browser_search_term, search_input_flags)
            if screenshot_search_autoselect and r.ImGui_IsItemActive(ctx) then
                screenshot_search_autoselect = false
            end
            if r.ImGui_IsItemActive(ctx) and r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_DownArrow()) and not screenshot_nav_index then
                screenshot_search_to_nav = true
                screenshot_search_blur_requested = true
            end
            r.ImGui_PopItemWidth(ctx)
            
            local btn_color, btn_hover, btn_active, btn_text = GetButtonColors()
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), btn_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), btn_hover)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), btn_active)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), btn_text)
            if browser_search_term ~= "" then
                r.ImGui_SameLine(ctx)
                if r.ImGui_Button(ctx, "X", 17, r.ImGui_GetFrameHeight(ctx)) then
                    ClearSearch()
                end
                if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Clear search") end
            end
            
            r.ImGui_SameLine(ctx)
            screenshot_sort_mode = screenshot_sort_mode or "alphabet"
            local effective_mode = (config and config.sort_mode) or screenshot_sort_mode
            local sort_label = (effective_mode == "alphabet") and "A" or (effective_mode == "rating") and "R" or "P"
            local button_height = r.ImGui_GetFrameHeight(ctx)
            if r.ImGui_Button(ctx, sort_label, 17, button_height) then
                local next_mode
                if effective_mode == "alphabet" then
                    next_mode = "rating"
                elseif effective_mode == "rating" then
                    next_mode = "type"
                else
                    next_mode = "alphabet"
                end
                if config then
                    config.sort_mode = next_mode
                    if SaveConfig then SaveConfig() end
                else
                    screenshot_sort_mode = next_mode
                end
                SortScreenshotResults()
            end
            if r.ImGui_IsItemClicked(ctx, r.ImGui_MouseButton_Right()) then
                show_type_order_popup = true
            end
            if r.ImGui_IsItemHovered(ctx) then
                if effective_mode == "alphabet" then
                    r.ImGui_SetTooltip(ctx, "Alphabetic sorting (click to switch to Rating)")
                elseif effective_mode == "rating" then
                    r.ImGui_SetTooltip(ctx, "Rating sorting (click to switch to Prefix)")
                else
                    r.ImGui_SetTooltip(ctx, "Prefix sorting (click to switch to Alphabetic)")
                end
            end
            
            r.ImGui_SameLine(ctx)
            local all_disabled = browser_search_term == ""
            if all_disabled then
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x666666FF)
            end
            if r.ImGui_Button(ctx, "All", 30, 17) and not all_disabled then
                SearchAllPlugins()
            end
            if all_disabled then
                r.ImGui_PopStyleColor(ctx, 1)
            end
            if r.ImGui_IsItemHovered(ctx) then
                r.ImGui_SetTooltip(ctx, "Search all plugins (ignores folder selection)")
            end
            r.ImGui_PopStyleColor(ctx, 4)
            ConsumeScreenshotSearchBlur("##ScreenshotSearchBlurMain")

            if changed then
                screenshot_folder_filter_suspended = false
                if screenshot_search_replace_requested and browser_search_term ~= "" and new_search:sub(1, #browser_search_term) == browser_search_term then
                    new_search = new_search:sub(#browser_search_term + 1)
                end
                screenshot_search_replace_requested = false
                browser_search_term = new_search
                if config.flicker_guard_enabled then _last_search_input_time = r.time_precise() end
                
                if config.always_search_all then
                    SearchAllPlugins()
                elseif browser_search_term == "" then
                    screenshot_search_results = {}
                    search_warning_message = nil
                    if current_filtered_fx and #current_filtered_fx > 0 then
                        for _, plugin in ipairs(current_filtered_fx) do
                            table.insert(screenshot_search_results, {name = plugin})
                        end
                    elseif selected_folder then
                        local filtered_plugins = GetPluginsForFolder(selected_folder)
                        for _, plugin in ipairs(filtered_plugins) do
                            table.insert(screenshot_search_results, {name = plugin})
                        end
                    end
                    SortScreenshotResults()
                    RequestClearScreenshotCache()
                    new_search_performed = true
                else
                    screenshot_search_results = {}
                    loaded_items_count = ITEMS_PER_BATCH
                    search_warning_message = nil
                    local MAX_RESULTS = 200
                    local too_many_results = false
                    local source_list = nil
                    if current_filtered_fx and #current_filtered_fx > 0 then
                        source_list = current_filtered_fx
                    elseif selected_folder or browser_panel_selected then
                        local folder_to_search = browser_panel_selected or selected_folder
                        source_list = GetPluginsForFolder(folder_to_search)
                    end
                    current_filtered_fx = {}
                    if source_list then
                        local count = 0
                        local term_l = browser_search_term:lower()
