    if r.ImGui_BeginPopup(ctx, "CustomizeOrderPopup") then
        r.ImGui_Text(ctx, "Use buttons to reorder:")
        for i, t in ipairs(config.type_order) do
            r.ImGui_Text(ctx, tostring(i) .. ". " .. t)
            r.ImGui_SameLine(ctx)
            if i > 1 and r.ImGui_Button(ctx, "Up##" .. i, 30, 0) then
                config.type_order[i], config.type_order[i-1] = config.type_order[i-1], config.type_order[i]
                SaveConfig()
            end
            r.ImGui_SameLine(ctx)
            if i < #config.type_order and r.ImGui_Button(ctx, "Down##" .. i, 40, 0) then
                config.type_order[i], config.type_order[i+1] = config.type_order[i+1], config.type_order[i]
                SaveConfig()
            end
        end
        if r.ImGui_Button(ctx, "Reset to Default", -1, 0) then
            config.type_order = {"VST3", "VST", "CLAP", "JS", "AU", "LV2", "OTHER"}
            SaveConfig()
        end
        r.ImGui_EndPopup(ctx)
    end
    
    return is_vertical
end

function DrawFxChains(tbl, path, show_hover_preview)
    local extension = ".RfxChain"
    path = path or ""
    if show_hover_preview == nil then show_hover_preview = true end  -- Default to showing preview
    local i = 1
    while i <= #tbl do
        local item = tbl[i]
        if type(item) == "table" and item.dir then
            -- SUBMAPPEN HANDELEN
            r.ImGui_SetNextWindowSize(ctx, MAX_SUBMENU_WIDTH, 0)  
            r.ImGui_SetNextWindowBgAlpha(ctx, config.window_alpha)
            reaper.ImGui_PushStyleColor(ctx, reaper.ImGui_Col_PopupBg(), config.background_color) 
            if r.ImGui_BeginMenu(ctx, item.dir) then               
                -- RECURSIEF SUBMAPPEN DOORLOPEN
                DrawFxChains(item, table.concat({ path, os_separator, item.dir }), show_hover_preview)              
                r.ImGui_EndMenu(ctx)               
            end  
            reaper.ImGui_PopStyleColor(ctx)
        elseif type(item) == "string" then
            -- NORMALE FX CHAIN FILES
            if r.ImGui_Selectable(ctx, item .. "##fxchain_" .. i) then
                -- Show FX Chain in screenshot window instead of adding directly
                local fx_chains_path = ResolveFxChainsRoot()
                local chain_file_path = fx_chains_path .. path .. os_separator .. item .. extension
                local relative_path = table.concat({ path, os_separator, item, extension })
                
                -- Parse the FX chain and show in screenshot window
                ShowFxChainInScreenshotWindow(chain_file_path, relative_path, item)
                show_screenshot_window = true
                screenshot_window_interactive = true
            end
            
            -- FX CHAIN HOVER PREVIEW (alleen als show_hover_preview enabled is)
            if show_hover_preview and r.ImGui_IsItemHovered(ctx) then
                local fx_chains_path = ResolveFxChainsRoot()
                local chain_file_path = fx_chains_path .. path .. os_separator .. item .. extension
                ShowFxChainPreview(chain_file_path, item)
            end
            
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "FXChainOptions_" .. i)
            end
            if r.ImGui_BeginPopup(ctx, "FXChainOptions_" .. i) then
                if r.ImGui_MenuItem(ctx, "Add to selected track(s)") then
                    local fx_chains_path = ResolveFxChainsRoot()
                    local chain_file_path = table.concat({ path, os_separator, item, extension })
                    if ADD_FX_TO_ITEM then
                        local selected_item = r.GetSelectedMediaItem(0, 0)
                        if selected_item then
                            local take = r.GetActiveTake(selected_item)
                            if take then
                                r.TakeFX_AddByName(take, chain_file_path, 1)
                            end
                        end
                    else
                        local selected_track_count = r.CountSelectedTracks(0)
                        if selected_track_count > 0 then
                            for i = 0, selected_track_count - 1 do
                                local track = r.GetSelectedTrack(0, i)
                                if track and r.ValidatePtr(track, "MediaTrack*") then
                                    AddFXToTrack(track, chain_file_path)
                                end
                            end
                            if config.close_after_adding_fx then
                                SHOULD_CLOSE_SCRIPT = true
                            end
                        end
                    end
                end
                if r.ImGui_MenuItem(ctx, "Replace selected track(s) FX") then
                    local fx_chains_path = ResolveFxChainsRoot()
                    local chain_file_path = table.concat({ path, os_separator, item, extension })
                    local selected_track_count = r.CountSelectedTracks(0)
                    if selected_track_count > 0 then
                        for i = 0, selected_track_count - 1 do
                            local track = r.GetSelectedTrack(0, i)
                            if track and r.ValidatePtr(track, "MediaTrack*") then
                                -- Remove all FX from track first
                                local fx_count = r.TrackFX_GetCount(track)
                                for j = fx_count - 1, 0, -1 do
                                    r.TrackFX_Delete(track, j)
                                end
                                -- Then add the FX chain
                                AddFXToTrack(track, chain_file_path)
                            end
                        end
                        if config.close_after_adding_fx then
                            SHOULD_CLOSE_SCRIPT = true
                        end
                    else
                        r.ShowMessageBox("No tracks selected. Please select one or more tracks first.", "Replace FX", 0)
                    end
                end
                if r.ImGui_MenuItem(ctx, "Rename") then
                    local retval, new_name = r.GetUserInputs("Rename FX Chain", 1, "New name:", item)
                    if retval then
                        local fx_chains_path = ResolveFxChainsRoot()
                        local old_path = fx_chains_path .. path .. os_separator .. item .. extension
                        local new_path = fx_chains_path .. path .. os_separator .. new_name .. extension
                        if os.rename(old_path, new_path) then
                            tbl[i] = new_name
                            FX_LIST_TEST, CAT_TEST = MakeFXFiles()  
                            r.ShowMessageBox("FX Chain renamed", "Success", 0)
                        else
                            r.ShowMessageBox("Could not rename FX Chain", "Error", 0)
                        end
                    end
                end
                if r.ImGui_MenuItem(ctx, "Delete") then
                    local fx_chains_path = ResolveFxChainsRoot()
                    local file_path = fx_chains_path .. path .. os_separator .. item .. extension
                    if os.remove(file_path) then
                        table.remove(tbl, i)
                        FX_LIST_TEST, CAT_TEST = MakeFXFiles() 
                        r.ShowMessageBox("FX Chain deleted", "Success", 0)
                        i = i - 1  -- Pas de index aan omdat we een element hebben verwijderd
                    else
                        r.ShowMessageBox("Could not delete FX Chain", "Error", 0)
                    end
                end
                r.ImGui_EndPopup(ctx)
            end
        elseif type(item) == "table" and not item.dir then
            for j = 1, #item do
                if type(item[j]) == "string" then
                    if r.ImGui_Selectable(ctx, item[j] .. "##fxchain_" .. i .. "_" .. j) then
                        -- Show FX Chain in screenshot window instead of adding directly
                        local fx_chains_path = ResolveFxChainsRoot()
                        local chain_file_path = fx_chains_path .. path .. os_separator .. item[j] .. extension
                        local relative_path = table.concat({ path, os_separator, item[j], extension })
                        
                        -- Parse the FX chain and show in screenshot window
                        ShowFxChainInScreenshotWindow(chain_file_path, relative_path, item[j])
                        show_screenshot_window = true
                        screenshot_window_interactive = true
                    end
                    
                    -- FX CHAIN HOVER PREVIEW (alleen als show_hover_preview enabled is)
                    if show_hover_preview and r.ImGui_IsItemHovered(ctx) then
                        local fx_chains_path = ResolveFxChainsRoot()
                        local chain_file_path = fx_chains_path .. path .. os_separator .. item[j] .. extension
                        ShowFxChainPreview(chain_file_path, item[j])
                    end
                    
                    if r.ImGui_IsItemClicked(ctx, 1) then
                        r.ImGui_OpenPopup(ctx, "FXChainOptions_" .. i .. "_" .. j)
                    end
                    if r.ImGui_BeginPopup(ctx, "FXChainOptions_" .. i .. "_" .. j) then
                        if r.ImGui_MenuItem(ctx, "Add to selected track(s)") then
                            local fx_chains_path = ResolveFxChainsRoot()
                            local chain_file_path = table.concat({ path, os_separator, item[j], extension })
                            if ADD_FX_TO_ITEM then
                                local selected_item = r.GetSelectedMediaItem(0, 0)
                                if selected_item then
                                    local take = r.GetActiveTake(selected_item)
                                    if take then
                                        r.TakeFX_AddByName(take, chain_file_path, 1)
                                    end
                                end
                            else
                                local selected_track_count = r.CountSelectedTracks(0)
                                if selected_track_count > 0 then
                                    for k = 0, selected_track_count - 1 do
                                        local track = r.GetSelectedTrack(0, k)
                                        if track and r.ValidatePtr(track, "MediaTrack*") then
                                            AddFXToTrack(track, chain_file_path)
                                        end
                                    end
                                    if config.close_after_adding_fx then
                                        SHOULD_CLOSE_SCRIPT = true
                                    end
                                end
                            end
                        end
                        if r.ImGui_MenuItem(ctx, "Replace selected track(s) FX") then
                            local fx_chains_path = ResolveFxChainsRoot()
                            local chain_file_path = table.concat({ path, os_separator, item[j], extension })
                            local selected_track_count = r.CountSelectedTracks(0)
                            if selected_track_count > 0 then
                                for k = 0, selected_track_count - 1 do
                                    local track = r.GetSelectedTrack(0, k)
                                    if track and r.ValidatePtr(track, "MediaTrack*") then
                                        -- Remove all FX from track first
                                        local fx_count = r.TrackFX_GetCount(track)
                                        for m = fx_count - 1, 0, -1 do
                                            r.TrackFX_Delete(track, m)
                                        end
                                        -- Then add the FX chain
                                        AddFXToTrack(track, chain_file_path)
                                    end
                                end
                                if config.close_after_adding_fx then
                                    SHOULD_CLOSE_SCRIPT = true
                                end
                            else
                                r.ShowMessageBox("No tracks selected. Please select one or more tracks first.", "Replace FX", 0)
                            end
                        end
                        if r.ImGui_MenuItem(ctx, "Rename") then
                            local retval, new_name = r.GetUserInputs("Rename FX Chain", 1, "New name:", item[j])
                            if retval then
                                local fx_chains_path = ResolveFxChainsRoot()
                                local old_path = fx_chains_path .. path .. os_separator .. item[j] .. extension
                                local new_path = fx_chains_path .. path .. os_separator .. new_name .. extension
                                if os.rename(old_path, new_path) then
                                    item[j] = new_name
                                    FX_LIST_TEST, CAT_TEST = MakeFXFiles()  
                                    r.ShowMessageBox("FX Chain renamed", "Success", 0)
                                else
                                    r.ShowMessageBox("Could not rename FX Chain", "Error", 0)
                                end
                            end
                        end
                        if r.ImGui_MenuItem(ctx, "Delete") then
                            local fx_chains_path = ResolveFxChainsRoot()
                            local file_path = fx_chains_path .. path .. os_separator .. item[j] .. extension
                            if os.remove(file_path) then
                                table.remove(item, j)
                                FX_LIST_TEST, CAT_TEST = MakeFXFiles() 
                                r.ShowMessageBox("FX Chain deleted", "Success", 0)
                            else
                                r.ShowMessageBox("Could not delete FX Chain", "Error", 0)
                            end
                        end
                        r.ImGui_EndPopup(ctx)
                    end
                end
            end
        end
        i = i + 1
    end
end

function LoadTemplate(template_path)
    local full_path = ResolveTrackTemplatesRoot() .. template_path
    if r.file_exists(full_path) then
        local track_count = r.CountTracks(0)
        r.PreventUIRefresh(1)
        r.Undo_BeginBlock()
        r.Main_openProject(full_path, 1)
        local new_track = r.GetTrack(0, track_count)
        if new_track then
            r.SetOnlyTrackSelected(new_track)
        end
        r.Undo_EndBlock("Load Track Template", -1)
        r.PreventUIRefresh(-1)
        r.UpdateArrange()
        r.TrackList_AdjustWindows(false)
        if config.close_after_adding_fx then
            SHOULD_CLOSE_SCRIPT = true
        end
        if config.hide_after_insert then
            SHOULD_HIDE_BROWSER = true
        end
    else
        r.ShowConsoleMsg("Template file not found: " .. full_path .. "\n")
    end
end

function DrawTrackTemplates(tbl, path)
    local extension = ".RTrackTemplate"
    path = path or ""
    local deleted = false
    
    for i = 1, #tbl do
        if deleted then break end
        
        if tbl[i].dir then
            if r.ImGui_BeginMenu(ctx, tbl[i].dir) then
                local cur_path = table.concat({ path, os_separator, tbl[i].dir })
                DrawTrackTemplates(tbl[i], cur_path)
                r.ImGui_EndMenu(ctx)
            end
        elseif type(tbl[i]) ~= "table" then
            if r.ImGui_Selectable(ctx, tbl[i] .. "##template_" .. i) then
                local template_str = table.concat({ path, os_separator, tbl[i], extension })
                LoadTemplate(template_str)
            end
            
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "TrackTemplateOptions_" .. i)
            end
            
            if r.ImGui_BeginPopup(ctx, "TrackTemplateOptions_" .. i) then
                if r.ImGui_MenuItem(ctx, "Rename") then
                    local retval, new_name = r.GetUserInputs("Rename Track Template", 1, "New name:", tbl[i])
                    if retval then
                        local templates_path = ResolveTrackTemplatesRoot()
                        local old_path = templates_path .. path .. os_separator .. tbl[i] .. extension
                        local new_path = templates_path .. path .. os_separator .. new_name .. extension
                        if os.rename(old_path, new_path) then
                            tbl[i] = new_name
                            FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                            r.ShowMessageBox("Track Template renamed", "Success", 0)
                        else
                            r.ShowMessageBox("Could not rename Track Template", "Error", 0)
                        end
                    end
                end
                
                if r.ImGui_MenuItem(ctx, "Delete") then
                    local templates_path = ResolveTrackTemplatesRoot()
                    local file_path = templates_path .. path .. os_separator .. tbl[i] .. extension
                    if os.remove(file_path) then
                        table.remove(tbl, i)
                        deleted = true
                        FX_LIST_TEST, CAT_TEST = MakeFXFiles()
                        r.ShowMessageBox("Track Template deleted", "Success", 0)
                    else
                        r.ShowMessageBox("Could not delete Track Template", "Error", 0)
                    end
                end
                r.ImGui_EndPopup(ctx)
            end
        end
    end
end

local function ApplyFolderPaginationSlice(plugins, folder_key)
    local total = #plugins
    local total_pages = math.max(1, math.ceil(total / ITEMS_PER_PAGE))
    local page = math.min(folder_page_state[folder_key] or 1, total_pages)
    folder_page_state[folder_key] = page
    local start_idx = (page - 1) * ITEMS_PER_PAGE + 1
    local end_idx = math.min(start_idx + ITEMS_PER_PAGE - 1, total)
    local sliced = {}
    for k = start_idx, end_idx do sliced[#sliced+1] = plugins[k] end
    return sliced, total
end

local function DrawFolderPaginationUI(folder_key, total_count)
    local total_pages = math.max(1, math.ceil(total_count / ITEMS_PER_PAGE))
    if total_pages <= 1 then return end
    local page = folder_page_state[folder_key] or 1
    r.ImGui_Dummy(ctx, 0, 4)
    r.ImGui_Indent(ctx, 20)
    if r.ImGui_Button(ctx, "<##fp_" .. folder_key, 15, 15) then
        folder_page_state[folder_key] = page > 1 and page - 1 or total_pages
        RequestClearScreenshotCache()
    end
    r.ImGui_SameLine(ctx)
    r.ImGui_Text(ctx, string.format("%d/%d", page, total_pages))
    r.ImGui_SameLine(ctx)
    if r.ImGui_Button(ctx, ">##fn_" .. folder_key, 15, 15) then
        folder_page_state[folder_key] = page < total_pages and page + 1 or 1
        RequestClearScreenshotCache()
    end
    r.ImGui_Unindent(ctx, 20)
end

function DrawBrowserItems(tbl, main_cat_name)
    local function EnsurePinnedList(cat)
        if not config.pinned_subgroups then config.pinned_subgroups = {} end
        if not config.pinned_subgroups[cat] then config.pinned_subgroups[cat] = {} end
        return config.pinned_subgroups[cat]
    end
    local function IsSubgroupPinned(cat, name)
        local lst = EnsurePinnedList(cat)
        for _, n in ipairs(lst) do if n == name then return true end end
        return false
    end
    local function PinSubgroup(cat, name)
        local lst = EnsurePinnedList(cat)
        if not IsSubgroupPinned(cat, name) then t_insert(lst, name); SavePinned() end
    end
    local function UnpinSubgroup(cat, name)
        local lst = EnsurePinnedList(cat)
        for i=#lst,1,-1 do if lst[i] == name then table.remove(lst, i); SavePinned(); break end end
    end
    local function BuildSubgroupDrawOrder(cat, items)
        local index_by_name = {}
        for i = 1, #items do index_by_name[items[i].name] = i end
        local order = {}
        local pinned = EnsurePinnedList(cat)
        for _, name in ipairs(pinned) do
            local idx = index_by_name[name]
            if idx then t_insert(order, idx) end
        end
        local pinned_set = {}
        for _, name in ipairs(pinned) do pinned_set[name] = true end
        for i = 1, #items do
            local nm = items[i].name
            if not pinned_set[nm] then t_insert(order, i) end
        end
        return order
    end

    local draw_order = BuildSubgroupDrawOrder(main_cat_name or "", tbl)
    
    -- Check of cache bestaat (veiligheid)
    if not global_search_cache or next(global_search_cache) == nil then BuildPluginCache() end

    for _, i in ipairs(draw_order) do
        local filtered_fx = {}
        local term_l = s_lower(browser_search_term)
        
        for _, fx in ipairs(tbl[i].fx) do
            local match = false
            if browser_search_term == "" then
                match = true
            else
                -- GEOPTIMALISEERD: Gebruik cache
                local data = global_search_cache[fx]
                if data then
                    if data.lower_name:find(term_l, 1, true) then
                        match = true
                    elseif data.lower_alias and data.lower_alias:find(term_l, 1, true) then
                        match = true
                    end
                else
                    -- Fallback
                    if s_lower(fx):find(term_l, 1, true) then match = true end
                end
            end
            
            if match then
                t_insert(filtered_fx, fx)
            end
        end

    filtered_fx = DedupeByTypePriority(filtered_fx)

    -- Apply subgroup ordering: pinned first, then favorites (optional), then others
    do
        local pinned = {}
        local favorites = {}
        local others = {}
        for _, fx in ipairs(filtered_fx) do
            if IsPluginPinned and IsPluginPinned(fx) then
                pinned[#pinned+1] = fx
            elseif favorite_set and favorite_set[fx] then
                favorites[#favorites+1] = fx
            else
                others[#others+1] = fx
            end
        end
        -- Sort each bucket by current sort mode (alphabet or rating)
        SortPlainPluginList(pinned, (config and config.sort_mode) or sort_mode or "alphabet")
        if config and config.show_favorites_on_top then
            SortPlainPluginList(favorites, (config and config.sort_mode) or sort_mode or "alphabet")
        end
        SortPlainPluginList(others, (config and config.sort_mode) or sort_mode or "alphabet")

        local reordered = {}
        
        -- Add pinned plugins first if show_pinned_on_top is enabled
        if config and config.show_pinned_on_top then
            for _, fx in ipairs(pinned) do reordered[#reordered+1] = fx end
        end
        
        if config and config.show_favorites_on_top then
            for _, fx in ipairs(favorites) do reordered[#reordered+1] = fx end
        else
            -- If not showing favorites on top, merge favorites into others
            for _, fx in ipairs(favorites) do others[#others+1] = fx end
        end
        
        -- Add pinned plugins to others if show_pinned_on_top is disabled
        if not (config and config.show_pinned_on_top) then
            for _, fx in ipairs(pinned) do others[#others+1] = fx end
        end
        
        for _, fx in ipairs(others) do reordered[#reordered+1] = fx end
        filtered_fx = reordered
    end

        if #filtered_fx > 0 then
            r.ImGui_PushID(ctx, i)
            r.ImGui_Indent(ctx, 10)
            local subgroup_name = tbl[i].name
            local header_text = subgroup_name
            if IsSubgroupPinned(main_cat_name or "", subgroup_name) then
                header_text = "\xF0\x9F\x93\x8C " .. header_text  -- "📌 "
            end
            local is_selected = (browser_panel_selected == tbl[i].name)
            if is_selected then
                local dl = r.ImGui_GetWindowDrawList(ctx)
                local x,y = r.ImGui_GetCursorScreenPos(ctx)
                local avail_w = r.ImGui_GetContentRegionAvail(ctx)
                local line_h = r.ImGui_GetTextLineHeightWithSpacing(ctx)
                r.ImGui_DrawList_AddRectFilled(dl, x-2, y, x + avail_w, y + line_h, 0xFF704030, 3)
            end
            if r.ImGui_Selectable(ctx, header_text .. "##browseritem_" .. i, is_selected) then
                SelectBrowserPanelItem(tbl[i].name)
                UpdateLastViewedFolder(tbl[i].name)
                loaded_items_count = ITEMS_PER_BATCH
                current_filtered_fx = filtered_fx 
                screenshot_search_results = {}
                if config.use_pagination then
                    local start_idx = (tbl[i].current_page - 1) * ITEMS_PER_PAGE + 1
                    local end_idx = math.min(start_idx + ITEMS_PER_PAGE - 1, #filtered_fx)
                    for j = start_idx, end_idx do
                        table.insert(screenshot_search_results, {name = filtered_fx[j]})
                    end
                    SortScreenshotResults()
                else
                    if view_mode == "list" then
                        for j = 1, #filtered_fx do
                            table.insert(screenshot_search_results, {name = filtered_fx[j]})
                        end
                    else
                        for j = 1, math.min(loaded_items_count, #filtered_fx) do
                            table.insert(screenshot_search_results, {name = filtered_fx[j]})
                        end
                    end
                    SortScreenshotResults()
                end
                ClearScreenshotCache()
            end
            r.ImGui_Unindent(ctx, 10)

            if not tbl[i].current_page then tbl[i].current_page = 1 end
            local total_pages = math.ceil(#filtered_fx / ITEMS_PER_PAGE)

            if r.ImGui_IsItemClicked(ctx, 1) then
                local popup_id = "browser_item_ctx_" .. tostring(main_cat_name or "") .. "_" .. i
                r.ImGui_OpenPopup(ctx, popup_id)
            end
            local popup_id = "browser_item_ctx_" .. tostring(main_cat_name or "") .. "_" .. i
            if r.ImGui_BeginPopup(ctx, popup_id) then
                local toggle_label = (view_mode == "screenshots" and "Show List" or "Show Screenshots")
                if r.ImGui_MenuItem(ctx, toggle_label) then
                    local previous_mode = view_mode
                    view_mode = (view_mode == "screenshots" and "list" or "screenshots")
                    config.view_mode = view_mode
                    SaveConfig()
                    if view_mode == "screenshots" then
                        if previous_mode ~= "screenshots" then RequestClearScreenshotCache() end
                    else
                        if current_filtered_fx and #current_filtered_fx > 0 then
                            screenshot_search_results = {}
                            for j = 1, #current_filtered_fx do
                                table.insert(screenshot_search_results, {name = current_filtered_fx[j]})
                            end
                        end
                    end
                end
                -- Pin / Unpin submenu
                if IsSubgroupPinned(main_cat_name or "", subgroup_name) then
                    if r.ImGui_MenuItem(ctx, "Unpin Subgroup") then
                        UnpinSubgroup(main_cat_name or "", subgroup_name)
                        if r.ImGui_CloseCurrentPopup then r.ImGui_CloseCurrentPopup(ctx) end
                    end
                else
                    if r.ImGui_MenuItem(ctx, "Pin Subgroup") then
                        PinSubgroup(main_cat_name or "", subgroup_name)
                        if r.ImGui_CloseCurrentPopup then r.ImGui_CloseCurrentPopup(ctx) end
                    end
                end
                if r.ImGui_MenuItem(ctx, "Capture Folder Screenshots") then
                    StartFolderScreenshots(subgroup_name)
                end
                r.ImGui_EndPopup(ctx)
            end

            if config.use_pagination and total_pages > 1 then
                r.ImGui_Indent(ctx, 20)
                if r.ImGui_Button(ctx, "<", 15, 15) then
                    if tbl[i].current_page > 1 then
                        tbl[i].current_page = tbl[i].current_page - 1
                    else
                        tbl[i].current_page = total_pages
                    end
                    local new_start = (tbl[i].current_page - 1) * ITEMS_PER_PAGE + 1
                    local new_end = math.min(new_start + ITEMS_PER_PAGE - 1, #filtered_fx)
                    screenshot_search_results = {}
                    for j = new_start, new_end do
                        table.insert(screenshot_search_results, {name = filtered_fx[j]})
                    end
                    SortScreenshotResults()
                    RequestClearScreenshotCache()
                    
                    -- Force texture reload for new page
                    for j = new_start, new_end do
                        local plugin_name = filtered_fx[j]
                        local screenshot_file = HasScreenshot(plugin_name)
                        if screenshot_file then
                            local relative_path = screenshot_file:gsub(screenshot_path, "")
                            local unique_key = relative_path .. "_" .. plugin_name
                            -- Remove from cache to force reload
                            search_texture_cache[unique_key] = nil
                            texture_last_used[unique_key] = nil
                            -- Add to queue for immediate loading
                            if not texture_load_queue[unique_key] then
                                texture_load_queue[unique_key] = { 
                                    file = screenshot_file, 
                                    queued_at = r.time_precise(), 
                                    plugin = plugin_name 
                                }
                            end
                        end
                    end
                end
                r.ImGui_SameLine(ctx)
                r.ImGui_Text(ctx, string.format("%d/%d", tbl[i].current_page, total_pages))
                r.ImGui_SameLine(ctx)
                if r.ImGui_Button(ctx, ">", 15, 15) then
                    if tbl[i].current_page < total_pages then
                        tbl[i].current_page = tbl[i].current_page + 1
                    else
                        tbl[i].current_page = 1
                    end
                    local new_start = (tbl[i].current_page - 1) * ITEMS_PER_PAGE + 1
                    local new_end = math.min(new_start + ITEMS_PER_PAGE - 1, #filtered_fx)
                    screenshot_search_results = {}
                    for j = new_start, new_end do
                        table.insert(screenshot_search_results, {name = filtered_fx[j]})
                    end
                    SortScreenshotResults()
                    RequestClearScreenshotCache()
                    
                    -- Force texture reload for new page
                    for j = new_start, new_end do
                        local plugin_name = filtered_fx[j]
                        local screenshot_file = HasScreenshot(plugin_name)
                        if screenshot_file then
                            local relative_path = screenshot_file:gsub(screenshot_path, "")
                            local unique_key = relative_path .. "_" .. plugin_name
                            -- Remove from cache to force reload
                            search_texture_cache[unique_key] = nil
                            texture_last_used[unique_key] = nil
                            -- Add to queue for immediate loading
                            if not texture_load_queue[unique_key] then
                                texture_load_queue[unique_key] = { 
                                    file = screenshot_file, 
                                    queued_at = r.time_precise(), 
                                    plugin = plugin_name 
                                }
                            end
                        end
                    end
                end
                r.ImGui_Unindent(ctx, 20)

                if main_cat_name == "FOLDERS" then
                    CheckFolderDropTarget(subgroup_name, "native")
                end

            end

            if tbl[i].is_open then
                r.ImGui_Indent(ctx, 20)
                if config.use_pagination then
                    local start_idx = (tbl[i].current_page - 1) * ITEMS_PER_PAGE + 1
                    local end_idx = math.min(start_idx + ITEMS_PER_PAGE - 1, #filtered_fx)
                    for j = start_idx, end_idx do
                        local display_name = GetDisplayPluginName(filtered_fx[j])
                        if r.ImGui_Selectable(ctx, display_name .. "  " .. GetStarsString(filtered_fx[j])) then
                            selected_folder = nil
                            selected_individual_item = filtered_fx[j]
                            screenshot_search_results = {{name = filtered_fx[j]}}
                            RequestClearScreenshotCache()
                        end
                        ShowPluginContextMenu(filtered_fx[j], "unique_id_" .. i .. "_" .. j)
                    end
                else
                    for j = 1, #filtered_fx do
                        local display_name = GetDisplayPluginName(filtered_fx[j])
                        if r.ImGui_Selectable(ctx, display_name .. "  " .. GetStarsString(filtered_fx[j])) then
                            selected_folder = nil
                            selected_individual_item = filtered_fx[j]
                            screenshot_search_results = {{name = filtered_fx[j]}}
                            RequestClearScreenshotCache()
                        end
                        ShowPluginContextMenu(filtered_fx[j], "unique_id_" .. i .. "_" .. j)
                    end
                end
                r.ImGui_Unindent(ctx, 20)
            end

            r.ImGui_PopID(ctx)
        end
    end
end



function ItemMatchesSearch(item_name, search_term)
    search_term = search_term or ""
    if search_term == "" then return true end
    return s_find(s_lower(item_name), s_lower(search_term), 1, true)
end

-- CUSTOM FOLDERS (NESTED)
function DisplayCustomFoldersInBrowser(folders, path_prefix)
    path_prefix = path_prefix or ""
    
    -- Set custom indentation spacing for the tree hierarchy
    local indent_px = config.custom_folder_indent or 20
    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_IndentSpacing(), indent_px)
    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), 0, 0)

    -- Calculate depth for color selection
    local depth = 1
    if path_prefix ~= "" then
        local _, count = path_prefix:gsub("/", "")
        depth = count + 2
    end
    local level_colors = config.custom_folder_level_colors or {}
    local color_idx = math.min(depth, #level_colors)
    local text_col = level_colors[color_idx] or config.custom_folder_text_color or r.ImGui_GetColor(ctx, r.ImGui_Col_Text())

    local function IsCustomPinned(full_path)
        if not config.pinned_custom_subfolders then return false end
        for _, p in ipairs(config.pinned_custom_subfolders) do if p == full_path then return true end end
        return false
    end
    local function PinCustom(full_path)
        config.pinned_custom_subfolders = config.pinned_custom_subfolders or {}
        if not IsCustomPinned(full_path) then 
            table.insert(config.pinned_custom_subfolders, full_path)
            SavePinned()
        end
    end
    local function UnpinCustom(full_path)
        if not config.pinned_custom_subfolders then return end
        for i=#config.pinned_custom_subfolders,1,-1 do
            if config.pinned_custom_subfolders[i] == full_path then table.remove(config.pinned_custom_subfolders, i); SavePinned(); break end
        end
    end
    
    local sorted_folder_names = {}
    for folder_name, _ in pairs(folders) do 
        if folder_name ~= "__folder_marker__" and type(folder_name) == "string" then
            table.insert(sorted_folder_names, folder_name)
        end
    end

    -- OPTIMIZATION: Pre-calculate pinned status and lower names to avoid string ops in sort loop
    local pinned_status = {}
    local lower_names = {}
    for _, name in ipairs(sorted_folder_names) do
        local full = (path_prefix == "" and name or (path_prefix .. "/" .. name))
        pinned_status[name] = IsCustomPinned(full)
        lower_names[name] = name:lower()
    end

    table.sort(sorted_folder_names, function(a, b)
        local ia = pinned_status[a]
        local ib = pinned_status[b]
        if ia ~= ib then return ia end -- pinned eerst
        return lower_names[a] < lower_names[b]
    end)
    
    -- GEBRUIK DE GESORTEERDE NAMEN
    for _, folder_name in ipairs(sorted_folder_names) do
        local folder_content = folders[folder_name]
        local full_path = path_prefix == "" and folder_name or (path_prefix .. "/" .. folder_name)
        
        -- Save original cursor position
        local original_cursor_x = r.ImGui_GetCursorPosX(ctx)
        
        -- Check if folder has subfolder structure (tree node display for container folders)
        if IsSubfolderStructure(folder_content) then
            -- TreeNode for folders WITH subfolders (container folders)
            
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemInnerSpacing(), 0, 0)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FramePadding(), 1, 1)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Header(), 0x00000000)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_HeaderHovered(), 0x3F3F3F3F)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_HeaderActive(), 0x3F3F3F3F)
            local tree_is_selected = (selected_folder == full_path)
            local tree_flags = r.ImGui_TreeNodeFlags_Framed() | r.ImGui_TreeNodeFlags_SpanAvailWidth() | r.ImGui_TreeNodeFlags_FramePadding() | r.ImGui_TreeNodeFlags_OpenOnArrow() | r.ImGui_TreeNodeFlags_OpenOnDoubleClick()
            if tree_is_selected then
                tree_flags = tree_flags | r.ImGui_TreeNodeFlags_Selected()
                local dl = r.ImGui_GetWindowDrawList(ctx)
                local x,y = r.ImGui_GetCursorScreenPos(ctx)
                local avail_w = r.ImGui_GetContentRegionAvail(ctx)
                local line_h = r.ImGui_GetTextLineHeightWithSpacing(ctx)
                r.ImGui_DrawList_AddRectFilled(dl, x, y, x + avail_w, y + line_h, 0xFF704030, 3)
            end
            local folder_label_text = config.custom_folder_force_uppercase and folder_name:upper() or folder_name
            local display_label = ((IsCustomPinned(full_path) and "\xF0\x9F\x93\x8C ") or "") .. folder_label_text
            if auto_expand_paths and auto_expand_paths[full_path] then
                r.ImGui_SetNextItemOpen(ctx, true, r.ImGui_Cond_Once())
            end
            local tree_id = full_path .. "##customTree"
            local open = r.ImGui_TreeNodeEx(ctx, tree_id, "", tree_flags)
            local tree_clicked = r.ImGui_IsItemClicked(ctx, 0)
            local tree_toggled = r.ImGui_IsItemToggledOpen(ctx)
            local tree_right_clicked = r.ImGui_IsItemClicked(ctx, 1)
            CheckFolderDropTarget(full_path, "custom")
            local item_min_x, item_min_y = r.ImGui_GetItemRectMin(ctx)
            local line_h = r.ImGui_GetTextLineHeight(ctx)
            local text_w, text_h = r.ImGui_CalcTextSize(ctx, display_label)
            local spacing = r.ImGui_GetTreeNodeToLabelSpacing(ctx)
            local text_x = item_min_x + spacing
            local text_y = item_min_y + (line_h - text_h) * 0.5 + 3
            local draw_list = r.ImGui_GetWindowDrawList(ctx)
            local orig_sx, orig_sy = r.ImGui_GetCursorScreenPos(ctx)
            local font_to_use = CustomFolderFont or NormalFont
            r.ImGui_PushFont(ctx, font_to_use, (config.custom_folder_use_default_font and config.font_size) or (config.custom_folder_font_size or config.font_size))
            r.ImGui_SetCursorScreenPos(ctx, text_x, text_y)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), text_col)
            r.ImGui_Text(ctx, display_label)
            r.ImGui_PopStyleColor(ctx)
            r.ImGui_PopFont(ctx)
            r.ImGui_SetCursorScreenPos(ctx, orig_sx, orig_sy)
            
            if tree_clicked and not tree_toggled then
                browser_panel_selected = nil
                selected_folder = full_path
                UpdateLastViewedFolder(full_path)
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                screenshot_search_results = {}
                folder_page_state[full_path] = 1
                local term_l = browser_search_term:lower()
                local matches = {}
                for k, plugin in pairs(folder_content) do
                    if type(k) == "number" and type(plugin) == "string" then
                        if FuzzyFind(plugin, term_l) then
                            matches[#matches+1] = plugin
                        end
                    end
                end
                if config.apply_type_priority then
                    matches = DedupeByTypePriority(matches)
                end
                for i = 1, #matches do
                    screenshot_search_results[#screenshot_search_results+1] = { name = matches[i] }
                end
                ClearScreenshotCache()
            end
            
            if tree_right_clicked then
                r.ImGui_OpenPopup(ctx, "TreeContextMenu_" .. full_path)
            end
            if r.ImGui_BeginPopup(ctx, "TreeContextMenu_" .. full_path) then
                if r.ImGui_MenuItem(ctx, "Add Subfolder") then
                    selected_folder_for_subfolder = full_path
                    selected_folder_name = folder_name
                    new_subfolder_name = ""
                    show_add_subfolder_popup = true
                end
                if r.ImGui_MenuItem(ctx, "Create Parent Folder Above") then
                    show_create_parent_folder_popup = true
                    selected_folder_for_parent = full_path
                    selected_folder_name = folder_name
                end
                local is_pinned = IsCustomPinned(full_path)
                if is_pinned then
                    if r.ImGui_MenuItem(ctx, "Unpin Folder") then UnpinCustom(full_path) end
                else
                    if r.ImGui_MenuItem(ctx, "Pin Folder") then PinCustom(full_path) end
                end
                if r.ImGui_MenuItem(ctx, "Capture Folder Screenshots") then
                    StartFolderScreenshots(full_path)
                end
                r.ImGui_Separator(ctx)
                if r.ImGui_MenuItem(ctx, "Rename Folder") then
                    show_rename_folder_popup = true
                    folder_to_rename = folder_name
                    folder_to_rename_path = path_prefix
                    new_folder_name_for_rename = folder_name
                end
                if r.ImGui_BeginMenu(ctx, "Move to Folder...") then
                    if r.ImGui_MenuItem(ctx, "[Root Level]") then
                        if MoveFolderTo(full_path, "") then
                            if selected_folder == full_path then
                                selected_folder = folder_name
                            end
                        end
                    end
                    r.ImGui_Separator(ctx)
                    local available_targets = CollectAllFolderPaths(config.custom_folders, "", full_path, {})
                    for _, target_path in ipairs(available_targets) do
                        if r.ImGui_MenuItem(ctx, target_path) then
                            if MoveFolderTo(full_path, target_path) then
                                if selected_folder == full_path then
                                    selected_folder = target_path .. "/" .. folder_name
                                end
                            end
                        end
                    end
                    if #available_targets == 0 then
                        r.ImGui_TextDisabled(ctx, "No other folders available")
                    end
                    r.ImGui_EndMenu(ctx)
                end
                if r.ImGui_MenuItem(ctx, "Delete Folder") then
                    local result = r.MB("Are you sure you want to delete '" .. folder_name .. "' and all its contents?", "Confirm Delete", 4)
                    if result == 6 then -- Yes
                        -- Navigate to parent and remove this folder
                        if path_prefix == "" then
                            -- Root level folder
                            config.custom_folders[folder_name] = nil
                        else
                            -- Nested folder - navigate to parent
                            local target = config.custom_folders
                            local path_parts = {}
                            for part in path_prefix:gmatch("[^/]+") do
                                table.insert(path_parts, part)
                            end
                            for i = 1, #path_parts do
                                target = target[path_parts[i]]
                                if not target then break end
                            end
                            if target then
                                target[folder_name] = nil
                            end
                        end
                        SaveCustomFolders()
                        
                        -- Clear selection if deleted folder was selected
                        if selected_folder == full_path or (selected_folder and selected_folder:find("^" .. full_path .. "/")) then
                            selected_folder = nil
                            screenshot_search_results = {}
                        end
                        
                        r.ShowMessageBox("Folder '" .. folder_name .. "' deleted", "Success", 0)
                    end
                end
                r.ImGui_EndPopup(ctx)
            end
            
            if open then
                -- No extra indent for subfolders - they already have TreeNode spacing
                DisplayCustomFoldersInBrowser(folder_content, full_path)
                r.ImGui_TreePop(ctx)
            end
            r.ImGui_PopStyleColor(ctx, 3)
            r.ImGui_PopStyleVar(ctx)
            r.ImGui_PopStyleVar(ctx)
            
            
            r.ImGui_SetCursorPosX(ctx, original_cursor_x)
            -- Consistent spacing: 2px for root, 0px for nested
            local spacing_after = path_prefix == "" and 2 or 0
            r.ImGui_SetCursorPosY(ctx, r.ImGui_GetCursorPosY(ctx) + spacing_after)
        else
            -- Selectable for folders WITHOUT subfolders (plugin folders)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FramePadding(), 1, 1)

            -- Apply consistent hover color for root level selectables
            if path_prefix == "" then
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Header(), 0x3F3F3F3F)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_HeaderHovered(), 0x3F3F3F3F)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_HeaderActive(), 0x3F3F3F3F)
            end
            
            local is_selected = (selected_folder == full_path)
            local is_pinned = IsCustomPinned(full_path)
            local folder_label_text = config.custom_folder_force_uppercase and folder_name:upper() or folder_name
            if is_selected then
                local dl = r.ImGui_GetWindowDrawList(ctx)
                local x,y = r.ImGui_GetCursorScreenPos(ctx)
                local text_w = r.ImGui_CalcTextSize(ctx, folder_label_text)
                local avail_w = r.ImGui_GetContentRegionAvail(ctx)
                local line_h = r.ImGui_GetTextLineHeightWithSpacing(ctx)
                r.ImGui_DrawList_AddRectFilled(dl, x-2, y, x + avail_w, y + line_h, 0xFF704030, 3)
            end
            local label = (is_pinned and "\xF0\x9F\x93\x8C " or "") .. folder_label_text
            
            -- Apply custom folder font
            local font_to_use = CustomFolderFont or NormalFont
            r.ImGui_PushFont(ctx, font_to_use, (config.custom_folder_use_default_font and config.font_size) or (config.custom_folder_font_size or config.font_size))
            
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), text_col)
            if r.ImGui_Selectable(ctx, label, is_selected) then
                browser_panel_selected = nil
                selected_folder = full_path
                UpdateLastViewedFolder(full_path)
                show_media_browser = false
                show_sends_window = false
                show_action_browser = false
                screenshot_search_results = {}
                folder_page_state[full_path] = 1
                local term_l = browser_search_term:lower()
                local matches = {}
                for k, plugin in pairs(folder_content) do
                    if type(k) == "number" and type(plugin) == "string" then
                        if FuzzyFind(plugin, term_l) then
                            matches[#matches+1] = plugin
                        end
                    end
                end
                if config.apply_type_priority then
                    matches = DedupeByTypePriority(matches)
                end
                for i = 1, #matches do
                    screenshot_search_results[#screenshot_search_results+1] = { name = matches[i] }
                end
                ClearScreenshotCache()
            end
            r.ImGui_PopStyleColor(ctx)
            
            r.ImGui_PopFont(ctx)

            if config.use_pagination and view_mode ~= "list" then
                local cf_plugins = GetPluginsFromCustomFolder(full_path) or {}
                local cf_total = 0
                for k, v in pairs(cf_plugins) do
                    if type(k) == "number" and type(v) == "string" then cf_total = cf_total + 1 end
                end
                local cf_pages = math.max(1, math.ceil(cf_total / ITEMS_PER_PAGE))
                if cf_pages > 1 then
                    local page = folder_page_state[full_path] or 1
                    r.ImGui_Indent(ctx, 20)
                    if r.ImGui_Button(ctx, "<##cfp_" .. full_path, 15, 15) then
                        folder_page_state[full_path] = page > 1 and page - 1 or cf_pages
                        if is_selected then RequestClearScreenshotCache() end
                    end
                    r.ImGui_SameLine(ctx)
                    r.ImGui_Text(ctx, string.format("%d/%d", page, cf_pages))
                    r.ImGui_SameLine(ctx)
                    if r.ImGui_Button(ctx, ">##cfn_" .. full_path, 15, 15) then
                        folder_page_state[full_path] = page < cf_pages and page + 1 or 1
                        if is_selected then RequestClearScreenshotCache() end
                    end
                    r.ImGui_Unindent(ctx, 20)
                end
            end

            CheckFolderDropTarget(full_path, "custom")

            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "FolderContextMenu_" .. full_path)
            end
            if r.ImGui_BeginPopup(ctx, "FolderContextMenu_" .. full_path) then
                DrawCustomFolderContextMenu(folder_name, path_prefix, full_path)
                r.ImGui_EndPopup(ctx)
            end
            
            
            -- Pop style colors for root level selectables
            if path_prefix == "" then
                r.ImGui_PopStyleColor(ctx, 3)
            end
            
            r.ImGui_PopStyleVar(ctx)

            -- Reset cursor position and add vertical spacing
            r.ImGui_SetCursorPosX(ctx, original_cursor_x)
            -- Consistent spacing: 2px for root, 0px for nested
            local spacing = path_prefix == "" and 2 or 0
            r.ImGui_SetCursorPosY(ctx, r.ImGui_GetCursorPosY(ctx) + spacing)
        end
    end
    
    r.ImGui_PopStyleVar(ctx) -- Pop ItemSpacing
    r.ImGui_PopStyleVar(ctx) -- Pop IndentSpacing
end

footer_resize_active = footer_resize_active or false
footer_last_mouse_y  = footer_last_mouse_y or 0

function ShowBrowserPanel()
    if not config[browser_panel_key] then return end

    if not initial_header_auto_expand_done
       and config.default_folder == LAST_OPENED_SENTINEL
       and last_viewed_folder
       and not (force_open_all_plugins_header or force_open_developer_header or force_open_category_header or force_open_folders_header) then
        MarkForcedHeaderForSubgroup(last_viewed_folder)
    end

    config.browser_footer_height = math.max(20, config.browser_footer_height or 150)
    local BROWSER_FOOTER_HEIGHT = config.browser_footer_height
    local browser_panel_start_y = r.ImGui_GetCursorPosY(ctx)
    browser_footer_text = browser_footer_text or "INFO BOX"
    browser_panel_show_info = browser_panel_show_info or false
    info_trackfx_drop_hovered = false
    info_itemfx_drop_hovered = false
    info_inputfx_drop_hovered = false
    drag_drop_target_folder = nil
    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ScrollbarSize(), 0)
    r.ImGui_BeginChild(ctx, "BrowserSection", config.browser_panel_width, -1)
    local section_pos_y = r.ImGui_GetCursorScreenPos(ctx)
    local section_start_y = section_pos_y 

    -- Header
    local header_open = r.ImGui_BeginChild(ctx, "BrowserHeader", -1, config.show_browser_search and 26 or 4, 0, r.ImGui_WindowFlags_NoNavInputs())
    if header_open then
    if config.show_browser_search then
        r.ImGui_PushItemWidth(ctx, 70)
        local search_input_flags = 0
        if screenshot_search_autoselect then
            search_input_flags = r.ImGui_InputTextFlags_AutoSelectAll()
        end
        if screenshot_search_focus_requested and not (config.show_screenshot_search ~= false) then
            r.ImGui_SetKeyboardFocusHere(ctx)
            screenshot_search_focus_requested = false
        end
        local changed_browser_search, new_browser_search = r.ImGui_InputTextWithHint(ctx, "##BrowserSearch", "Search...", browser_search_term, search_input_flags)
        if screenshot_search_autoselect and r.ImGui_IsItemActive(ctx) then
            screenshot_search_autoselect = false
        end
        if r.ImGui_IsItemActive(ctx) and r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_DownArrow()) and not screenshot_nav_index then
            screenshot_search_to_nav = true
            screenshot_search_blur_requested = true
        end
        r.ImGui_PopItemWidth(ctx)
        local btn_color, btn_hover, btn_active, btn_text = GetButtonColors()
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), btn_color)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), btn_hover)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), btn_active)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), btn_text)
        if browser_search_term ~= "" then
            r.ImGui_SameLine(ctx)
            if r.ImGui_Button(ctx, "X", 17, r.ImGui_GetFrameHeight(ctx)) then
                ClearSearch()
            end
            if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Clear search") end
        end
        if changed_browser_search then
            screenshot_folder_filter_suspended = false
            if screenshot_search_replace_requested and browser_search_term ~= "" and new_browser_search:sub(1, #browser_search_term) == browser_search_term then
                new_browser_search = new_browser_search:sub(#browser_search_term + 1)
            end
            screenshot_search_replace_requested = false
            browser_search_term = new_browser_search
            if config.always_search_all then
                SearchAllPlugins()
            elseif browser_search_term ~= "" and browser_panel_selected then
                RefreshCurrentScreenshotView()
            end
        end
        r.ImGui_SameLine(ctx)
        screenshot_sort_mode = screenshot_sort_mode or "alphabet"
        local effective_mode = (config and config.sort_mode) or screenshot_sort_mode
        local sort_label = (effective_mode == "alphabet") and "A" or (effective_mode == "rating") and "R" or "P"
        local button_height = r.ImGui_GetFrameHeight(ctx)
        if r.ImGui_Button(ctx, sort_label, 17, button_height) then
            local next_mode
            if effective_mode == "alphabet" then
                next_mode = "rating"
            elseif effective_mode == "rating" then
                next_mode = "type"
            else
                next_mode = "alphabet"
            end
            if config then
                config.sort_mode = next_mode
                if SaveConfig then SaveConfig() end
            else
                screenshot_sort_mode = next_mode
            end
            SortScreenshotResults()
        end
        if r.ImGui_IsItemHovered(ctx) then
            if effective_mode == "alphabet" then
                r.ImGui_SetTooltip(ctx, "Alphabetic sorting (click to switch to Rating)")
            elseif effective_mode == "rating" then
                r.ImGui_SetTooltip(ctx, "Rating sorting (click to switch to Prefix)")
            else
                r.ImGui_SetTooltip(ctx, "Prefix sorting (click to switch to Alphabetic)")
            end
        end
        r.ImGui_SameLine(ctx)
        local all_disabled = browser_search_term == ""
        if all_disabled then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x666666FF)
        end
        if r.ImGui_Button(ctx, "All", 30, button_height) and not all_disabled then
            SearchAllPlugins()
        end
        if all_disabled then
            r.ImGui_PopStyleColor(ctx, 1)
        end
