                                    r.Undo_BeginBlock()
                                    r.TrackFX_CopyToTrack(TRACK, rfx_idx, TRACK, (i - 1) + 0x1000000, true)
                                    r.Undo_EndBlock("Move Input FX Up", -1)
                                end
                                if i < rec_count - 1 and r.ImGui_MenuItem(ctx, "Move Down") then
                                    r.Undo_BeginBlock()
                                    r.TrackFX_CopyToTrack(TRACK, rfx_idx, TRACK, (i + 2) + 0x1000000, true)
                                    r.Undo_EndBlock("Move Input FX Down", -1)
                                end
                                r.ImGui_Separator(ctx)
                                if r.ImGui_MenuItem(ctx, "Delete") then
                                    r.Undo_BeginBlock()
                                    r.TrackFX_Delete(TRACK, rfx_idx)
                                    r.Undo_EndBlock("Delete Input FX", -1)
                                end
                                r.ImGui_EndPopup(ctx)
                            end
                        end
                    end
                    r.ImGui_PopStyleVar(ctx)
                end
                local _, rfx_zone_ey = r.ImGui_GetCursorScreenPos(ctx)
                if rfx_zone_ey - rfx_zone_sy < 20 then rfx_zone_ey = rfx_zone_sy + 20 end
                if dragging_fx_name then
                    local mx, my = r.ImGui_GetMousePos(ctx)
                    if mx >= rfx_zone_sx and mx <= rfx_zone_sx + rfx_zone_w and my >= rfx_zone_sy and my <= rfx_zone_ey then
                        info_inputfx_drop_hovered = true
                        local dl = r.ImGui_GetWindowDrawList(ctx)
                        r.ImGui_DrawList_AddRectFilled(dl, rfx_zone_sx, rfx_zone_sy, rfx_zone_sx + rfx_zone_w, rfx_zone_ey, 0x00FF8820, 3)
                        r.ImGui_DrawList_AddRect(dl, rfx_zone_sx, rfx_zone_sy, rfx_zone_sx + rfx_zone_w, rfx_zone_ey, 0x00FF8860, 3)
                    end
                end
            else
                r.ImGui_Text(ctx, "Tags: -")
                r.ImGui_Dummy(ctx, 0, 6)
                r.ImGui_Separator(ctx)
                r.ImGui_Text(ctx, "Track FX: -")
                r.ImGui_Dummy(ctx, 0, 4)
                r.ImGui_Separator(ctx)
                r.ImGui_Text(ctx, "Item FX: -")
                r.ImGui_Dummy(ctx, 0, 4)
                r.ImGui_Separator(ctx)
                r.ImGui_Text(ctx, "Input FX: -")
            end
        end
        if info_open then
            r.ImGui_EndChild(ctx)
        end
        r.ImGui_PopStyleVar(ctx)
    end
    
    if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") and browser_panel_show_info then
        local btn_w = (r.ImGui_GetContentRegionAvail(ctx) - 8) / 3
        local is_armed = r.GetMediaTrackInfo_Value(TRACK, "I_RECARM") == 1
        local is_muted = r.GetMediaTrackInfo_Value(TRACK, "B_MUTE") == 1
        local is_soloed = r.GetMediaTrackInfo_Value(TRACK, "I_SOLO") > 0

        if is_armed then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0xCC2222FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xDD3333FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0xEE4444FF)
        else
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x3A3A3AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A5A5AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x7A7A7AFF)
        end
        if r.ImGui_Button(ctx, "Arm##info_arm", btn_w, 20) then
            r.SetMediaTrackInfo_Value(TRACK, "I_RECARM", is_armed and 0 or 1)
        end
        r.ImGui_PopStyleColor(ctx, 3)

        r.ImGui_SameLine(ctx)
        if is_muted then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0xCC8800FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xDDA020FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0xEEB030FF)
        else
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x3A3A3AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A5A5AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x7A7A7AFF)
        end
        if r.ImGui_Button(ctx, "Mute##info_mute", btn_w, 20) then
            r.SetMediaTrackInfo_Value(TRACK, "B_MUTE", is_muted and 0 or 1)
        end
        r.ImGui_PopStyleColor(ctx, 3)

        r.ImGui_SameLine(ctx)
        if is_soloed then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0xCCCC00FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0xDDDD20FF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0xEEEE30FF)
        else
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x3A3A3AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A5A5AFF)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x7A7A7AFF)
        end
        if r.ImGui_Button(ctx, "Solo##info_solo", btn_w, 20) then
            r.SetMediaTrackInfo_Value(TRACK, "I_SOLO", is_soloed and 0 or 2)
        end
        r.ImGui_PopStyleColor(ctx, 3)
    end

    local toggle_label = browser_panel_show_info and "BROWSER" or "INFO"
    local toggle_has_track_color = false
    if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
        local tc_u32, tt_u32 = GetTrackColorAndTextColor(TRACK)
        local tr = ((tc_u32 >> 24) & 0xFF)
        local tg = ((tc_u32 >> 16) & 0xFF)
        local tb = ((tc_u32 >> 8) & 0xFF)
        local hover_u32 = (math.min(255, tr + 25) << 24) | (math.min(255, tg + 25) << 16) | (math.min(255, tb + 25) << 8) | 0xFF
        local active_u32 = (math.min(255, tr + 40) << 24) | (math.min(255, tg + 40) << 16) | (math.min(255, tb + 40) << 8) | 0xFF
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), tc_u32)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), hover_u32)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), active_u32)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), tt_u32)
        toggle_has_track_color = true
    end
    if r.ImGui_Button(ctx, toggle_label, -1, 20) then
        browser_panel_show_info = not browser_panel_show_info
    end
    if toggle_has_track_color then
        r.ImGui_PopStyleColor(ctx, 4)
    end
    if r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, browser_panel_show_info and "Switch to Plugin Browser" or "Switch to Track Info Panel")
    end

    r.ImGui_EndChild(ctx) -- BrowserSection
    r.ImGui_PopStyleVar(ctx) -- outer ScrollbarSize

    r.ImGui_SameLine(ctx)
    local splitter_width = 6
    local splitter_base, splitter_hover, splitter_active = GetButtonColors()
    local base_r = ((splitter_base >> 24) & 0xFF)
    local base_g = ((splitter_base >> 16) & 0xFF)
    local base_b = ((splitter_base >> 8) & 0xFF)
    local light_base = (math.min(255, base_r + 5) << 24) | (math.min(255, base_g + 5) << 16) | (math.min(255, base_b + 5) << 8) | 0xFF
    local light_hover = (math.min(255, base_r + 20) << 24) | (math.min(255, base_g + 20) << 16) | (math.min(255, base_b + 20) << 8) | 0xFF
    local light_active = (math.min(255, base_r + 35) << 24) | (math.min(255, base_g + 35) << 16) | (math.min(255, base_b + 35) << 8) | 0xFF
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), light_base)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), light_hover)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), light_active)
    
    local splitter_x, splitter_y = r.ImGui_GetCursorScreenPos(ctx)
    local _, avail_h = r.ImGui_GetContentRegionAvail(ctx)
    
    r.ImGui_Button(ctx, "##splitter", splitter_width, -1)
    
    local dl = r.ImGui_GetWindowDrawList(ctx)
    local center_x = splitter_x + splitter_width / 2
    local center_y = splitter_y + avail_h / 2
    local dot_spacing = 4
    local dot_radius = 1.5
    local dot_color = 0xFFFFFFFF
    r.ImGui_DrawList_AddCircleFilled(dl, center_x, center_y - dot_spacing, dot_radius, dot_color)
    r.ImGui_DrawList_AddCircleFilled(dl, center_x, center_y, dot_radius, dot_color)
    r.ImGui_DrawList_AddCircleFilled(dl, center_x, center_y + dot_spacing, dot_radius, dot_color)
    
    local window_width = r.ImGui_GetWindowWidth(ctx)
    local max_width = window_width - 150
    if r.ImGui_IsItemActive(ctx) then
        config.browser_panel_width = config.browser_panel_width + r.ImGui_GetMouseDragDelta(ctx)
        r.ImGui_ResetMouseDragDelta(ctx)
        config.browser_panel_width = math.max(130, math.min(config.browser_panel_width, max_width))
    end
    if r.ImGui_IsItemDeactivated(ctx) then
        SaveConfig()
    end
    r.ImGui_PopStyleColor(ctx, 3)
    r.ImGui_SameLine(ctx)
end

function CheckScrollAndLoadMore(all_plugins)
    if not config.use_pagination and all_plugins and #all_plugins > ITEMS_PER_BATCH then
        local ss_open = r.ImGui_BeginChild(ctx, "ScreenshotList", 0, 0, 0, r.ImGui_WindowFlags_NoNavInputs())
        if ss_open then
            local current_scroll = r.ImGui_GetScrollY(ctx)
            local max_scroll = r.ImGui_GetScrollMaxY(ctx)
            
            if current_scroll > 0 and current_scroll/max_scroll > 0.7 and loaded_items_count < #all_plugins then
                local new_count = math.min(loaded_items_count + ITEMS_PER_BATCH, #all_plugins)
                if new_count > loaded_items_count then
                    if not screenshot_search_results then
                        screenshot_search_results = {}
                    end
                    
                    for i = loaded_items_count + 1, new_count do
                        if all_plugins[i] then
                            table.insert(screenshot_search_results, {name = all_plugins[i]})
                        end
                    end
                    loaded_items_count = new_count
                end
            end
            r.ImGui_EndChild(ctx)
        end
    end
end

function ScaleScreenshotSize(width, height, max_display_size)
    local max_height = max_display_size * 1.2 
    local display_width = max_display_size
    local display_height = display_width * (height / width)
    
    if display_height > max_height then
        display_height = max_height
        display_width = display_height * (width / height)
    end
    
    return display_width, display_height
end

local list_hover_texture_cache = {}
local MAX_HOVER_TEXTURES = 50

function RenderListViewItems(plugin_list, id_prefix, opts)
    opts = opts or {}
    local is_search = opts.is_search or false
    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FramePadding(), 2, 2)
    ScreenshotNavReset()
    local nav_items = {}
    for i, raw_entry in ipairs(plugin_list) do
        local plugin_name, is_fx_chain_item
        if is_search then
            local fx = raw_entry
            if fx.is_message then
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFF00FF)
                r.ImGui_TextWrapped(ctx, GetDisplayPluginName(fx.name))
                r.ImGui_PopStyleColor(ctx)
                goto list_continue
            elseif fx.is_separator then
                if fx.kind == 'chain_divider' and fx.label then
                    r.ImGui_Separator(ctx)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                    r.ImGui_Text(ctx, "\xF0\x9F\x94\x97 " .. fx.label)
                    r.ImGui_PopStyleColor(ctx)
                    if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Right-click for options") end
                    if r.ImGui_IsItemClicked(ctx, 1) then
                        r.ImGui_OpenPopup(ctx, "chain_div_list_" .. id_prefix .. "_" .. i)
                    end
                    if ShowChainDividerContextMenu then ShowChainDividerContextMenu("chain_div_list_" .. id_prefix .. "_" .. i, fx) end
                else
                    local label = (fx.kind == 'pinned_end') and "--- Pinned End ---" or "--- Favorites End ---"
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
                    r.ImGui_Text(ctx, label)
                    r.ImGui_PopStyleColor(ctx)
                end
                goto list_continue
            else
                plugin_name = fx.name
                is_fx_chain_item = fx.is_fx_chain_item
            end
        else
            if raw_entry == "--Favorites End--" then
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
                r.ImGui_Text(ctx, "--- Favorites End ---")
                r.ImGui_PopStyleColor(ctx)
                goto list_continue
            elseif raw_entry == "--Pinned End--" then
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
                r.ImGui_Text(ctx, "--- Pinned End ---")
                r.ImGui_PopStyleColor(ctx)
                goto list_continue
            else
                plugin_name = raw_entry
            end
        end

        do
            local display_name = GetDisplayPluginName(plugin_name)
            local stars = GetStarsString(plugin_name)
            local prefix = ""
            if config.show_pinned_overlay and IsPluginPinned and IsPluginPinned(plugin_name) then
                prefix = prefix .. "📌 "
            end
            if config.show_favorite_overlay and favorite_set and favorite_set[plugin_name] then
                prefix = prefix .. "★ "
            end
            local _list_sc = NextScreenshotShortcutLabel(plugin_name)
            if _list_sc then prefix = prefix .. "[" .. _list_sc .. "] " end

            local is_selected = (screenshot_nav_index == i) or (screenshot_multi_selected[i] == true)
            local activated = r.ImGui_Selectable(ctx, prefix .. display_name .. (stars ~= "" and "  " .. stars or "") .. "##" .. id_prefix .. "_" .. i, is_selected)

            ScreenshotNavRegister(i, 1, 0, 0, plugin_name)
            nav_items[#nav_items+1] = plugin_name

            if not is_fx_chain_item then
                if config.enable_drag_add_fx then
                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) then
                        potential_drag_fx_name = plugin_name
                        drag_start_x, drag_start_y = r.ImGui_GetMousePos(ctx)
                    end
                    if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseDown(ctx, 0) then
                        local mx, my = r.ImGui_GetMousePos(ctx)
                        if math.abs(mx - drag_start_x) > 3 or math.abs(my - drag_start_y) > 3 then
                            dragging_fx_name = plugin_name
                            potential_drag_fx_name = nil
                        end
                    end
                    if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseReleased(ctx, 0) then
                        potential_drag_fx_name = nil
                    end
                end

                local do_add = false
                if config.add_fx_with_double_click then
                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsMouseDoubleClicked(ctx, 0) then
                        HandleMultiSelectClick(i)
                    end
                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx, 0) and dragging_fx_name ~= plugin_name then
                        do_add = true
                    end
                else
                    if activated and dragging_fx_name ~= plugin_name then
                        do_add = true
                    end
                end
                if do_add then
                    local target_track = GetTargetTrack()
                    if target_track then
                        local fx_index = AddFXToTrack(target_track, plugin_name)
                        LAST_USED_FX = plugin_name
                        if config.open_floating_after_adding and fx_index and fx_index >= 0 then
                            r.TrackFX_Show(target_track, fx_index, 3)
                        end
                        if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                    end
                end
            end

            ShowPluginContextMenu(plugin_name, id_prefix .. "_ctx_" .. i)
            ShowListHoverScreenshot(plugin_name)
            HandleListItemDrag(plugin_name)
        end

        ::list_continue::
    end
    r.ImGui_PopStyleVar(ctx)
    HandleScreenshotNavigation(nav_items)
end

function ShowListHoverScreenshot(plugin_name)
    if not config.list_hover_screenshot then return end
    if not r.ImGui_IsItemHovered(ctx) then return end
    local safe_name = (plugin_name or ""):gsub("[^%w%s-]", "_")
    local file = screenshot_path .. safe_name .. ".png"
    local texture = list_hover_texture_cache[plugin_name]
    if not texture then
        local count = 0
        for _ in pairs(list_hover_texture_cache) do count = count + 1 end
        if count >= MAX_HOVER_TEXTURES then
            for k, tex in pairs(list_hover_texture_cache) do
                if k ~= plugin_name then
                    r.ImGui_Detach(ctx, tex)
                    list_hover_texture_cache[k] = nil
                    count = count - 1
                    if count < MAX_HOVER_TEXTURES / 2 then break end
                end
            end
        end
        if r.file_exists(file) then
            texture = r.ImGui_CreateImage(file)
            if texture then
                r.ImGui_Attach(ctx, texture)
                list_hover_texture_cache[plugin_name] = texture
            end
        end
    end
    if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
        local w, h = r.ImGui_Image_GetSize(texture)
        if w and h then
            local max_w = 300
            local scale = max_w / w
            local dw, dh = m_floor(w * scale), m_floor(h * scale)
            r.ImGui_BeginTooltip(ctx)
            SafeImage(ctx, texture, dw, dh)
            r.ImGui_EndTooltip(ctx)
        end
    end
end

