                if config.show_project_col_samplerate then
                    r.ImGui_TableSetupColumn(ctx, "SR", 0, 0.7)
                end
                if config.show_project_col_tracks then
                    r.ImGui_TableSetupColumn(ctx, "Tracks", 0, 0.7)
