                if config.show_project_col_status then
                    r.ImGui_TableSetupColumn(ctx, "Status", 0, 1)
                end
                if config.show_project_col_rating then
                    r.ImGui_TableSetupColumn(ctx, "Rating", 0, 1)
                end
                if config.show_project_col_type then
                    r.ImGui_TableSetupColumn(ctx, "Type", 0, 1)
                end
                if config.show_project_col_artist then
                    r.ImGui_TableSetupColumn(ctx, "Artist", 0, 1.5)
                end
                if config.show_project_col_title then
                    r.ImGui_TableSetupColumn(ctx, "Title", 0, 1.5)
                end
                if config.show_project_col_genre then
                    r.ImGui_TableSetupColumn(ctx, "Genre", 0, 1)
                end
                if config.show_project_col_year then
                    r.ImGui_TableSetupColumn(ctx, "Year", 0, 0.6)
                end
                if config.show_project_col_client then
                    r.ImGui_TableSetupColumn(ctx, "Client", 0, 1.2)
                end
                if config.show_project_col_deadline then
                    r.ImGui_TableSetupColumn(ctx, "Deadline", 0, 1)
                end
                if config.show_project_col_tags then
                    r.ImGui_TableSetupColumn(ctx, "Tags", 0, 2)
                end
                r.ImGui_TableSetupScrollFreeze(ctx, 0, 1)
                r.ImGui_TableHeadersRow(ctx)

                local need_sort, has_specs = r.ImGui_TableNeedSort(ctx)
                if need_sort and has_specs then
                    local ok, col_idx, _, sort_dir = r.ImGui_TableGetColumnSortSpecs(ctx, 0)
                    if ok then
                        local col_names = {"preview", "name", "image"}
                        if config.show_project_col_sizes then table.insert(col_names, "size") end
                        if config.show_project_col_lengths then table.insert(col_names, "length") end
                        if config.show_project_col_media then table.insert(col_names, "media") end
                        if config.show_project_col_paths then table.insert(col_names, "path") end
                        if config.show_project_col_bpm then table.insert(col_names, "bpm") end
                        if config.show_project_col_samplerate then table.insert(col_names, "samplerate") end
                        if config.show_project_col_tracks then table.insert(col_names, "tracks") end
                        if config.show_project_col_dates then table.insert(col_names, "date") end
                        if config.show_project_col_comment then table.insert(col_names, "comment") end
                        if config.show_project_col_status then table.insert(col_names, "status") end
                        if config.show_project_col_rating then table.insert(col_names, "rating") end
                        if config.show_project_col_type then table.insert(col_names, "type") end
                        if config.show_project_col_artist then table.insert(col_names, "artist") end
                        if config.show_project_col_title then table.insert(col_names, "title") end
                        if config.show_project_col_genre then table.insert(col_names, "genre") end
                        if config.show_project_col_year then table.insert(col_names, "year") end
                        if config.show_project_col_client then table.insert(col_names, "client") end
                        if config.show_project_col_deadline then table.insert(col_names, "deadline") end
                        if config.show_project_col_tags then table.insert(col_names, "tags") end

                        project_sort_column = col_names[col_idx + 1] or "name"
                        project_sort_ascending = sort_dir == r.ImGui_SortDirection_Ascending()
                    end
                end

                if project_sort_column and project_sort_column ~= "preview" then
                    for _, p in ipairs(filtered_projects) do
                        if not p.cached_size then p.cached_size = GetFileSize(p.path) end
                        if p.cached_length == nil then
                            local prev_path = GetProjectPreviewPath(p.path)
                            if prev_path then
                                local src = r.PCM_Source_CreateFromFile(prev_path)
                                p.cached_length = src and r.GetMediaSourceLength(src) or 0
                                if src and r.PCM_Source_Destroy then pcall(r.PCM_Source_Destroy, src) end
                            else
                                p.cached_length = 0
                            end
                        end
                        if not p.cached_media then p.cached_media = CountProjectFolderFiles(p.path) end
                        if p.cached_cover == nil then p.cached_cover = GetProjectCoverPath(p.path) ~= nil end
                        if not p.cached_date then
                            if reaper.JS_File_Stat then
                                local retval, _, _, _, datetime = reaper.JS_File_Stat(p.path)
                                p.cached_date = (retval and datetime) or ""
                            else
                                p.cached_date = ""
                            end
                        end
                        if not p.cached_rpp_info then
                            p.cached_rpp_info = ParseRPPHeader(p.path) or {}
                        end
                    end

                    local sc = project_sort_column
                    local asc = project_sort_ascending
                    table.sort(filtered_projects, function(a, b)
                        local va, vb
                        if sc == "name" then
                            va, vb = a.name:lower(), b.name:lower()
                        elseif sc == "image" then
                            va, vb = a.cached_cover and 1 or 0, b.cached_cover and 1 or 0
                        elseif sc == "size" then
                            va, vb = a.cached_size or 0, b.cached_size or 0
                        elseif sc == "length" then
                            va, vb = a.cached_length or 0, b.cached_length or 0
                        elseif sc == "media" then
                            va, vb = a.cached_media or 0, b.cached_media or 0
                        elseif sc == "date" then
                            va, vb = a.cached_date or "", b.cached_date or ""
                        elseif sc == "path" then
                            va, vb = a.path:lower(), b.path:lower()
                        elseif sc == "comment" then
                            va, vb = (project_comments[a.path] or ""):lower(), (project_comments[b.path] or ""):lower()
                        elseif sc == "bpm" then
                            va, vb = (a.cached_rpp_info and a.cached_rpp_info.bpm) or 0, (b.cached_rpp_info and b.cached_rpp_info.bpm) or 0
                        elseif sc == "samplerate" then
                            va, vb = (a.cached_rpp_info and a.cached_rpp_info.samplerate) or 0, (b.cached_rpp_info and b.cached_rpp_info.samplerate) or 0
                        elseif sc == "tracks" then
                            va, vb = (a.cached_rpp_info and a.cached_rpp_info.track_count) or 0, (b.cached_rpp_info and b.cached_rpp_info.track_count) or 0
                        elseif sc == "status" or sc == "type" or sc == "artist" or sc == "title" or sc == "genre" or sc == "year" or sc == "client" or sc == "deadline" then
                            local da = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(a.path, a.cached_rpp_info) or {}
                            local db = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(b.path, b.cached_rpp_info) or {}
                            local key = sc
                            if sc == "type" then key = "project_type" end
                            va, vb = (da[key] or ""):lower(), (db[key] or ""):lower()
                        elseif sc == "rating" then
                            local da = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(a.path, a.cached_rpp_info) or {}
                            local db = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(b.path, b.cached_rpp_info) or {}
                            va, vb = da.rating or 0, db.rating or 0
                        elseif sc == "tags" then
                            local da = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(a.path, a.cached_rpp_info) or {}
                            local db = TKFXBProjectMeta and TKFXBProjectMeta.GetDisplay(b.path, b.cached_rpp_info) or {}
                            va, vb = table.concat(da.tags or {}, " "):lower(), table.concat(db.tags or {}, " "):lower()
                        else
                            va, vb = a.name:lower(), b.name:lower()
                        end
                        if va == vb then return a.path < b.path end
                        if asc then return va < vb else return va > vb end
                    end)
                end

                for i, project in ipairs(filtered_projects) do
                    r.ImGui_PushID(ctx, project.path)
                    r.ImGui_TableNextRow(ctx)
                    r.ImGui_TableNextColumn(ctx)

                    if project.cached_has_preview == nil then
                        project.cached_preview_path = GetProjectPreviewPath(project.path)
                        project.cached_has_preview = project.cached_preview_path ~= nil
                    end
                    if project.cached_cover == nil then
                        project.cached_cover = GetProjectCoverPath(project.path) ~= nil
                    end
                    local preview_path = project.cached_preview_path
                    local has_preview = project.cached_has_preview
                    local has_cover = project.cached_cover

                    if has_preview then
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x50FA7BFF)
                    else
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x555555FF)
                    end
                    r.ImGui_Text(ctx, has_preview and "\xE2\x97\x8F" or "\xE2\x97\x8B")
                    r.ImGui_PopStyleColor(ctx)

                    r.ImGui_TableNextColumn(ctx)

                    local is_selected = (selected_project and selected_project.path == project.path)

                    if r.ImGui_Selectable(ctx, project.name, is_selected, r.ImGui_SelectableFlags_SpanAllColumns() | r.ImGui_SelectableFlags_AllowOverlap()) then
                        selected_project = project
                        config.last_selected_project_path = project.path
                        SaveConfig()

                        ReleaseCurrentPreview()
                        if has_preview then
                            local source = r.PCM_Source_CreateFromFile(preview_path)
                            current_preview = r.CF_CreatePreview(source)
                            r.CF_Preview_SetValue(current_preview, "D_VOLUME", preview_volume)
                            current_source = source
                        end

                        current_project_info = {
                            path = project.path,
                            name = project.name,
                            has_preview = has_preview,
                            length = has_preview and r.GetMediaSourceLength(current_source) or 0,
                            size = GetFileSize(project.path),
                            folder_files = CountProjectFolderFiles(project.path),
                            rpp_info = ParseRPPHeader(project.path)
                        }
                    end

                    if r.ImGui_IsItemClicked(ctx, 1) then
                        r.ImGui_OpenPopup(ctx, "ProjectContextMenu_" .. i)
                    end

                    r.ImGui_TableNextColumn(ctx)
                    if has_cover then
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                        r.ImGui_Text(ctx, "Yes")
                    else
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x555555FF)
                        r.ImGui_Text(ctx, "No")
                    end
                    r.ImGui_PopStyleColor(ctx)

                    if config.show_project_col_sizes then
                        r.ImGui_TableNextColumn(ctx)
                        if not project.cached_size then
                            project.cached_size = GetFileSize(project.path)
                        end
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                        r.ImGui_Text(ctx, FormatFileSize(project.cached_size))
                        r.ImGui_PopStyleColor(ctx)
                    end

                    if config.show_project_col_lengths then
                        r.ImGui_TableNextColumn(ctx)
                        if project.cached_length == nil then
                            if has_preview then
                                local src = r.PCM_Source_CreateFromFile(preview_path)
                                if src then
                                    project.cached_length = r.GetMediaSourceLength(src)
                                    if r.PCM_Source_Destroy then pcall(r.PCM_Source_Destroy, src) end
                                else
                                    project.cached_length = 0
                                end
                            else
                                project.cached_length = 0
                            end
                        end
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                        r.ImGui_Text(ctx, FormatDuration(project.cached_length))
                        r.ImGui_PopStyleColor(ctx)
                    end

                    if config.show_project_col_media then
                        r.ImGui_TableNextColumn(ctx)
                        if not project.cached_media then
                            project.cached_media = CountProjectFolderFiles(project.path)
                        end
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                        r.ImGui_Text(ctx, tostring(project.cached_media))
                        r.ImGui_PopStyleColor(ctx)
                    end

                    if config.show_project_col_paths then
                        r.ImGui_TableNextColumn(ctx)
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                        r.ImGui_Text(ctx, project.path)
                        r.ImGui_PopStyleColor(ctx)
                    end

                    if config.show_project_col_bpm or config.show_project_col_samplerate or config.show_project_col_tracks then
                        if not project.cached_rpp_info then
                            project.cached_rpp_info = ParseRPPHeader(project.path) or {}
                        end
                        local ri = project.cached_rpp_info
                        if config.show_project_col_bpm then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, ri.bpm and tostring(ri.bpm) or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_samplerate then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, ri.samplerate and tostring(ri.samplerate) or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_tracks then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, ri.track_count and ri.track_count > 0 and tostring(ri.track_count) or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                    end

                    if config.show_project_col_dates then
                        r.ImGui_TableNextColumn(ctx)
                        if not project.cached_date then
                            if reaper.JS_File_Stat then
                                local retval, _, _, _, datetime = reaper.JS_File_Stat(project.path)
                                project.cached_date = (retval and datetime) or ""
                            else
                                project.cached_date = ""
                            end
                        end
                        if project.cached_date ~= "" then
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, project.cached_date)
                            r.ImGui_PopStyleColor(ctx)
                        end
                    end

                    if config.show_project_col_comment then
                        r.ImGui_TableNextColumn(ctx)
                        r.ImGui_PushItemWidth(ctx, -1)
                        local cur_comment = project_comments[project.path] or ""
                        local changed, new_comment = r.ImGui_InputText(ctx, "##comment_" .. i, cur_comment)
                        if changed then
                            if new_comment == "" then
                                project_comments[project.path] = nil
                            else
                                project_comments[project.path] = new_comment
                            end
                            SaveProjectComments()
                        end
                        r.ImGui_PopItemWidth(ctx)
                    end

                    local _meta_needed = config.show_project_col_status or config.show_project_col_rating
                        or config.show_project_col_type or config.show_project_col_artist or config.show_project_col_title
                        or config.show_project_col_genre or config.show_project_col_year or config.show_project_col_client
                        or config.show_project_col_deadline or config.show_project_col_tags
                    if _meta_needed and TKFXBProjectMeta then
                        if not project.cached_rpp_info then
                            project.cached_rpp_info = ParseRPPHeader(project.path) or {}
                        end
                        local md = TKFXBProjectMeta.GetDisplay(project.path, project.cached_rpp_info)
                        if config.show_project_col_status then
                            r.ImGui_TableNextColumn(ctx)
                            local status_colors = {
                                Idea = 0x7AA2F7FF, Tracking = 0xE0AF68FF, Mixing = 0xBB9AF7FF,
                                Mastering = 0xF7768EFF, Released = 0x9ECE6AFF,
                            }
                            local col = status_colors[md.status] or 0x999999FF
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), col)
                            r.ImGui_Text(ctx, md.status ~= "" and md.status or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_rating then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xE0AF68FF)
                            local rt = md.rating or 0
                            if rt > 0 then
                                r.ImGui_Text(ctx, string.rep("\xE2\x98\x85", rt) .. string.rep("\xE2\x98\x86", 5 - rt))
                            else
                                r.ImGui_Text(ctx, "-")
                            end
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_type then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x9ECE6AFF)
                            r.ImGui_Text(ctx, md.project_type ~= "" and md.project_type or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_artist then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xCCCCCCFF)
                            r.ImGui_Text(ctx, md.artist ~= "" and md.artist or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_title then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xCCCCCCFF)
                            r.ImGui_Text(ctx, md.title ~= "" and md.title or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_genre then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, md.genre ~= "" and md.genre or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_year then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, md.year ~= "" and md.year or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_client then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, md.client ~= "" and md.client or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_deadline then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x999999FF)
                            r.ImGui_Text(ctx, md.deadline ~= "" and md.deadline or "-")
                            r.ImGui_PopStyleColor(ctx)
                        end
                        if config.show_project_col_tags then
                            r.ImGui_TableNextColumn(ctx)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                            if md.tags and #md.tags > 0 then
                                local parts = {}
                                for _, t in ipairs(md.tags) do parts[#parts + 1] = "#" .. t end
                                r.ImGui_Text(ctx, table.concat(parts, " "))
                            else
                                r.ImGui_Text(ctx, "-")
                            end
                            r.ImGui_PopStyleColor(ctx)
                        end
                    end

                    if r.ImGui_BeginPopup(ctx, "ProjectContextMenu_" .. i) then
                        if r.ImGui_MenuItem(ctx, "Open Project") then
                            open_project(project.path)
                        end
                        
                        if r.ImGui_MenuItem(ctx, "Open in New Tab") then
                            r.Main_OnCommand(41929, 0)
                            r.Main_openProject(project.path)
                        end

                        if r.ImGui_MenuItem(ctx, "Edit Metadata...") then
                            TKFXBProjectMeta.OpenEditor(project)
                        end

                        if r.ImGui_BeginMenu(ctx, "Make Preview") then
                            if r.ImGui_MenuItem(ctx, "Full project") then
                                DoMakeProjectPreview(project.path, "full")
                            end
                            if r.ImGui_MenuItem(ctx, "Time selection") then
                                DoMakeProjectPreview(project.path, "timesel")
                            end
                            if r.ImGui_MenuItem(ctx, "Custom audio file...") then
                                DoMakeProjectPreviewCustom(project.path)
                            end
                            r.ImGui_EndMenu(ctx)
                        end

                        if r.ImGui_MenuItem(ctx, "Manage Previews...") then
                            manage_previews_target_path = project.path
                            manage_previews_open_request = true
                        end
                    
                        if r.ImGui_BeginMenu(ctx, "Play Project Audio") then
                            local project_directory = project.path:match("(.*[/\\])")
                            local audio_files = {}
                            
                            local idx = 0
                            local file = r.EnumerateFiles(project_directory, idx)
                            while file do
                                if file:match("%.wav$") or file:match("%.mp3$") or 
                                   file:match("%.aiff$") or file:match("%.ogg$") or 
                                   file:match("%.flac$") then
                                    table.insert(audio_files, file)
                                end
                                idx = idx + 1
                                file = r.EnumerateFiles(project_directory, idx)
                            end
                            
                            for _, filename in ipairs(audio_files) do
                                if r.ImGui_MenuItem(ctx, filename) then
                                    if current_preview then
                                        r.CF_Preview_StopAll()
                                    end
                                    ReleaseCurrentPreview()
                                    local source = r.PCM_Source_CreateFromFile(project_directory .. filename)
                                    if source then
                                        current_preview = r.CF_CreatePreview(source)
                                        r.CF_Preview_SetValue(current_preview, "D_VOLUME", preview_volume)
                                        current_source = source
                                        r.CF_Preview_Play(current_preview)
                                    end
                                end
                            end
                            
                            r.ImGui_EndMenu(ctx)
                        end

                        r.ImGui_Separator(ctx)
                        if r.ImGui_MenuItem(ctx, "Set Cover Image...") then
                            SetProjectCover(project.path)
                        end
                        local has_cover = GetProjectCoverPath(project.path) ~= nil
                        if has_cover then
                            if r.ImGui_MenuItem(ctx, "Remove Cover Image") then
                                local safe_name = project.path:match("([^/\\]+)%.rpp$") or ""
                                safe_name = safe_name:gsub("[^%w%s-]", "_")
                                os.remove(project_covers_path .. safe_name .. ".png")
                                os.remove(project_covers_path .. safe_name .. ".jpg")
                                project_cover_loaded_for = nil
                                project_cover_texture = nil
                            end
                        end
                        
                    
                        r.ImGui_EndPopup(ctx)
                    end
                    r.ImGui_PopID(ctx)
                end
                r.ImGui_EndTable(ctx)
                end
            r.ImGui_EndChild(ctx)

            TKFXBProjectMeta.DrawEditor()

            if manage_previews_open_request then
                manage_previews_open_request = nil
                r.ImGui_OpenPopup(ctx, "##ManagePreviews")
            end
            if r.ImGui_BeginPopup(ctx, "##ManagePreviews") then
                local target = manage_previews_target_path
                if target then
                    local dir = target:match("(.*[/\\])") or ""
                    local proj_name = target:match("([^/\\]+)%.rpp$") or ""
                    local prefix = proj_name .. ".tkprev."
                    local allowed_ext = { wav = 1, mp3 = 1, flac = 1, ogg = 1 }
                    r.ImGui_Text(ctx, "Previews: " .. proj_name)
                    r.ImGui_Separator(ctx)
                    local list = {}
                    if dir ~= "" and proj_name ~= "" then
                        local i = 0
                        repeat
                            local f = r.EnumerateFiles(dir, i)
                            local ext = f and f:match("%.([^%.]+)$")
                            if f and f:sub(1, #prefix) == prefix and ext and allowed_ext[ext:lower()] then
                                local full = dir .. f
                                local stamp_part = f:sub(#prefix + 1, -(#ext + 2))
                                local ts = tonumber(stamp_part:match("^(%d+)")) or 0
                                local mtime = 0
                                if r.JS_File_Stat then
                                    local rv, _, _, mt = r.JS_File_Stat(full)
                                    if rv then mtime = tonumber(mt) or 0 end
                                end
                                list[#list + 1] = { name = f, full = full, ts = ts, mtime = mtime, score = ts * 1e9 + mtime }
                            end
                            i = i + 1
                        until not f
