                r.ImGui_Text(ctx, "  Drag plugins here to build a chain...")
                r.ImGui_PopStyleColor(ctx)
            else
                r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), 8, 4)
                for ci = 1, #chain_builder_plugins do
                    local cp = chain_builder_plugins[ci]
