                    if config.clean_plugin_names or config.remove_manufacturer_names then
                        display_name = GetDisplayPluginName(cp)
                    end
                    r.ImGui_PushID(ctx, ci)

                    r.ImGui_BeginGroup(ctx)
                    local num_label = tostring(ci)
                    local grp_sx, grp_sy = r.ImGui_GetCursorScreenPos(ctx)
                    local tex = LoadChainFxScreenshot(cp)
                    local clicked = false
                    if tex and r.ImGui_ValidatePtr(tex, 'ImGui_Image*') then
                        local iw, ih = r.ImGui_Image_GetSize(tex)
                        if iw and ih then
                            local dw = thumb_w
                            local dh = dw * (ih / iw)
                            if dh > thumb_h then
                                dh = thumb_h
                                dw = dh * (iw / ih)
                            end
                            clicked = r.ImGui_ImageButton(ctx, "cb_" .. ci, tex, dw, dh)
                        else
                            clicked = r.ImGui_Button(ctx, display_name .. "##cb", thumb_w, thumb_h)
                        end
                    else
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), cb_btn)
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), cb_btn_hover)
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), cb_btn_active)
                        clicked = r.ImGui_Button(ctx, display_name .. "##cb", thumb_w, thumb_h)
                        r.ImGui_PopStyleColor(ctx, 3)
                    end

                    local cdl = r.ImGui_GetWindowDrawList(ctx)
                    local num_tw = r.ImGui_CalcTextSize(ctx, num_label)
                    r.ImGui_DrawList_AddRectFilled(cdl, grp_sx, grp_sy, grp_sx + num_tw + 6, grp_sy + 14, 0x000000B0, 3)
                    r.ImGui_DrawList_AddText(cdl, grp_sx + 3, grp_sy + 1, cb_accent, num_label)

                    if r.ImGui_BeginDragDropSource(ctx, r.ImGui_DragDropFlags_None()) then
                        r.ImGui_SetDragDropPayload(ctx, "CHAIN_REORDER", tostring(ci))
                        r.ImGui_Text(ctx, display_name)
                        r.ImGui_EndDragDropSource(ctx)
                    end
                    if r.ImGui_BeginDragDropTarget(ctx) then
                        local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "CHAIN_REORDER")
                        if rv then
                            local src = tonumber(payload)
                            if src and src ~= ci then
                                local item = table.remove(chain_builder_plugins, src)
                                local chunk_item = table.remove(chain_builder_chunks, src) or nil
                                local dst = ci
                                if src < ci then dst = dst end
                                table.insert(chain_builder_plugins, dst, item)
                                table.insert(chain_builder_chunks, dst, chunk_item)
                                config.chain_builder_plugins = chain_builder_plugins
                                SaveConfig()
                            end
                        end
                        r.ImGui_EndDragDropTarget(ctx)
                    end
                    local btn_hovered = r.ImGui_IsItemHovered(ctx)
                    local btn_rclicked = r.ImGui_IsItemClicked(ctx, 1)

                    local trunc_name = display_name
                    local max_text_w = thumb_w - 4
                    local tw = r.ImGui_CalcTextSize(ctx, trunc_name)
                    if tw > max_text_w then
                        while #trunc_name > 3 and r.ImGui_CalcTextSize(ctx, trunc_name .. "..") > max_text_w do
                            trunc_name = trunc_name:sub(1, -2)
                        end
                        trunc_name = trunc_name .. ".."
                    end
                    local name_w = r.ImGui_CalcTextSize(ctx, trunc_name)
                    local name_offset = (thumb_w - name_w) * 0.5
                    if name_offset > 0 then r.ImGui_SetCursorPosX(ctx, r.ImGui_GetCursorPosX(ctx) + name_offset) end
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xCCCCCCFF)
                    r.ImGui_Text(ctx, trunc_name)
                    r.ImGui_PopStyleColor(ctx)
                    r.ImGui_EndGroup(ctx)

                    if btn_rclicked then
                        table.remove(chain_builder_plugins, ci)
                        if chain_builder_chunks[ci] then table.remove(chain_builder_chunks, ci) end
                        config.chain_builder_plugins = chain_builder_plugins
                        SaveConfig()
                        r.ImGui_PopID(ctx)
                        break
                    end
                    if btn_hovered then
                        r.ImGui_SetTooltip(ctx, cp .. "\nRight-click to remove | Drag to reorder")
                    end
                    r.ImGui_SameLine(ctx)
                    r.ImGui_PopID(ctx)
                end
                r.ImGui_PopStyleVar(ctx)
            end
            r.ImGui_EndChild(ctx)
        end

        if r.ImGui_BeginDragDropTarget(ctx) then
            local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "CHAIN_REORDER")
            r.ImGui_EndDragDropTarget(ctx)
        end

        local dice_w = btn_row_h
        local btn_spacing = 4
        local count_text = string.format("(%d)", #chain_builder_plugins)
        local count_w = r.ImGui_CalcTextSize(ctx, count_text) + 10
        local total_btns = 6
        local usable = avail_w - pad * 2 - dice_w - count_w - btn_spacing * (total_btns + 1)
        local btn_w = math.max(38, math.floor(usable / total_btns))
        r.ImGui_SetCursorPosX(ctx, r.ImGui_GetCursorPosX(ctx) + pad)
        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), 4, 0)
        if r.ImGui_Button(ctx, "Commit##cb", btn_w, btn_row_h) then
            if #chain_builder_plugins > 0 then
                local sel_count = r.CountSelectedTracks(0)
                if sel_count > 0 then
                    r.Undo_BeginBlock()
                    r.PreventUIRefresh(1)
                    for ti = 0, sel_count - 1 do
                        local track = r.GetSelectedTrack(0, ti)
                        if track then
                            for ci, pname in ipairs(chain_builder_plugins) do
                                local fx_idx = AddFXToTrack(track, pname, true)
                                if fx_idx >= 0 and chain_builder_chunks[ci] then
                                    RestoreChainBuilderChunk(track, fx_idx, chain_builder_chunks[ci])
                                end
                            end
                        end
                    end
                    r.PreventUIRefresh(-1)
                    r.Undo_EndBlock("FX Chain Builder: Add chain to " .. sel_count .. " track(s)", -1)
                end
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            local sel_count = r.CountSelectedTracks(0)
            r.ImGui_SetTooltip(ctx, "Add chain to " .. sel_count .. " selected track(s)\nChain stays until you Clear")
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Replace##cb", btn_w, btn_row_h) then
            if #chain_builder_plugins > 0 then
                local sel_count = r.CountSelectedTracks(0)
                if sel_count > 0 then
                    r.Undo_BeginBlock()
                    r.PreventUIRefresh(1)
                    for ti = 0, sel_count - 1 do
                        local track = r.GetSelectedTrack(0, ti)
                        if track then
                            local existing = r.TrackFX_GetCount(track)
                            for fi = existing - 1, 0, -1 do
                                r.TrackFX_Delete(track, fi)
                            end
                            for ci, pname in ipairs(chain_builder_plugins) do
                                local fx_idx = AddFXToTrack(track, pname, true)
                                if fx_idx >= 0 and chain_builder_chunks[ci] then
                                    RestoreChainBuilderChunk(track, fx_idx, chain_builder_chunks[ci])
                                end
                            end
                        end
                    end
                    r.PreventUIRefresh(-1)
                    r.Undo_EndBlock("FX Chain Builder: Replace chain on " .. sel_count .. " track(s)", -1)
                end
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            local sel_count = r.CountSelectedTracks(0)
            r.ImGui_SetTooltip(ctx, "Replace FX chain on " .. sel_count .. " selected track(s)\nRemoves all existing FX first")
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Clear##cb", btn_w, btn_row_h) then
            chain_builder_plugins = {}
            chain_builder_chunks = {}
            config.chain_builder_plugins = chain_builder_plugins
            SaveConfig()
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Save##cb", btn_w, btn_row_h) then
            if #chain_builder_plugins > 0 then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                local track_count = r.CountTracks(0)
                r.InsertTrackAtIndex(track_count, false)
                local temp_track = r.GetTrack(0, track_count)
                if temp_track then
                    for ci, pname in ipairs(chain_builder_plugins) do
                        local fx_idx = AddFXToTrack(temp_track, pname, true)
                        if fx_idx >= 0 and chain_builder_chunks[ci] then
                            RestoreChainBuilderChunk(temp_track, fx_idx, chain_builder_chunks[ci])
                        end
                    end
                    local _, chunk = r.GetTrackStateChunk(temp_track, "", false)
                    local fxchain_block = nil
                    local fxchain_start = chunk:find("<FXCHAIN")
                    if fxchain_start then
                        local depth = 0
                        local i = fxchain_start
                        while i <= #chunk do
                            local c = chunk:sub(i, i)
                            if c == "<" then depth = depth + 1
                            elseif c == ">" then
                                depth = depth - 1
                                if depth == 0 then
                                    fxchain_block = chunk:sub(fxchain_start, i)
                                    break
                                end
                            end
                            i = i + 1
                        end
                    end
                    r.DeleteTrack(temp_track)
                    if fxchain_block then
                        local chain_dir = ResolveFxChainsRoot()
                        local safe_name = "Chain Builder " .. os.date("%Y-%m-%d_%H-%M-%S")
                        local chain_path = chain_dir .. os_separator .. safe_name .. ".RfxChain"
                        local f = io.open(chain_path, "w")
                        if f then
                            f:write(fxchain_block .. "\n")
                            f:close()
                        end
                    end
                end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Chain Builder Save", -1)
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            r.ImGui_SetTooltip(ctx, "Save chain as .RfxChain file")
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Load##cb", btn_w, btn_row_h) then
            local retval, file_path
            if r.JS_Dialog_BrowseForOpenFiles then
                retval, file_path = r.JS_Dialog_BrowseForOpenFiles("Load FX Chain", ResolveFxChainsRoot(), "", "FX Chain (*.RfxChain)\0*.RfxChain\0All Files (*.*)\0*.*\0", false)
            else
                retval, file_path = r.GetUserFileNameForRead("", "Load FX Chain", ".RfxChain")
            end
            if retval == 1 and file_path and file_path ~= "" then
                local loaded = ParseFxChainFile(file_path)
                if loaded and #loaded > 0 then
                    for _, fx in ipairs(loaded) do
                        table.insert(chain_builder_plugins, fx)
                        chain_builder_chunks[#chain_builder_plugins] = false
                    end
                    config.chain_builder_plugins = chain_builder_plugins
                    SaveConfig()
                end
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            r.ImGui_SetTooltip(ctx, "Load .RfxChain into builder")
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Grab##cb", btn_w, btn_row_h) then
            local track = r.GetSelectedTrack(0, 0)
            if not track then track = r.GetMasterTrack(0) end
            if track and r.ValidatePtr2(0, track, "MediaTrack*") then
                local fx_count = r.TrackFX_GetCount(track)
                if fx_count > 0 then
                    chain_builder_plugins = {}
                    chain_builder_chunks = GrabChainBuilderChunks(track)
                    for fi = 0, fx_count - 1 do
                        local retval, fx_name = r.TrackFX_GetFXName(track, fi)
                        if retval and fx_name and fx_name ~= "" then
                            chain_builder_plugins[#chain_builder_plugins + 1] = fx_name
                        end
                    end
                    config.chain_builder_plugins = chain_builder_plugins
                    SaveConfig()
                end
            end
        end
        if r.ImGui_IsItemHovered(ctx) then
            local track = r.GetSelectedTrack(0, 0)
            local tip = "Grab FX chain from selected track"
            if track then
                local _, name = r.GetTrackName(track)
                local num = math.floor(r.GetMediaTrackInfo_Value(track, "IP_TRACKNUMBER"))
                tip = tip .. "\nTrack " .. num .. ": " .. name
                tip = tip .. " (" .. r.TrackFX_GetCount(track) .. " FX)"
            else
                tip = tip .. "\n(no track selected)"
            end
            r.ImGui_SetTooltip(ctx, tip)
        end
        r.ImGui_SameLine(ctx)

        local chain_templates = {
            { name = "Clean Channel",   slots = {"instrument", "tone", "dynamics", "timebased"} },
            { name = "Lo-Fi",           slots = {"instrument", "tone", "modulation", "timebased"} },
            { name = "Ambient Pad",     slots = {"instrument", "modulation", "timebased", "timebased"} },
            { name = "Aggressive",      slots = {"instrument", "tone", "tone", "dynamics"} },
            { name = "Wet & Wide",      slots = {"instrument", "modulation", "modulation", "timebased"} },
            { name = "Vocal Chain",     slots = {"tone", "dynamics", "dynamics", "timebased"} },
            { name = "Guitar Rig",      slots = {"tone", "tone", "modulation", "timebased"} },
            { name = "Drum Bus",        slots = {"tone", "dynamics", "dynamics", "tone"} },
            { name = "Synth Stack",     slots = {"instrument", "instrument", "tone", "timebased"} },
            { name = "FX Mangler",      slots = {"tone", "modulation", "tone", "modulation"} },
        }

        local tone_kw = {"eq", "filter", "saturator", "saturat", "distort", "overdrive", "exciter", "waveshap", "bitcrush", "amp", "cabinet", "preamp", "tube", "warm", "drive", "fuzz", "clipper"}
        local dyn_kw = {"compressor", "compress", "limiter", "limit", "gate", "expander", "transient", "dynamics", "leveler", "de%-ess", "deess", "multiband"}
        local mod_kw = {"chorus", "flanger", "phaser", "tremolo", "vibrato", "rotary", "leslie", "ensemble", "unison", "detune", "pitch", "harmoniz", "autotune", "vocoder", "ringmod", "stereo", "widen", "imager"}
        local time_kw = {"reverb", "delay", "echo", "room", "hall", "plate", "spring", "convol", "shimmer", "ambien", "space", "diffus"}

        local function classify_fx(name)
            local low = name:lower()
            for _, kw in ipairs(tone_kw) do if low:find(kw) then return "tone" end end
            for _, kw in ipairs(dyn_kw) do if low:find(kw) then return "dynamics" end end
            for _, kw in ipairs(mod_kw) do if low:find(kw) then return "modulation" end end
            for _, kw in ipairs(time_kw) do if low:find(kw) then return "timebased" end end
            return "other"
        end

        local function build_pools()
            local pools = { instrument = {}, tone = {}, dynamics = {}, modulation = {}, timebased = {}, other = {} }
            if not FX_LIST_TEST then return pools end
            for _, name in ipairs(FX_LIST_TEST) do
                if IsInstrumentPlugin(name) then
                    pools.instrument[#pools.instrument + 1] = name
                else
                    local cat = classify_fx(name)
                    pools[cat][#pools[cat] + 1] = name
                end
            end
            return pools
        end

        local function pick_random(pool, used)
            if not pool or #pool == 0 then return nil end
            local attempts = 0
            while attempts < 20 do
                local pick = pool[math.random(#pool)]
                if not used[pick] then
                    used[pick] = true
                    return pick
                end
                attempts = attempts + 1
            end
            return pool[math.random(#pool)]
        end

        local function apply_template(tmpl)
            math.randomseed(os.time() + math.floor(r.time_precise() * 1000))
            local pools = build_pools()
            local fallback_order = {"tone", "dynamics", "modulation", "timebased", "other"}
            local used = {}
            chain_builder_plugins = {}
            chain_builder_chunks = {}
            for _, slot_cat in ipairs(tmpl.slots) do
                local fx = pick_random(pools[slot_cat], used)
                if not fx and slot_cat ~= "instrument" then
                    for _, fb in ipairs(fallback_order) do
                        if fb ~= slot_cat then
                            fx = pick_random(pools[fb], used)
                            if fx then break end
                        end
                    end
                end
                if fx then
                    chain_builder_plugins[#chain_builder_plugins + 1] = fx
                end
            end
            config.chain_builder_plugins = chain_builder_plugins
            SaveConfig()
        end

        if r.ImGui_Button(ctx, "\xF0\x9F\x8E\xB2##cb", btn_row_h, btn_row_h) then
            local pools = build_pools()
            math.randomseed(os.time() + math.floor(r.time_precise() * 1000))
            local used = {}
            chain_builder_chunks = {}
            if #pools.instrument > 0 then
                local pick = pick_random(pools.instrument, used)
                if pick then table.insert(chain_builder_plugins, pick) end
            end
            local chain_slots = {
                {"tone", "dynamics", "other"},
                {"dynamics", "modulation", "other"},
                {"modulation", "timebased", "other"},
            }
            for _, slot in ipairs(chain_slots) do
                for _, cat in ipairs(slot) do
                    local fx = pick_random(pools[cat], used)
                    if fx then
                        table.insert(chain_builder_plugins, fx)
                        break
                    end
                end
            end
            config.chain_builder_plugins = chain_builder_plugins
            SaveConfig()
        end
        if r.ImGui_IsItemHovered(ctx) then
            r.ImGui_SetTooltip(ctx, "Left-click: Random (1 instr + 3 FX)\nRight-click: Chain Templates")
        end
        if r.ImGui_IsItemClicked(ctx, 1) then
            r.ImGui_OpenPopup(ctx, "ChainTemplateMenu")
        end
        if r.ImGui_BeginPopup(ctx, "ChainTemplateMenu") then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFFFF80)
            r.ImGui_Text(ctx, "Chain Templates")
            r.ImGui_PopStyleColor(ctx)
            r.ImGui_Separator(ctx)
            for _, tmpl in ipairs(chain_templates) do
                local slot_names = {}
                for _, s in ipairs(tmpl.slots) do
                    local labels = {instrument="\xF0\x9F\x8E\xB9", tone="\xF0\x9F\x8E\x9B", dynamics="\xF0\x9F\x94\x8A", modulation="\xF0\x9F\x8C\x80", timebased="\xF0\x9F\x8C\x8A"}
                    slot_names[#slot_names + 1] = labels[s] or "\xE2\x9A\xA1"
                end
                local label = tmpl.name .. "  " .. table.concat(slot_names, " \xE2\x86\x92 ")
                if r.ImGui_MenuItem(ctx, label) then
                    apply_template(tmpl)
                end
            end
            r.ImGui_EndPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFFFF80)
        r.ImGui_SetCursorPosY(ctx, r.ImGui_GetCursorPosY(ctx) + 3)
        r.ImGui_Text(ctx, string.format("(%d)", #chain_builder_plugins))
        r.ImGui_PopStyleColor(ctx)
        r.ImGui_PopStyleVar(ctx)
        
        r.ImGui_Dummy(ctx, 0, 5)
    end

    local _multi_count = GetMultiSelectedCount()
    if _multi_count > 1 then
        local _controls_layout = config.screenshot_controls_layout or "horizontal"
        local _controls_auto_vertical = (_controls_layout == "auto" and r.ImGui_GetContentRegionAvail(ctx) < 300)
        local _controls_are_vertical = (_controls_layout == "vertical" or _controls_auto_vertical)
        local _sel_text = string.format("[%d selected]", _multi_count)
        if not _controls_are_vertical then
            r.ImGui_SameLine(ctx)
        end
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x00BFFFCC)
        r.ImGui_Text(ctx, _sel_text)
        r.ImGui_PopStyleColor(ctx)
    end

    if config.show_custom_folder_tabs and type(config.custom_folders) == "table" then
        local function CollectTopLevelNames(tbl)
            local names = {}
            for n, _ in pairs(tbl) do
                if n ~= "__folder_marker__" and type(n) == "string" then
                    names[#names + 1] = n
                end
            end
            table.sort(names, function(a, b) return a:lower() < b:lower() end)
            return names
        end
        local function ResolveCustomNode(full_path)
            if not full_path or full_path == "" then return nil end
            local node = config.custom_folders
            for part in full_path:gmatch("[^/]+") do
                if type(node) ~= "table" then return nil end
                node = node[part]
            end
            return node
        end
        local function HasSubfolders(node)
            if type(node) ~= "table" then return false end
            for k, v in pairs(node) do
                if k ~= "__folder_marker__" and type(k) == "string" and type(v) == "table" then
                    return true
                end
            end
            return false
        end
        local level_colors = config.custom_folder_level_colors or {}
        local default_text = config.custom_folder_text_color or r.ImGui_GetColor(ctx, r.ImGui_Col_Text())
        local function LevelColor(d)
            local idx = math.min(d, #level_colors)
            if idx < 1 then idx = 1 end
            return level_colors[idx] or default_text
        end
        cftab_scroll_pending = cftab_scroll_pending or {}
        local function DrawTabRow(names, depth, parent_path)
            if #names == 0 and depth ~= 1 then return end
            local scroll_mode = config.custom_folder_tabs_overflow_scroll
            local avail_w = r.ImGui_GetContentRegionAvail(ctx)
            local spacing = 4
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), spacing, spacing)

            local function DrawPlus()
                local plus_w = 22
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x3F3F3F3F)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x5F5F5F5F)
                if r.ImGui_Button(ctx, "+##cftab_add_root", plus_w, 0) then
                    show_add_root_folder_popup = true
                    new_root_folder_name = ""
                    r.ImGui_OpenPopup(ctx, "Add Custom Folder")
                end
                r.ImGui_PopStyleColor(ctx, 3)
                if r.ImGui_IsItemHovered(ctx) then
                    r.ImGui_SetTooltip(ctx, "Create a new custom folder")
                end
                return plus_w
            end

            local function DrawVirtualTabs(initial_sameline)
                local total_w = 0
                local first = true
                local function DrawVirtualTab(label, target, tooltip)
                    if first then
                        if initial_sameline then
                            r.ImGui_SameLine(ctx)
                            total_w = total_w + spacing
                        end
                    else
                        r.ImGui_SameLine(ctx)
                        total_w = total_w + spacing
                    end
                    first = false
                    local is_active = (selected_folder == target)
                    if is_active then
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x4A6FA5FF)
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A7FB5FF)
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x3A5F95FF)
                    end
                    local txt_w = r.ImGui_CalcTextSize(ctx, label)
                    local btn_w = txt_w + 16
                    if r.ImGui_Button(ctx, label .. "##cftab_virt_" .. target, btn_w, 0) then
                        if target == "__ALL__" then
                            SelectFolderExclusive(nil)
                        else
                            if is_active then
                                SelectFolderExclusive(nil)
                            else
                                SelectFolderExclusive(target)
                            end
                        end
                    end
                    if is_active then r.ImGui_PopStyleColor(ctx, 3) end
                    if tooltip and r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, tooltip) end
                    total_w = total_w + btn_w
                end

                if config.show_tab_all then
                    DrawVirtualTab("All", "__ALL__", "Show all plugins (clear folder filter)")
                end
                if config.show_tab_favorites then
                    local cnt = favorite_plugins and #favorite_plugins or 0
                    local lbl = "\xE2\x98\x85 Favorites" .. (config.show_tab_plugin_count and cnt > 0 and (" (" .. cnt .. ")") or "")
                    DrawVirtualTab(lbl, "Favorites", "Plugins marked as favorite")
                end
                if config.show_tab_recent then
                    local cnt = recent_plugins and #recent_plugins or 0
                    local lbl = "Recent" .. (config.show_tab_plugin_count and cnt > 0 and (" (" .. cnt .. ")") or "")
                    DrawVirtualTab(lbl, "Recent", "Recently added plugins")
                end
                return total_w
            end

            local function DrawTab(i, name, row_w_in)
                local row_w = row_w_in
                local full_path = (parent_path == "" or parent_path == nil) and name or (parent_path .. "/" .. name)
                local label = config.custom_folder_force_uppercase and name:upper() or name
                local display_label = label
                if config.show_tab_plugin_count then
                    local node = ResolveCustomNode(full_path)
                    local plugin_count = 0
                    if type(node) == "table" then
                        for k, v in pairs(node) do
                            if type(k) == "number" and type(v) == "string" then
                                plugin_count = plugin_count + 1
                            end
                        end
                    end
                    if plugin_count > 0 then
                        display_label = label .. " (" .. plugin_count .. ")"
                    end
                end
                local btn_label = display_label .. "##cftab_" .. depth .. "_" .. i
                local txt_w = r.ImGui_CalcTextSize(ctx, display_label)
                local btn_w = txt_w + 16
                local need_sameline = (depth == 1 or i > 1)
                if need_sameline then
                    if scroll_mode or (row_w + btn_w + spacing <= avail_w) then
                        r.ImGui_SameLine(ctx)
                        row_w = row_w + spacing
                    else
                        row_w = 0
                    end
                end
                local sel_now = selected_folder
                local is_sel = (sel_now == full_path)
                local is_ancestor = false
                if not is_sel and type(sel_now) == "string" then
                    if sel_now:sub(1, #full_path + 1) == full_path .. "/" then
                        is_ancestor = true
                    end
                end
                local txt_col = LevelColor(depth)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), txt_col)
                if is_sel then
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x4A6FA5FF)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A7FB5FF)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x3A5F95FF)
                elseif is_ancestor then
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x35507AFF)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x456088FF)
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x2A4068FF)
                end
                if r.ImGui_Button(ctx, btn_label, btn_w, 0) then
                    if is_sel then
                        SelectFolderExclusive(nil)
                    else
                        SelectFolderExclusive(full_path)
                    end
                end
                CheckFolderDropTarget(full_path, "custom")
                if r.ImGui_IsItemClicked(ctx, 1) then
                    r.ImGui_OpenPopup(ctx, "FolderContextMenu_" .. full_path)
                end
                if r.ImGui_BeginPopup(ctx, "FolderContextMenu_" .. full_path) then
                    DrawCustomFolderContextMenu(name, parent_path or "", full_path)
                    r.ImGui_EndPopup(ctx)
                end
                if is_sel or is_ancestor then r.ImGui_PopStyleColor(ctx, 3) end
                r.ImGui_PopStyleColor(ctx)
                row_w = row_w + btn_w
                return row_w
            end

            if scroll_mode then
                local arrow_w = 20
                local btn_h = r.ImGui_GetFrameHeight(ctx)
                local child_id = "cftab_scroll_" .. depth .. "_" .. (parent_path or "")
                local outer_used = 0
                if depth == 1 then
                    outer_used = outer_used + DrawPlus() + spacing
                    r.ImGui_SameLine(ctx)
                end
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x3F3F3F3F)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x5F5F5F5F)
                if r.ImGui_Button(ctx, "<##" .. child_id, arrow_w, btn_h) then
                    cftab_scroll_pending[child_id] = (cftab_scroll_pending[child_id] or 0) - 100
                end
                r.ImGui_PopStyleColor(ctx, 3)
                r.ImGui_SameLine(ctx)
                local child_w = avail_w - outer_used - arrow_w*2 - spacing*2
                if child_w < 50 then child_w = 50 end
                local visible = r.ImGui_BeginChild(ctx, child_id, child_w, btn_h + 4, 0, r.ImGui_WindowFlags_HorizontalScrollbar() | r.ImGui_WindowFlags_NoScrollbar())
                if visible then
                    if cftab_scroll_pending[child_id] then
                        r.ImGui_SetScrollX(ctx, r.ImGui_GetScrollX(ctx) + cftab_scroll_pending[child_id])
                        cftab_scroll_pending[child_id] = nil
                    end
                    local row_w = 0
                    if depth == 1 then
                        row_w = row_w + DrawVirtualTabs(false)
                    end
                    for i, name in ipairs(names) do
                        row_w = DrawTab(i, name, row_w)
                    end
                    r.ImGui_EndChild(ctx)
                end
                r.ImGui_SameLine(ctx)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x3F3F3F3F)
                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x5F5F5F5F)
                if r.ImGui_Button(ctx, ">##" .. child_id, arrow_w, btn_h) then
                    cftab_scroll_pending[child_id] = (cftab_scroll_pending[child_id] or 0) + 100
                end
                r.ImGui_PopStyleColor(ctx, 3)
            else
                local row_w = 0
                if depth == 1 then
                    row_w = DrawPlus()
                    row_w = row_w + DrawVirtualTabs(true)
                end
                for i, name in ipairs(names) do
                    row_w = DrawTab(i, name, row_w)
                end
            end
            r.ImGui_PopStyleVar(ctx)
        end

        local top_names = CollectTopLevelNames(config.custom_folders)
        do
            DrawTabRow(top_names, 1, "")

            local _sel_snap = selected_folder
            if config.custom_folder_tabs_show_nested and _sel_snap and type(_sel_snap) == "string"
               and _sel_snap ~= "Favorites" and _sel_snap ~= "Recent" and _sel_snap ~= "Current Track FX" and _sel_snap ~= "Current Project FX" then
                local active_top = _sel_snap:match("^([^/]+)")
                if active_top and config.custom_folders[active_top] then
                    if config.custom_folder_tabs_breadcrumb then
                        local segments = {}
                        for seg in (_sel_snap .. "/"):gmatch("([^/]+)/") do
                            segments[#segments+1] = seg
                        end
                        if #segments >= 2 then
                            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), 4, 4)
                            local accum_path = ""
                            for i, seg in ipairs(segments) do
                                accum_path = (i == 1) and seg or (accum_path .. "/" .. seg)
                                if i > 1 then
                                    r.ImGui_SameLine(ctx)
                                    r.ImGui_TextDisabled(ctx, ">")
                                    r.ImGui_SameLine(ctx)
                                end
                                local seg_label = config.custom_folder_force_uppercase and seg:upper() or seg
                                local is_last = (i == #segments)
                                local txt_col = LevelColor(i)
                                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), txt_col)
                                if is_last then
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x4A6FA5FF)
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x5A7FB5FF)
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x3A5F95FF)
                                end
                                if r.ImGui_Button(ctx, seg_label .. "##bc_" .. i, 0, 0) then
                                    SelectFolderExclusive(accum_path)
                                end
                                if is_last then r.ImGui_PopStyleColor(ctx, 3) end
                                r.ImGui_PopStyleColor(ctx)
                            end
                            r.ImGui_PopStyleVar(ctx)
                            local node = ResolveCustomNode(_sel_snap)
                            if HasSubfolders(node) then
                                local sub_names = CollectTopLevelNames(node)
                                if #sub_names > 0 then
                                    DrawTabRow(sub_names, #segments + 1, _sel_snap)
                                end
                            end
                        else
                            local node = ResolveCustomNode(active_top)
                            if HasSubfolders(node) then
                                local sub_names = CollectTopLevelNames(node)
                                if #sub_names > 0 then
                                    DrawTabRow(sub_names, 2, active_top)
                                end
                            end
                        end
                    else
                        local current_depth = 1
                        local current_path = active_top
                        while true do
                            local node = ResolveCustomNode(current_path)
                            if not HasSubfolders(node) then break end
                            local sub_names = CollectTopLevelNames(node)
                            if #sub_names == 0 then break end
                            DrawTabRow(sub_names, current_depth + 1, current_path)
                            if _sel_snap:sub(1, #current_path + 1) == current_path .. "/" then
                                local rest = _sel_snap:sub(#current_path + 2)
                                local next_part = rest:match("^([^/]+)")
                                if next_part then
                                    current_path = current_path .. "/" .. next_part
                                    current_depth = current_depth + 1
                                else
                                    break
                                end
                            else
                                break
                            end
                        end
                    end
                end
            end
            r.ImGui_Dummy(ctx, 0, 4)
        end
    end

    r.ImGui_BeginChild(ctx, "ScreenshotList", 0, 0, 0, r.ImGui_WindowFlags_NoNavInputs())
            if config.flicker_guard_enabled then
                local now = r.time_precise()
                local sig = _build_screenshot_signature()
                local sig_changed = (sig ~= _last_screenshot_signature)
                local typed_recently = (now - _last_search_input_time) * 1000.0 < _search_debounce_ms
                if sig_changed and not typed_recently then
                    if _pending_clear_cache then
                        ClearScreenshotCache()
                        _pending_clear_cache = false
                    end
                    _last_screenshot_signature = sig
                end
            end
            local scroll_y = r.ImGui_GetScrollY(ctx)
            local scroll_max_y = r.ImGui_GetScrollMaxY(ctx)
            screenshot_search_results = screenshot_search_results or {}
            if current_filtered_fx and not config.use_pagination and #current_filtered_fx > loaded_items_count then
                if scroll_max_y <= 0 or (scroll_y > 0 and scroll_y/scroll_max_y > 0.8) then
                    loaded_items_count = loaded_items_count + ITEMS_PER_BATCH
                    for i = #screenshot_search_results + 1, math.min(loaded_items_count, #current_filtered_fx) do
                        table.insert(screenshot_search_results, {name = current_filtered_fx[i]})
                    end
                end
            end
            if folder_changed or new_search_performed then
                r.ImGui_SetScrollY(ctx, 0)
                folder_changed = false
                new_search_performed = false
            end
            if selected_folder ~= last_selected_folder and selected_folder then
                folder_changed = true
                last_selected_folder = selected_folder
            end


            if selected_folder then
                local filtered_plugins = {}
                screenshot_shortcut_frame_idx = 0
                if IsShortcutContextEligible() then
                    ResetShortcutMap()
                    local flags = r.ImGui_FocusedFlags_RootAndChildWindows() | r.ImGui_FocusedFlags_NoPopupHierarchy()
                    local win_focused = r.ImGui_IsWindowFocused(ctx, flags)
                    local item_active = r.ImGui_IsAnyItemActive(ctx)
                    screenshot_shortcuts_window_focused = win_focused and not item_active
                else
                    screenshot_shortcuts_window_focused = false
                end
                
                if selected_folder == "Favorites" or selected_folder == "Recent" then
                    filtered_plugins = (selected_folder == "Recent") and recent_plugins or favorite_plugins
                    local pinned, others = {}, {}
                    local term = (screenshot_folder_filter_suspended and "" or browser_search_term):lower()
                    for _, plugin in ipairs(filtered_plugins) do
                        if FuzzyFind(plugin, term) then
                            if IsPluginPinned and IsPluginPinned(plugin) then pinned[#pinned+1] = plugin else others[#others+1] = plugin end
                        end
                    end
                    if config.apply_type_priority then
                        pinned = DedupeByTypePriority(pinned)
                        others = DedupeByTypePriority(others)
                    end
                    if selected_folder ~= "Recent" then
                        SortPlainPluginList(pinned, config.sort_mode)
                        SortPlainPluginList(others, config.sort_mode)
                    end
                    local display_plugins = {}
                    
                    -- Add pinned plugins first if show_pinned_on_top is enabled
                    if config and config.show_pinned_on_top then
                        for _, p in ipairs(pinned) do display_plugins[#display_plugins+1] = p end
                        if #pinned > 0 and #others > 0 then display_plugins[#display_plugins+1] = "--Pinned End--" end
                    else
                        -- Add pinned plugins to others if show_pinned_on_top is disabled
                        for _, p in ipairs(pinned) do others[#others+1] = p end
                        if selected_folder ~= "Recent" then
                            SortPlainPluginList(others, config.sort_mode)
                        end
                    end
                    
                    for _, p in ipairs(others) do display_plugins[#display_plugins+1] = p end
                    filtered_plugins = display_plugins
                    -- Sync visible names for texture pruning (Current Track FX)
                    current_filtered_fx = {}
                    for _, fx in ipairs(display_plugins) do
                        if type(fx) == 'table' and fx.fx_name then
                            current_filtered_fx[#current_filtered_fx+1] = fx.fx_name
                        end
                    end
                    -- Sync visible list for texture pruning (custom folders)
                    current_filtered_fx = {}
                    for _, name in ipairs(display_plugins) do
                        if type(name) == 'string' and name ~= "--Favorites End--" and name ~= "--Pinned End--" then
                            current_filtered_fx[#current_filtered_fx+1] = name
                        end
                    end

                    if #filtered_plugins == 0 then
                        r.ImGui_Text(ctx, (selected_folder == "Recent") and "No Recent plugins match search." or "No Favorites match search.")
                    else
                        if view_mode == "list" then
                            RenderListViewItems(filtered_plugins, "favorites_list")
                        elseif config.use_polaroid_layout or config.use_showcase_layout or config.use_masonry_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                            local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                            local masonry_data = {}
                            for _, plugin in ipairs(with_shot) do
                                if plugin == "--Favorites End--" then
                                    masonry_data[#masonry_data+1] = {is_separator = true, label = "--- Favorites End ---"}
                                elseif plugin == "--Pinned End--" then
                                    masonry_data[#masonry_data+1] = {is_separator = true, label = "--- Pinned End ---"}
                                else
                                    masonry_data[#masonry_data+1] = {name = plugin, shortcut = NextScreenshotShortcutLabel(plugin)}
                                end
                            end
                            if config.use_polaroid_layout then
                                DrawPolaroidLayout(masonry_data)
                            elseif config.use_showcase_layout then
                                DrawShowcaseLayout(masonry_data)
                            elseif config.use_uniform_layout then
                                DrawUniformLayout(masonry_data)
                            elseif config.use_neon_layout then
                                DrawNeonLayout(masonry_data)
                            elseif config.use_vinyl_layout then
                                DrawVinylLayout(masonry_data)
                            else
                                DrawMasonryLayout(masonry_data)
                            end
                            RenderMissingList(missing)
                        else
                            local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                            ApplyTopScreenshotSpacing()
                            for i, plugin_name in ipairs(with_shot) do
                                if plugin_name == "--Favorites End--" or plugin_name == "--Pinned End--" then
                                    DrawHorizontalSeparatorBar((config.compact_screenshots and 2 or 3), 0x606060FF)
                                    r.ImGui_Dummy(ctx, 0, (config.compact_screenshots and 6 or 10))
                                else
                                    local column = (i - 1) % num_columns
                                    local card_horiz_spacing = config.use_modern_cards and 12 or 0
                                    if column > 0 then r.ImGui_SameLine(ctx, 0, card_horiz_spacing) end
                                    local nav_cy = r.ImGui_GetCursorPosY(ctx)
                                    r.ImGui_BeginGroup(ctx)
                                    local screenshot_file = HasScreenshot(plugin_name)
                                    local texture = LoadSearchTexture(screenshot_file, plugin_name)
                                    if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                        local w, h = r.ImGui_Image_GetSize(texture)
                                        if w and h then
                                            local dw, dh = ScaleScreenshotSize(w, h, display_size)
                                            local clicked = r.ImGui_ImageButton(ctx, "fav_" .. i, texture, dw, dh)
                                            ScreenshotNavRegister(i, column + 1, 0, nav_cy, plugin_name)
                                            do
                                                local ntlx, ntly = r.ImGui_GetItemRectMin(ctx)
                                                local nbrx, nbry = r.ImGui_GetItemRectMax(ctx)
                                                DrawNavSelectionBorder(i, ntlx, ntly, nbrx, nbry)
                                                DrawModernCardBackground(ntlx, ntly, nbrx - ntlx, nbry - ntly)
                                                DrawModernCardForeground(ntlx, ntly, nbrx - ntlx, nbry - ntly)
                                            end
                                            if IsPluginPinned and IsPluginPinned(plugin_name) then
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawPinnedOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                            end
                                            if favorite_set and favorite_set[plugin_name] then
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawFavoriteOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                            end
                                            do
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawNameOnScreenshot(tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                RenderScreenshotShortcut(plugin_name, tlx, tly)
                                            end
                                            if config.enable_drag_add_fx then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx,0) then
                                                    potential_drag_fx_name = plugin_name
                                                    drag_start_x, drag_start_y = r.ImGui_GetMousePos(ctx)
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseDown(ctx,0) then
                                                    local mx,my = r.ImGui_GetMousePos(ctx)
                                                    if math.abs(mx-drag_start_x) > 3 or math.abs(my-drag_start_y) > 3 then
                                                        dragging_fx_name = plugin_name
                                                        potential_drag_fx_name = nil
                                                    end
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseReleased(ctx,0) then
                                                    potential_drag_fx_name = nil
                                                end
                                            end
                                            local do_add = false
                                            if config.add_fx_with_double_click then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsMouseDoubleClicked(ctx, 0) then HandleMultiSelectClick(i) end
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx,0) and dragging_fx_name ~= plugin_name then do_add = true end
                                            else
                                                if clicked and dragging_fx_name ~= plugin_name then do_add = true end
                                            end
                                            if do_add then
                                                local target_track = GetTargetTrack()
                                                if target_track then
                                                    local fx_index = AddFXToTrack(target_track, plugin_name)
                                                    LAST_USED_FX = plugin_name
                                                    if config.open_floating_after_adding and fx_index >= 0 then
                                                        r.TrackFX_Show(target_track, fx_index, 3)
                                                    end
                                                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                                                end
                                            end
                                            ShowPluginContextMenu(plugin_name, "favorites_win_" .. i)
                                            local display_name = GetDisplayPluginName(plugin_name)
                                            local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[plugin_name] and not config.show_name_on_hover_only
                                            if show_name_text then
                                                r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + dw)
                                                r.ImGui_Text(ctx, display_name)
                                                r.ImGui_PopTextWrapPos(ctx)
                                                r.ImGui_Text(ctx, GetStarsString(plugin_name))
                                            end
                                        end
                                    end
                                    r.ImGui_EndGroup(ctx)
                                    if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                                        local stars = GetStarsString(plugin_name)
                                        r.ImGui_SetTooltip(ctx, GetDisplayPluginName(plugin_name) .. (stars ~= "" and "\n" .. stars or ""))
                                    end
                                    if not config.compact_screenshots and column == num_columns - 1 then
                                        local row_spacing = config.use_modern_cards and 12 or 5
                                        r.ImGui_Dummy(ctx, 0, row_spacing)
                                    end
                                end
                            end
                            HandleScreenshotNavigation(with_shot)
                            RenderMissingList(missing)
                        end

                    end -- END favorites condition

                -- CUSTOM FOLDERS RENDERING
                elseif (selected_folder and next(GetPluginsFromCustomFolder(selected_folder) or {}) ~= nil) then
                    filtered_plugins = GetPluginsFromCustomFolder(selected_folder or "") or {}
                    local display_plugins = {}
                    if config.show_favorites_on_top then
                        local term_l = GetLowerName(screenshot_folder_filter_suspended and "" or browser_search_term)
                        local pinned, favorites, regular = {}, {}, {}
                        for _, plugin in ipairs(filtered_plugins) do
                            if GetLowerName(plugin):find(term_l, 1, true) then
                                if IsPluginPinned and IsPluginPinned(plugin) then
                                    pinned[#pinned+1] = plugin
                                elseif favorite_set[plugin] then
                                    favorites[#favorites+1] = plugin
                                else
                                    regular[#regular+1] = plugin
                                end
                            end
                        end
                        if config.apply_type_priority then
                            pinned = DedupeByTypePriority(pinned)
                            favorites = DedupeByTypePriority(favorites)
                            regular = DedupeByTypePriority(regular)
                        end
                        SortPlainPluginList(pinned, config.sort_mode)
                        SortPlainPluginList(favorites, config.sort_mode)
                        SortPlainPluginList(regular, config.sort_mode)
                        
                        -- Add pinned plugins first if show_pinned_on_top is enabled
                        if config and config.show_pinned_on_top then
                            for _, p in ipairs(pinned) do display_plugins[#display_plugins+1] = p end
                            if #pinned>0 and (#favorites>0 or #regular>0) then display_plugins[#display_plugins+1] = "--Pinned End--" end
                        else
                            -- Add pinned plugins to regular if show_pinned_on_top is disabled
                            for _, p in ipairs(pinned) do regular[#regular+1] = p end
                            SortPlainPluginList(regular, config.sort_mode)
                        end
                        
                        for _, p in ipairs(favorites) do display_plugins[#display_plugins+1] = p end
                        if #favorites>0 and #regular>0 then display_plugins[#display_plugins+1] = "--Favorites End--" end
                        for _, p in ipairs(regular) do display_plugins[#display_plugins+1] = p end
                    else
                        -- show_favorites_on_top is false: still check pinned-on-top setting
                        local term_l = GetLowerName(screenshot_folder_filter_suspended and "" or browser_search_term)
                        local pinned, others = {}, {}
                        for _, plugin in ipairs(filtered_plugins) do
                            if GetLowerName(plugin):find(term_l,1,true) then
                                if IsPluginPinned and IsPluginPinned(plugin) then pinned[#pinned+1] = plugin else others[#others+1] = plugin end
                            end
                        end
                        if config.apply_type_priority then
                            pinned = DedupeByTypePriority(pinned)
                            others = DedupeByTypePriority(others)
                        end
                        SortPlainPluginList(pinned, config.sort_mode)
                        SortPlainPluginList(others, config.sort_mode)
                        
                        -- Add pinned plugins first if show_pinned_on_top is enabled
                        if config and config.show_pinned_on_top then
                            for _, p in ipairs(pinned) do display_plugins[#display_plugins+1] = p end
                            if #pinned>0 and #others>0 then display_plugins[#display_plugins+1] = "--Pinned End--" end
                        else
                            -- Add pinned plugins to others if show_pinned_on_top is disabled
                            for _, p in ipairs(pinned) do others[#others+1] = p end
                            SortPlainPluginList(others, config.sort_mode)
                        end
                        
                        for _, p in ipairs(others) do display_plugins[#display_plugins+1] = p end
                    end
                    filtered_plugins = display_plugins
                    local custom_total_count = #filtered_plugins
                    if config.use_pagination then
                        filtered_plugins = ApplyFolderPaginationSlice(filtered_plugins, selected_folder or "?")
                    end
                    -- Sync visible names for texture pruning (Current Project FX)
                    current_filtered_fx = {}
                    for _, plugin in ipairs(display_plugins) do
                        if type(plugin) == 'table' and plugin.fx_name then
                            current_filtered_fx[#current_filtered_fx+1] = plugin.fx_name
                        end
                    end

                    if #filtered_plugins == 0 then
                        r.ImGui_Text(ctx, "No Custom Folder plugins match search.")
                    else
                        if view_mode == "list" then
                            RenderListViewItems(filtered_plugins, "custom_list")
                        elseif config.use_polaroid_layout or config.use_showcase_layout or config.use_masonry_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                            local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                            local masonry_data = {}
                            
                            for _, plugin in ipairs(with_shot) do
                                if plugin == "--Favorites End--" then
                                    masonry_data[#masonry_data+1] = { is_separator = true, kind = "favorites_end" }
                                elseif plugin == "--Pinned End--" then
                                    masonry_data[#masonry_data+1] = { is_separator = true, kind = "pinned_end" }
                                else
                                    masonry_data[#masonry_data+1] = { name = plugin, shortcut = NextScreenshotShortcutLabel(plugin) }
                                end
                            end
                            if config.use_polaroid_layout then
                                DrawPolaroidLayout(masonry_data)
                            elseif config.use_showcase_layout then
                                DrawShowcaseLayout(masonry_data)
                            elseif config.use_uniform_layout then
                                DrawUniformLayout(masonry_data)
                            elseif config.use_neon_layout then
                                DrawNeonLayout(masonry_data)
                            elseif config.use_vinyl_layout then
                                DrawVinylLayout(masonry_data)
                            else
                                DrawMasonryLayout(masonry_data)
                            end
                            RenderMissingList(missing)
                        else
                            local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                            ApplyTopScreenshotSpacing()
                            ScreenshotNavReset()
                            for i, plugin_name in ipairs(with_shot) do
                                if plugin_name == "--Favorites End--" or plugin_name == "--Pinned End--" then
                                    DrawHorizontalSeparatorBar((config.compact_screenshots and 2 or 3), 0x606060FF)
                                    r.ImGui_Dummy(ctx, 0, (config.compact_screenshots and 6 or 10))
                                else
                                    local column = (i - 1) % num_columns
                                    local card_horiz_spacing = config.use_modern_cards and 12 or 0
                                    if column > 0 then r.ImGui_SameLine(ctx, 0, card_horiz_spacing) end
                                    local nav_cy = r.ImGui_GetCursorPosY(ctx)
                                    r.ImGui_BeginGroup(ctx)
                                    local screenshot_file = HasScreenshot(plugin_name)
                                    local texture = LoadSearchTexture(screenshot_file, plugin_name)
                                    if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                        local w, h = r.ImGui_Image_GetSize(texture)
                                        if w and h then
                                            local dw, dh = ScaleScreenshotSize(w, h, display_size)
                                            local clicked = r.ImGui_ImageButton(ctx, "custom_" .. i, texture, dw, dh)
                                            ScreenshotNavRegister(i, column + 1, 0, nav_cy, plugin_name)
                                            do
                                                local ntlx, ntly = r.ImGui_GetItemRectMin(ctx)
                                                local nbrx, nbry = r.ImGui_GetItemRectMax(ctx)
                                                DrawNavSelectionBorder(i, ntlx, ntly, nbrx, nbry)
                                                DrawModernCardBackground(ntlx, ntly, nbrx - ntlx, nbry - ntly)
                                                DrawModernCardForeground(ntlx, ntly, nbrx - ntlx, nbry - ntly)
                                            end
                                            if pinned_set and pinned_set[plugin_name] then
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawPinnedOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                            end
                                            if favorite_set and favorite_set[plugin_name] then
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawFavoriteOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                            end
                                            do
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawNameOnScreenshot(tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                RenderScreenshotShortcut(plugin_name, tlx, tly)
                                            end
                                            if config.enable_drag_add_fx then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx,0) then
                                                    potential_drag_fx_name = plugin_name
                                                    drag_start_x, drag_start_y = r.ImGui_GetMousePos(ctx)
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseDown(ctx,0) then
                                                    local mx,my = r.ImGui_GetMousePos(ctx)
                                                    if math.abs(mx-drag_start_x) > 3 or math.abs(my-drag_start_y) > 3 then
                                                        dragging_fx_name = plugin_name
                                                        potential_drag_fx_name = nil
                                                    end
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseReleased(ctx,0) then
                                                    potential_drag_fx_name = nil
                                                end
                                            end
                                            local do_add = false
                                            if config.add_fx_with_double_click then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsMouseDoubleClicked(ctx, 0) then HandleMultiSelectClick(i) end
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx,0) and dragging_fx_name ~= plugin_name then do_add = true end
                                            else
                                                if clicked and dragging_fx_name ~= plugin_name then do_add = true end
                                            end
                                            if do_add then
                                                local target_track = GetTargetTrack()
                                                if target_track then
                                                    local fx_index = AddFXToTrack(target_track, plugin_name)
                                                    LAST_USED_FX = plugin_name
                                                    if config.open_floating_after_adding and fx_index >= 0 then
                                                        r.TrackFX_Show(target_track, fx_index, 3)
                                                    end
                                                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                                                end
                                            end
                                            ShowPluginContextMenu(plugin_name, "custom_win_" .. i)
                                            local display_name = GetDisplayPluginName(plugin_name)
                                            local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[plugin_name] and not config.show_name_on_hover_only
                                            if show_name_text then
                                                r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + dw)
                                                r.ImGui_Text(ctx, display_name)
                                                r.ImGui_PopTextWrapPos(ctx)
                                                r.ImGui_Text(ctx, GetStarsString(plugin_name))
                                            end
                                        end
                                    end
                                    r.ImGui_EndGroup(ctx)
                                    if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                                        local stars = GetStarsString(plugin_name)
                                        r.ImGui_SetTooltip(ctx, GetDisplayPluginName(plugin_name) .. (stars ~= "" and "\n" .. stars or ""))
                                    end
                                    if not config.compact_screenshots and column == num_columns - 1 then
                                        local row_spacing = config.use_modern_cards and 12 or 5
                                        r.ImGui_Dummy(ctx, 0, row_spacing)
                                    end
                                end
                            end
                            HandleScreenshotNavigation(with_shot)
                            RenderMissingList(missing)
                        end
                    end
                elseif selected_folder == "Current Project FX" then
                    filtered_plugins = GetCurrentProjectFX()
                    local display_plugins = {}
                    local _proj_term = (screenshot_folder_filter_suspended and "" or browser_search_term):lower()
                    for _, fx in ipairs(filtered_plugins) do
                        if FuzzyFind(fx.fx_name, _proj_term) then
                            table.insert(display_plugins, fx)
                        end
                    end
                    filtered_plugins = display_plugins
                    
                    if not screenshot_search_results then
                        screenshot_search_results = {}
                    end
                    
                    if #filtered_plugins > 0 then
                        if config.use_polaroid_layout or config.use_showcase_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                            local groups = {}
                            local order = {}
                            for _, plugin in ipairs(filtered_plugins) do
                                local key
                                if plugin.is_master then
                                    key = "master_track"
                                else
                                    key = (plugin.track_number or "?") .. "_" .. (plugin.track_name or "")
                                end
                                if not groups[key] then
                                    groups[key] = {plugins = {}, sample = plugin}
                                    order[#order+1] = key
                                end
                                groups[key].plugins[#groups[key].plugins+1] = plugin
                            end
                            for _, key in ipairs(order) do
                                local g = groups[key]
                                local sample = g.sample
                                local hdr_track = nil
                                if sample.is_master then
                                    hdr_track = r.GetMasterTrack(0)
                                else
                                    hdr_track = r.GetTrack(0, (sample.track_number or 1) - 1)
                                end
                                local hdr_color, hdr_text_color
                                if sample.is_master then
                                    hdr_color, hdr_text_color = 0x404040FF, 0xFFFFFFFF
                                else
                                    hdr_color, hdr_text_color = GetTrackColorAndTextColor(hdr_track)
                                end
                                r.ImGui_Separator(ctx)
                                local _tmp_popped_stylevars_grp = false
                                if not popped_view_stylevars then r.ImGui_PopStyleVar(ctx, 2); _tmp_popped_stylevars_grp = true end
                                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ChildBg(), hdr_color)
                                local _hdr_grp_open = r.ImGui_BeginChild(ctx, "ProjFXGrpHdr_" .. key, -1, 22)
                                r.ImGui_PopStyleColor(ctx)
                                if _hdr_grp_open then
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x00000000)
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x00000000)
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), hdr_text_color)
                                    local label
                                    if sample.is_master then
                                        label = "Master Track"
                                    else
                                        label = string.format("Track %d: %s", sample.track_number or 0, sample.track_name ~= '' and sample.track_name or 'Unnamed')
                                    end
                                    if r.ImGui_Button(ctx, label, -1, 20) then
                                        if hdr_track then r.SetOnlyTrackSelected(hdr_track) end
                                    end
                                    r.ImGui_PopStyleColor(ctx, 4)
                                    r.ImGui_EndChild(ctx)
                                end
                                if _tmp_popped_stylevars_grp then
                                    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ScrollbarSize(), config.show_screenshot_scrollbar and 14 or 1)
                                    r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowPadding(), 5, 0)
                                end
                                local name_to_fx = {}
                                local masonry_data = {}
                                for _, p in ipairs(g.plugins) do
                                    if p.fx_name and HasScreenshot(p.fx_name) then
                                        name_to_fx[p.fx_name] = p
                                        masonry_data[#masonry_data+1] = {name = p.fx_name, shortcut = NextScreenshotShortcutLabel(p.fx_name)}
                                    end
                                end
                                local prev_override = _layout_fx_click_override
                                _layout_fx_click_override = function(plugin_name)
                                    local p = name_to_fx[plugin_name]
                                    if not p or not p.fx_index or p.fx_index < 0 then return false end
                                    local trk
                                    if p.is_master then
                                        trk = r.GetMasterTrack(0)
                                    else
                                        trk = r.GetTrack(0, (p.track_number or 1) - 1)
                                    end
                                    if trk and r.ValidatePtr(trk, "MediaTrack*") then
                                        local is_open = r.TrackFX_GetFloatingWindow(trk, p.fx_index)
                                        r.TrackFX_Show(trk, p.fx_index, is_open and 2 or 3)
                                        return true
                                    end
                                    return false
                                end
                                r.ImGui_PushID(ctx, "ProjFXGrp_" .. key)
                                if config.use_polaroid_layout then
                                    DrawPolaroidLayout(masonry_data)
                                elseif config.use_showcase_layout then
                                    DrawShowcaseLayout(masonry_data)
                                elseif config.use_uniform_layout then
                                    DrawUniformLayout(masonry_data)
                                elseif config.use_neon_layout then
                                    DrawNeonLayout(masonry_data)
                                elseif config.use_vinyl_layout then
                                    DrawVinylLayout(masonry_data)
                                end
                                r.ImGui_PopID(ctx)
                                _layout_fx_click_override = prev_override
                            end
                            goto skip_current_project_fx_render
                        end
                        local current_track_identifier = nil
                        local column_width = available_width / num_columns

                         for i, plugin in ipairs(filtered_plugins) do
                            local track_identifier
                            
                            if plugin.is_master then
                                track_identifier = "master_track"
                            else
                                track_identifier = (plugin.track_number or "Unknown") .. "_" .. (plugin.track_name or "Unnamed")
                            end
                            
                            if track_identifier ~= current_track_identifier then
                                current_track_identifier = track_identifier

                                if plugin.is_master then
                                    -- MASTER TRACK HEADER
                                    r.ImGui_Separator(ctx)
                                    -- Ensure no outstanding style vars are active while this child is open
                                    local _tmp_popped_stylevars_master = false
                                    if not popped_view_stylevars then r.ImGui_PopStyleVar(ctx, 2); _tmp_popped_stylevars_master = true end
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ChildBg(), 0x404040FF)
                                    local _hdr_master_open = r.ImGui_BeginChild(ctx, "TrackHeaderMaster", -1, 20)
                                    r.ImGui_PopStyleColor(ctx) -- always pop ChildBg
                                    if _hdr_master_open then
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFFFFFF)
                                        
                                        local master_collapsed = master_track_collapsed or false
                                        if r.ImGui_Button(ctx, master_collapsed and "+" or "-", 20, 20) then
                                            master_track_collapsed = not master_collapsed
                                            ClearScreenshotCache()
                                        end
                                        
                                        r.ImGui_SameLine(ctx)
                                        if r.ImGui_Button(ctx, "Master Track") then
                                            r.SetOnlyTrackSelected(r.GetMasterTrack(0))
                                        end
                                        r.ImGui_PopStyleColor(ctx, 4)
                                        r.ImGui_EndChild(ctx)
                                    end
                                    r.ImGui_Dummy(ctx, 0, 0)
                                    if _tmp_popped_stylevars_master then
                                        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ScrollbarSize(), config.show_screenshot_scrollbar and 14 or 1)
                                        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowPadding(), 5, 0)
                                    end
                                else
                                    -- ANDERE TRACKS HEADER
                                    local track_color, text_color = GetTrackColorAndTextColor(reaper.GetTrack(0, plugin.track_number - 1))
                                    local track_number = plugin.track_number
                                    r.ImGui_Separator(ctx)
                                    -- Ensure no outstanding style vars are active while this child is open
                                    local _tmp_popped_stylevars_trkhdr = false
                                    if not popped_view_stylevars then r.ImGui_PopStyleVar(ctx, 2); _tmp_popped_stylevars_trkhdr = true end
                                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ChildBg(), track_color)
                                    local _hdr_track_open = r.ImGui_BeginChild(ctx, "TrackHeader" .. track_number, -1, 20)
                                    r.ImGui_PopStyleColor(ctx) -- always pop ChildBg
                                    if _hdr_track_open then
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x00000000)
                                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), text_color)
                                        local is_collapsed = collapsed_tracks[track_number] or false
                                        if r.ImGui_Button(ctx, is_collapsed and "+" or "-", 20, 20) then
                                            collapsed_tracks[track_number] = not is_collapsed
                                            if not is_collapsed then
                                                ClearScreenshotCache()
                                                GetPluginsForFolder(selected_folder)
                                            end
                                        end
                                        if r.ImGui_IsItemClicked(ctx, 1) then  -- Rechtermuisklik
                                            all_tracks_collapsed = not all_tracks_collapsed
                                            for j = 1, r.CountTracks(0) do
                                                collapsed_tracks[j] = all_tracks_collapsed
                                            end
                                            ClearScreenshotCache()
                                            GetPluginsForFolder(selected_folder)
                                        end
                                        r.ImGui_SameLine(ctx)
                                        if r.ImGui_Button(ctx, "Track " .. track_number .. ": " .. plugin.track_name) then
                                            r.SetOnlyTrackSelected(reaper.GetTrack(0, plugin.track_number - 1))
                                        end
                                        r.ImGui_PopStyleColor(ctx, 4)
                                        r.ImGui_EndChild(ctx)
                                    end
                                    r.ImGui_Dummy(ctx, 0, 0)
                                    if _tmp_popped_stylevars_trkhdr then
                                        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ScrollbarSize(), config.show_screenshot_scrollbar and 14 or 1)
                                        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowPadding(), 5, 0)
                                    end
                                end
                            end
                            
                            local should_show_fx = true
                            if plugin.is_master then
                                should_show_fx = not master_track_collapsed
                            else
                                should_show_fx = not collapsed_tracks[plugin.track_number]
                            end
                            
                            if should_show_fx then
                                local column = (i - 1) % num_columns
                                if column > 0 then
                                    r.ImGui_SameLine(ctx)
                                end
                                r.ImGui_BeginGroup(ctx)
                                r.ImGui_PushItemWidth(ctx, column_width)
                                if plugin and plugin.fx_name then
                                    local safe_name = plugin.fx_name:gsub("[^%w%s-]", "_")
                                    local screenshot_file = screenshot_path .. safe_name .. ".png"
                                    if r.file_exists(screenshot_file) then
                                        local texture = LoadSearchTexture(screenshot_file, plugin.fx_name)
                                        if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                            local width, height = r.ImGui_Image_GetSize(texture)
                                            if width and height then
                                                local display_width, display_height = ScaleScreenshotSize(width, height, display_size)
                                                                                        
                                            local unique_id = "project_fx_" .. i .. "_" .. (plugin.track_number or 0) .. "_" .. (plugin.fx_index or 0)

                                            local clicked = r.ImGui_ImageButton(ctx, unique_id, texture, display_width, display_height)
                                            
                                            local item_min_x, item_min_y = r.ImGui_GetItemRectMin(ctx)
                                            local item_max_x, item_max_y = r.ImGui_GetItemRectMax(ctx)
                                            DrawModernCardBackground(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y)
                                            DrawModernCardForeground(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y)
                                            DrawNameOnScreenshot(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, plugin.fx_name)
                                            DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, plugin.fx_name)
                                            DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, plugin.fx_name)
                                            if r.ImGui_BeginDragDropSource(ctx, r.ImGui_DragDropFlags_None()) then
                                                local payload_str = (plugin.is_master and "M" or tostring(plugin.track_number)) .. ":" .. tostring(plugin.fx_index)
                                                r.ImGui_SetDragDropPayload(ctx, "PROJFX_SHOT_DRAG", payload_str)
                                                r.ImGui_Text(ctx, GetDisplayPluginName(plugin.fx_name))
                                                r.ImGui_EndDragDropSource(ctx)
                                            end
                                            if r.ImGui_BeginDragDropTarget(ctx) then
                                                local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "PROJFX_SHOT_DRAG")
                                                if rv then
                                                    local src_track_str, src_fx_str = payload:match("^(.+):(%d+)$")
                                                    local dst_track_str = plugin.is_master and "M" or tostring(plugin.track_number)
                                                    if src_track_str == dst_track_str then
                                                        local src_fx = tonumber(src_fx_str)
                                                        local dst_fx = plugin.fx_index
                                                        if src_fx and dst_fx and src_fx ~= dst_fx then
                                                            local track
                                                            if plugin.is_master then
                                                                track = r.GetMasterTrack(0)
                                                            else
                                                                track = r.GetTrack(0, plugin.track_number - 1)
                                                            end
                                                            if track and r.ValidatePtr(track, "MediaTrack*") then
                                                                if src_fx < dst_fx then dst_fx = dst_fx + 1 end
                                                                r.Undo_BeginBlock()
                                                                r.TrackFX_CopyToTrack(track, src_fx, track, dst_fx, true)
                                                                r.Undo_EndBlock("Reorder Track FX", -1)
                                                                RefreshCurrentScreenshotView()
                                                            end
                                                        end
                                                    end
                                                end
                                                r.ImGui_EndDragDropTarget(ctx)
                                            end
                                            if clicked or (config.add_fx_with_double_click and r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx, 0)) then
                                                if plugin.is_master then
                                                    local master_track = r.GetMasterTrack(0)
                                                    if plugin.fx_index ~= nil then
                                                        local is_open = r.TrackFX_GetFloatingWindow(master_track, plugin.fx_index)
                                                        r.TrackFX_Show(master_track, plugin.fx_index, is_open and 2 or 3)
                                                    end
                                                else
                                                    local track = r.GetTrack(0, plugin.track_number - 1)
                                                    if track and r.ValidatePtr(track, "MediaTrack*") and plugin.fx_index ~= nil then
                                                        local is_open = r.TrackFX_GetFloatingWindow(track, plugin.fx_index)
                                                        r.TrackFX_Show(track, plugin.fx_index, is_open and 2 or 3)
                                                    end
                                                end
                                            end

                                                ShowFXContextMenu({
                                                    fx_name = plugin.fx_name,
                                                    track_number = plugin.track_number,
                                                    fx_index = plugin.fx_index,
                                                    is_master = plugin.is_master
                                                }, "current_project_fx_" .. i)
                                                local display_name = GetDisplayPluginName(plugin.fx_name)
                                                local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[plugin.fx_name] and not config.show_name_on_hover_only
                                                if show_name_text then
                                                    r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + display_width)
                                                    r.ImGui_Text(ctx, display_name)
                                                    r.ImGui_PopTextWrapPos(ctx)
                                                    r.ImGui_Text(ctx, GetStarsString(plugin.fx_name))
                                                end
                                            end
                                        end
                                    end
                                end
                                r.ImGui_PopItemWidth(ctx)
                                r.ImGui_EndGroup(ctx)
                                if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                                    local stars = GetStarsString(plugin.fx_name)
                                    r.ImGui_SetTooltip(ctx, GetDisplayPluginName(plugin.fx_name) .. (stars ~= "" and "\n" .. stars or ""))
                                end
                                
                                if not config.compact_screenshots and column == num_columns - 1 then
                                    local row_spacing = config.use_modern_cards and 12 or 5
                                    r.ImGui_Dummy(ctx, 0, row_spacing)
                                end
                            end
                        end
                    else
                        r.ImGui_Text(ctx, "No Plugins in Selected Folder.")
                    end
                    ::skip_current_project_fx_render::

                elseif selected_folder == "Current Track FX" then
                    filtered_plugins = GetCurrentTrackFX()
                    local display_plugins = {}
                    local _track_term = (screenshot_folder_filter_suspended and "" or browser_search_term):lower()
                    for _, fx in ipairs(filtered_plugins) do
                        if FuzzyFind(fx.fx_name, _track_term) then
                            table.insert(display_plugins, fx)
                        end
                    end
                    filtered_plugins = display_plugins

                    if TRACK and r.ValidatePtr2(0, TRACK, "MediaTrack*") then
                        local track_color_u32, text_color_u32 = GetTrackColorAndTextColor(TRACK)
                        local track_number = r.GetMediaTrackInfo_Value(TRACK, "IP_TRACKNUMBER") or 0
                        local _, track_name = r.GetTrackName(TRACK, "")
                        r.ImGui_Separator(ctx)
                        -- Ensure no outstanding style vars are active while this child is open
                        local _tmp_popped_stylevars_curhdr = false
                        if not popped_view_stylevars then r.ImGui_PopStyleVar(ctx, 2); _tmp_popped_stylevars_curhdr = true end
                        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ChildBg(), track_color_u32)
                        local cur_header_open = r.ImGui_BeginChild(ctx, "CurrentTrackHeader", -1, 22)
                        r.ImGui_PopStyleColor(ctx) -- always pop ChildBg
                        if cur_header_open then
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x00000000)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), 0x00000000)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonActive(), 0x00000000)
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), text_color_u32)
                            current_track_fx_collapsed = current_track_fx_collapsed or false
                            if r.ImGui_Button(ctx, (current_track_fx_collapsed and "+" or "-") .. "##CollapseCurrentTrack", 20, 20) then
                                current_track_fx_collapsed = not current_track_fx_collapsed
                                ClearScreenshotCache()
                            end
                            r.ImGui_SameLine(ctx)
                            if r.ImGui_Button(ctx, string.format("Track %d: %s", track_number, track_name ~= '' and track_name or 'Unnamed'), -1, 20) then
                                r.SetOnlyTrackSelected(TRACK)
                            end
                            r.ImGui_PopStyleColor(ctx, 4)
                            r.ImGui_EndChild(ctx)
                        end
                        if _tmp_popped_stylevars_curhdr then
                            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ScrollbarSize(), config.show_screenshot_scrollbar and 14 or 1)
                            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowPadding(), 5, 0)
                        end
                        if current_track_fx_collapsed then
                            goto skip_current_track_fx_render
                        end
                    end


                    -- ALTERNATIEVE LAYOUTS VOOR CURRENT TRACK FX (lijst/masonry uitgesloten)
                    if config.use_polaroid_layout or config.use_showcase_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                        local name_to_fx = {}
                        local with_shot = {}
                        for _, fx in ipairs(filtered_plugins) do
                            if fx and fx.fx_name then
                                name_to_fx[fx.fx_name] = fx
                                if HasScreenshot(fx.fx_name) then
                                    with_shot[#with_shot+1] = fx.fx_name
                                end
                            end
                        end
                        local masonry_data = {}
                        for _, pname in ipairs(with_shot) do
                            masonry_data[#masonry_data+1] = {name = pname, shortcut = NextScreenshotShortcutLabel(pname)}
                        end
                        local prev_override = _layout_fx_click_override
                        _layout_fx_click_override = function(plugin_name)
                            local fx = name_to_fx[plugin_name]
                            if fx and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") and fx.fx_index and fx.fx_index >= 0 then
                                local is_open = r.TrackFX_GetFloatingWindow(TRACK, fx.fx_index)
                                r.TrackFX_Show(TRACK, fx.fx_index, is_open and 2 or 3)
                                return true
                            end
                            return false
                        end
                        if config.use_polaroid_layout then
                            DrawPolaroidLayout(masonry_data)
                        elseif config.use_showcase_layout then
                            DrawShowcaseLayout(masonry_data)
                        elseif config.use_uniform_layout then
                            DrawUniformLayout(masonry_data)
                        elseif config.use_neon_layout then
                            DrawNeonLayout(masonry_data)
                        elseif config.use_vinyl_layout then
                            DrawVinylLayout(masonry_data)
                        end
                        _layout_fx_click_override = prev_override
                        goto skip_current_track_fx_render
                    end

                    -- NORMALE LAYOUT VOOR CURRENT TRACK FX (MASONRY UITGEZET)
                    local available_width = r.ImGui_GetContentRegionAvail(ctx)
                    local card_spacing = config.use_modern_cards and 12 or 0
                    local num_columns = math.max(1, math.floor(available_width / (display_size + card_spacing)))
                    local column_width = available_width / num_columns
            
                    for i, fx in ipairs(filtered_plugins) do
                        local column = (i - 1) % num_columns
                        if column > 0 then
                            r.ImGui_SameLine(ctx)
                        end
            
                        r.ImGui_BeginGroup(ctx)
                        local safe_name = fx.fx_name:gsub("[^%w%s-]", "_")
                        local screenshot_file = screenshot_path .. safe_name .. ".png"
                        
                        if r.file_exists(screenshot_file) then
                            local texture = LoadSearchTexture(screenshot_file, fx.fx_name)
                            if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                local width, height = r.ImGui_Image_GetSize(texture)
                                if width and height then
                                    local display_width, display_height = ScaleScreenshotSize(width, height, display_size)
                                    
                                    local button_id = "track_fx_" .. i .. "_" .. fx.fx_index
                                    local clicked = r.ImGui_ImageButton(ctx, button_id, texture, display_width, display_height)
                                    
                                    local item_min_x, item_min_y = r.ImGui_GetItemRectMin(ctx)
                                    local item_max_x, item_max_y = r.ImGui_GetItemRectMax(ctx)
                                    DrawModernCardBackground(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y)
                                    DrawModernCardForeground(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y)
                                    DrawNameOnScreenshot(item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, fx.fx_name)
                                    DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, fx.fx_name)
                                    DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), item_min_x, item_min_y, item_max_x - item_min_x, item_max_y - item_min_y, fx.fx_name)

                                    if r.ImGui_BeginDragDropSource(ctx, r.ImGui_DragDropFlags_None()) then
                                        r.ImGui_SetDragDropPayload(ctx, "TRACKFX_SHOT_DRAG", tostring(fx.fx_index))
                                        r.ImGui_Text(ctx, GetDisplayPluginName(fx.fx_name))
                                        r.ImGui_EndDragDropSource(ctx)
                                    end
                                    if r.ImGui_BeginDragDropTarget(ctx) then
                                        local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "TRACKFX_SHOT_DRAG")
                                        if rv then
                                            local src = tonumber(payload)
                                            if src and src ~= fx.fx_index then
                                                local dest = fx.fx_index
                                                if src < dest then dest = dest + 1 end
                                                r.Undo_BeginBlock()
                                                r.TrackFX_CopyToTrack(TRACK, src, TRACK, dest, true)
                                                r.Undo_EndBlock("Reorder Track FX", -1)
                                                RefreshCurrentScreenshotView()
                                            end
                                        end
                                        r.ImGui_EndDragDropTarget(ctx)
                                    end

                                    if clicked then
                                        if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                                            local fx_index = fx.fx_index
                                            if fx_index and fx_index >= 0 then
                                                local is_open = r.TrackFX_GetFloatingWindow(TRACK, fx_index)
                                                r.TrackFX_Show(TRACK, fx_index, is_open and 2 or 3)
                                            end
                                        end
                                    end

                                    if r.ImGui_IsItemClicked(ctx, 1) then
                                        r.ImGui_OpenPopup(ctx, "CurrentTrackFXMenu_" .. i)
                                    end

                                    ShowFXContextMenu({
                                        fx_name = fx.fx_name,
                                        track_number = r.GetMediaTrackInfo_Value(TRACK, "IP_TRACKNUMBER")
                                    }, "current_track_" .. i)

                                    local display_name = GetDisplayPluginName(fx.fx_name)
                                    local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[fx.fx_name] and not config.show_name_on_hover_only
                                    if show_name_text then
                                        r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + display_width)
                                        r.ImGui_Text(ctx, display_name)
                                        r.ImGui_PopTextWrapPos(ctx)
                                        r.ImGui_Text(ctx, GetStarsString(fx.fx_name))
                                    end
                                end
                            end
                        end
                        r.ImGui_EndGroup(ctx)
                        if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                            local stars = GetStarsString(fx.fx_name)
                            r.ImGui_SetTooltip(ctx, GetDisplayPluginName(fx.fx_name) .. (stars ~= "" and "\n" .. stars or ""))
                        end
                        
                        if not config.compact_screenshots and column == num_columns - 1 then
                            local row_spacing = config.use_modern_cards and 12 or 5
                            r.ImGui_Dummy(ctx, 0, row_spacing)
                        end
                    end

                    ::skip_current_track_fx_render::

                else
                    -- NORMALE FOLDERS WEERGAVE
                    for i = 1, #CAT_TEST do
                        if CAT_TEST[i].name == "FOLDERS" then
                            for j = 1, #CAT_TEST[i].list do
                                if CAT_TEST[i].list[j].name == selected_folder then
                                    filtered_plugins = CAT_TEST[i].list[j].fx
                                    local display_plugins = {}
                                    
                                    if config.show_favorites_on_top then
                                        local pinned = {}
                                        local favorites = {}
                                        local regular = {}
                                        local term_l = GetLowerName(screenshot_folder_filter_suspended and "" or browser_search_term)
                                        for _, plugin in ipairs(filtered_plugins) do
                                            if GetLowerName(plugin):find(term_l, 1, true) then
                                                if pinned_set[plugin] then
                                                    pinned[#pinned+1] = plugin
                                                elseif favorite_set[plugin] then
                                                    favorites[#favorites+1] = plugin
                                                else
                                                    regular[#regular+1] = plugin
                                                end
                                            end
                                        end
                                        SortPlainPluginList(pinned, config.sort_mode)
                                        SortPlainPluginList(favorites, config.sort_mode)
                                        SortPlainPluginList(regular, config.sort_mode)
                                        
                                        -- Add pinned plugins first if show_pinned_on_top is enabled
                                        if config and config.show_pinned_on_top then
                                            for _, plugin in ipairs(pinned) do display_plugins[#display_plugins+1] = plugin end
                                            if #pinned>0 and (#favorites>0 or #regular>0) then display_plugins[#display_plugins+1] = "--Pinned End--" end
                                        else
                                            -- Add pinned plugins to regular if show_pinned_on_top is disabled
                                            for _, plugin in ipairs(pinned) do regular[#regular+1] = plugin end
                                            SortPlainPluginList(regular, config.sort_mode)
                                        end
                                        
                                        for _, plugin in ipairs(favorites) do display_plugins[#display_plugins+1] = plugin end
                                        if #favorites>0 and #regular>0 then display_plugins[#display_plugins+1] = "--Favorites End--" end
                                        for _, plugin in ipairs(regular) do display_plugins[#display_plugins+1] = plugin end
                                    else
                                        -- show_favorites_on_top is false: still check pinned-on-top setting
                                        local term_l = GetLowerName(screenshot_folder_filter_suspended and "" or browser_search_term)
                                        local pinned, others = {}, {}
                                        for _, plugin in ipairs(filtered_plugins) do
                                            if GetLowerName(plugin):find(term_l, 1, true) then
                                                if pinned_set[plugin] then pinned[#pinned+1] = plugin else others[#others+1] = plugin end
                                            end
                                        end
                                        if config.apply_type_priority then
                                            pinned = DedupeByTypePriority(pinned)
                                            others = DedupeByTypePriority(others)
                                        end
                                        SortPlainPluginList(pinned, config.sort_mode)
                                        SortPlainPluginList(others, config.sort_mode)
                                        
                                        -- Add pinned plugins first if show_pinned_on_top is enabled
                                        if config and config.show_pinned_on_top then
                                            for _, p in ipairs(pinned) do display_plugins[#display_plugins+1] = p end
                                            if #pinned>0 and #others>0 then display_plugins[#display_plugins+1] = "--Pinned End--" end
                                        else
                                            -- Add pinned plugins to others if show_pinned_on_top is disabled
                                            for _, p in ipairs(pinned) do others[#others+1] = p end
                                            SortPlainPluginList(others, config.sort_mode)
                                        end
                                        
                                        for _, p in ipairs(others) do display_plugins[#display_plugins+1] = p end
                                    end
                                    
                                    if config.apply_type_priority then
                                        display_plugins = DedupeByTypePriority(display_plugins)
                                    end
                                    filtered_plugins = display_plugins
                                    -- Keep the global visible list in sync so texture queue pruning includes folder items
                                    current_filtered_fx = {}
                                    for _, name in ipairs(display_plugins) do
                                        if type(name) == 'string' and name ~= "--Favorites End--" and name ~= "--Pinned End--" then
                                            current_filtered_fx[#current_filtered_fx+1] = name
                                        end
                                    end
                                    break
                                end
                            end
                            break
                        end
                    end
                    
                    if selected_folder and selected_folder ~= "Current Project FX" and selected_folder ~= "Current Track FX" then
                        if view_mode == "list" then
                            RenderListViewItems(filtered_plugins, "folder_list")
                        else
                            local card_spacing = config.use_modern_cards and 12 or 0
                            local min_columns = math.floor(available_width / (display_size + card_spacing))
                            local actual_display_size = math.min(display_size, available_width / min_columns)
                            local num_columns = math.max(1, min_columns)
                            local column_width = available_width / num_columns

                            local folder_total_count = #filtered_plugins
                            if config.use_pagination then
                                local folder_key = selected_folder or "?"
                                filtered_plugins, folder_total_count = ApplyFolderPaginationSlice(filtered_plugins, folder_key)
                            else
                                if #filtered_plugins > loaded_items_count then
                                    local limited = {}
                                    for li = 1, loaded_items_count do limited[li] = filtered_plugins[li] end
                                    filtered_plugins = limited
                                end
                            end

                            if config.use_polaroid_layout or config.use_showcase_layout or config.use_masonry_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                                if filtered_plugins then
                                    local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                                    local masonry_data = {}
                                    for _, plugin in ipairs(with_shot) do
                                        if plugin == "--Favorites End--" then
                                            masonry_data[#masonry_data+1] = {is_separator = true, label = "--- Favorites End ---"}
                                        elseif plugin == "--Pinned End--" then
                                            masonry_data[#masonry_data+1] = {is_separator = true, label = "--- Pinned End ---"}
                                        else
                                            masonry_data[#masonry_data+1] = {name = plugin}
                                        end
                                    end
                                    if config.use_polaroid_layout then
                                        DrawPolaroidLayout(masonry_data)
                                    elseif config.use_showcase_layout then
                                        DrawShowcaseLayout(masonry_data)
                                    elseif config.use_uniform_layout then
                                        DrawUniformLayout(masonry_data)
                                    elseif config.use_neon_layout then
                                        DrawNeonLayout(masonry_data)
                                    elseif config.use_vinyl_layout then
                                        DrawVinylLayout(masonry_data)
                                    else
                                        DrawMasonryLayout(masonry_data)
                                    end
                                    RenderMissingList(missing)
                                end
                            else
                                local with_shot, missing = SplitPluginsByScreenshot(filtered_plugins)
                                ApplyTopScreenshotSpacing()
                                ScreenshotNavReset()
                                for i, plugin_name in ipairs(with_shot) do
                                    if plugin_name == "--Favorites End--" or plugin_name == "--Pinned End--" then
                                        DrawHorizontalSeparatorBar((config.compact_screenshots and 2 or 3), 0x606060FF)
                                        -- Extra breathing room below the divider in grid view for Folders
                                        r.ImGui_Dummy(ctx, 0, (config.compact_screenshots and 6 or 10))
                                    else
                                        local column = (i - 1) % num_columns
                                        local card_horiz_spacing = config.use_modern_cards and 12 or 0
                                        if column > 0 then r.ImGui_SameLine(ctx, 0, card_horiz_spacing) end
                                        local nav_cy = r.ImGui_GetCursorPosY(ctx)
                                        r.ImGui_BeginGroup(ctx)
                                        local screenshot_file = HasScreenshot(plugin_name)
                                        local texture = LoadSearchTexture(screenshot_file, plugin_name)
                                        if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                            local width, height = r.ImGui_Image_GetSize(texture)
                                            if width and height then
                                                local display_width, display_height = ScaleScreenshotSize(width, height, display_size)
                                                local folder_clicked = r.ImGui_ImageButton(ctx, "folder_plugin_" .. i, texture, display_width, display_height)
                                                ScreenshotNavRegister(i, column + 1, 0, nav_cy, plugin_name)
                                                local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                DrawNavSelectionBorder(i, tlx, tly, brx, bry)
                                                DrawModernCardBackground(tlx, tly, brx - tlx, bry - tly)
                                                DrawModernCardForeground(tlx, tly, brx - tlx, bry - tly)
                                                if IsPluginPinned and IsPluginPinned(plugin_name) then
                                                    DrawPinnedOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                                end
                                                if favorite_set and favorite_set[plugin_name] then
                                                    local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                    local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                    DrawFavoriteOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                                end
                                                do
                                                    local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                                    local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                                    DrawNameOnScreenshot(tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                    DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                    DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                                end
                                                local do_add = false
                                                if config.enable_drag_add_fx then
                                                    -- On initial mouse press over the image, mark as potential drag source
                                                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx,0) then
                                                        potential_drag_fx_name = plugin_name
                                                        drag_start_x, drag_start_y = r.ImGui_GetMousePos(ctx)
                                                    end
                                                    if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseDown(ctx,0) then
                                                        local mx,my = r.ImGui_GetMousePos(ctx)
                                                        if math.abs(mx - drag_start_x) > 3 or math.abs(my - drag_start_y) > 3 then
                                                            dragging_fx_name = plugin_name
                                                            potential_drag_fx_name = nil
                                                        end
                                                    end
                                                    if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseReleased(ctx,0) then
                                                        potential_drag_fx_name = nil
                                                    end
                                                end
                                                if config.add_fx_with_double_click then
                                                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsMouseDoubleClicked(ctx, 0) then HandleMultiSelectClick(i) end
                                                    if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx,0) and dragging_fx_name ~= plugin_name then do_add = true end
                                                else
                                                    if folder_clicked and dragging_fx_name ~= plugin_name then do_add = true end
                                                end
                                                if do_add then
                                                    local target_track = GetTargetTrack()
                                                    if target_track then
                                                        local fx_index = AddFXToTrack(target_track, plugin_name)
                                                        LAST_USED_FX = plugin_name
                                                        if config.open_floating_after_adding and fx_index >= 0 then
                                                            r.TrackFX_Show(target_track, fx_index, 3)
                                                        end
                                                        if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                                                    end
                                                end
                                                ShowPluginContextMenu(plugin_name, "folder_" .. i)
                                                local display_name = GetDisplayPluginName(plugin_name)
                                                local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[plugin_name] and not config.show_name_on_hover_only
                                                if show_name_text then
                                                    r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + display_width)
                                                    r.ImGui_Text(ctx, display_name)
                                                    r.ImGui_PopTextWrapPos(ctx)
                                                    r.ImGui_Text(ctx, GetStarsString(plugin_name))
                                                end
                                            end
                                        end
                                        r.ImGui_EndGroup(ctx)
                                        if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                                            local stars = GetStarsString(plugin_name)
                                            r.ImGui_SetTooltip(ctx, GetDisplayPluginName(plugin_name) .. (stars ~= "" and "\n" .. stars or ""))
                                        end
                                        if not config.compact_screenshots and column == num_columns - 1 then
                                            local row_spacing = config.use_modern_cards and 12 or 5
                                            r.ImGui_Dummy(ctx, 0, row_spacing)
                                        end
                                    end
                                end
                                HandleScreenshotNavigation(with_shot)
                                RenderMissingList(missing)
                            end
                        end
                    end
                end
    
            elseif screenshot_search_results and #screenshot_search_results > 0 then
                local available_width = r.ImGui_GetContentRegionAvail(ctx)
                if config.use_global_screenshot_size then
                    display_size = config.global_screenshot_size
                elseif config.resize_screenshots_with_window then
                    display_size = available_width - 10
                else
                    display_size = config.folder_specific_sizes["SearchResults"] or config.screenshot_window_size
                end
                if view_mode == "list" then
                    RenderListViewItems(screenshot_search_results, "search_list", { is_search = true })
                else
                    if config.use_polaroid_layout or config.use_showcase_layout or config.use_masonry_layout or config.use_uniform_layout or config.use_neon_layout or config.use_vinyl_layout then
                        local plain_names = {}
                        local messages = {}
                        for _, fx in ipairs(screenshot_search_results) do
                            if fx.is_message then
                                messages[#messages+1] = fx 
                            elseif fx.is_separator then
                                if fx.kind == 'chain_divider' then
                                    plain_names[#plain_names+1] = "--Chain:" .. (fx.label or "") .. "--"
                                elseif fx.kind == 'pinned_end' then
                                    plain_names[#plain_names+1] = "--Pinned End--"
                                else
                                    plain_names[#plain_names+1] = "--Favorites End--"
                                end
                            else
                                plain_names[#plain_names+1] = fx.name
                            end
                        end
                        local with_shot, missing = SplitPluginsByScreenshot(plain_names)
                        local masonry_data = {}
                        for _, msg in ipairs(messages) do masonry_data[#masonry_data+1] = msg end
                        
                        local buttons_height = 0  
                        if current_fx_chain_relative_path and current_fx_chain_name then
                            buttons_height = DrawFxChainActionButtons("masonry")
                        end
                        
                        for _, plugin_name in ipairs(with_shot) do
                            local chain_label = plugin_name:match("^%-%-Chain:(.+)%-%-$")
                            if chain_label then
                                local sep_data = {is_separator = true, kind = "chain_divider", label = chain_label}
                                for _, fx in ipairs(screenshot_search_results) do
                                    if fx.is_separator and fx.kind == 'chain_divider' and fx.label == chain_label then
                                        sep_data.chain_file_path = fx.chain_file_path
                                        sep_data.chain_relative_path = fx.chain_relative_path
                                        sep_data.chain_name = fx.chain_name
                                        break
                                    end
                                end
                                masonry_data[#masonry_data+1] = sep_data
                            elseif plugin_name == "--Favorites End--" then
                                masonry_data[#masonry_data+1] = {is_separator = true, kind = "favorites_end"}
                            elseif plugin_name == "--Pinned End--" then
                                masonry_data[#masonry_data+1] = {is_separator = true, kind = "pinned_end"}
                            else
                                masonry_data[#masonry_data+1] = {name = plugin_name}
                            end
                        end
                        if config.use_polaroid_layout then
                            DrawPolaroidLayout(masonry_data, buttons_height)
                        elseif config.use_showcase_layout then
                            DrawShowcaseLayout(masonry_data, buttons_height)
                        elseif config.use_uniform_layout then
                            DrawUniformLayout(masonry_data, buttons_height)
                        elseif config.use_neon_layout then
                            DrawNeonLayout(masonry_data, buttons_height)
                        elseif config.use_vinyl_layout then
                            DrawVinylLayout(masonry_data, buttons_height)
                        else
                            DrawMasonryLayout(masonry_data, buttons_height)
                        end
                        RenderMissingList(missing)
                    else
                        local card_spacing = config.use_modern_cards and 12 or 0
                        local num_columns = math.max(1, math.floor(available_width / (display_size + card_spacing)))
                        local plain_names = {}
                        local messages = {}
                        for _, fx in ipairs(screenshot_search_results) do
                            if fx.is_message then
                                messages[#messages+1] = fx
                            elseif fx.is_separator then
                                if fx.kind == 'chain_divider' then
                                    plain_names[#plain_names+1] = "--Chain:" .. (fx.label or "") .. "--"
                                elseif fx.kind == 'pinned_end' then
                                    plain_names[#plain_names+1] = "--Pinned End--"
                                else
                                    plain_names[#plain_names+1] = "--Favorites End--"
                                end
                            else
                                plain_names[#plain_names+1] = fx.name
                            end
                        end
                        local with_shot, missing = SplitPluginsByScreenshot(plain_names)
                        for _, msg in ipairs(messages) do
                            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0xFFFF00FF)
                            local display_name = GetDisplayPluginName(msg.name)
                            r.ImGui_TextWrapped(ctx, display_name)
                            r.ImGui_PopStyleColor(ctx)
                        end
                        
                        if current_fx_chain_relative_path and current_fx_chain_name then
                            DrawFxChainActionButtons("normal")
                        end
                        
                        if #with_shot > 0 then ApplyTopScreenshotSpacing() end
                        ScreenshotNavReset()
                        for i, plugin_name in ipairs(with_shot) do
                            local chain_label = plugin_name:match("^%-%-Chain:(.+)%-%-$")
                            if chain_label then
                                DrawHorizontalSeparatorBar((config.compact_screenshots and 2 or 3), 0x606060FF)
                                r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x7AA2F7FF)
                                r.ImGui_Text(ctx, "\xF0\x9F\x94\x97 " .. chain_label)
                                r.ImGui_PopStyleColor(ctx)
                                if r.ImGui_IsItemHovered(ctx) then r.ImGui_SetTooltip(ctx, "Right-click for options") end
                                if r.ImGui_IsItemClicked(ctx, 1) then
                                    r.ImGui_OpenPopup(ctx, "chain_div_grid_" .. i)
                                end
                                local sep_fx = nil
                                for _, fx in ipairs(screenshot_search_results) do
                                    if fx.is_separator and fx.kind == 'chain_divider' and fx.label == chain_label then
                                        sep_fx = fx; break
                                    end
                                end
                                if sep_fx then ShowChainDividerContextMenu("chain_div_grid_" .. i, sep_fx) end
                                r.ImGui_Dummy(ctx, 0, (config.compact_screenshots and 4 or 8))
                            elseif plugin_name == "--Favorites End--" or plugin_name == "--Pinned End--" then
                                DrawHorizontalSeparatorBar((config.compact_screenshots and 2 or 3), 0x606060FF)
                                r.ImGui_Dummy(ctx, 0, (config.compact_screenshots and 6 or 10))
                            else
                            local is_fx_chain_item = false
                            for _, fx in ipairs(screenshot_search_results) do
                                if fx.name == plugin_name and fx.is_fx_chain_item then
                                    is_fx_chain_item = true
                                    break
                                end
                            end
                            
                            local column = (i - 1) % num_columns
                            local card_horiz_spacing = config.use_modern_cards and 12 or 0
                            if column > 0 then r.ImGui_SameLine(ctx, 0, card_horiz_spacing) end
                            local nav_cy = r.ImGui_GetCursorPosY(ctx)
                            r.ImGui_BeginGroup(ctx)
                            local screenshot_file = HasScreenshot(plugin_name)
                            if screenshot_file then
                                local texture = LoadSearchTexture(screenshot_file, plugin_name)
                                if texture and r.ImGui_ValidatePtr(texture, 'ImGui_Image*') then
                                    local width, height = r.ImGui_Image_GetSize(texture)
                                    if width and height then
                                        local display_width, display_height = ScaleScreenshotSize(width, height, display_size)
                                        local clicked = r.ImGui_ImageButton(ctx, "search_result_" .. i, texture, display_width, display_height)
                                        ScreenshotNavRegister(i, column + 1, 0, nav_cy, plugin_name)
                                        local tlx, tly = r.ImGui_GetItemRectMin(ctx)
                                        local brx, bry = r.ImGui_GetItemRectMax(ctx)
                                        DrawNavSelectionBorder(i, tlx, tly, brx, bry)
                                        DrawModernCardBackground(tlx, tly, brx - tlx, bry - tly)
                                        DrawModernCardForeground(tlx, tly, brx - tlx, bry - tly)
                                        if pinned_set and pinned_set[plugin_name] then
                                            DrawPinnedOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                        end
                                        if favorite_set and favorite_set[plugin_name] then
                                            DrawFavoriteOverlayAt(tlx, tly, brx - tlx, bry - tly)
                                        end
                                        DrawNameOnScreenshot(tlx, tly, brx - tlx, bry - tly, plugin_name)
                                        DrawTypeBadgeOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                        DrawRatingOverlay(r.ImGui_GetWindowDrawList(ctx), tlx, tly, brx - tlx, bry - tly, plugin_name)
                                        
                                        if not is_fx_chain_item then
                                            if config.enable_drag_add_fx then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx,0) then
                                                    potential_drag_fx_name = plugin_name
                                                    drag_start_x, drag_start_y = r.ImGui_GetMousePos(ctx)
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseDown(ctx,0) then
                                                    local mx,my = r.ImGui_GetMousePos(ctx)
                                                    if math.abs(mx-drag_start_x) > 3 or math.abs(my-drag_start_y) > 3 then
                                                        dragging_fx_name = plugin_name
                                                        potential_drag_fx_name = nil
                                                    end
                                                end
                                                if potential_drag_fx_name == plugin_name and r.ImGui_IsMouseReleased(ctx,0) then
                                                    potential_drag_fx_name = nil
                                                end
                                            end
                                            local do_add = false
                                            if config.add_fx_with_double_click then
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsMouseDoubleClicked(ctx, 0) then HandleMultiSelectClick(i) end
                                                if r.ImGui_IsItemHovered(ctx) and r.ImGui_IsMouseDoubleClicked(ctx,0) and dragging_fx_name ~= plugin_name then do_add = true end
                                            else
                                                if clicked and dragging_fx_name ~= plugin_name then do_add = true end
                                            end
                                            if do_add then
                                                local target_track = GetTargetTrack()
                                                if target_track then
                                                    local fx_index = AddFXToTrack(target_track, plugin_name)
                                                    LAST_USED_FX = plugin_name
                                                    if config.open_floating_after_adding and fx_index and fx_index >= 0 then
                                                        r.TrackFX_Show(target_track, fx_index, 3)
                                                    end
                                                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                                                end
                                            end
                                        end
                                        
                                        ShowPluginContextMenu(plugin_name, "search_" .. i)
                                        local display_name = GetDisplayPluginName(plugin_name)
                                        local show_name_text = config.show_name_in_screenshot_window and not config.hidden_names[plugin_name] and not config.show_name_on_hover_only
                                        if show_name_text then
                                            r.ImGui_PushTextWrapPos(ctx, r.ImGui_GetCursorPosX(ctx) + display_width)
                                            r.ImGui_Text(ctx, display_name)
                                            r.ImGui_PopTextWrapPos(ctx)
                                            r.ImGui_Text(ctx, GetStarsString(plugin_name))
                                        end
                                    end
                                end
                            end
                            r.ImGui_EndGroup(ctx)
                            if config.show_name_on_hover_only and r.ImGui_IsItemHovered(ctx) then
                                local stars = GetStarsString(plugin_name)
                                r.ImGui_SetTooltip(ctx, GetDisplayPluginName(plugin_name) .. (stars ~= "" and "\n" .. stars or ""))
                            end
                            if column == num_columns - 1 and not config.compact_screenshots then
                                local row_spacing = config.use_modern_cards and 12 or 5
                                r.ImGui_Dummy(ctx, 0, row_spacing)
                            end
                                end
                        end
                        HandleScreenshotNavigation(with_shot)
                        RenderMissingList(missing)
                    end
                end
            else
                r.ImGui_Text(ctx, "Select a folder or enter a search term.")
            end
            if r.ImGui_IsWindowHovered(ctx) and r.ImGui_IsMouseClicked(ctx, 0) and not r.ImGui_IsAnyItemHovered(ctx) then
                screenshot_multi_selected = {}
                screenshot_nav_index = nil
                screenshot_nav_anchor = nil
            end
            r.ImGui_Dummy(ctx, 0, 0)
            if is_screenshot_branch then
                r.ImGui_EndChild(ctx) 
            end
            end
        if not popped_view_stylevars then r.ImGui_PopStyleVar(ctx, 2) end
        
        r.ImGui_EndChild(ctx) -- End ScreenshotList
        
        config.screenshot_window_width = r.ImGui_GetWindowWidth(ctx)
        -- Store window height without progress bar adjustment
        local current_height = r.ImGui_GetWindowHeight(ctx)
        if bulk_screenshot_progress > 0 and bulk_screenshot_progress < 1 then
            config.screenshot_window_height = current_height - 30
        else
            config.screenshot_window_height = current_height
        end
        r.ImGui_End(ctx)
    end
    r.ImGui_PopStyleColor(ctx)
    r.ImGui_PopStyleVar(ctx)
    
    -- Add Root Custom Folder popup (outside main window, always available)
    if show_add_root_folder_popup then
        r.ImGui_OpenPopup(ctx, "Add Custom Folder")
        show_add_root_folder_popup = false  -- Reset flag after opening
    end
    
    if r.ImGui_BeginPopupModal(ctx, "Add Custom Folder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Create a new custom folder")
        r.ImGui_Separator(ctx)
        
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputTextWithHint(ctx, "##NewRootFolder", "Enter folder name", new_root_folder_name or "")
        if changed then
            new_root_folder_name = new_name
        end
        r.ImGui_PopItemWidth(ctx)
        
        r.ImGui_Separator(ctx)
        if r.ImGui_Button(ctx, "Create", 100, 0) then
            if new_root_folder_name and new_root_folder_name ~= "" then
                -- Create new root-level custom folder
                if not config.custom_folders then
                    config.custom_folders = {}
                end
                
                if not config.custom_folders[new_root_folder_name] then
                    -- Use folder marker to force it to be recognized as a folder structure
                    config.custom_folders[new_root_folder_name] = { ["__folder_marker__"] = true }
                    SaveCustomFolders()
                end
            end
            new_root_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            new_root_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        
        r.ImGui_EndPopup(ctx)
    end
    
    -- Add Subfolder popup (outside main window, always available)
    if show_add_subfolder_popup then
        r.ImGui_OpenPopup(ctx, "Add Subfolder")
        show_add_subfolder_popup = false
    end
    
    if r.ImGui_BeginPopupModal(ctx, "Add Subfolder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Add subfolder to: " .. (selected_folder_for_subfolder or ""))
        r.ImGui_Spacing(ctx)
        
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputTextWithHint(ctx, "##NewSubfolder", "Enter subfolder name", new_subfolder_name or "")
        if changed then
            new_subfolder_name = new_name
        end
        r.ImGui_PopItemWidth(ctx)
        
        r.ImGui_Separator(ctx)
        if r.ImGui_Button(ctx, "Create", 100, 0) then
            if new_subfolder_name and new_subfolder_name ~= "" and selected_folder_for_subfolder then
                local parts = {}
                for part in selected_folder_for_subfolder:gmatch("[^/]+") do
                    table.insert(parts, part)
                end
                
                local current = config.custom_folders
                for i = 1, #parts do
                    if not current[parts[i]] then
                        current[parts[i]] = {}
                    end
                    current = current[parts[i]]
                end
                
                current[new_subfolder_name] = {}
                SaveCustomFolders()
            end
            new_subfolder_name = ""
            selected_folder_for_subfolder = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            new_subfolder_name = ""
            selected_folder_for_subfolder = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        
        r.ImGui_EndPopup(ctx)
    end
    
    -- Create Parent Folder popup (outside main window, always available)
    if show_create_parent_folder_popup then
        r.ImGui_OpenPopup(ctx, "Create Parent Folder")
        show_create_parent_folder_popup = false  -- Reset flag after opening
    end
    
    if r.ImGui_BeginPopupModal(ctx, "Create Parent Folder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Create parent folder above: " .. (selected_folder_for_parent or ""))
        r.ImGui_Separator(ctx)
        
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputTextWithHint(ctx, "##NewParentFolder", "Enter parent folder name", new_parent_folder_name or "")
        if changed then
            new_parent_folder_name = new_name
        end
        r.ImGui_PopItemWidth(ctx)
        
        r.ImGui_Separator(ctx)
        if r.ImGui_Button(ctx, "Create", 100, 0) then
            if new_parent_folder_name and new_parent_folder_name ~= "" and selected_folder_for_parent then
                -- Parse the current folder path
                local parts = {}
                for part in selected_folder_for_parent:gmatch("[^/]+") do
                    table.insert(parts, part)
                end
                
                -- Navigate to the parent of the selected folder
                local current = config.custom_folders
                for i = 1, #parts - 1 do
                    if not current[parts[i]] then
                        current[parts[i]] = {}
                    end
                    current = current[parts[i]]
                end
                
                -- Get the selected folder name (last part)
                local folder_name = parts[#parts]
                
                -- Store the contents of the selected folder
                local folder_content = current[folder_name]
                
                -- Create the new parent folder
                if not current[new_parent_folder_name] then
                    current[new_parent_folder_name] = { ["__folder_marker__"] = true }
                end
                
                -- Move the selected folder under the new parent
                current[new_parent_folder_name][folder_name] = folder_content
                
                -- Remove the old location
                current[folder_name] = nil
                
                SaveCustomFolders()
            end
            new_parent_folder_name = ""
            selected_folder_for_parent = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            new_parent_folder_name = ""
            selected_folder_for_parent = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        
        r.ImGui_EndPopup(ctx)
    end
    
    -- Rename Folder popup
    if show_rename_folder_popup then
        r.ImGui_OpenPopup(ctx, "Rename Folder")
        show_rename_folder_popup = false
    end
    
    if r.ImGui_BeginPopupModal(ctx, "Rename Folder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Rename folder: " .. (folder_to_rename or ""))
        r.ImGui_Separator(ctx)
        
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputTextWithHint(ctx, "##RenameFolder", "Enter new folder name", new_folder_name_for_rename or "")
        if changed then
            new_folder_name_for_rename = new_name
        end
        r.ImGui_PopItemWidth(ctx)
        r.ImGui_Spacing(ctx)
        
        if r.ImGui_Button(ctx, "Rename", 100, 0) then
            if new_folder_name_for_rename and new_folder_name_for_rename ~= "" and new_folder_name_for_rename ~= folder_to_rename then
                -- Navigate to the folder's parent
                local target = config.custom_folders
                if folder_to_rename_path ~= "" then
                    for part in folder_to_rename_path:gmatch("[^/]+") do
                        target = target[part]
                        if not target then break end
                    end
                end
                
                if target and target[folder_to_rename] then
                    -- Check if new name already exists
                    if target[new_folder_name_for_rename] then
                        r.ShowMessageBox("A folder with that name already exists!", "Error", 0)
                    else
                        -- Rename: copy content to new key and remove old key
                        target[new_folder_name_for_rename] = target[folder_to_rename]
                        target[folder_to_rename] = nil
                        SaveCustomFolders()
                        
                        -- Update selected_folder if it was the renamed folder
                        if selected_folder then
                            local old_path = (folder_to_rename_path ~= "" and folder_to_rename_path .. "/" or "") .. folder_to_rename
                            local new_path = (folder_to_rename_path ~= "" and folder_to_rename_path .. "/" or "") .. new_folder_name_for_rename
                            if selected_folder == old_path then
                                selected_folder = new_path
                            end
                        end
                    end
                end
            end
            folder_to_rename = nil
            folder_to_rename_path = ""
            new_folder_name_for_rename = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            folder_to_rename = nil
            folder_to_rename_path = ""
            new_folder_name_for_rename = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        
        r.ImGui_EndPopup(ctx)
    end

    if show_native_folder_create_popup then
        r.ImGui_OpenPopup(ctx, "Create New Native Folder")
        show_native_folder_create_popup = false
    end
    if r.ImGui_BeginPopupModal(ctx, "Create New Native Folder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Create a new native FX folder")
        r.ImGui_Separator(ctx)
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputTextWithHint(ctx, "##NativeFolderName", "Enter folder name", new_native_folder_name or "")
        if changed then new_native_folder_name = new_name end
        r.ImGui_PopItemWidth(ctx)
        r.ImGui_Spacing(ctx)
        if r.ImGui_Button(ctx, "Create", 100, 0) then
            if new_native_folder_name ~= "" then
                local new_idx = CreateNativeFolder(new_native_folder_name)
                if new_idx and new_native_folder_for_plugin and new_native_folder_for_plugin ~= "" then
                    AddPluginToNativeFolder(new_idx, new_native_folder_for_plugin)
                end
                RefreshAfterNativeFolderChange()
            end
            new_native_folder_name = ""
            new_native_folder_for_plugin = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            new_native_folder_name = ""
            new_native_folder_for_plugin = nil
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end

    if show_smart_folder_popup then
        local popup_name = smart_folder_edit_idx and "Edit Smart Folder" or "Create Smart Folder"
        r.ImGui_OpenPopup(ctx, popup_name)
        show_smart_folder_popup = false
    end
    local smart_popup_name = smart_folder_edit_idx and "Edit Smart Folder" or "Create Smart Folder"
    if r.ImGui_BeginPopupModal(ctx, smart_popup_name, nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, smart_folder_edit_idx and "Edit smart folder query" or "Create a new smart folder")
        r.ImGui_Separator(ctx)
        r.ImGui_PushItemWidth(ctx, 400)
        local name_changed, new_name = r.ImGui_InputTextWithHint(ctx, "##SmartFolderName", "Folder name", smart_folder_edit_name or "")
        if name_changed then smart_folder_edit_name = new_name end

        local query_changed, new_query = r.ImGui_InputTextWithHint(ctx, "##SmartFolderQuery", "Search query (e.g. comp or \"pro-q\")", smart_folder_edit_query or "")
        if query_changed then
            smart_folder_edit_query = new_query
            smart_folder_preview_dirty = true
        end
        r.ImGui_PopItemWidth(ctx)

        r.ImGui_TextDisabled(ctx, "Syntax: keywords (implicit AND), and/or/not, \"exact match\"")

        if smart_folder_preview_dirty then
            smart_folder_preview_results = EvaluateSmartFolderQuery(smart_folder_edit_query)
            smart_folder_preview_dirty = false
        end

        r.ImGui_Spacing(ctx)
        r.ImGui_Text(ctx, "Matching plugins: " .. #smart_folder_preview_results)

        if #smart_folder_preview_results > 0 then
            if r.ImGui_BeginChild(ctx, "##SmartPreview", 400, 200, 1) then
                for i = 1, math.min(#smart_folder_preview_results, 200) do
                    r.ImGui_Text(ctx, smart_folder_preview_results[i])
                end
                if #smart_folder_preview_results > 200 then
                    r.ImGui_TextDisabled(ctx, "... and " .. (#smart_folder_preview_results - 200) .. " more")
                end
                r.ImGui_EndChild(ctx)
            end
        end

        r.ImGui_Separator(ctx)
        local btn_label = smart_folder_edit_idx and "Save" or "Create"
        if r.ImGui_Button(ctx, btn_label, 100, 0) then
            if smart_folder_edit_name ~= "" and smart_folder_edit_query ~= "" then
                if smart_folder_edit_idx then
                    RenameNativeFolder(smart_folder_edit_idx, smart_folder_edit_name)
                    UpdateNativeSmartFolder(smart_folder_edit_idx, smart_folder_edit_query)
                else
                    CreateNativeSmartFolder(smart_folder_edit_name, smart_folder_edit_query)
                end
                RefreshAfterNativeFolderChange()
            end
            smart_folder_edit_name = ""
            smart_folder_edit_query = ""
            smart_folder_edit_idx = nil
            smart_folder_preview_results = {}
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            smart_folder_edit_name = ""
            smart_folder_edit_query = ""
            smart_folder_edit_idx = nil
            smart_folder_preview_results = {}
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end

    if show_rename_native_folder_popup then
        r.ImGui_OpenPopup(ctx, "Rename Native Folder")
        show_rename_native_folder_popup = false
    end
    if r.ImGui_BeginPopupModal(ctx, "Rename Native Folder", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Rename native folder")
        r.ImGui_Separator(ctx)
        r.ImGui_PushItemWidth(ctx, 300)
        local changed, new_name = r.ImGui_InputText(ctx, "##RenameNativeFolder", rename_native_folder_name or "")
        if changed then rename_native_folder_name = new_name end
        r.ImGui_PopItemWidth(ctx)
        r.ImGui_Spacing(ctx)
        if r.ImGui_Button(ctx, "Rename", 100, 0) then
            if rename_native_folder_idx and rename_native_folder_name ~= "" then
                RenameNativeFolder(rename_native_folder_idx, rename_native_folder_name)
                RefreshAfterNativeFolderChange()
            end
            rename_native_folder_idx = nil
            rename_native_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            rename_native_folder_idx = nil
            rename_native_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end

    if show_delete_native_folder_popup then
        r.ImGui_OpenPopup(ctx, "Delete Native Folder?")
        show_delete_native_folder_popup = false
    end
    if r.ImGui_BeginPopupModal(ctx, "Delete Native Folder?", nil, r.ImGui_WindowFlags_AlwaysAutoResize()) then
        r.ImGui_Text(ctx, "Are you sure you want to delete this native folder?")
        r.ImGui_Spacing(ctx)
        r.ImGui_TextDisabled(ctx, pending_delete_native_folder_name or "")
        r.ImGui_Spacing(ctx)
        r.ImGui_Separator(ctx)
        if r.ImGui_Button(ctx, "Delete", 100, 0) then
            if pending_delete_native_folder_idx then
                DeleteNativeFolder(pending_delete_native_folder_idx)
                RefreshAfterNativeFolderChange()
            end
            pending_delete_native_folder_idx = nil
            pending_delete_native_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 100, 0) then
            pending_delete_native_folder_idx = nil
            pending_delete_native_folder_name = ""
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end
    
    return visible
end

function ShowBulkScreenshotProgressWindow()
    if bulk_screenshot_progress <= 0 or bulk_screenshot_progress >= 1 then
        return
    end
    
    -- Get viewport size for centering
    local viewport = r.ImGui_GetMainViewport(ctx)
    local work_x, work_y = r.ImGui_Viewport_GetWorkPos(viewport)
    local work_w, work_h = r.ImGui_Viewport_GetWorkSize(viewport)
    
    r.ImGui_SetNextWindowSize(ctx, 400, 80, r.ImGui_Cond_Always())
    r.ImGui_SetNextWindowPos(ctx, work_x + work_w / 2 - 200, work_y + work_h / 2 - 40, r.ImGui_Cond_Always())
    
    local window_flags = r.ImGui_WindowFlags_NoCollapse() | r.ImGui_WindowFlags_NoResize() | r.ImGui_WindowFlags_NoScrollbar()
    local visible, open = r.ImGui_Begin(ctx, "Bulk Screenshot Progress", true, window_flags)
    
    if visible then
        r.ImGui_Text(ctx, "Creating plugin screenshots...")
        r.ImGui_Spacing(ctx)
        
        local progress_text = string.format("%d / %d plugins (%.1f%%)", loaded_fx_count, total_fx_count, bulk_screenshot_progress * 100)
        r.ImGui_ProgressBar(ctx, bulk_screenshot_progress, -1, 30, progress_text)
        
        r.ImGui_Spacing(ctx)
        if r.ImGui_Button(ctx, "Cancel", -1, 25) then
            STOP_REQUESTED = true
        end
        
        r.ImGui_End(ctx)
    end
    
    if not open then
        STOP_REQUESTED = true
    end
end

function FilterTracksByTag(tag)
    local matching_tracks = {}
    local track_count = r.CountTracks(0)
    for i = 0, track_count - 1 do
        local track = r.GetTrack(0, i)
        local guid = r.GetTrackGUID(track)
        if track_tags[guid] then
            for _, track_tag in ipairs(track_tags[guid]) do
                if track_tag == tag then
                    table.insert(matching_tracks, track)
                    break
                end
            end
        end
    end
    return matching_tracks
end

function DrawTagContextMenu(ctx, popup_id, current_guid, current_tags)
    if r.ImGui_BeginPopup(ctx, popup_id) then
        local ctag = tag_ctx_menu_tag
        if ctag then
            local tagged_tracks = FilterTracksByTag(ctag)
            local tagged_count = #tagged_tracks

            if current_tags then
                if r.ImGui_MenuItem(ctx, "Remove from This Track") then
                    for ix = #current_tags, 1, -1 do
                        if current_tags[ix] == ctag then table.remove(current_tags, ix) end
                    end
                    SaveTags()
                end
            end
            if r.ImGui_MenuItem(ctx, "Add '" .. ctag .. "' to Selected Tracks") then
                r.Undo_BeginBlock()
                local sel_count = r.CountSelectedTracks(0)
                for i = 0, sel_count - 1 do
                    local tr = r.GetSelectedTrack(0, i)
                    local tg = r.GetTrackGUID(tr)
                    track_tags[tg] = track_tags[tg] or {}
                    if not table.contains(track_tags[tg], ctag) then
                        table.insert(track_tags[tg], ctag)
                    end
                end
                SaveTags()
                r.Undo_EndBlock("Add tag to selected tracks", -1)
            end
            if r.ImGui_MenuItem(ctx, "Remove '" .. ctag .. "' from Selected Tracks") then
                r.Undo_BeginBlock()
                local sel_count = r.CountSelectedTracks(0)
                for i = 0, sel_count - 1 do
                    local tr = r.GetSelectedTrack(0, i)
                    local tg = r.GetTrackGUID(tr)
                    if track_tags[tg] then
                        for ix = #track_tags[tg], 1, -1 do
                            if track_tags[tg][ix] == ctag then table.remove(track_tags[tg], ix) end
                        end
                    end
                end
                SaveTags()
                r.Undo_EndBlock("Remove tag from selected tracks", -1)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Select Tracks with '" .. ctag .. "' (" .. tagged_count .. ")") then
                r.Main_OnCommand(40297, 0)
                for _, tr in ipairs(tagged_tracks) do r.SetTrackSelected(tr, true) end
            end
            if r.ImGui_MenuItem(ctx, "Unselect All Tracks") then
                r.Main_OnCommand(40297, 0)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Hide Tracks with '" .. ctag .. "'") then
                r.PreventUIRefresh(1)
                for _, tr in ipairs(tagged_tracks) do
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINTCP", 0)
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINMIXER", 0)
                end
                r.PreventUIRefresh(-1)
                r.TrackList_AdjustWindows(false)
            end
            if r.ImGui_MenuItem(ctx, "Show Tracks with '" .. ctag .. "'") then
                r.PreventUIRefresh(1)
                for _, tr in ipairs(tagged_tracks) do
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINTCP", 1)
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINMIXER", 1)
                end
                r.PreventUIRefresh(-1)
                r.TrackList_AdjustWindows(false)
            end
            if r.ImGui_MenuItem(ctx, "Hide All Tracks Except '" .. ctag .. "'") then
                local tagged_set = {}
                for _, tr in ipairs(tagged_tracks) do tagged_set[r.GetTrackGUID(tr)] = true end
                r.PreventUIRefresh(1)
                for i = 0, r.CountTracks(0) - 1 do
                    local tr = r.GetTrack(0, i)
                    local visible = tagged_set[r.GetTrackGUID(tr)] and true or false
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINTCP", visible and 1 or 0)
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINMIXER", visible and 1 or 0)
                end
                r.PreventUIRefresh(-1)
                r.TrackList_AdjustWindows(false)
            end
            if r.ImGui_MenuItem(ctx, "Show All Tracks") then
                r.PreventUIRefresh(1)
                for i = 0, r.CountTracks(0) - 1 do
                    local tr = r.GetTrack(0, i)
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINTCP", 1)
                    r.SetMediaTrackInfo_Value(tr, "B_SHOWINMIXER", 1)
                end
                r.PreventUIRefresh(-1)
                r.TrackList_AdjustWindows(false)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Rename All Tracks with '" .. ctag .. "'") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                for _, tr in ipairs(tagged_tracks) do
                    r.GetSetMediaTrackInfo_String(tr, "P_NAME", ctag, true)
                end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Rename tagged tracks to tag name", -1)
            end
            if r.ImGui_MenuItem(ctx, "Rename All Tracks with '" .. ctag .. "' (numbered)") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                for idx, tr in ipairs(tagged_tracks) do
                    r.GetSetMediaTrackInfo_String(tr, "P_NAME", ctag .. " " .. string.format("%02d", idx), true)
                end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Rename tagged tracks to tag name numbered", -1)
            end
            if current_tags and current_guid then
                if r.ImGui_MenuItem(ctx, "Rename Current Track with '" .. ctag .. "'") then
                    r.Undo_BeginBlock()
                    if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                        r.GetSetMediaTrackInfo_String(TRACK, "P_NAME", ctag, true)
                    end
                    r.Undo_EndBlock("Rename current track to tag name", -1)
                end
            end
            if r.ImGui_MenuItem(ctx, "Rename Tagged Tracks to First Plugin") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                for _, tr in ipairs(tagged_tracks) do
                    local fx_count = r.TrackFX_GetCount(tr)
                    if fx_count > 0 then
                        local _, fx_name = r.TrackFX_GetFXName(tr, 0, "")
                        if fx_name and fx_name ~= "" then
                            local clean = fx_name:match(":%s*(.+)") or fx_name
                            clean = clean:gsub("%s*%b()", "")
                            r.GetSetMediaTrackInfo_String(tr, "P_NAME", clean, true)
                        end
                    end
                end
                r.PreventUIRefresh(-1)
                r.Undo_EndBlock("Rename tagged tracks to first plugin", -1)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Move to New Folder") then
                r.Undo_BeginBlock()
                r.PreventUIRefresh(1)
                if tagged_count > 0 then
                    local indices = {}
                    for _, tr in ipairs(tagged_tracks) do
                        local idx = r.GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER")
                        t_insert(indices, idx)
                    end
                    t_sort(indices)
                    local insert_pos = indices[1] - 1
                    r.InsertTrackAtIndex(insert_pos, true)
                    local folder_track = r.GetTrack(0, insert_pos)
                    r.GetSetMediaTrackInfo_String(folder_track, "P_NAME", ctag, true)
                    r.SetMediaTrackInfo_Value(folder_track, "I_FOLDERDEPTH", 1)
                    for i, tr in ipairs(tagged_tracks) do
                        local cur_idx = math.floor(r.GetMediaTrackInfo_Value(tr, "IP_TRACKNUMBER"))
                        local target = insert_pos + i + 1
                        if cur_idx ~= target then
                            r.ReorderSelectedTracks(target - 1, 0)
                        end
                    end
                    local last_tagged = tagged_tracks[#tagged_tracks]
                    local last_idx = math.floor(r.GetMediaTrackInfo_Value(last_tagged, "IP_TRACKNUMBER"))
                    local last_tr = r.GetTrack(0, last_idx - 1)
                    if last_tr then
                        local cur_depth = r.GetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH")
                        r.SetMediaTrackInfo_Value(last_tr, "I_FOLDERDEPTH", cur_depth - 1)
                    end
                end
                r.PreventUIRefresh(-1)
                r.TrackList_AdjustWindows(false)
                r.Undo_EndBlock("Move tagged tracks to new folder", -1)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_MenuItem(ctx, "Mute Tracks with '" .. ctag .. "'") then
                r.Undo_BeginBlock()
                for _, tr in ipairs(tagged_tracks) do r.SetMediaTrackInfo_Value(tr, "B_MUTE", 1) end
                r.Undo_EndBlock("Mute tagged tracks", -1)
            end
            if r.ImGui_MenuItem(ctx, "Unmute Tracks with '" .. ctag .. "'") then
                r.Undo_BeginBlock()
                for _, tr in ipairs(tagged_tracks) do r.SetMediaTrackInfo_Value(tr, "B_MUTE", 0) end
                r.Undo_EndBlock("Unmute tagged tracks", -1)
            end
            if r.ImGui_MenuItem(ctx, "Solo Tracks with '" .. ctag .. "'") then
                r.Undo_BeginBlock()
                for _, tr in ipairs(tagged_tracks) do r.SetMediaTrackInfo_Value(tr, "I_SOLO", 1) end
                r.Undo_EndBlock("Solo tagged tracks", -1)
            end
            if r.ImGui_MenuItem(ctx, "Unsolo All Tracks") then
                r.Undo_BeginBlock()
                for i = 0, r.CountTracks(0) - 1 do
                    r.SetMediaTrackInfo_Value(r.GetTrack(0, i), "I_SOLO", 0)
                end
                r.Undo_EndBlock("Unsolo all tracks", -1)
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_BeginMenu(ctx, "Set Color...") then
                local flags = r.ImGui_ColorEditFlags_NoInputs() | r.ImGui_ColorEditFlags_NoLabel()
                local changed_col, new_col = r.ImGui_ColorEdit4(ctx, "##tag_color_pick", tag_color_edit_color, flags)
                if changed_col then tag_color_edit_color = new_col end
                r.ImGui_SameLine(ctx)
                if r.ImGui_Button(ctx, "Apply##tag_color_apply") then
                    tag_colors[ctag] = tag_color_edit_color
                    SaveTags()
                    r.ImGui_CloseCurrentPopup(ctx)
                end
                r.ImGui_EndMenu(ctx)
            end
            if tag_colors[ctag] then
                if r.ImGui_MenuItem(ctx, "Apply Tag Color to Tracks") then
                    r.Undo_BeginBlock()
                    local col = tag_colors[ctag]
                    local rd, g, b = r.ImGui_ColorConvertU32ToDouble4(col)
                    local native = r.ColorToNative(m_floor(rd * 255), m_floor(g * 255), m_floor(b * 255)) | 0x1000000
                    for _, tr in ipairs(tagged_tracks) do
                        r.SetMediaTrackInfo_Value(tr, "I_CUSTOMCOLOR", native)
                    end
                    r.Undo_EndBlock("Apply tag color to tracks", -1)
                end
                if r.ImGui_MenuItem(ctx, "Remove Color") then
                    tag_colors[ctag] = nil
                    SaveTags()
                end
            end

            r.ImGui_Separator(ctx)

            if r.ImGui_BeginMenu(ctx, "Rename Tag...") then
                r.ImGui_PushItemWidth(ctx, 120)
                local ch, nv = r.ImGui_InputText(ctx, "##tag_rename_input", tag_rename_buffer)
                if ch then tag_rename_buffer = nv end
                r.ImGui_SameLine(ctx)
                if r.ImGui_Button(ctx, "OK##tag_rename_ok") then
                    local new_name = tag_rename_buffer
                    if new_name ~= "" and new_name ~= ctag then
                        for tg, arr in pairs(track_tags) do
                            for ix, t in ipairs(arr) do
                                if t == ctag then arr[ix] = new_name end
                            end
                        end
                        available_tags[new_name] = true
                        available_tags[ctag] = nil
                        if tag_colors[ctag] then
                            tag_colors[new_name] = tag_colors[ctag]
                            tag_colors[ctag] = nil
                        end
                        SaveTags()
                        tag_ctx_menu_tag = new_name
                    end
                    tag_rename_active = false
                    r.ImGui_CloseCurrentPopup(ctx)
                end
                r.ImGui_PopItemWidth(ctx)
                r.ImGui_EndMenu(ctx)
            end
            if r.ImGui_MenuItem(ctx, "Delete '" .. ctag .. "' Globally") then
                for tg, arr in pairs(track_tags) do
                    for ix = #arr, 1, -1 do
                        if arr[ix] == ctag then table.remove(arr, ix) end
                    end
                end
                available_tags[ctag] = nil
                tag_colors[ctag] = nil
                SaveTags()
            end
        end
        r.ImGui_EndPopup(ctx)
    end
end

function Filter_actions(filter_text)
    if old_filter == filter_text then return old_t end
    filter_text = Lead_Trim_ws(filter_text)
    local t = {}
    if filter_text == "" or not filter_text then return t end
    
    local words = {}
    for word in filter_text:gmatch("%S+") do
        words[#words+1] = word:lower()
    end

    -- Check cache
    if not global_search_cache or next(global_search_cache) == nil then BuildPluginCache() end

    for i = 1, #FX_LIST_TEST do
        local raw_name = FX_LIST_TEST[i]
        if not config.excluded_plugins[raw_name] then
            
            -- GEOPTIMALISEERD: Gebruik cache
            local data = global_search_cache[raw_name]
            local name_l, alias_l
            
            if data then
                name_l = data.lower_name
                alias_l = data.lower_alias
            else
                name_l = raw_name:lower()
                local alias = plugin_aliases[raw_name]
                alias_l = alias and alias:lower() or nil
            end
            
            local found = true
            for _, word in ipairs(words) do
                local match_word = false
                if name_l:find(word, 1, true) then
                    match_word = true
                elseif alias_l and alias_l:find(word, 1, true) then
                    match_word = true
                end
                
                if not match_word then
                    found = false
                    break
                end
            end
            
            if found then 
                local len = data and data.display_len or raw_name:len()
                t[#t + 1] = { score = len - filter_text:len(), name = raw_name } 
            end
        end
    end
    if #t >= 2 then SortTable(t, "score", "name") end
    old_t, old_filter = t, filter_text
    return t
end

function FilterBox()
    local default_type_order = {"VST3", "VST", "CLAP", "JS", "AU", "LV2", "OTHER"}
    if not config.type_order then config.type_order = default_type_order end
    local show_customize_popup = false
    local window_width = r.ImGui_GetWindowWidth(ctx)
    local window_height = r.ImGui_GetWindowHeight(ctx)
    local track_info_width = math.max(window_width - 10, 125)
    local x_button_width = 20
    local margin = 3
    local search_width = track_info_width - (x_button_width * 3) - (margin * 2)
   
    local sort_mode = config.sort_mode or "score" -- "score", "alphabet", "rating", "type"

    local top_buttons_height = config.hideTopButtons and 5 or 30
    local tags_height = config.show_tags and current_tag_window_height or 0
    local meter_height = config.hideMeter and 0 or 90
    local meter_spacing = 5
    local bottom_buttons_height = config.hideBottomButtons and 0 or 70
    local volume_slider_height = config.hideVolumeSlider and 0 or 40
    
    local total_ui_elements = top_buttons_height + tags_height + meter_height + meter_spacing + bottom_buttons_height + volume_slider_height
    local search_results_max_height = window_height - total_ui_elements - 100
    local should_focus_main_search = (main_search_focus_requested or r.ImGui_IsWindowAppearing(ctx)) and not config.show_screenshot_window
    if should_focus_main_search then
        r.ImGui_SetKeyboardFocusHere(ctx)
        main_search_focus_requested = false
    end
    
    r.ImGui_PushItemWidth(ctx, search_width)
    local input_flags = 0
    if should_focus_main_search and FILTER ~= "" then
        input_flags = r.ImGui_InputTextFlags_AutoSelectAll()
    end
    local changed
    changed, FILTER = r.ImGui_InputTextWithHint(ctx, '##input', "SEARCH FX", FILTER, input_flags)
    if changed then
    new_search_performed = true
    end
    r.ImGui_PopItemWidth(ctx)
    r.ImGui_SameLine(ctx)
    if r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Enter()) or r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_KeypadEnter()) then
        if FILTER == "" then
            if last_viewed_folder then
                r.ImGui_SetScrollY(ctx, 0)
                show_screenshot_window = true
                screenshot_window_interactive = true
                screenshot_search_results = {}
                ClearScreenshotCache()
                if IsNonFoldersSubgroup(last_viewed_folder) then
                    browser_panel_selected = last_viewed_folder
                    selected_folder = nil
                    current_filtered_fx = GetFxListForSubgroup(last_viewed_folder) or {}
                    local cap = loaded_items_count or ITEMS_PER_BATCH or 30
                    for j = 1, math.min(cap, #current_filtered_fx) do
                        table.insert(screenshot_search_results, {name = current_filtered_fx[j]})
                    end
                else
                    SelectFolderExclusive(last_viewed_folder)
                    GetPluginsForFolder(selected_folder)
                end
            end
        else
            UpdateLastViewedFolder(selected_folder)
            screenshot_search_results = Filter_actions(FILTER)
            new_search_performed = true
            update_search_screenshots = true
            show_screenshot_window = true
            screenshot_window_interactive = true
            selected_folder = nil
            ClearScreenshotCache()
        end
    end
    r.ImGui_SameLine(ctx)
    local button_height = r.ImGui_GetFrameHeight(ctx)
    if r.ImGui_Button(ctx, "T", x_button_width, button_height) then
        config.show_type_dividers = not config.show_type_dividers
        SaveConfig()
    end
    r.ImGui_SameLine(ctx)
    local sort_label_main = (sort_mode == "alphabet") and "A" or ((sort_mode == "rating") and "R" or ((sort_mode == "type") and "P" or "Sc"))
    if r.ImGui_Button(ctx, sort_label_main, x_button_width, button_height) then
        if sort_mode == "score" then
            sort_mode = "alphabet"
        elseif sort_mode == "alphabet" then
            sort_mode = "rating"
        elseif sort_mode == "rating" then
            sort_mode = "type"
        else
            sort_mode = "score"
        end
        config.sort_mode = sort_mode
        SaveConfig()
    end
    if r.ImGui_IsItemClicked(ctx, r.ImGui_MouseButton_Right()) then
        r.ImGui_OpenPopup(ctx, "TypeOrderPopup")
    end
    if r.ImGui_BeginPopup(ctx, "TypeOrderPopup") then
        if r.ImGui_Selectable(ctx, "Default (VST3 > VST > CLAP > JS > AU > LV2 > OTHER)") then
            config.type_order = {"VST3", "VST", "CLAP", "JS", "AU", "LV2", "OTHER"}
            SaveConfig()
        end
        if r.ImGui_Selectable(ctx, "Alphabetical (AU > CLAP > JS > LV2 > OTHER > VST > VST3)") then
            config.type_order = {"AU", "CLAP", "JS", "LV2", "OTHER", "VST", "VST3"}
            SaveConfig()
        end
        if r.ImGui_Selectable(ctx, "Reverse (OTHER > LV2 > AU > JS > CLAP > VST > VST3)") then
            config.type_order = {"OTHER", "LV2", "AU", "JS", "CLAP", "VST", "VST3"}
            SaveConfig()
        end
        if r.ImGui_Selectable(ctx, "Customize Order...") then
            show_customize_popup = true
        end
        r.ImGui_EndPopup(ctx)
    end
    if show_customize_popup then
        r.ImGui_OpenPopup(ctx, "CustomizeOrderPopup")
        show_customize_popup = false
    end
    if r.ImGui_BeginPopup(ctx, "CustomizeOrderPopup") then
        r.ImGui_Text(ctx, "Use buttons to reorder:")
        for i, t in ipairs(config.type_order) do
            r.ImGui_Text(ctx, tostring(i) .. ". " .. t)
            r.ImGui_SameLine(ctx)
            if i > 1 and r.ImGui_Button(ctx, "Up##" .. i, 30, 0) then
                config.type_order[i], config.type_order[i-1] = config.type_order[i-1], config.type_order[i]
                SaveConfig()
            end
            r.ImGui_SameLine(ctx)
            if i < #config.type_order and r.ImGui_Button(ctx, "Down##" .. i, 40, 0) then
                config.type_order[i], config.type_order[i+1] = config.type_order[i+1], config.type_order[i]
                SaveConfig()
            end
        end
        if r.ImGui_Button(ctx, "Reset to Default", -1, 0) then
            config.type_order = {"VST3", "VST", "CLAP", "JS", "AU", "LV2", "OTHER"}
            SaveConfig()
        end
        r.ImGui_EndPopup(ctx)
    end
    if r.ImGui_IsItemHovered(ctx) then
        if sort_mode == "score" then
            r.ImGui_SetTooltip(ctx, "Score sorting (click to switch to Alphabetic)")
        elseif sort_mode == "alphabet" then
            r.ImGui_SetTooltip(ctx, "Alphabetic sorting (click to switch to Rating)")
        elseif sort_mode == "rating" then
            r.ImGui_SetTooltip(ctx, "Rating sorting (click to switch to Prefix)")
        else
            r.ImGui_SetTooltip(ctx, "Prefix sorting (click to switch to Score)\nRight-click for type order options")
        end
    end
    r.ImGui_SameLine(ctx)
    if r.ImGui_Button(ctx, "X", x_button_width, button_height) then
        FILTER = ""
        screenshot_search_results = nil
        current_fx_chain_path = nil
        current_fx_chain_relative_path = nil
        current_fx_chain_name = nil
        r.ImGui_SetScrollY(ctx, 0)
        show_screenshot_window = true
        show_media_browser = false
        if config.default_folder == LAST_OPENED_SENTINEL and last_viewed_folder then
            if IsNonFoldersSubgroup(last_viewed_folder) then
                browser_panel_selected = last_viewed_folder
                selected_folder = nil
                    current_filtered_fx = GetFxListForSubgroup(last_viewed_folder) or {}
                    if config.apply_type_priority then
                        current_filtered_fx = DedupeByTypePriority(current_filtered_fx)
                    end
                screenshot_search_results = {}
                local cap = loaded_items_count or ITEMS_PER_BATCH or 30
                for j = 1, math.min(cap, #current_filtered_fx) do
                    table.insert(screenshot_search_results, {name = current_filtered_fx[j]})
                end
            else
                browser_panel_selected = nil
                selected_folder = last_viewed_folder
            end
        else
            browser_panel_selected = nil
            selected_folder = config.default_folder
        end

    if config.default_folder == "Projects" then
        show_media_browser = true
        show_sends_window = false
        show_action_browser = false
        selected_folder = nil
    elseif config.default_folder == "Sends/Receives" then
        show_media_browser = false
        show_sends_window = true
        show_action_browser = false
        selected_folder = nil
    elseif config.default_folder == "Actions" then
        show_media_browser = false
        show_sends_window = false
        show_action_browser = true
        selected_folder = nil
    else
        show_media_browser = false
        show_sends_window = false
        show_action_browser = false
        ClearScreenshotCache()
        if selected_folder then
            local filtered_plugins = GetPluginsForFolder(selected_folder)
            loaded_items_count = ITEMS_PER_BATCH or loaded_items_count or 30
            screenshot_search_results = {}
            for i = 1, math.min(loaded_items_count, #filtered_plugins) do
                local plugin_name = filtered_plugins[i]
                table.insert(screenshot_search_results, { name = plugin_name })
            end
            -- Prefetch only the first visible batch to avoid massive queue spikes in very large folders
            local prefetch_cap = math.min(#filtered_plugins, loaded_items_count or ITEMS_PER_BATCH or 30)
            for i = 1, prefetch_cap do
                local plugin_name = filtered_plugins[i]
                local safe_name = plugin_name:gsub("[^%w%s-]", "_")
                local screenshot_file = screenshot_path .. safe_name .. ".png"
                if r.file_exists(screenshot_file) then
                    local relative_path = screenshot_file:gsub(screenshot_path, "")
                    local unique_key = relative_path .. "_" .. (plugin_name or "unknown")
                    if not texture_load_queue[unique_key] and not search_texture_cache[unique_key] then
                        texture_load_queue[unique_key] = { file = screenshot_file, queued_at = r.time_precise(), plugin = plugin_name }
                    end
                end
            end
        end
    end
end
    local filtered_fx = Filter_actions(FILTER)
    if sort_mode == "alphabet" then
        table.sort(filtered_fx, function(a, b) 
            local na = a.name:match('^[^:]+: (.+)$') or a.name
            local nb = b.name:match('^[^:]+: (.+)$') or b.name
            return na:lower() < nb:lower() 
        end)
    elseif sort_mode == "rating" then
        table.sort(filtered_fx, function(a, b)
            local ra = plugin_ratings[a.name] or 0
            local rb = plugin_ratings[b.name] or 0
            if ra == rb then
                local na = a.name:match('^[^:]+: (.+)$') or a.name
                local nb = b.name:match('^[^:]+: (.+)$') or b.name
                return na:lower() < nb:lower()
            else
                return ra > rb
            end
        end)
    elseif sort_mode == "type" then
        table.sort(filtered_fx, function(a, b)
            local ta = GetPluginType(a.name)
            local tb = GetPluginType(b.name)
            if ta == tb then
                local na = a.name:match('^[^:]+: (.+)$') or a.name
                local nb = b.name:match('^[^:]+: (.+)$') or b.name
                return na:lower() < nb:lower()
            else
                local order = {}
                for i, t in ipairs(config.type_order) do order[t] = i end
                return (order[ta] or 8) < (order[tb] or 8)
            end
        end)
    else -- default: score
        table.sort(filtered_fx, function(a, b)
            if a.score == b.score then
                local na = a.name:match('^[^:]+: (.+)$') or a.name
                local nb = b.name:match('^[^:]+: (.+)$') or b.name
                return na:lower() < nb:lower()
            end
            return a.score < b.score
        end)
    end

    local window_height = r.ImGui_GetWindowHeight(ctx)
    local bottom_buttons_height = config.hideBottomButtons and 0 or 70
    local available_height = window_height - r.ImGui_GetCursorPosY(ctx) - bottom_buttons_height - 10
    if #filtered_fx ~= 0 then
    local popupp_open = r.ImGui_BeginChild(ctx, "##popupp", -1, search_results_max_height, 0, r.ImGui_WindowFlags_NoNav())
    if popupp_open then
            if config.show_type_dividers then
                
                local types = {
                    VST = {}, VSTi = {}, 
                    VST3 = {}, VST3i = {}, 
                    JS = {}, JSi = {}, 
                    AU = {}, AUi = {}, 
                    CLAP = {}, CLAPi = {}, 
                    LV2 = {}, LV2i = {}
                }
                
                local global_idx = 1
                for i = 1, #filtered_fx do
                    local name = filtered_fx[i].name
                    if name:match("^VST3i:") then
                        table.insert(types.VST3i, filtered_fx[i])
                    elseif name:match("^VST3:") then
                        table.insert(types.VST3, filtered_fx[i])
                    elseif name:match("^VSTi:") then
                        table.insert(types.VSTi, filtered_fx[i])
                    elseif name:match("^VST:") then
                        table.insert(types.VST, filtered_fx[i])
                    elseif name:match("^CLAPi:") then
                        table.insert(types.CLAPi, filtered_fx[i])
                    elseif name:match("^CLAP:") then
                        table.insert(types.CLAP, filtered_fx[i])
                    elseif name:match("^JSi:") then
                        table.insert(types.JSi, filtered_fx[i])
                    elseif name:match("^JS:") then
                        table.insert(types.JS, filtered_fx[i])
                    elseif name:match("^AUi:") then
                        table.insert(types.AUi, filtered_fx[i])
                    elseif name:match("^AU:") then
                        table.insert(types.AU, filtered_fx[i])
                    elseif name:match("^LV2i:") then
                        table.insert(types.LV2i, filtered_fx[i])
                    elseif name:match("^LV2:") then
                        table.insert(types.LV2, filtered_fx[i])
                    end
                end
    
                for type, plugins in pairs(types) do
                    if #plugins > 0 then
                        if sort_mode == "alphabet" then
                            table.sort(plugins, function(a, b) 
                                return a.name:lower() < b.name:lower() 
                            end)
                        elseif sort_mode == "rating" then
                            table.sort(plugins, function(a, b)
                                local ra = plugin_ratings[a.name] or 0
                                local rb = plugin_ratings[b.name] or 0
                                if ra == rb then
                                    return a.name:lower() < b.name:lower()
                                else
                                    return ra > rb
                                end
                            end)
                        else -- default: score
                            table.sort(plugins, function(a, b)
                                if a.score == b.score then
                                    return a.name:lower() < b.name:lower()
                                end
                                return a.score < b.score
                            end)
                        end
                        r.ImGui_Dummy(ctx, 0, 5)
                        r.ImGui_Separator(ctx)
                        r.ImGui_Text(ctx, type .. " Plugins")
                        r.ImGui_Separator(ctx)
                        
                        for _, plugin in ipairs(plugins) do
                            local display_name = GetDisplayPluginName(plugin.name)
                            if r.ImGui_Selectable(ctx, display_name .. "  " .. GetStarsString(plugin.name) .. "##search_" .. global_idx, global_idx == ADDFX_Sel_Entry) then
                                local fx_index = AddFXToTrack(TRACK, plugin.name)
                                r.ImGui_CloseCurrentPopup(ctx)
                                LAST_USED_FX = plugin.name
                                
                                -- OPEN FLOATING ALS OPTIE ENABLED IS
                                if config.open_floating_after_adding and fx_index >= 0 then
                                    r.TrackFX_Show(TRACK, fx_index, 3) -- 3 = open floating
                                end
                            end
    
                            if r.ImGui_IsItemHovered(ctx) then
                                if plugin.name ~= current_hovered_plugin then
                                    current_hovered_plugin = plugin.name
                                    if config.show_screenshot_in_search then
                                        LoadPluginScreenshot(current_hovered_plugin)
                                    end
                                end
                                is_screenshot_visible = true
                                if not config.show_screenshot_in_search or not ScreenshotExists(plugin.name) then
                                    r.ImGui_BeginTooltip(ctx)
                                    local disp = GetDisplayPluginName(plugin.name)
                                    r.ImGui_Text(ctx, disp)
                                    r.ImGui_EndTooltip(ctx)
                                end
                            end
    
                            if r.ImGui_IsItemClicked(ctx, 1) then
                                r.ImGui_OpenPopup(ctx, "DrawItemsPluginMenu_" .. global_idx)
                            end
    
                            ShowPluginContextMenu(plugin.name, "search_" .. global_idx)
                            global_idx = global_idx + 1
                        end
                    end
                end
            else
                -- Original view
                for i = 1, #filtered_fx do
                    local search_display = GetDisplayPluginName(filtered_fx[i].name)
                    if r.ImGui_Selectable(ctx, search_display .. "  " .. GetStarsString(filtered_fx[i].name) .. "##search_" .. i, i == ADDFX_Sel_Entry) then
                    local fx_index = AddFXToTrack(TRACK, filtered_fx[i].name)
                    r.ImGui_CloseCurrentPopup(ctx)
                    LAST_USED_FX = filtered_fx[i].name
                    
                        -- OPEN FLOATING ALS OPTIE ENABLED IS
                        if config.open_floating_after_adding and fx_index >= 0 then
                            r.TrackFX_Show(TRACK, fx_index, 3) -- 3 = open floating
                        end
                    end

    
                    if r.ImGui_IsItemHovered(ctx) then
                        if filtered_fx[i].name ~= current_hovered_plugin then
                            current_hovered_plugin = filtered_fx[i].name
                            if config.show_screenshot_in_search then
                                LoadPluginScreenshot(current_hovered_plugin)
                            end
                        end
                        is_screenshot_visible = true
                        if not config.show_screenshot_in_search or not ScreenshotExists(filtered_fx[i].name) then
                            r.ImGui_BeginTooltip(ctx)
                            r.ImGui_Text(ctx, filtered_fx[i].name)
                            r.ImGui_EndTooltip(ctx)
                        end
                    end
    
                    ShowPluginContextMenu(filtered_fx[i].name, "search_" .. i)
                end
            end
    
            if not r.ImGui_IsWindowHovered(ctx) then
                is_screenshot_visible = false
                current_hovered_plugin = nil
            end
        end
        r.ImGui_EndChild(ctx)
    
    
        if r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Enter()) or r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_KeypadEnter()) then
            if ADDFX_Sel_Entry and ADDFX_Sel_Entry > 0 and ADDFX_Sel_Entry <= #filtered_fx then
                local fx_index = AddFXToTrack(TRACK, filtered_fx[ADDFX_Sel_Entry].name)
                LAST_USED_FX = filtered_fx[ADDFX_Sel_Entry].name
                
                -- OPEN FLOATING ALS OPTIE ENABLED IS
                if config.open_floating_after_adding and fx_index >= 0 then
                    r.TrackFX_Show(TRACK, fx_index, 3) -- 3 = open floating
                end
                
                ADDFX_Sel_Entry = nil
                FILTER = ''
                r.ImGui_CloseCurrentPopup(ctx)
            end
        elseif r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_UpArrow()) then
            ADDFX_Sel_Entry = (ADDFX_Sel_Entry or 1) - 1
            if ADDFX_Sel_Entry < 1 then ADDFX_Sel_Entry = #filtered_fx end
        elseif r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_DownArrow()) then
            ADDFX_Sel_Entry = (ADDFX_Sel_Entry or 0) + 1
            if ADDFX_Sel_Entry > #filtered_fx then ADDFX_Sel_Entry = 1 end
        end
        
    end
    if r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Escape()) then
        FILTER = ''
        r.ImGui_CloseCurrentPopup(ctx)
    end
    return #filtered_fx ~= 0
end

function DrawItems(tbl, main_cat_name)
    if menu_direction_right then
        r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_SelectableTextAlign(), 1, 0.5)
    end
   
    local items = tbl or {}
    for i = 1, #items do
        r.ImGui_PushStyleVar(ctx, reaper.ImGui_StyleVar_WindowRounding(), 7)
        r.ImGui_PushStyleVar(ctx, reaper.ImGui_StyleVar_FrameRounding(), 3)      
        r.ImGui_PushStyleColor(ctx, reaper.ImGui_Col_PopupBg(), config.background_color)
        r.ImGui_SetNextWindowBgAlpha(ctx, config.window_alpha)
        r.ImGui_SetNextWindowSize(ctx, FX_LIST_WIDTH, 0)
       
        if r.ImGui_BeginMenu(ctx, tbl[i].name) then
            if main_cat_name == "FOLDERS" then
                local pinned = {}
                local favorites = {}
                local regular = {}
                local all_unpinned = {}
           
                for j = 1, #tbl[i].fx do
                    local name = tbl[i].fx[j]
                    if pinned_set[name] then
                        table.insert(pinned, {index = j, name = name})
                    elseif favorite_set[name] then
                        table.insert(favorites, {index = j, name = name})
                        table.insert(all_unpinned, {index = j, name = name})
                    else
                        table.insert(regular, {index = j, name = name})
                        table.insert(all_unpinned, {index = j, name = name})
                    end
                end
           
                -- Sorteer helpers voor popuplijsten
                local function sort_group(group)
                    table.sort(group, function(a, b)
                        if config.sort_mode == "rating" then
                            local ra = plugin_ratings[a.name] or 0
                            local rb = plugin_ratings[b.name] or 0
                            if ra == rb then
                                return a.name:lower() < b.name:lower()
                            else
                                return ra > rb
                            end
                        else
                            return a.name:lower() < b.name:lower()
                        end
                    end)
                end

                sort_group(pinned)
                if config.show_favorites_on_top then
                    sort_group(favorites)
                    sort_group(regular)
                else
                    sort_group(all_unpinned)
                end

                local plugins_to_show
                if config.show_favorites_on_top then
                    plugins_to_show = {
                        {key = "pinned", list = pinned},
                        {key = "favorites", list = favorites},
                        {key = "regular", list = regular},
                    }
                else
                    plugins_to_show = {
                        {key = "pinned", list = pinned},
                        {key = "others", list = all_unpinned},
                    }
                end
       
                for group_idx, group in ipairs(plugins_to_show) do
                    local plugin_group = group.list
                    for _, plugin in ipairs(plugin_group) do
                        local list_display = GetDisplayPluginName(plugin.name)
                        if r.ImGui_Selectable(ctx, list_display .. "  " .. GetStarsString(plugin.name) .. "##plugin_list_" .. i .. "_" .. plugin.index) then
                            if ADD_FX_TO_ITEM then
                                AddFXToItem(plugin.name)
                            else
                                if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                                    local fx_index = AddFXToTrack(TRACK, plugin.name)
                                    
                                    -- OPEN FLOATING ALS OPTIE ENABLED IS
                                    if config.open_floating_after_adding and fx_index >= 0 then
                                        r.TrackFX_Show(TRACK, fx_index, 3) -- 3 = open floating
                                    end
                                end
                            end
                            LAST_USED_FX = plugin.name
                            if config.close_after_adding_fx and not IS_COPYING_TO_ALL_TRACKS then
                                SHOULD_CLOSE_SCRIPT = true
                            end
                        end
                        if r.ImGui_IsItemHovered(ctx) then
                            if plugin.name ~= current_hovered_plugin then
                                current_hovered_plugin = plugin.name
                                LoadPluginScreenshot(current_hovered_plugin)
                            end
                            is_screenshot_visible = true
                        end
                       
                        ShowPluginContextMenu(plugin.name, "folders_" .. i .. "_" .. plugin.index)
                    end
                    -- separators between groups
                    if group.key == "pinned" and #plugin_group > 0 then
                        -- show pinned end if any following group has items
                        local has_following = false
                        for k = group_idx + 1, #plugins_to_show do
                            if #plugins_to_show[k].list > 0 then has_following = true break end
                        end
                        if has_following then
                            if r.ImGui_Selectable(ctx, "--Pinned End--", false, r.ImGui_SelectableFlags_Disabled()) then end
                        end
                    elseif group.key == "favorites" and #favorites > 0 and #regular > 0 then
                        if r.ImGui_Selectable(ctx, "--Favorites End--", false, r.ImGui_SelectableFlags_Disabled()) then end
                    end
                end
            else
                if tbl[i] and tbl[i].fx then
                    -- Bouw entries met display- en originele naam, met pinned eerst
                    local pinned_entries = {}
                    local other_entries = {}
                    for j = 1, #tbl[i].fx do
                        local original = tbl[i].fx[j]
                        if original then
                            local name_for_display = original
                            if main_cat_name == "ALL PLUGINS" and tbl[i].name ~= "INSTRUMENTS" then
                                name_for_display = name_for_display:gsub("^(%S+:)", "")
                            elseif main_cat_name == "DEVELOPER" then
                                name_for_display = name_for_display:gsub(' %(' .. Literalize(tbl[i].name) .. '%)', "")
                            end
                            local cat_display = GetDisplayPluginName(name_for_display)
                            local entry = { display = cat_display, original = original, index = j }
                            if pinned_set[original] then table.insert(pinned_entries, entry) else table.insert(other_entries, entry) end
                        end
                    end

                    local function sort_entries(entries)
                        table.sort(entries, function(a, b)
                        if config.sort_mode == "rating" then
                            local ra = plugin_ratings[a.original] or 0
                            local rb = plugin_ratings[b.original] or 0
                            if ra == rb then
                                return a.display:lower() < b.display:lower()
                            else
                                return ra > rb
                            end
                        else
                            return a.display:lower() < b.display:lower()
                        end
                    end)
                    end
                    sort_entries(pinned_entries)
                    sort_entries(other_entries)

                    for _, e in ipairs(pinned_entries) do
                        if r.ImGui_Selectable(ctx, e.display .. "  " .. GetStarsString(e.original) .. "##plugin_list_" .. i .. "_" .. e.index) then
                            if ADD_FX_TO_ITEM then
                                AddFXToItem(e.original)
                            else
                                if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                                    local fx_index = AddFXToTrack(TRACK, e.original)
                                    if config.open_floating_after_adding and fx_index >= 0 then
                                        r.TrackFX_Show(TRACK, fx_index, 3)
                                    end
                                end
                            end
                            LAST_USED_FX = e.original
                            if config.close_after_adding_fx and not IS_COPYING_TO_ALL_TRACKS then
                                SHOULD_CLOSE_SCRIPT = true
                            end
                        end
                        if r.ImGui_IsItemHovered(ctx) then
                            if e.original ~= current_hovered_plugin then
                                current_hovered_plugin = e.original
                                LoadPluginScreenshot(current_hovered_plugin)
                            end
                            is_screenshot_visible = true
                        end
                        ShowPluginContextMenu(e.original, "category_" .. i .. "_" .. e.index)
                    end
                    -- Separator if we also have others
                    if #pinned_entries > 0 and #other_entries > 0 then
                        if r.ImGui_Selectable(ctx, "--Pinned End--", false, r.ImGui_SelectableFlags_Disabled()) then end
                    end
                    for _, e in ipairs(other_entries) do
                        if r.ImGui_Selectable(ctx, e.display .. "  " .. GetStarsString(e.original) .. "##plugin_list_" .. i .. "_" .. e.index) then
                            if ADD_FX_TO_ITEM then
                                AddFXToItem(e.original)
                            else
                                if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                                    local fx_index = AddFXToTrack(TRACK, e.original)
                                    if config.open_floating_after_adding and fx_index >= 0 then
                                        r.TrackFX_Show(TRACK, fx_index, 3)
                                    end
                                end
                            end
                            LAST_USED_FX = e.original
                            if config.close_after_adding_fx and not IS_COPYING_TO_ALL_TRACKS then
                                SHOULD_CLOSE_SCRIPT = true
                            end
                        end
                        if r.ImGui_IsItemHovered(ctx) then
                            if e.original ~= current_hovered_plugin then
                                current_hovered_plugin = e.original
                                LoadPluginScreenshot(current_hovered_plugin)
                            end
                            is_screenshot_visible = true
                        end
                        ShowPluginContextMenu(e.original, "category_" .. i .. "_" .. e.index)
                    end
                end
            end
           
            if not r.ImGui_IsAnyItemHovered(ctx) and not r.ImGui_IsPopupOpen(ctx, "", r.ImGui_PopupFlags_AnyPopupId()) then
                r.ImGui_CloseCurrentPopup(ctx)
            end
           
            r.ImGui_EndMenu(ctx)
        end
       
        reaper.ImGui_PopStyleVar(ctx, 2)
        reaper.ImGui_PopStyleColor(ctx)
    end
   
    if menu_direction_right then
        r.ImGui_PopStyleVar(ctx)
    end
end

function DrawFavorites()
    -- Pinned-first ordering inside the favorites menu (if enabled)
    local pinned, others = {}, {}
    for _, fav in ipairs(favorite_plugins) do
        if pinned_set[fav] then pinned[#pinned+1] = fav else others[#others+1] = fav end
    end
    SortPlainPluginList(pinned, config.sort_mode)
    SortPlainPluginList(others, config.sort_mode)
    local merged = {}
    
    -- Add pinned plugins first if show_pinned_on_top is enabled
    if config and config.show_pinned_on_top then
        for _, p in ipairs(pinned) do merged[#merged+1] = p end
        if #pinned>0 and #others>0 then merged[#merged+1] = "--Pinned End--" end
    else
        -- Add pinned plugins to others if show_pinned_on_top is disabled
        for _, p in ipairs(pinned) do others[#others+1] = p end
        SortPlainPluginList(others, config.sort_mode)
    end
    
    for _, p in ipairs(others) do merged[#merged+1] = p end

    for i, fav in ipairs(merged) do
        if fav == "--Pinned End--" then
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
            r.ImGui_Text(ctx, "--- Pinned End ---")
            r.ImGui_PopStyleColor(ctx)
        else
            local fav_display_global = GetDisplayPluginName(fav)
            if r.ImGui_Selectable(ctx, fav_display_global .. "  " .. GetStarsString(fav) .. "##favorites_" .. i) then
            if TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
                local fx_index = AddFXToTrack(TRACK, fav)
                
                -- OPEN FLOATING ALS OPTIE ENABLED IS
                if config.open_floating_after_adding and fx_index >= 0 then
                    r.TrackFX_Show(TRACK, fx_index, 3) -- 3 = open floating
                end
            end
            LAST_USED_FX = fav
            if config.close_after_adding_fx and not IS_COPYING_TO_ALL_TRACKS then
                SHOULD_CLOSE_SCRIPT = true
            end
            end
   
            if r.ImGui_IsItemHovered(ctx) then
                if fav ~= current_hovered_plugin then
                    current_hovered_plugin = fav
                    LoadPluginScreenshot(current_hovered_plugin)
                end
                is_screenshot_visible = true
            end
            ShowPluginContextMenu(fav, "favorites_" .. i)
        end
    end
    if not r.ImGui_IsWindowHovered(ctx) then
        is_screenshot_visible = false
        current_hovered_plugin = nil
        
    end
end

function CalculateButtonWidths(total_width, num_buttons, spacing)
    local available_width = total_width - (spacing * (num_buttons - 1))
    return available_width / num_buttons
end

function DrawBottomButtons()
    if not config.hideBottomButtons then
    if not TRACK or not reaper.ValidatePtr(TRACK, "MediaTrack*") then return end
    local window_width = r.ImGui_GetWindowWidth(ctx)
    local track_info_width = math.max(window_width - 10, 125)
    local button_spacing = 3
    local windowHeight = r.ImGui_GetWindowHeight(ctx)
    local buttonHeight = 65
    r.ImGui_SetCursorPosY(ctx, windowHeight - buttonHeight - 42)
    -- volumeslider
    if not config.hideVolumeSlider then
        local half_width = (track_info_width - button_spacing) / 2
      
        -- Pan slider met context menu
        r.ImGui_PushItemWidth(ctx, half_width)
        local pan_mode = r.GetMediaTrackInfo_Value(TRACK, "I_PANMODE")

        if pan_mode == 6 then -- Dual Pan mode
            -- Linker pan slider
            r.ImGui_PushItemWidth(ctx, half_width/2 - 2)
            local pan_L = r.GetMediaTrackInfo_Value(TRACK, "D_DUALPANL")
            local pan_L_changed, new_pan_L = r.ImGui_SliderDouble(ctx, "##PanL", pan_L, -1, 1, "L: %.2f")
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "PanModeMenu")
            end
            
            if pan_L_changed then
                r.SetMediaTrackInfo_Value(TRACK, "D_DUALPANL", new_pan_L)
            end
            
            -- Rechter pan slider
            r.ImGui_SameLine(ctx)
            r.ImGui_PushItemWidth(ctx, half_width/2 - 2)
            local pan_R = r.GetMediaTrackInfo_Value(TRACK, "D_DUALPANR")
            local pan_R_changed, new_pan_R = r.ImGui_SliderDouble(ctx, "##PanR", pan_R, -1, 1, "R: %.2f")
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "PanModeMenu")
            end
            if pan_R_changed then
                r.SetMediaTrackInfo_Value(TRACK, "D_DUALPANR", new_pan_R)
            end
        else
            -- Normale pan slider
            local pan = r.GetMediaTrackInfo_Value(TRACK, "D_PAN")
            local pan_changed, new_pan = r.ImGui_SliderDouble(ctx, "##Pan", pan, -1, 1, "Pan: %.2f")
            if r.ImGui_IsItemClicked(ctx, 1) then
                r.ImGui_OpenPopup(ctx, "PanModeMenu")
            end
            if pan_changed then
                r.SetMediaTrackInfo_Value(TRACK, "D_PAN", new_pan)
            end
        end

        if r.ImGui_BeginPopup(ctx, "PanModeMenu") then
            if r.ImGui_MenuItem(ctx, "Reset Pan") then
                if pan_mode == 6 then
                    r.SetMediaTrackInfo_Value(TRACK, "D_DUALPANL", 0.0)
                    r.SetMediaTrackInfo_Value(TRACK, "D_DUALPANR", 0.0)
                else
                    r.SetMediaTrackInfo_Value(TRACK, "D_PAN", 0.0)
                end
            end
            if r.ImGui_MenuItem(ctx, "Stereo Pan") then
                r.Main_OnCommand(r.NamedCommandLookup("_SWS_AWPANSTEREOPAN"), 0)
            end
            if r.ImGui_MenuItem(ctx, "Stereo Balance") then
                r.Main_OnCommand(r.NamedCommandLookup("_SWS_AWPANBALANCENEW"), 0)
            end
            if r.ImGui_MenuItem(ctx, "Dual Pan") then
                r.Main_OnCommand(r.NamedCommandLookup("_SWS_AWPANDUALPAN"), 0)
            end
            if r.ImGui_MenuItem(ctx, "3x Balance") then
                r.Main_OnCommand(r.NamedCommandLookup("_SWS_AWPANBALANCEOLD"), 0)
            end
            r.ImGui_EndPopup(ctx)
        end

        -- Width slider
        r.ImGui_SameLine(ctx)
        r.ImGui_PushItemWidth(ctx, half_width)
        local width = r.GetMediaTrackInfo_Value(TRACK, "D_WIDTH")
        local display_width = width * 100
        local width_changed, new_width = r.ImGui_SliderDouble(ctx, "##Width", display_width, -100, 100, "Width: %.0f%%")
        if r.ImGui_IsItemClicked(ctx, 1) then  -- rechtsklik
            r.SetMediaTrackInfo_Value(TRACK, "D_WIDTH", 1.0)  -- reset naar 100%
        end
        if width_changed then
            r.SetMediaTrackInfo_Value(TRACK, "D_WIDTH", new_width / 100)
        end
        
        -- volume slider
        local volume = r.GetMediaTrackInfo_Value(TRACK, "D_VOL")
        if volume and volume > 0 then
            local volume_db = math.floor(20 * math.log(volume, 10) + 0.5)
            r.ImGui_PushItemWidth(ctx, track_info_width)
            
            local changed, new_volume_db = r.ImGui_SliderInt(ctx, "##Volume", volume_db, -60, 12, "%d dB")
    
            if r.ImGui_IsItemHovered(ctx) then
                r.ImGui_SetTooltip(ctx, "Rightclick 0db /double Rightclick -12db")
                if r.ImGui_IsMouseDoubleClicked(ctx, 1) then
                    new_volume_db = -12
                    changed = true
                elseif r.ImGui_IsMouseClicked(ctx, 1) then
                    new_volume_db = 0
                    changed = true
                end
            end
    
            if changed then
                local new_volume = 10^(new_volume_db/20)
                r.SetMediaTrackInfo_Value(TRACK, "D_VOL", new_volume)
            end
            r.ImGui_PopItemWidth(ctx)
        end
    end
    r.ImGui_PushFont(ctx, NormalFont, config.font_size - 1)
    r.ImGui_SetCursorPosY(ctx, windowHeight - buttonHeight)
    -- Eerste rij knoppen
    local num_buttons_row1 = 3
    local button_width_row1 = CalculateButtonWidths(track_info_width, num_buttons_row1, button_spacing)
    if r.ImGui_Button(ctx, "FXCH", button_width_row1) then
        CreateFXChain()
    end
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Make FXChain from Plugins on selected Track")
    end
    r.ImGui_SameLine(ctx, 0, button_spacing)
    if r.ImGui_Button(ctx, "COPY", button_width_row1) then
        r.Main_OnCommand(r.NamedCommandLookup("_S&M_SMART_CPY_FXCHAIN"), 0)
    end
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Copy All FX on the Selected Track")
    end
    r.ImGui_SameLine(ctx, 0, button_spacing)
    if r.ImGui_Button(ctx, "PASTE", button_width_row1) then
        r.Main_OnCommand(r.NamedCommandLookup("_S&M_SMART_PST_FXCHAIN"), 0)
    end
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Paste All FX to The selected Track")
    end
    
    -- Tweede rij knoppen
    local num_buttons_row2 = 3
    local button_width_row2 = CalculateButtonWidths(track_info_width, num_buttons_row2, button_spacing)
    local bypass_state = r.GetMediaTrackInfo_Value(TRACK, "I_FXEN") == 0
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), bypass_state and 0x0080FFFF or config.button_background_color)
    if r.ImGui_Button(ctx, "BYPASS", button_width_row2) then
        local new_state = bypass_state and 1 or 0
        r.SetMediaTrackInfo_Value(TRACK, "I_FXEN", new_state)
    end
    r.ImGui_PopStyleColor(ctx)
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "ByPass All FX on the selected Track")
    end
    r.ImGui_SameLine(ctx, 0, button_spacing)
    if r.ImGui_Button(ctx, "SNAP", button_width_row2) then
        r.ImGui_OpenPopup(ctx, "SnapConfirmation")
    end
    if r.ImGui_BeginPopup(ctx, "SnapConfirmation") then
        r.ImGui_Text(ctx, "Open first FX on track (floating) and click OK")
        if r.ImGui_Button(ctx, "OK") then
            CaptureFirstTrackFX()
            ClearScreenshotCache()
            BuildScreenshotIndex(true)
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel") then
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end
    
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Make screenshot of First FX on the selected Track (must be floating)")
    end  
    r.ImGui_SameLine(ctx, 0, button_spacing)
    local vkb_active = r.GetToggleCommandStateEx(0, 40377)
    if vkb_active == 1 then
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), 0x0080FFFF)
    else
        r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), config.button_background_color)
    end
    if r.ImGui_Button(ctx, "VKB", button_width_row2) then
        r.Main_OnCommand(40377, 0)
    end
    r.ImGui_PopStyleColor(ctx)
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Show Virtual Keyboard")
    end

    -- Derde rij knoppen
    local num_buttons_row3 = 3
    local button_width_row3 = CalculateButtonWidths(track_info_width, num_buttons_row3, button_spacing)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), IsMuted(TRACK) and 0xFF0000FF or config.button_background_color)
    if r.ImGui_Button(ctx, "MUTE", button_width_row3) then
    ToggleMute(TRACK)
    end
    r.ImGui_PopStyleColor(ctx)
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Mute selected Track")
    end
    r.ImGui_SameLine(ctx, 0, button_spacing)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), IsSoloed(TRACK) and 0xFFFF00FF or config.button_background_color)
    if r.ImGui_Button(ctx, "SOLO", button_width_row3) then
    ToggleSolo(TRACK)
    end
    r.ImGui_PopStyleColor(ctx)
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Solo selected Track")
    end
    r.ImGui_SameLine(ctx, 0, button_spacing)
    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), IsArmed(TRACK) and 0xFF0000FF or config.button_background_color)
    if r.ImGui_Button(ctx, "ARM", button_width_row3) then
    ToggleArm(TRACK)
    end
    r.ImGui_PopFont(ctx)
    r.ImGui_PopStyleColor(ctx)
    if config.show_tooltips and r.ImGui_IsItemHovered(ctx) then
        r.ImGui_SetTooltip(ctx, "Arm selected Track")
    end
    
    end
end

function ShowTrackFX()
    if not TRACK or not reaper.ValidatePtr(TRACK, "MediaTrack*") then
        r.ImGui_Text(ctx, "No track selected")
        return
    end
    local fx_list_height = (config.fx_track_list_height and config.fx_track_list_height > 40) and config.fx_track_list_height or 260
    local track_fxlist_open = r.ImGui_BeginChild(ctx, "TrackFXList", -1, fx_list_height)
    if track_fxlist_open then
        r.ImGui_Dummy(ctx, 0, 5)
        r.ImGui_Text(ctx, "FX on Track:")
        local fx_count = r.TrackFX_GetCount(TRACK)
        if fx_count > 0 then
            local track_bypassed = r.GetMediaTrackInfo_Value(TRACK, "I_FXEN") == 0
            for i = 0, fx_count - 1 do
                local retval, fx_name = r.TrackFX_GetFXName(TRACK, i, "")
                local is_open = r.TrackFX_GetFloatingWindow(TRACK, i)
                local is_enabled = r.TrackFX_GetEnabled(TRACK, i)                
                local display_name = is_enabled and fx_name or fx_name .. " (Bypassed)"                
                r.ImGui_PushID(ctx, i)
                if not is_enabled or track_bypassed then
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
                end
                if r.ImGui_Selectable(ctx, display_name .. "##trackfx_" .. i) then
                    if is_open then
                        r.TrackFX_Show(TRACK, i, 2)
                    else
                        r.TrackFX_Show(TRACK, i, 3)
                    end
                end
                if not is_enabled or track_bypassed then
                    r.ImGui_PopStyleColor(ctx)
                end
                if r.ImGui_BeginDragDropSource(ctx, r.ImGui_DragDropFlags_None()) then
                    r.ImGui_SetDragDropPayload(ctx, "MAIN_TRACKFX_DRAG", tostring(i))
                    r.ImGui_Text(ctx, fx_name)
                    r.ImGui_EndDragDropSource(ctx)
                end
                if r.ImGui_BeginDragDropTarget(ctx) then
                    local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "MAIN_TRACKFX_DRAG")
                    if rv then
                        local src = tonumber(payload)
                        if src and src ~= i then
                            local dest = i
                            if src < dest then dest = dest + 1 end
                            r.Undo_BeginBlock()
                            r.TrackFX_CopyToTrack(TRACK, src, TRACK, dest, true)
                            r.Undo_EndBlock("Reorder Track FX", -1)
                        end
                    end
                    r.ImGui_EndDragDropTarget(ctx)
                end

                if r.ImGui_IsItemClicked(ctx, 1) then
                    r.ImGui_OpenPopup(ctx, "TrackFXCtx_" .. i)
                end
                if r.ImGui_BeginPopup(ctx, "TrackFXCtx_" .. i) then
                    if r.ImGui_MenuItem(ctx, "Delete") then
                        r.TrackFX_Delete(TRACK, i)
                        if config.selected_folder == "Current Track FX" or config.selected_folder == "Current Project FX" then
                            RefreshCurrentScreenshotView()
                        end
                    end
                    if r.ImGui_MenuItem(ctx, "Copy to all tracks") then
                        IS_COPYING_TO_ALL_TRACKS = true
                        local track_count = r.CountTracks(0)
                        for j = 0, track_count - 1 do
                            local target_track = r.GetTrack(0, j)
                            if target_track ~= TRACK then
                                r.TrackFX_CopyToTrack(TRACK, i, target_track, r.TrackFX_GetCount(target_track), false)
                            end
                        end
                        IS_COPYING_TO_ALL_TRACKS = false
                    end
                    if r.ImGui_MenuItem(ctx, "Copy Plugin") then
                        copied_plugin = {track = TRACK, index = i}
                    end                    
                    if r.ImGui_MenuItem(ctx, "Paste Plugin", nil, copied_plugin ~= nil) then
                        if copied_plugin then
                            local _, orig_name = r.TrackFX_GetFXName(copied_plugin.track, copied_plugin.index, "")
                            AddFXToTrack(TRACK, orig_name)
                        end
                    end                   
                    if r.ImGui_MenuItem(ctx, is_enabled and "Bypass plugin" or "Unbypass plugin") then
                        r.TrackFX_SetEnabled(TRACK, i, not is_enabled)
                    end
                    if favorite_set[fx_name] then
                        if r.ImGui_MenuItem(ctx, "Remove from Favorites") then
                            RemoveFromFavorites(fx_name)
                        end
                    else
                        if r.ImGui_MenuItem(ctx, "Add to Favorites") then
                            AddToFavorites(fx_name)
                        end
                    end
                    r.ImGui_EndPopup(ctx)
                end
                r.ImGui_PopID(ctx)
            end
        else
            r.ImGui_Text(ctx, "No FX on Track")
        end
        if copied_plugin then
            local is_empty_track = fx_count == 0
            local button_text = is_empty_track and "Paste Plugin" or "Paste Plugin at End"
            if r.ImGui_Button(ctx, button_text) then
                local _, orig_name = r.TrackFX_GetFXName(copied_plugin.track, copied_plugin.index, "")
                local insert_position = is_empty_track and 0 or fx_count
                r.TrackFX_CopyToTrack(copied_plugin.track, copied_plugin.index, TRACK, insert_position, false)
            end        
            if r.ImGui_IsItemClicked(ctx, 1) then  -- Rechtermuisklik
                r.ImGui_OpenPopup(ctx, "PastePluginMenu")
            end      
            if r.ImGui_BeginPopup(ctx, "PastePluginMenu") then
                if r.ImGui_MenuItem(ctx, "Paste Plugin at Beginning") then
                    local _, orig_name = r.TrackFX_GetFXName(copied_plugin.track, copied_plugin.index, "")
                    r.TrackFX_CopyToTrack(copied_plugin.track, copied_plugin.index, TRACK, 0, false)
                end
                r.ImGui_EndPopup(ctx)
            end
        end       
    end
    r.ImGui_EndChild(ctx)
end

function ShowItemFX()
    local item = r.GetSelectedMediaItem(0, 0)
    if not item then return end
    local take = r.GetActiveTake(item)
    if not take then return end

    local min_height = r.ImGui_GetCursorPosY(ctx)
    local window_height = r.ImGui_GetWindowHeight(ctx)
    local available_height = window_height - r.ImGui_GetCursorPosY(ctx)
    local fx_list_height = available_height - 25

    local item_fxlist_open = r.ImGui_BeginChild(ctx, "ItemFXList", -1, fx_list_height)
    if item_fxlist_open then
        r.ImGui_Dummy(ctx, 0, 5)
        r.ImGui_Text(ctx, "FX on Item:")
        local fx_count = r.TakeFX_GetCount(take)
        if fx_count > 0 then
            for i = 0, fx_count - 1 do
                local retval, fx_name = r.TakeFX_GetFXName(take, i, "")
                local is_open = r.TakeFX_GetFloatingWindow(take, i)
                local is_enabled = r.TakeFX_GetEnabled(take, i)
                local display_name = is_enabled and fx_name or fx_name .. " (Bypassed)"

                r.ImGui_PushID(ctx, i)
                if not is_enabled then
                    r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), 0x808080FF)
                end
                if r.ImGui_Selectable(ctx, display_name .. "##itemfx_" .. i) then
                    if is_open then
                        r.TakeFX_Show(take, i, 2)
                    else
                        r.TakeFX_Show(take, i, 3)
                    end
                end
                if not is_enabled then
                    r.ImGui_PopStyleColor(ctx)
                end
                if r.ImGui_BeginDragDropSource(ctx, r.ImGui_DragDropFlags_None()) then
                    r.ImGui_SetDragDropPayload(ctx, "MAIN_ITEMFX_DRAG", tostring(i))
                    r.ImGui_Text(ctx, fx_name)
                    r.ImGui_EndDragDropSource(ctx)
                end
                if r.ImGui_BeginDragDropTarget(ctx) then
                    local rv, payload = r.ImGui_AcceptDragDropPayload(ctx, "MAIN_ITEMFX_DRAG")
                    if rv then
                        local src = tonumber(payload)
                        if src and src ~= i then
                            local dest = i
                            if src < dest then dest = dest + 1 end
                            r.Undo_BeginBlock()
                            r.TakeFX_CopyToTake(take, src, take, dest, true)
                            r.Undo_EndBlock("Reorder Item FX", -1)
                        end
                    end
                    r.ImGui_EndDragDropTarget(ctx)
                end
                if r.ImGui_IsItemClicked(ctx, 1) then
                    r.ImGui_OpenPopup(ctx, "ItemFXCtx_" .. i)
                end
                if r.ImGui_BeginPopup(ctx, "ItemFXCtx_" .. i) then
                    if r.ImGui_MenuItem(ctx, "Delete") then
                        r.TakeFX_Delete(take, i)
                    end
                    if r.ImGui_MenuItem(ctx, "Copy Plugin") then
                        copied_plugin = {take = take, index = i}
                    end
                    if r.ImGui_MenuItem(ctx, "Paste Plugin", nil, copied_plugin ~= nil) then
                        if copied_plugin then
                            local _, orig_name = r.TakeFX_GetFXName(copied_plugin.take, copied_plugin.index, "")
                            r.TakeFX_AddByName(take, orig_name, -1000)
                        end
                    end
                    if r.ImGui_MenuItem(ctx, is_enabled and "Bypass plugin" or "Unbypass plugin") then
                        r.TakeFX_SetEnabled(take, i, not is_enabled)
                    end
                    r.ImGui_EndPopup(ctx)
                end
                r.ImGui_PopID(ctx)
            end
        else
            r.ImGui_Text(ctx, "No FX on Item")
        end

        if copied_plugin then
            local is_empty = fx_count == 0
            local button_text = is_empty and "Paste Plugin" or "Paste Plugin at End"
            if r.ImGui_Button(ctx, button_text) then
                local _, orig_name = r.TakeFX_GetFXName(copied_plugin.take, copied_plugin.index, "")
                local insert_position = is_empty and 0 or fx_count
                r.TakeFX_CopyToTake(copied_plugin.take, copied_plugin.index, take, insert_position, false)
            end
        end
    end
    r.ImGui_EndChild(ctx)
end


function GetTrackType(track)
    if not track or not reaper.ValidatePtr(track, "MediaTrack*") then
        return "No Track"
    end
    if track == r.GetMasterTrack(0) then return "Master" end
    local audio_count = 0
    local midi_count = 0
    local is_folder = r.GetMediaTrackInfo_Value(track, "I_FOLDERDEPTH") > 0
    local is_child = r.GetParentTrack(track) ~= nil
    local item_count = r.CountTrackMediaItems(track)
    for i = 0, item_count - 1 do
        local item = r.GetTrackMediaItem(track, i)
        local take = r.GetActiveTake(item)
        if take then
            if r.TakeIsMIDI(take) then
                midi_count = midi_count + 1
            else
                audio_count = audio_count + 1
            end
        end
    end
    local track_type = ""
    if is_folder then
        track_type = "Folder "
    elseif is_child then
        track_type = "Child "
    end
    if audio_count > 0 and midi_count > 0 then
        return track_type .. "Mixed"
    elseif midi_count > 0 then
        return track_type .. "MIDI"
    elseif audio_count > 0 then
        return track_type .. "Audio"
    else
        return track_type .. "Empty"
    end
end

