function EnsureWindowVisible()
    if config.hide_main_window then
        if not was_hidden then
            was_docked_before_hide = (dock and dock ~= 0)
        end
        config.dock_screenshot_window = false
        config.show_screenshot_window = true
        was_hidden = true
    else
        if was_hidden then
            -- Only restore position/size if window was NOT docked before hiding
            if not was_docked_before_hide then
                local viewport = r.ImGui_GetMainViewport(ctx)
                local vp_x, vp_y = r.ImGui_Viewport_GetPos(viewport)
                local vp_w, vp_h = r.ImGui_Viewport_GetWorkSize(viewport)
                
                local window_w = 200
                local window_h = 600
                local center_x = vp_x + (vp_w - window_w) * 0.5
                local center_y = vp_y + (vp_h - window_h) * 0.5
                
                r.ImGui_SetNextWindowPos(ctx, center_x, center_y, r.ImGui_Cond_Always())
                r.ImGui_SetNextWindowSize(ctx, window_w, window_h, r.ImGui_Cond_Always())
            end
            -- If it was docked, let ImGui restore the docking automatically
            
            was_hidden = false
            was_docked_before_hide = false
        end
    end
end

-- Centralized drag & drop handling function
function HandleDragAndDrop()
    if config.enable_drag_add_fx and dragging_fx_name then
        local pubs = GetDraggedPluginNames() or { dragging_fx_name }
        if #pubs == 0 then pubs = { dragging_fx_name } end
        r.SetExtState("TKFXB", "drag_fx", table.concat(pubs, "\n"), false)
    elseif r.HasExtState("TKFXB", "drag_fx") then
        r.DeleteExtState("TKFXB", "drag_fx", false)
    end
    if r.ImGui_IsMouseDoubleClicked(ctx, 0) then
        dragging_fx_name = nil
        potential_drag_fx_name = nil
        if r.HasExtState("TKFXB", "drag_fx") then r.DeleteExtState("TKFXB", "drag_fx", false) end
        return
    end
    if config.enable_drag_add_fx and dragging_fx_name and r.ImGui_IsMouseReleased(ctx,0) then
        if r.GetExtState("TKFXB", "drag_consumed") == "1" then
            r.DeleteExtState("TKFXB", "drag_consumed", false)
            r.DeleteExtState("TKFXB", "drag_fx", false)
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            drag_drop_target_folder = nil
            chain_builder_hovered = false
            info_trackfx_drop_hovered = false
            info_itemfx_drop_hovered = false
            info_inputfx_drop_hovered = false
            return
        end
        local mix_target = r.GetExtState("TKMIX", "rack_target")
        if mix_target and mix_target ~= "" then
            local guid, idx_str = mix_target:match("^(.-)|(%-?%d+)$")
            local insert_idx = tonumber(idx_str or "")
            local target_track = nil
            if guid and guid ~= "" then
                local cnt = r.CountTracks(0)
                for ti = 0, cnt - 1 do
                    local t = r.GetTrack(0, ti)
                    if r.GetTrackGUID(t) == guid then target_track = t break end
                end
            end
            if target_track and insert_idx then
                local plugins = GetDraggedPluginNames()
                if plugins and #plugins > 0 then
                    r.Undo_BeginBlock()
                    for k, pname in ipairs(plugins) do
                        if insert_idx < 0 then
                            r.TrackFX_AddByName(target_track, pname, false, -1)
                        else
                            r.TrackFX_AddByName(target_track, pname, false, -1000 - (insert_idx + k - 1))
                        end
                        LAST_USED_FX = pname
                    end
                    r.Undo_EndBlock("Add FX to Mixer Rack", -1)
                end
            end
            r.DeleteExtState("TKMIX", "rack_target", false)
            r.DeleteExtState("TKFXB", "drag_fx", false)
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            drag_drop_target_folder = nil
            chain_builder_hovered = false
            info_trackfx_drop_hovered = false
            info_itemfx_drop_hovered = false
            info_inputfx_drop_hovered = false
            return
        end
        if drag_drop_target_folder then
            local plugins = GetDraggedPluginNames()
            if drag_drop_target_folder.type == "custom" then
                AddPluginsToCustomFolderByPath(drag_drop_target_folder.path, plugins)
            elseif drag_drop_target_folder.type == "native" then
                local nf = GetNativeFolderNames()
                local folder_idx = nil
                for _, entry in ipairs(nf) do
                    if entry.name == drag_drop_target_folder.path then folder_idx = entry.idx break end
                end
                if folder_idx then
                    local added = 0
                    for _, pname in ipairs(plugins) do
                        if AddPluginToNativeFolder(folder_idx, pname) then
                            added = added + 1
                        end
                    end
                    if added > 0 then
                        RefreshAfterNativeFolderChange()
                    else
                        InvalidateNativeFolderCache()
                    end
                end
            end
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            drag_drop_target_folder = nil
            return
        end
        local plugins = GetDraggedPluginNames()
        if config.show_chain_builder and chain_builder_hovered then
            for _, pname in ipairs(plugins) do
                table.insert(chain_builder_plugins, pname)
                chain_builder_chunks[#chain_builder_plugins] = false
            end
            config.chain_builder_plugins = chain_builder_plugins
            SaveConfig()
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            chain_builder_hovered = false
            return
        end
        if info_trackfx_drop_hovered and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            r.Undo_BeginBlock()
            for _, pname in ipairs(plugins) do
                AddFXToTrack(TRACK, pname)
                LAST_USED_FX = pname
            end
            r.Undo_EndBlock("Add FX to Track", -1)
            if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            info_trackfx_drop_hovered = false
            return
        end
        if info_itemfx_drop_hovered then
            local item = r.GetSelectedMediaItem(0, 0)
            if item then
                local take = r.GetActiveTake(item)
                if take then
                    r.Undo_BeginBlock()
                    for _, pname in ipairs(plugins) do
                        r.TakeFX_AddByName(take, pname, 1)
                        LAST_USED_FX = pname
                    end
                    r.Undo_EndBlock("Add FX to Item", -1)
                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                    if config.hide_after_insert then SHOULD_HIDE_BROWSER = true end
                end
            end
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            info_itemfx_drop_hovered = false
            return
        end
        if info_inputfx_drop_hovered and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            r.Undo_BeginBlock()
            for _, pname in ipairs(plugins) do
                r.TrackFX_AddByName(TRACK, pname, true, -1)
                LAST_USED_FX = pname
            end
            r.Undo_EndBlock("Add FX to Input FX", -1)
            if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            if config.hide_after_insert then SHOULD_HIDE_BROWSER = true end
            dragging_fx_name = nil
            potential_drag_fx_name = nil
            info_inputfx_drop_hovered = false
            return
        end
        local shift = r.ImGui_IsKeyDown(ctx, r.ImGui_Key_LeftShift()) or r.ImGui_IsKeyDown(ctx, r.ImGui_Key_RightShift())
        if shift then
            local sx, sy = r.GetMousePosition()
            local item = r.GetItemFromPoint and r.GetItemFromPoint(sx, sy, false) or nil
            if item then
                local take = r.GetActiveTake(item)
                if take then
                    r.Undo_BeginBlock()
                    for _, pname in ipairs(plugins) do
                        r.TakeFX_AddByName(take, pname, 1)
                        LAST_USED_FX = pname
                    end
                    r.Undo_EndBlock("Add FX to Item", -1)
                    if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
                    if config.hide_after_insert then SHOULD_HIDE_BROWSER = true end
                end
            end
        else
            local sx, sy = r.GetMousePosition()
            local track = select(1, r.GetTrackFromPoint(sx, sy))
            if track then
                local last_fx_index = nil
                for _, pname in ipairs(plugins) do
                    local fx_index = AddFXToTrack(track, pname)
                    LAST_USED_FX = pname
                    if fx_index and fx_index >= 0 then
                        last_fx_index = fx_index
                    end
                end
                if config.open_floating_after_adding and last_fx_index and last_fx_index >= 0 then
                    r.TrackFX_Show(track, last_fx_index, 3)
                end
                if config.close_after_adding_fx then SHOULD_CLOSE_SCRIPT = true end
            end
        end
        dragging_fx_name = nil
        potential_drag_fx_name = nil
        if r.HasExtState("TKFXB", "drag_fx") then r.DeleteExtState("TKFXB", "drag_fx", false) end
    end
end

-----------------------------------------------------------------------------------------
local fx_browser_open = false
local last_fx_file_time = 0
local needs_screenshot_refresh = false
local last_window_check_time = 0
local WINDOW_CHECK_INTERVAL = 2.5 -- Check every 2.5 seconds

local function CheckFXBrowserWindow()
    local now = r.time_precise()
    if now - last_window_check_time < WINDOW_CHECK_INTERVAL then return end
    last_window_check_time = now

    -- Venster detectie via command state (40271 = FX Browser toggle) of JS
    local toggle = r.GetToggleCommandState(40271)
    local hwnd = r.JS_Window_Find and r.JS_Window_Find("FX Browser", true) or nil
    local was_open = fx_browser_open
    if toggle == 1 or hwnd then
        fx_browser_open = true
        native_fx_browser_hwnd = hwnd  -- Store window handle for focus management
    else
        fx_browser_open = false
        native_fx_browser_hwnd = nil
    end
    
    -- Melding bij verandering
    if fx_browser_open and not was_open then
        -- Popup wordt getoond in pauze branch
    elseif not fx_browser_open and was_open then
        needs_screenshot_refresh = true  -- Forceer refresh van screenshots na hervat
    end
end

local last_fx_count = -1

function Main()
    local frame_start = r.time_precise()

    if ctx and r.ImGui_ValidatePtr(ctx, 'ImGui_Context*') and r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Escape()) then
        SHOULD_CLOSE_SCRIPT = true
    end

    
    SetRunningState(true)
    r.SetExtState("TK_FX_BROWSER_MINI", "heartbeat", tostring(r.time_precise()), false)
    MaybeClearCaches()

    do
        local stamp = r.GetExtState("TK_FX_BROWSER_SYNC", "config_changed")
        if stamp ~= "" and stamp ~= last_config_stamp then
            last_config_stamp = stamp
            local source = stamp:match("^([^|]+)")
            if source ~= "MINI" then
                LoadConfig()
                window_alpha_int = math.floor((config.window_alpha or 1) * 100)
                needs_font_update = true
            end
        end
    end

    if projects_loading then
        if projects_loading_frame > 0 then
            projects_loading_frame = projects_loading_frame - 1
        else
            LoadProjects()
        end
    end

    if tk_pending_deletes then tk_pending_deletes = nil end
    
    if not ctx or not r.ImGui_ValidatePtr(ctx, 'ImGui_Context*') then
        InitializeImGuiContext()
        return r.defer(Main)
    end   
        if not TRACK or not r.ValidatePtr(TRACK, "MediaTrack*") then
        local selected_track = r.GetSelectedTrack(0, 0)
        local master_track = r.GetMasterTrack(0)
        if r.IsTrackSelected(master_track) then
            TRACK = master_track
        elseif selected_track then
            TRACK = selected_track
        else
            local first_track = r.GetTrack(0, 0)
            TRACK = first_track or master_track
        end
    end

    if needs_font_update then
        UpdateFonts()
        needs_font_update = false
    end
    local currentProjectPath = r.EnumProjects(-1, '')
    if lastProjectPath ~= currentProjectPath then
        InitializeImGuiContext()
        lastProjectPath = currentProjectPath
        if not r.ImGui_ValidatePtr(ctx, 'ImGui_Context*') then
            return r.defer(Main)
        end
    end
        
        local prev_track = TRACK
        local selected_track = r.GetSelectedTrack(0, 0)
        local master_track = r.GetMasterTrack(0)
        if r.IsTrackSelected(master_track) then
            TRACK = master_track
            is_master_track_selected = true
        elseif selected_track then
            TRACK = selected_track
            is_master_track_selected = false
        end
        
        if TRACK ~= last_selected_track then
            if selected_folder == "Current Track FX" then
                filtered_plugins = GetCurrentTrackFX()
                current_filtered_fx = GetPluginsForFolder("Current Track FX")
                ClearScreenshotCache()
            end
            if TRACK then
                last_fx_count = r.TrackFX_GetCount(TRACK)
            else
                last_fx_count = -1
            end
        end

        if selected_folder == "Current Track FX" and TRACK and r.ValidatePtr(TRACK, "MediaTrack*") then
            local current_fx_count = r.TrackFX_GetCount(TRACK)
            if current_fx_count ~= last_fx_count then
                filtered_plugins = GetCurrentTrackFX()
                current_filtered_fx = GetPluginsForFolder("Current Track FX")
                ClearScreenshotCache()
                last_fx_count = current_fx_count
            end
        end
        
        last_selected_track = TRACK
        
        ProcessTextureLoadQueue()
        if needs_screenshot_refresh then
            ClearScreenshotCache()
            needs_screenshot_refresh = false
        end
        local now = r.time_precise()
        if now - last_cleanup_time > 300 then
            ClearScreenshotCache(true)
            last_cleanup_time = now
        end
        if r.ImGui_ValidatePtr(ctx, 'ImGui_Context*') then
            pushed_main_styles = true
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_FrameRounding(), 2)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowRounding(), 7)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_ItemSpacing(), 3, 3)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_WindowPadding(), 5, 5)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_GrabMinSize(), 8)
            r.ImGui_PushStyleVar(ctx, r.ImGui_StyleVar_GrabRounding(), 3)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_WindowBg(), config.background_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Text(), r.ImGui_ColorConvertDouble4ToU32(config.text_gray/255, config.text_gray/255, config.text_gray/255, 1))
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Button(), config.button_background_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_ButtonHovered(), config.button_hover_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_Tab(), config.tab_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_TabHovered(), config.tab_hovered_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_FrameBg(), config.frame_bg_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_FrameBgHovered(), config.frame_bg_hover_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_FrameBgActive(), config.frame_bg_active_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_SliderGrab(), config.slider_grab_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_SliderGrabActive(), config.slider_active_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_PopupBg(), config.dropdown_bg_color)
            r.ImGui_PushStyleColor(ctx, r.ImGui_Col_CheckMark(), r.ImGui_ColorConvertDouble4ToU32(0.7, 0.7, 0.7, 1.0))
            r.ImGui_PushFont(ctx, NormalFont, config.font_size)
            r.ImGui_SetNextWindowBgAlpha(ctx, config.window_alpha)
        else
            pushed_main_styles = false
            InitializeImGuiContext()
        end

    -- DISABLED: Native FX Browser detection (caused 200ms+ freezes every 2.5s via JS_Window_Find)
    -- CheckFXBrowserWindow()
    if false and fx_browser_open then
        -- Pop styles om fout te voorkomen
        if pushed_main_styles then
            r.ImGui_PopFont(ctx)
            r.ImGui_PopStyleColor(ctx, 13) -- 13 StyleColors
            r.ImGui_PopStyleVar(ctx, 6)    -- 6 StyleVars
            pushed_main_styles = false     -- Reset flag
        end
        
        -- Create a minimal invisible window to keep ImGui context valid
        local pause_flags = r.ImGui_WindowFlags_NoTitleBar() | 
                           r.ImGui_WindowFlags_NoResize() | 
                           r.ImGui_WindowFlags_NoMove() | 
                           r.ImGui_WindowFlags_NoScrollbar() | 
                           r.ImGui_WindowFlags_NoScrollWithMouse() | 
                           r.ImGui_WindowFlags_NoCollapse() | 
                           r.ImGui_WindowFlags_NoFocusOnAppearing()
        
        r.ImGui_SetNextWindowPos(ctx, -1000, -1000)
        r.ImGui_SetNextWindowSize(ctx, 1, 1)
        local pause_visible, pause_open = r.ImGui_Begin(ctx, 'TK FX BROWSER Mini (Paused)', true, pause_flags)
        if pause_visible then
            r.ImGui_Text(ctx, "") -- Empty content
            r.ImGui_End(ctx)
        end
        
        if pause_open then
            r.defer(Main)
        end
        return
    end

-- Check visibility states
local general_visibility = CheckVisibilityState()
if pending_clear_on_show then
    pending_clear_on_show = false
    local saved_term = browser_search_term
    if not selected_folder and not browser_panel_selected then
        if last_selected_folder_before_global then
            selected_folder = last_selected_folder_before_global
            last_selected_folder_before_global = nil
        elseif last_panel_before_global then
            browser_panel_selected = last_panel_before_global
            last_panel_before_global = nil
        end
    end
    current_filtered_fx = nil
    if saved_term ~= "" and config.always_search_all then
        SearchAllPlugins()
    else
        RefreshCurrentScreenshotView()
    end
    screenshot_search_autoselect = (saved_term ~= "")
    screenshot_folder_filter_suspended = false
    _last_screenshot_signature = _build_screenshot_signature()
end
local should_show_main_window = ShouldShowMainWindow()

-- If whole script is hidden (TOGGLE_VISIBILITY), show hidden window
if not general_visibility then
    -- Window is hidden but script keeps running
    -- Clean up any pushed styles before creating hidden window
    if pushed_main_styles then
        r.ImGui_PopFont(ctx)
        r.ImGui_PopStyleColor(ctx, 13) -- 13 StyleColors
        r.ImGui_PopStyleVar(ctx, 6)    -- 6 StyleVars
        pushed_main_styles = false     -- Reset flag om dubbels te voorkomen
    end
    
    -- Create a minimal invisible window to keep the script active
    local invisible_flags = r.ImGui_WindowFlags_NoTitleBar() | 
                           r.ImGui_WindowFlags_NoResize() | 
                           r.ImGui_WindowFlags_NoMove() | 
                           r.ImGui_WindowFlags_NoScrollbar() | 
                           r.ImGui_WindowFlags_NoScrollWithMouse() | 
                           r.ImGui_WindowFlags_NoCollapse() | 
                           r.ImGui_WindowFlags_NoFocusOnAppearing()
    
    r.ImGui_SetNextWindowPos(ctx, -1000, -1000)
    r.ImGui_SetNextWindowSize(ctx, 1, 1)
    local hidden_visible, hidden_open = r.ImGui_Begin(ctx, 'TK FX BROWSER MINI (Hidden)', true, invisible_flags)
    if hidden_visible then
        r.ImGui_Text(ctx, "") -- Empty content
        r.ImGui_End(ctx)
    end
    
    if hidden_open then
        r.defer(Main)
    end
    return
end

if not should_show_main_window then
    -- Mini version always shows screenshot window
    ShowScreenshotWindow()
    
    -- Show bulk screenshot progress in separate window
    ShowBulkScreenshotProgressWindow()
    
    if config.show_debug_window then
        ShowDebugWindow()
    end

    DrawShortcutsWindow()
    
    if show_settings then
        show_settings = ShowConfigWindow()
    end

    if rename_plugin_open then
        r.ImGui_OpenPopup(ctx, "Rename Plugin")
    end
    
    if r.ImGui_BeginPopupModal(ctx, "Rename Plugin", true, r.ImGui_WindowFlags_AlwaysAutoResize() | r.ImGui_WindowFlags_NoSavedSettings() | r.ImGui_WindowFlags_TopMost()) then
        r.ImGui_Text(ctx, "Original Name: " .. rename_plugin_target)
        r.ImGui_Separator(ctx)
        
        local changed, new_name = r.ImGui_InputText(ctx, "New Name (Alias)", rename_plugin_new_name, 256)
        if changed then rename_plugin_new_name = new_name end
        
        if r.ImGui_Button(ctx, "Save", 120) or r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Enter()) or r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_KeypadEnter()) then
            if rename_plugin_new_name == "" or rename_plugin_new_name == rename_plugin_target then
                plugin_aliases[rename_plugin_target] = nil
            else
                plugin_aliases[rename_plugin_target] = rename_plugin_new_name
            end
            SaveAliases()
            -- Invalidate caches
            plugin_lower_name = {}
            BuildPluginCache() -- UPDATE CACHE
            ClearScreenshotCache()
            BuildScreenshotIndex(true)
            rename_plugin_open = false
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Reset", 120) then
            rename_plugin_new_name = rename_plugin_target
            -- Reset logic should probably also clear the alias if it was set, but here it just resets the input field?
            -- Wait, the original code just reset the input field: rename_plugin_new_name = rename_plugin_target
            -- But if the user wants to actually reset the alias to default, they should probably clear it and save.
            -- The Main script has a Reset button that clears the alias.
            -- Let's check the Main script logic again.
            -- Main script: plugin_aliases[renaming_plugin_name] = nil; SavePluginAliases(); ...
            -- Mini script: rename_plugin_new_name = rename_plugin_target
            -- The Mini script "Reset" button seems to only reset the text input to the original name, not clear the alias immediately.
            -- However, if I want to match the Main script behavior or at least ensure cache is consistent if they save...
            -- Actually, the user asked to apply the changes. The changes in Main script included updating the cache on Reset.
            -- But in Mini script, the Reset button logic is different (it just resets the input field).
            -- I should probably leave the Reset button logic as is for now unless I want to change its behavior to match Main.
            -- But wait, if I change the alias via Save, I update the cache.
            -- If I don't change the alias (just reset input), I don't need to update cache.
            -- So I only need to update the Save block.
        end
        r.ImGui_SameLine(ctx)
        if r.ImGui_Button(ctx, "Cancel", 120) or r.ImGui_IsKeyPressed(ctx, r.ImGui_Key_Escape()) then
            rename_plugin_open = false
            r.ImGui_CloseCurrentPopup(ctx)
        end
        r.ImGui_EndPopup(ctx)
    end
    
    if config.enable_drag_add_fx then
        DrawDragOverlay()
    end
    
    -- Handle drag & drop completion when main window is hidden
    HandleDragAndDrop()
    
    -- Frame time profiling
    local frame_time = r.time_precise() - frame_start
    if frame_time > 0.1 then  -- Meer dan 100ms = freeze
        local msg = string.format("⚠️ SLOW FRAME: %.3fs (%.0fms)", frame_time, frame_time * 1000)
        DebugLog(msg)  -- Naar internal debug window
    end
    
    if pushed_main_styles then
        r.ImGui_PopFont(ctx)
        r.ImGui_PopStyleColor(ctx, 13) -- 13 StyleColors
        r.ImGui_PopStyleVar(ctx, 6)    -- 6 StyleVars
    end
    
    if SHOULD_CLOSE_SCRIPT then
        SetRunningState(false)
        return
    end

    if SHOULD_HIDE_BROWSER then
        r.SetExtState("TK_FX_BROWSER_MINI", "visibility", "hidden", true)
        SHOULD_HIDE_BROWSER = false
    end

    HandleScreenshotShortcutInput()
    collectgarbage("step", 200)
    r.defer(Main)
    return
end

end
